CREATE TABLE IF NOT EXISTS Canciones (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  titulo TEXT NOT NULL,
  letra TEXT NOT NULL,
  grupo TEXT,
  extras TEXT
);

CREATE TABLE IF NOT EXISTS Configuraciones (
  clave TEXT PRIMARY KEY,
  valor TEXT NOT NULL
);


