INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (1, 'Abba Padre', '[{"c":"","l":"El Señor, el Señor ya está aquí"},{"c":"","l":"derramando su amor sobre ti"},{"c":"","l":"y cantemos para Él,"},{"c":"","l":"y entonemos a una voz,"},{"c":"","l":"y cantemos para Él,"},{"c":"","l":"y entonemos a una voz."},{"c":"","l":""},{"c":"","l":"*Abba Padre, venga tu Reino*"},{"c":"","l":"*Abba Padre, venga tu Reino*"},{"c":"","l":""},{"c":"","l":"Deja toda tristeza y dolor,"},{"c":"","l":"y levanta tus brazos a Dios,"},{"c":"","l":"y cantemos para él,"},{"c":"","l":"y entonemos a una voz,"},{"c":"","l":"y cantemos para él,"},{"c":"","l":"y entonemos a una voz."},{"c":"","l":""},{"c":"","l":"*Abba Padre, venga tu Reino*"},{"c":"","l":"*Abba Padre, venga tu Reino*"},{"c":"","l":""},{"c":"","l":"Alabemos con el corazón,"},{"c":"","l":"y que reine por siempre su amor,"},{"c":"","l":"y cantemos para él,"},{"c":"","l":"y entonemos a una voz,"},{"c":"","l":"y cantemos para él,"},{"c":"","l":"y entonemos a una voz."},{"c":"","l":""},{"c":"","l":"*Abba Padre, venga tu Reino*"},{"c":"","l":"*Abba Padre, venga tu Reino*"}]', 'ENTRADA', '{"youtube_url":"https://www.youtube.com/watch?v=XEaOHUgBba4&list=RDXEaOHUgBba4","autor":""}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (2, 'Vienen con alegría', '[{"c":"Re","l":"Vienen con alegría señor,"},{"c":"","l":"cantando vienen con alegría señor."},{"c":"","l":""},{"c":"Sol                     Re","l":"Los que caminan por la vida señor"},{"c":"    Mi7              La7","l":"sembrando tu paz y amor."},{"c":"Re","l":"Vienen trayendo la esperanza"},{"c":"     La7                Re","l":"a un mundo cargado de ansiedad"},{"c":"                                 La7","l":"a un mundo que busca y que no alcanza,"},{"c":"                         Re","l":"caminos de amor y de amistad."},{"c":"","l":""},{"c":"Re","l":"Vienen trayendo entre sus manos"},{"c":"   La7                         Re","l":"Esfuerzos de hermanos por la paz"},{"c":"                         La7","l":"Deseos de un mundo más humano"},{"c":"                            Re","l":"Que nacen del bien y la verdad."},{"c":"","l":""},{"c":"","l":"Cuando el odio y la violencia"},{"c":"","l":"aniden en nuestro corazón"},{"c":"","l":"el mundo sabrá que por herencia"},{"c":"","l":"le guardan tristezas y dolor..."}]', 'ENTRADA', '{"youtube_url":"https://www.youtube.com/watch?v=E1Gw1vtmLnE","autor":"C. Gabaraín"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (3, 'Qué lindo llegar cantando', '[{"c":"","l":"Qué lindo llegar cantando"},{"c":"","l":"a tu casa Padre Dios,"},{"c":"","l":"y hermanados en el canto"},{"c":"","l":"comenzar nuestra oración."},{"c":"","l":"Darte gracias y alabanzas,"},{"c":"","l":"pedirte ayuda y perdón."},{"c":"","l":"Qué lindo llegar cantando"},{"c":"","l":"a tu casa Padre Dios."},{"c":"","l":""},{"c":"","l":"Qué lindo traer la vida"},{"c":"","l":"a nuestra celebración,"},{"c":"","l":"contarle a nuestros hermanos"},{"c":"","l":"y que se vuelva oración,"},{"c":"","l":"sudor, lágrima, esperanza,"},{"c":"","l":"trabajo, rezo y amor."},{"c":"","l":"Qué lindo rezar cantando"},{"c":"","l":"la vida que se nos dio."},{"c":"","l":""},{"c":"","l":"Qué lindo encontrar hermanos"},{"c":"","l":"que viven la misma fe,"},{"c":"","l":"y amando son serviciales"},{"c":"","l":"y esperando saben ver"},{"c":"","l":"que el Reino de Dios avanza"},{"c":"","l":"sencillamente y de a pie."},{"c":"","l":"Qué lindo rezar cantando"},{"c":"","l":"el misterio de la fe."},{"c":"","l":""},{"c":"","l":"Qué lindo saber que somos"},{"c":"","l":"una Iglesia comunión,"},{"c":"","l":"que nace con el bautismo"},{"c":"","l":"y crece con la misión"},{"c":"","l":"de unir entre sí a los hombres"},{"c":"","l":"y a la humanidad con Dios."},{"c":"","l":"Qué lindo rezar cantando"},{"c":"","l":"y sentir la comunión."},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (4, 'En el nombre de Dios', '[{"c":"","l":"Aquí estamos Señor, en tu casa otra vez"},{"c":"","l":"¡Qué alegría volverte a encontrar!"},{"c":"","l":"Vamos a compartir y expresar nuestra fe"},{"c":"","l":"como hermanos en torno al altar."},{"c":"","l":""},{"c":"","l":"En el Nombre de Dios vamos a celebrar"},{"c":"","l":"el misterio de la Salvación."},{"c":"","l":"El Señor nos dará su Palabra y su pan,"},{"c":"","l":"es la Fiesta del Pueblo de Dios."},{"c":"","l":""},{"c":"","l":"Partiremos tu pan, signo de comunión,"},{"c":"","l":"beberemos tu vino de amor."},{"c":"","l":"Y a la vez sellarás con nosotros Señor"},{"c":"","l":"una Alianza que viene de Dios."},{"c":"","l":""},{"c":"","l":"Nos amaste Señor como nadie jamás,"},{"c":"","l":"nos da fuerzas tu fidelidad."},{"c":"","l":"En la mesa de Dios, hoy nos transformarás"},{"c":"","l":"en fermento de comunidad"},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (5, 'Juntos como hermanos', '[{"c":"","l":"Juntos como hermanos,"},{"c":"","l":"miembros de una iglesia,"},{"c":"","l":"vamos caminando,"},{"c":"","l":"al encuentro del señor."},{"c":"","l":""},{"c":"","l":"Es largo el caminar,"},{"c":"","l":"por el desierto bajo el sol"},{"c":"","l":"no podemos avanzar"},{"c":"","l":"sin la ayuda del Señor."},{"c":"","l":""},{"c":"","l":"Unidos al orar,"},{"c":"","l":"unidos en una canción,"},{"c":"","l":"viviremos nuestra fe"},{"c":"","l":"con la ayuda del Señor."},{"c":"","l":""},{"c":"","l":"La Iglesia en marcha está"},{"c":"","l":"a un mundo nuevo vamos ya,"},{"c":"","l":"donde reinará el amor,"},{"c":"","l":"donde reinará la paz."},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (6, 'Hoy tu Espíritu, Señor', '[{"c":"","l":"Hoy tu Espíritu Señor"},{"c":"","l":"nos congrega en la unidad,"},{"c":"","l":"nos da fuerza para andar"},{"c":"","l":"renovados en tu amor."},{"c":"","l":""},{"c":"","l":"Santo Espí&shy;ritu de Dios,"},{"c":"","l":"de la paz y de la Luz,"},{"c":"","l":"que nos das a conocer"},{"c":"","l":"el misterio de Jesús."},{"c":"","l":"Ven, al fin, a saciar"},{"c":"","l":"nuestra sed de paz."},{"c":"","l":""},{"c":"","l":"Este mundo y su dolor"},{"c":"","l":"clama ardiente de ansiedad."},{"c":"","l":"Que tu Espí&shy;ritu de amor"},{"c":"","l":"lo conduzca a la verdad."},{"c":"","l":"Ven, al fin, a reinar,"},{"c":"","l":"cambia al mundo ya."},{"c":"","l":""},{"c":"","l":"Ni la carga de la Cruz"},{"c":"","l":"nuestras fuerzas redirá."},{"c":"","l":"La alegrí&shy;a que Tú das"},{"c":"","l":"nadie no la ha de quitar."},{"c":"","l":"Ven, al fin, a cantar"},{"c":"","l":"en mi voz: Amén."},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', '{"youtube_url":"","autor":"Reigada"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (7, 'La Virgen María nos reúne', '[{"c":"","l":"La Virgen María nos reúne"},{"c":"","l":"en nombre del Señor,"},{"c":"","l":"del Señor Jesús,Dios nuestro Señor."},{"c":"","l":""},{"c":"","l":"Venimos a buscar el pan de la Palabra,"},{"c":"","l":"Palabra del Señor que reconforta el alma."},{"c":"","l":""},{"c":"","l":"Venimos a comer el Pan sacramentado,"},{"c":"","l":"el Cuerpo del Señor, Jesús resucitado."},{"c":"","l":""},{"c":"","l":"Venimos a llevar el pan de la alegría,"},{"c":"","l":"mensaje que nos dio el Hijo de María."},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (8, 'Qué alegría cuando me dijeron', '[{"c":"","l":"¡Qué alegría cuando me dijeron:"},{"c":"","l":"“vamos a la casa del señor”!"},{"c":"","l":"ya están pisando nuestros pies"},{"c":"","l":"tus umbrales, Jerusalén."},{"c":"","l":""},{"c":"","l":"Jerusalén está fundada"},{"c":"","l":"como ciudad bien compacta."},{"c":"","l":"Allá suben las tribus,"},{"c":"","l":"las tribus del Señor."},{"c":"","l":""},{"c":"","l":"Según la costumbre de Israel:"},{"c":"","l":"a celebrar el nombre del Señor;"},{"c":"","l":"en ella están los tribunales de Justicia,"},{"c":"","l":"en el palacio de David."},{"c":"","l":""},{"c":"","l":"Desead la paz a Jerusalén:"},{"c":"","l":"“Vivan seguros los que te aman,"},{"c":"","l":"haya paz dentro de tus muros,"},{"c":"","l":"en tus palacios seguridad”."},{"c":"","l":""},{"c":"","l":"Por mis hermanos y compañeros"},{"c":"","l":"voy a decir la paz contigo"},{"c":"","l":"por la casa del señor nuestro Dios"},{"c":"","l":"te deseo todo bien."},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (9, 'Canten todos', '[{"c":"","l":"Canten todos la alegría"},{"c":"","l":"de vivir en Dios."},{"c":"","l":""},{"c":"","l":"La buena noticia de Cristo Jesús,"},{"c":"","l":"la entienden los pobres y es fuerza y es luz."},{"c":"","l":"Si estamos abiertos cuando hablas Señor"},{"c":"","l":"nos da tu Palabra la paz interior."},{"c":"","l":""},{"c":"","l":"El hambre y la sed de justicia nos dan"},{"c":"","l":"la ardiente pasión de guardar tu verdad."},{"c":"","l":""},{"c":"","l":"Al hombre sediento de vida y verdad"},{"c":"","l":"tan sólo Tú, Cristo, lo puedes colmar."},{"c":"","l":""},{"c":"","l":"Creer es mirar con tus ojos, Señor,"},{"c":"","l":"y darle a la vida todo su valor."},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', '{"youtube_url":"","autor":"J. C. Labaké"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (10, 'Somos un pueblo que camina', '[{"c":"","l":"Somos un pueblo que camina"},{"c":"","l":"y juntos caminando podremos alcanzar,"},{"c":"","l":"otra ciudad que no se acaba,"},{"c":"","l":"sin penas ni tristezas,"},{"c":"","l":"ciudad de eternidad."},{"c":"","l":""},{"c":"","l":"Somos un pueblo que camina,"},{"c":"","l":"que marcha por el mundo,"},{"c":"","l":"buscando otra ciudad."},{"c":"","l":"Somos errantes peregrinos"},{"c":"","l":"en busca de un destino,"},{"c":"","l":"destino de unidad."},{"c":"","l":""},{"c":"","l":"Siempre seremos caminantes,"},{"c":"","l":"pues solo caminando podremos alcanzar"},{"c":"","l":"otra ciudad que no se acaba,"},{"c":"","l":"sin penas ni tristezas,"},{"c":"","l":"ciudad de eternidad."},{"c":"","l":"Danos valor siempre constante"},{"c":"","l":"valor en las tristezas, valor en nuestro afán."},{"c":"","l":"Danos la luz de tu Palabra"},{"c":"","l":"que guíe nuestros pasos en este caminar."},{"c":"","l":""},{"c":"","l":"Marcha, Señor, junto a nosotros"},{"c":"","l":"Pues solo en tu presencia podremos alcanzar"},{"c":"","l":"otra ciudad que no se acaba,"},{"c":"","l":"sin penas ni tristezas ciudad de eternidad."},{"c":"","l":""}]', 'ENTRADA', '{"youtube_url":"","autor":"E. Mateu"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (11, 'Vine a alabar a Dios', '[{"c":"","l":"Vine a alabar a Dios,"},{"c":"","l":"Vine a alabar a Dios,"},{"c":"","l":"Vine a alabar su Nombre."},{"c":"","l":"Vine a alabar a Dios."},{"c":"","l":""},{"c":"","l":"Él llegó a mi vida en un día muy especial,"},{"c":"","l":"cambió mi corazón por un nuevo corazón"},{"c":"","l":"y esa es la razón por la que digo que"},{"c":"","l":"vine a alabar a Dios."},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (12, 'Cristo Joven', '[{"c":"","l":"Ven hermano y cántale a Cristo"},{"c":"","l":"a ese Cristo joven que un día nos redimió,"},{"c":"","l":"haz de tu amor una plegaria,"},{"c":"","l":"un simple canto alegre que el Señor escuchará."},{"c":"","l":""},{"c":"","l":"Ven aquí, canta ya,"},{"c":"","l":"no te olvides tú de Cristo."},{"c":"","l":"Piensa que en la cruz"},{"c":"","l":"por nosotros Él se dio, por amor."},{"c":"","l":""},{"c":"","l":"No te alejes del camino marcado,"},{"c":"","l":"que Cristo ha señalado para acercarnos a Él,"},{"c":"","l":"devuélvele con fe inquebrantable"},{"c":"","l":"el amor incuestionable que nos ha ofrecido El."},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (13, 'En siete días', '[{"c":"","l":"En siete días creó Dios al mundo"},{"c":"","l":"Adán pecó y perdió el cielo"},{"c":"","l":"Jesús vino para redimirnos"},{"c":"","l":"murió en la cruz y nos salvó."},{"c":"","l":""},{"c":"","l":"Den al Señor sus Alabanzas"},{"c":"","l":"Denle poder, honor y Gloria"},{"c":"","l":"A una voz, cántenle un Himno al Señor"},{"c":"","l":""},{"c":"","l":"A Moisés Dios dijo \\\"haz mi pueblo libre"},{"c":"","l":"Yo seré tu guía, siempre sígueme,"},{"c":"","l":"Salieron ya de Egipto y el mar pasaron,"},{"c":"","l":"Cantaron y bailaron, se llenaron de júbilo."},{"c":"","l":""},{"c":"","l":"Jesús dijo a Pedro \\\"ven te llamo"},{"c":"","l":"el camino es duro, mas iré contigo\\\""},{"c":"","l":"Pedro respondió \\\"Soy un pecador\\\""},{"c":"","l":"tiro su red y hacia el Señor corrió."},{"c":"","l":"Entrégate hermano al Señor Jesús,"},{"c":"","l":"Él te ama aunque seas pecador,"},{"c":"","l":"El pago el precio de tu salvación"},{"c":"","l":"y ahora eres una nueva creación."},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (14, 'Bendeciré al Señor (Salmo 33)', '[{"c":"","l":"Bendeciré al Señor en todo tiempo"},{"c":"","l":"y mi boca no cesará de alabarlo."},{"c":"","l":"Mi alma se enorgullece en el Señor"},{"c":"","l":"que lo oigan los humildes y se alegren."},{"c":"","l":""},{"c":"","l":"Prueben que bueno es el señor,"},{"c":"","l":"hagan la prueba y véanlo,"},{"c":"","l":"dichoso aquel que busca en Él refugio."},{"c":"","l":""},{"c":"","l":"Engrandezcan conmigo al Señor,"},{"c":"","l":"ensalcemos todos su nombre."},{"c":"","l":"Busqué al Señor y me dio una respuesta"},{"c":"","l":"me libró de todos mis temores."},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (15, 'Iglesia Peregrina', '[{"c":"","l":"Todos unidos formando un solo cuerpo,"},{"c":"","l":"un cuerpo que en la Pascua nació;"},{"c":"","l":"miembros de Cristo en sangre redimidos,"},{"c":"","l":"Iglesia peregrina de Dios."},{"c":"","l":""},{"c":"","l":"Vive en nosotros la fuerza del Espíritu"},{"c":"","l":"que el Hijo desde el Padre envió,"},{"c":"","l":"El nos conduce, nos guía y alimenta,"},{"c":"","l":"Iglesia peregrina de Dios."},{"c":"","l":""},{"c":"","l":"Somos en la tierra"},{"c":"","l":"semilla de otro reino,"},{"c":"","l":"somos testimonio de amor."},{"c":"","l":"Paz para las guerras"},{"c":"","l":"y luz entre las sombras"},{"c":"","l":"Iglesia peregrina de Dios."},{"c":"","l":""},{"c":"","l":"Rugen tormentas y a veces nuestra barca"},{"c":"","l":"parece que ha perdido el timón."},{"c":"","l":"Miras con miedo, no tienes confianza,"},{"c":"","l":"Iglesia peregrina de Dios."},{"c":"","l":"Una esperanza nos llena de alegría;"},{"c":"","l":"presencia que el Señor prometió."},{"c":"","l":"Vamos cantando, El viene con nosotros,"},{"c":"","l":"Iglesia peregrina de Dios."},{"c":"","l":""},{"c":"","l":"Todos nacidos en un solo bautismo,"},{"c":"","l":"unidos en la misma comunión."},{"c":"","l":"Todos viviendo en una misma casa,"},{"c":"","l":"Iglesia peregrina de Dios."},{"c":"","l":"Todos prendidos en una misma suerte,"},{"c":"","l":"ligados a la misma salvación"},{"c":"","l":"somos un cuerpo y Cristo es la Cabeza"},{"c":"","l":"Iglesia peregrina de Dios."},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (16, 'Aleluya por esa gente', '[{"c":"","l":"Los que tienen y nunca se olvidan"},{"c":"","l":"que a otros les falta."},{"c":"","l":"Los que nunca usaron la fuerza"},{"c":"","l":"sino la razón."},{"c":"","l":"Los que dan una mano y ayudan"},{"c":"","l":"a los que han caído"},{"c":"","l":"esa gente es feliz porque vive"},{"c":"","l":"muy cerca de Dios."},{"c":"","l":""},{"c":"","l":"Aleluya, Aleluya"},{"c":"","l":"Por esa gente que vive y que siente"},{"c":"","l":"En su vida el amor"},{"c":"","l":"Aleluya, Aleluya"},{"c":"","l":"Por esa gente que vive y que siente"},{"c":"","l":"En su vida el amor"},{"c":"","l":""},{"c":"","l":"Los que ponen en todas las cosas"},{"c":"","l":"amor y justicia."},{"c":"","l":"Los que nunca sembraron el odio"},{"c":"","l":"tampoco el dolor"},{"c":"","l":"los que dan y no piensan jamás"},{"c":"","l":"en su recompensa"},{"c":"","l":"Esa gente es feliz porque vive"},{"c":"","l":"muy cerca de Dios."},{"c":"","l":""},{"c":"","l":"Los que son generosos y dan"},{"c":"","l":"de su pan un pedazo."},{"c":"","l":"Los que siempre trabajan pensando"},{"c":"","l":"en un mundo mejor"},{"c":"","l":"Los que están liberados de todas"},{"c":"","l":"sus ambiciones"},{"c":"","l":"Esa gente es feliz porque vive"},{"c":"","l":"muy cerca de Dios."},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (17, 'Dios trino', '[{"c":"","l":"En nombre del Padre,"},{"c":"","l":"en nombre del hijo,"},{"c":"","l":"en nombre del Santo Espíritu,"},{"c":"","l":"estamos aquí."},{"c":"","l":""},{"c":"","l":"Para alabar y agradecer,"},{"c":"","l":"bendecir y adorar,"},{"c":"","l":"estamos aquí, a tu disposición."},{"c":"","l":"Para alabar y agradecer,"},{"c":"","l":"bendecir y adorar,"},{"c":"","l":"estamos aquí, Señor"},{"c":"","l":"Dios trino de amor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (18, 'Mensajero de la paz', '[{"c":"","l":"Es hermoso ver bajar de la montaña"},{"c":"","l":"los pies del mensajero de la paz..."},{"c":"","l":""},{"c":"","l":"El Señor envió a sus discípulos,"},{"c":"","l":"los mando de dos en dos..."},{"c":"","l":""},{"c":"","l":"Los mando a las ciudades,"},{"c":"","l":"y lugares donde iba a ir él."},{"c":"","l":""},{"c":"","l":"La cosecha es abundante,"},{"c":"","l":"les dijo el Señor al partir..."},{"c":"","l":""},{"c":"","l":"Pídanle al dueño del campo,"},{"c":"","l":"que envíe más obreros a la mies."},{"c":"","l":""},{"c":"","l":"Al entrar en una casa,"},{"c":"","l":"saluden anunciando la paz."},{"c":"","l":""},{"c":"","l":"El Reino de Dios está cerca,"},{"c":"","l":"a todos anunciarán."},{"c":"","l":""},{"c":"","l":"Los que a ustedes los reciban,"},{"c":"","l":"me habrán recibido a Mí."},{"c":"","l":""},{"c":"","l":"Quien recibe mi Palabra,"},{"c":"","l":"recibe al que me envió."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (19, 'Dios de la vida', '[{"c":"","l":"Somos un nuevo pueblo,"},{"c":"","l":"Gestando un mundo distinto,"},{"c":"","l":"Los que en el amor creemos,"},{"c":"","l":"Los que en el amor vivimos."},{"c":"","l":"Llevamos este tesoro,"},{"c":"","l":"En vasijas de barro,"},{"c":"","l":"Es un mensaje del cielo"},{"c":"","l":"Y nadie podrá callarnos."},{"c":"","l":""},{"c":"","l":"Y proclamamos un nuevo día,"},{"c":"","l":"Porque la muerte ha sido vencida."},{"c":"","l":"Y anunciamos esta buena noticia,"},{"c":"","l":"Hemos sido salvados,"},{"c":"","l":"por el Dios de la Vida."},{"c":"","l":""},{"c":"","l":"En el medio de la noche,"},{"c":"","l":"Encendemos una luz,"},{"c":"","l":"En el nombre de Jesús."},{"c":"","l":""},{"c":"","l":"Sembradores del desierto,"},{"c":"","l":"Buenas nuevas anunciamos,"},{"c":"","l":"Extranjeros en un mundo"},{"c":"","l":"Que no entiende nuestro canto."},{"c":"","l":"Y aunque a veces nos cansamos,"},{"c":"","l":"Nunca nos desanimamos,"},{"c":"","l":"Porque somos peregrinos"},{"c":"","l":"y es el amor nuestro camino."},{"c":"","l":""},{"c":"","l":"Y renunciamos a la mentira,"},{"c":"","l":"Vamos trabajando por la justicia."},{"c":"","l":"Y rechazamos toda idolatría,"},{"c":"","l":"Porque está entre nosotros,"},{"c":"","l":"el Dios de la vida."},{"c":"","l":""},{"c":"","l":"En el medio de la noche,"},{"c":"","l":"Encendemos una luz,"},{"c":"","l":"En el nombre de Jesús."},{"c":"","l":""},{"c":"","l":"Que nuestro mensaje llegue,"},{"c":"","l":"Más allá de las fronteras,"},{"c":"","l":"Y resuene en todo el mundo"},{"c":"","l":"Y será una nueva tierra."},{"c":"","l":"Es un canto de victoria,"},{"c":"","l":"A pesar de las heridas,"},{"c":"","l":"Alzaremos nuestras voces,"},{"c":"","l":"Por el triunfo de la vida."},{"c":"","l":""},{"c":"","l":"Y cantaremos con alegría,"},{"c":"","l":"Corazones abiertos,"},{"c":"","l":"Nuestras manos unidas."},{"c":"","l":"Y celebraremos con alegría"},{"c":"","l":"Porque está entre nosotros"},{"c":"","l":"El Dios de la vida."},{"c":"","l":""},{"c":"","l":"En el medio de la noche,"},{"c":"","l":"Encendemos una luz,"},{"c":"","l":"En el nombre de Jesús."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', '{"youtube_url":"","autor":"Daniel Poli"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (20, 'Alabaré', '[{"c":"","l":"Alabare, alabare, alabare, alabare,"},{"c":"","l":"alabare a mi Señor"},{"c":"","l":""},{"c":"","l":"Juan vio el número de los elegidos"},{"c":"","l":"y todos alababan al Señor,"},{"c":"","l":"unos rezaban otros cantaban"},{"c":"","l":"y todos alababan al Señor."},{"c":"","l":""},{"c":"","l":"Somos tus hijos, Dios Padre eterno,"},{"c":"","l":"tu nos has creado por amor,"},{"c":"","l":"te alabamos, te bendecimos"},{"c":"","l":"y todos cantamos en tu honor."},{"c":"","l":""},{"c":"","l":"Todos unidos, juntos cantemos"},{"c":"","l":"glorias y alabanzas al señor"},{"c":"","l":"gloria al Padre, Gloria al Hijo"},{"c":"","l":"y Gloria al Espíritu de Amor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (21, 'Reunidos aquí', '[{"c":"","l":"Reunidos aquí, para alabar al Señor, nuevamente aquí, en unión."},{"c":"","l":"Algo nuevo va a suceder,"},{"c":"","l":"algo nuevo que Dios preparó."},{"c":"","l":"Reunidos aquí, para alabar al Señor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (22, 'Hoy perdóname', '[{"c":"","l":"Hoy perdóname,"},{"c":"","l":"hoy por siempre,"},{"c":"","l":"sin mirar la mentira"},{"c":"","l":"el vacío en nuestras vidas"},{"c":"","l":"nuestra falta de amor y caridad."},{"c":"","l":"Hoy perdóname,"},{"c":"","l":"hoy por siempre,"},{"c":"","l":"aun sabiendo que he caído"},{"c":"","l":"que de ti siempre había huido"},{"c":"","l":"hoy regreso arrepentido vuelvo a ti,"},{"c":"","l":"vuelvo a ti, vuelvo a ti, vuelvo a ti."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (23, 'Déjame nacer de nuevo', '[{"c":"","l":"Tú conoces la dureza en mi sentir"},{"c":"","l":"y la terquedad que hay en mi corazón."},{"c":"","l":"Son las cosas que me alejaron de Ti, Señor,"},{"c":"","l":"dame vida nueva con tu amor."},{"c":"","l":""},{"c":"","l":"Déjame nacer de nuevo,"},{"c":"","l":"Déjame nacer de nuevo,"},{"c":"","l":"Déjame nacer de nuevo, oh Señor."},{"c":"","l":"No importa la edad que tenga,"},{"c":"","l":"Tú no la tienes en cuenta."},{"c":"","l":"Déjame nacer de nuevo, oh Señor."},{"c":"","l":""},{"c":"","l":"Tú conoces el pecado que hay en mí"},{"c":"","l":"y el dolor que dejo en mi corazón."},{"c":"","l":"Por la muerte que he causado vuelvo a Ti, Señor,"},{"c":"","l":"Dame nueva vida en tu amor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (24, 'Kyrie', '[{"c":"","l":"Señor, ten piedad de nosotros."},{"c":"","l":"Cristo, ten piedad de nosotros."},{"c":"","l":"Señor, ten piedad de nosotros."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (25, 'La hemorroísa', '[{"c":"","l":"Se tu cual mujer que fue y tocó el borde del vestido de Jesús. Poder salió de Él y ella  sano,  y si lo tocas tú, sanas también."},{"c":"","l":""},{"c":"","l":"Dame un nuevo corazón"},{"c":"","l":"que te alabe noche y día."},{"c":"","l":"Dame un nuevo corazón."},{"c":"","l":"oh Jesús tu eres mi vida."},{"c":"","l":"Dame un nuevo corazón"},{"c":"","l":"y que sea morada tuya."},{"c":"","l":"Dame un nuevo corazón,"},{"c":"","l":"dame un nuevo corazón. Aleluya."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (26, 'Una vez más rezaré', '[{"c":"","l":"Una vez más rezaré,"},{"c":"","l":"de rodillas me pondré"},{"c":"","l":"puede ser que una vez más"},{"c":"","l":"El me perdone."},{"c":"","l":""},{"c":"","l":"Le diré que soy humano"},{"c":"","l":"que pequé, que lucho en vano,"},{"c":"","l":"puede ser que una vez más"},{"c":"","l":"El me perdone."},{"c":"","l":""},{"c":"","l":"Para un Dios que conoció la tentación"},{"c":"","l":"del amigo la traición"},{"c":"","l":"yo no dudo me perdone Dios mi amigo."},{"c":"","l":""},{"c":"","l":"Yo vi sufrir a mi hermano"},{"c":"","l":"y no le tendí la mano,"},{"c":"","l":"puede ser que una vez más"},{"c":"","l":"El me perdone."},{"c":"","l":""},{"c":"","l":"Lo vi solo y desahuciado"},{"c":"","l":"y yo de brazos cruzados"},{"c":"","l":"puede ser que una vez más"},{"c":"","l":"El me perdone."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (27, 'Zamba del perdón', '[{"c":"","l":"Perdón, por aquel mendigo,"},{"c":"","l":"por aquella lágrima que hice brillar."},{"c":"","l":"Perdón, por aquellos ojos"},{"c":"","l":"que al buscar los míos no quise mirar."},{"c":"","l":""},{"c":"","l":"Señor, no le di mi mano"},{"c":"","l":"se encontraba solo y lo dejó partir,"},{"c":"","l":"perdón, por no dar cariño"},{"c":"","l":"por sólo buscarlo y tan lejos de Ti."},{"c":"","l":""},{"c":"","l":"*Señor, por qué soy así."},{"c":"","l":"Estoy como ciego, no sé comprender."},{"c":"","l":"Señor, Tú eres mi esperanza"},{"c":"","l":"dame tu mirada, que te sepa ver.*"},{"c":"","l":""},{"c":"","l":"Señor, no estoy siempre alegre"},{"c":"","l":"no doy luz a otros que están junto a mí,"},{"c":"","l":"perdón, por esta tristeza,"},{"c":"","l":"por sentirme solo cuando estás ahí"},{"c":"","l":""},{"c":"","l":"Perdón, por otros hermanos"},{"c":"","l":"a quienes no importa de tu padecer,"},{"c":"","l":"estás cerca del que sufre,"},{"c":"","l":"pasan a tu lado pero no te ven."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (28, 'Tendrá', '[{"c":"","l":"Tendrá que haber un nuevo día tendrá que haber un nuevo sol,"},{"c":"","l":"en donde todo sea alegría,"},{"c":"","l":"en donde todo sea Amor."},{"c":"","l":""},{"c":"","l":"Gracias Señor por mis caídas,"},{"c":"","l":"gracias Señor por tu perdón,"},{"c":"","l":"por nosotros diste la vida,"},{"c":"","l":"nosotros la damos por vos."},{"c":"","l":""},{"c":"","l":"Veré nacer un nuevo Día,"},{"c":"","l":"verá brillar de nuevo el sol,"},{"c":"","l":"renacerá una esperanza,"},{"c":"","l":"renacerá la dicha,"},{"c":"","l":"renaceremos al Amor"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (29, 'El Perdón', '[{"c":"","l":"Sé que es difícil perdonar,"},{"c":"","l":"cuando no sabes amar;"},{"c":"","l":"el rencor es algo tan amargo dentro."},{"c":"","l":"No te deja sonreír, ya no puedes vivir,"},{"c":"","l":"por qué no dejas eso atrás"},{"c":"","l":"y empieza a amar."},{"c":"","l":""},{"c":"","l":"Hay alguien que te amo,"},{"c":"","l":"su propia vida te entregó"},{"c":"","l":"para que fueras libre de tu cautiverio. Perdonar a los demás, sin importar si hicieron mal;"},{"c":"","l":"por qué no dejas eso atrás"},{"c":"","l":"y empiezas a amar"},{"c":"","l":""},{"c":"","l":"Solo Dios puede juzgar,"},{"c":"","l":"el perdonar es una decisión"},{"c":"","l":"que deja en libertad tu corazón"},{"c":"","l":"y calma toda herida;"},{"c":"","l":"perdonar a los demás,"},{"c":"","l":"sin importar si hicieron mal;"},{"c":"","l":"porque no dejas eso atrás y empieza a amar"},{"c":"","l":""},{"c":"","l":"empieza a perdonar..."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (30, 'Perdón, perdón', '[{"c":"","l":"Perdón, perdón, perdóname Señor,"},{"c":"","l":"ante ti, yo pequé, perdóname Señor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (31, 'Vuelve tu mirada', '[{"c":"","l":"Pon tus ojos en sus ojos"},{"c":"","l":"y míralo un momento con amor."},{"c":"","l":"Pon tu vida entre sus manos"},{"c":"","l":"y escucha su voz."},{"c":"","l":"Por caminar sin mirarlo has tropezado,"},{"c":"","l":"estas herido y angustiado,"},{"c":"","l":"no te niegues la oportunidad."},{"c":"","l":""},{"c":"","l":"*Vuelve tu mirada al Señor"},{"c":"","l":"y recibe el misterio,"},{"c":"","l":"para salir del dolor y el temor."},{"c":"","l":"Vuelve tu mirada al Señor,"},{"c":"","l":"que él no desprecia"},{"c":"","l":"un corazón sincero.*"},{"c":"","l":""},{"c":"","l":"Pon en él tus esperanzas,"},{"c":"","l":"deja que te acaricie el corazón."},{"c":"","l":"Pon tus piedras a sus pies"},{"c":"","l":"confía en su amor."},{"c":"","l":"Por caminar sin mirarlo has tropezado,"},{"c":"","l":"estas herido y encerrado,"},{"c":"","l":"no hace bien tanta soledad."}]', 'PERDON', '{"youtube_url":"","autor":"Mariví"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (32, 'Transparencia', '[{"c":"","l":"Dame tu transparencia,"},{"c":"","l":"oh Fuente de Ser, Fuente de la vida!"},{"c":"","l":"Dame tu transparencia,"},{"c":"","l":"el deseo claro, tu estable armonía."},{"c":"","l":""},{"c":"","l":"No dejes que preocupen mi alma en exceso."},{"c":"","l":"La nube que tiene que cruzar mi cielo,"},{"c":"","l":"dame ojos limpios,"},{"c":"","l":"corazón más creyente y más bueno."},{"c":"","l":"Dame tu transparencia,"},{"c":"","l":"oh, Fuente de Todo, Fuente de hermosura!"},{"c":"","l":"Dame tu transparencia,"},{"c":"","l":"creativa mis manos, mansas y seguras."},{"c":"","l":""},{"c":"","l":"Lava mi corazón del mal que lo enturbia."},{"c":"","l":"Mi amor sea un arroyo, de aguas profundas."},{"c":"","l":"Dame alma de niño,"},{"c":"","l":"transparente a la mirada tuya."},{"c":"","l":""},{"c":"","l":"Dame tu transparencia,"},{"c":"","l":"oh, Fuente de Amor, Fuente de la Gracia!"},{"c":"","l":"Dame tu transparencia,"},{"c":"","l":"recta la intención y fiel la palabra."},{"c":"","l":""},{"c":"","l":"Devuelve la inocencia que robo el pecado,"},{"c":"","l":"la estable certeza de saberme amado."},{"c":"","l":"Dame tu presencia,"},{"c":"","l":"agua viva que limpia mi barro."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', '{"youtube_url":"","autor":"Eduardo Meana"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (33, 'Renuévame', '[{"c":"","l":"Renuévame, Señor Jesús,"},{"c":"","l":"ya no quiero ser igual."},{"c":"","l":"Renuévame, Señor Jesús,"},{"c":"","l":"pon en mi tu corazón."},{"c":"","l":""},{"c":"","l":"Porque todo lo que hay dentro de mí,"},{"c":"","l":"necesita ser cambiado Señor."},{"c":"","l":"Porque todo lo que hay"},{"c":"","l":"dentro de mi corazón,"},{"c":"","l":"necesita más de Ti . . ."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (34, '¿Cómo puedes tu orar?', '[{"c":"","l":"¿Cómo puedes tú orar"},{"c":"","l":"enojado con tu hermano? (2)"},{"c":"","l":"Dios no escucha la oración"},{"c":"","l":"Dios no escucha la oración"},{"c":"","l":"Si no estás reconciliado. (2)"},{"c":"","l":""},{"c":"","l":"Cristo dijo, perdonad"},{"c":"","l":"si queréis ser perdonados, (2)"},{"c":"","l":"porque aquel que no perdona"},{"c":"","l":"porque aquel que no perdona"},{"c":"","l":"no podrá ser perdonado. (2)"},{"c":"","l":""},{"c":"","l":"Mandamiento nuevo os doy"},{"c":"","l":"que os améis unos a otros (2)"},{"c":"","l":"como yo os he amado"},{"c":"","l":"como yo os he amado"},{"c":"","l":"os améis también vosotros. (2)"},{"c":"","l":""},{"c":"","l":"Amémonos de corazón"},{"c":"","l":"no de labios ni de oídos, (2)"},{"c":"","l":"para cuando Cristo venga"},{"c":"","l":"para cuando Cristo venga"},{"c":"","l":"nos encuentre bien unidos. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (35, 'Perdón Señor', '[{"c":"","l":"Perdón Señor hoy yo te ofendí"},{"c":"","l":"perdóname por no comprender"},{"c":"","l":"que me amabas antes de nacer"},{"c":"","l":"que me esperas ya en mi atardecer."},{"c":"","l":""},{"c":"","l":"Perdóname pues no sé vivir"},{"c":"","l":"de mis hermanos yo me separé"},{"c":"","l":"del calor de tu dulce hogar"},{"c":"","l":"quiero revivir, haz que vuelva a Ti."},{"c":"","l":""},{"c":"","l":"Ayúdame quiero serte fiel"},{"c":"","l":"resucitar contigo esta vez"},{"c":"","l":"y llevarte en mi caminar"},{"c":"","l":"por esta ciudad hacia los demás."},{"c":"","l":""},{"c":"","l":"Igual que el sol que al despertar"},{"c":"","l":"sabe que tiene mucho que brindar"},{"c":"","l":"yo al fin se porque vivir"},{"c":"","l":"porque tu perdón fecundó mi andar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PERDON', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (36, 'Alianza', '[{"c":"","l":"Te amé con todo mi amor"},{"c":"","l":"Te rescate del horror"},{"c":"","l":"Y te curé en el desierto"},{"c":"","l":"Calme tu hambre y tu sed"},{"c":"","l":"Con juramento sellé"},{"c":"","l":"Un pacto de amor eterno..."},{"c":"","l":"Oh ¿por qué entonces te rebelaste"},{"c":"","l":"fueron sordos a mi voz tus oídos?"},{"c":"","l":"Y ahora estás tan sin luz,"},{"c":"","l":"estás perdido."},{"c":"","l":""},{"c":"","l":"¿Por qué no vuelves hijo mío"},{"c":"","l":"si está en mis brazos tu lugar?"},{"c":"","l":"Si túconoces el camino"},{"c":"","l":"¿Por qué, por qué esperar?"},{"c":"","l":"¿Por qué no vuelves pueblo mío?"},{"c":"","l":"Te abro las fuentes del perdón,"},{"c":"","l":"que resplandezca nuestra alianza,"},{"c":"","l":"será un lazo de amor."},{"c":"","l":""},{"c":"","l":"Mi rayo resplandeció,"},{"c":"","l":"tu corazón aprendió,"},{"c":"","l":"que son mi amor y justicia."},{"c":"","l":"Probaste mi intimidad,"},{"c":"","l":"Mi ley que es miel de bondad"},{"c":"","l":"Para curar tu malicia."},{"c":"","l":"Oh ¿por qué entonces te separaste?"},{"c":"","l":"Te apoyaste en lo que es nada y vacío"},{"c":"","l":"Y ahora estás desolado, estás herido"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'GLORIA', '{"youtube_url":"","autor":"Eduardo Meana"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (37, 'Gloria a Dios (Chacarera)', '[{"c":"","l":"Gloria a Dios en el cielo"},{"c":"","l":"y en la tierra paz a los hombres"},{"c":"","l":""},{"c":"","l":"Gloria a vos Padre Nuestro poder y amor"},{"c":"","l":"Que hiciste de la nada la creación"},{"c":"","l":"Y por salvar al mundo de sus pecados"},{"c":"","l":"Enviaste desde el cielo a tu Hijo amado."},{"c":"","l":""},{"c":"","l":"Gloria a vos Jesucristo Dios hecho hombre"},{"c":"","l":"Que llevas en tu carga nuestros dolores"},{"c":"","l":"Que venciste a la muerte crucificado"},{"c":"","l":"Y reinas junto al Padre resucitado"},{"c":"","l":""},{"c":"","l":"Gloria a vos Santo Espíritu viento y fuego"},{"c":"","l":"Que hiciste de los pueblos un solo pueblo"},{"c":"","l":"Que animas a la Iglesia con tu aliento"},{"c":"","l":"Para que anuncie al mundo el Evangelio"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'GLORIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (38, 'Gloria a Dios, Gloria al Padre', '[{"c":"","l":"Gloria a Dios, Gloria a Dios,"},{"c":"","l":"Gloria al Padre."},{"c":"","l":"A Él que sea la gloria."},{"c":"","l":"Aleluya amén."},{"c":"","l":""},{"c":"","l":"Gloria a Dios, Gloria a Dios,"},{"c":"","l":"Gloria al hijo."},{"c":"","l":"A Él que sea la Gloria."},{"c":"","l":"Aleluya amén."},{"c":"","l":""},{"c":"","l":"Gloria a Dios, Gloria a Dios,"},{"c":"","l":"Espíritu Santo."},{"c":"","l":"A Él que sea la Gloria"},{"c":"","l":"Aleluya amén."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'GLORIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (39, 'Gloria (Formoseño)', '[{"c":"","l":"Gloria a Dios en el Cielo"},{"c":"","l":"y en la tierra paz al pueblo. (2)"},{"c":"","l":""},{"c":"","l":"Por tu inmensa gloria,"},{"c":"","l":"Te alabamos todos,"},{"c":"","l":"Te adoramos todos"},{"c":"","l":"Te glorificamos"},{"c":"","l":""},{"c":"","l":"Señor Rey Celestial"},{"c":"","l":"y Dios Padre Poderoso. (2)"},{"c":"","l":""},{"c":"","l":"Señor Hijo Jesucristo,"},{"c":"","l":"cordero de nuestro Dios. (2)"},{"c":"","l":""},{"c":"","l":"Tú que quitas el pecado,"},{"c":"","l":"apiádate de nosotros. (2)"},{"c":"","l":""},{"c":"","l":"Porque tú sólo eres Santo,"},{"c":"","l":"Altísimo Jesucristo. (2)"},{"c":"","l":""},{"c":"","l":"En la gloria de Dios Padre,"},{"c":"","l":"Con el Espíritu Santo. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'GLORIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (40, 'Gloria', '[{"c":"","l":"Gloria a Dios, en el cielo,"},{"c":"","l":"y en la tierra paz"},{"c":"","l":"a los hombres que ama el Señor."},{"c":"","l":""},{"c":"","l":"Gloria al Padre creador,"},{"c":"","l":"que con gran amor,"},{"c":"","l":"nos ha hecho dueños, de la creación."},{"c":"","l":""},{"c":"","l":"Gloria a Jesucristo Rey,"},{"c":"","l":"nuestro redentor,"},{"c":"","l":"que para salvarnos, en la cruz murió."},{"c":"","l":""},{"c":"","l":"Gloria al Espíritu,"},{"c":"","l":"que con su calor,"},{"c":"","l":"nos hace testigos del amor de Dios."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'GLORIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (41, 'Gloria (Mejía)', '[{"c":"","l":"*Gloria, gloria a Dios en el cielo"},{"c":"","l":"y en la tierra a los hombres paz.*"},{"c":"","l":""},{"c":"","l":"Te alabamos y te bendecimos,"},{"c":"","l":"te adoramos y glorificamos."},{"c":"","l":"Y nosotros hoy te damos gracias"},{"c":"","l":"por tu grande y eterna gloria..."},{"c":"","l":""},{"c":"","l":"*Gloria, gloria a Dios en el cielo"},{"c":"","l":"y en la tierra a los hombres paz.*"},{"c":"","l":""},{"c":"","l":"Señor Dios nuestro, Padre... Padre, Padre,"},{"c":"","l":"Señor Dios Hijo... piedad, piedad,"},{"c":"","l":"piedad Señor."},{"c":"","l":""},{"c":"","l":"Tu que quitas el pecado del mundo... escúchanos, escúchanos."},{"c":"","l":"Tu que estás a la derecha del Padre..."},{"c":"","l":"piedad, piedad, piedad Señor."},{"c":"","l":""},{"c":"","l":"Solo tú eres Santo, solo tu Señor,"},{"c":"","l":"solo tu altísimo Jesucristo,"},{"c":"","l":"con el Santo Espíritu en la gloria de Dios Padre."},{"c":"","l":""},{"c":"","l":"Amén, Amén, Amén..."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'GLORIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (42, 'Gloria', '[{"c":"","l":"Gloria, gloria, gloria, gloria..."},{"c":"","l":""},{"c":"","l":"A Jesús, el Señor, al cordero de Dios,"},{"c":"","l":"al nombre sobre todo, nombre."},{"c":"","l":""}]', 'GLORIA', '{"youtube_url":"","autor":"Martín Valverde"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (43, 'Gloria a Dios (Misa Criolla)', '[{"c":"","l":"Gloria a Dios, en las alturas"},{"c":"","l":"y en la tierra, paz a los hombres,"},{"c":"","l":"Paz a los hombres,"},{"c":"","l":"Paz a los hombres que ama el Señor"},{"c":"","l":""},{"c":"","l":"Te alabamos, te bendecimos,"},{"c":"","l":"te adoramos, glorificamos."},{"c":"","l":""},{"c":"","l":"Te damos gracias, te damos gracias,"},{"c":"","l":"Te damos gracias, por tu inmensa gloria."},{"c":"","l":"Señor Dios, Rey Celestial..."},{"c":"","l":""},{"c":"","l":"Dios Padre Todopoderoso."},{"c":"","l":"Señor, Hijo único, Jesucristo,"},{"c":"","l":"Señor Dios, Cordero de Dios,"},{"c":"","l":"Hijo del Padre,"},{"c":"","l":"Tú que quitas el pecado del mundo,"},{"c":"","l":"Ten piedad de nosotros."},{"c":"","l":"Tú que quitas el pecado del mundo,"},{"c":"","l":"Atiende nuestras súplicas."},{"c":"","l":"Tú que reinas con el Padre,"},{"c":"","l":"Ten piedad de nosotros... de nosotros."},{"c":"","l":""},{"c":"","l":"Gloria a Dios en las alturas"},{"c":"","l":"y en la tierra paz a los hombres,"},{"c":"","l":"paz a los hombres,"},{"c":"","l":"paz a los hombres que ama el Señor."},{"c":"","l":""},{"c":"","l":"Porque Tú solo eres santo,"},{"c":"","l":"Solo Tú, Señor Tú solo."},{"c":"","l":"Tú solo Altísimo Jesucristo,"},{"c":"","l":"Tú solo Altísimo Jesucristo."},{"c":"","l":"Con el Espíritu Santo,"},{"c":"","l":"Con el Espíritu Santo."},{"c":"","l":""},{"c":"","l":"En la gloria de Dios Padre..."},{"c":"","l":"Amen, Amen... Amén."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALELUYA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (44, 'Aleluya, Aleluya', '[{"c":"","l":"Aleluya, Aleluya, Aleluya, Aleluya."},{"c":"","l":"Aleluyaaa, leluyaaa, leluyaaa, leluya."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALELUYA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (45, 'Busca primero', '[{"c":"","l":"Busca primero el Reino de Dios,"},{"c":"","l":"y su perfecta justicia."},{"c":"","l":"Y lo demás añadido será,"},{"c":"","l":"Aleluya, aleluya."},{"c":"","l":""},{"c":"","l":"Aleluya, alelu aleluya"},{"c":"","l":"Aleluya, aleluya"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALELUYA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (46, 'Aleluya, Gloria Aleluya', '[{"c":"","l":"Cantad alegres, cantad a Dios"},{"c":"","l":"Habitantes de toda la tierra"},{"c":"","l":"Servid a Dios con alegría"},{"c":"","l":"Llegar a Él con regocijo"},{"c":"","l":""},{"c":"","l":"Aleluya, gloria aleluya (x4)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALELUYA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (47, 'Ale, Ale', '[{"c":"","l":"Ale, ale, ale, lu u ya (x3)"},{"c":"","l":"Aleluya! Aleluya!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALELUYA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (48, 'Aleluya, Gloria al Señor', '[{"c":"","l":"Alelu, alelu, alelu, aleluya"},{"c":"","l":"Gloria al Señor."},{"c":"","l":"Gloria la Señor, nuestro Padre"},{"c":"","l":"Gloria la Señor, Jesucristo"},{"c":"","l":"Gloria al Espíritu Santo"},{"c":"","l":"Gloria al Señor."},{"c":"","l":""},{"c":"","l":""}]', 'ALELUYA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (49, 'Yo soy el Maestro', '[{"c":"","l":"Yo soy el Maestro, yo soy el pastor,Aleluya."},{"c":"","l":"Feliz quien me sigue y escucha mi voz"},{"c":"","l":"Aleluya"},{"c":"","l":""},{"c":"","l":""}]', 'ALELUYA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (50, 'Los ángeles cantan', '[{"c":"","l":"Aleluya, aleluya,"},{"c":"","l":"aleluya, aleluya"},{"c":"","l":""},{"c":"","l":"Los ángeles cantan la gloria de Dios"},{"c":"","l":"Ha nacido el niño, Brindémosle amor"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (51, 'Coplas de Yaraví', '[{"c":"","l":"Señor, que nuestra vida sea"},{"c":"","l":"cual una quena simple y recta,"},{"c":"","l":"para que Tú puedas llenarla,"},{"c":"","l":"llenarla con tu música"},{"c":"","l":""},{"c":"","l":"Señor, que nuestra vida sea"},{"c":"","l":"arcilla blanda entre tus manos,"},{"c":"","l":"para que Tú puedas formarla,"},{"c":"","l":"formarla a tu manera"},{"c":"","l":"Señor, que nuestra vida sea,"},{"c":"","l":"semilla suelta por el aire,"},{"c":"","l":"para que Tú puedas sembrarla,"},{"c":"","l":"sembrarla donde quieras"},{"c":"","l":""},{"c":"","l":"Señor, que nuestra vida sea,"},{"c":"","l":"leñita humilde y siempre seca"},{"c":"","l":"para que Tú puedas quemarla"},{"c":"","l":"quemarla para el pobre ."},{"c":"","l":""}]', 'OFRENDAS', '{"youtube_url":"","autor":"P. Catena"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (52, 'Tu pones lo demás', '[{"c":"","l":"Un día de bodas el vino faltó"},{"c":"","l":"Imposiblepoderlo comprar."},{"c":"","l":"Que bello milagrohiciste, Señor"},{"c":"","l":"con el agua de aquelmanantial!"},{"c":"","l":"Colmaste hasta el borde delvino mejor"},{"c":"","l":"las tinajas que pude llenar."},{"c":"","l":"Yo puse mi esfuerzo, yo puse mi afán"},{"c":"","l":"Túpusiste, Jesús, lo demás."},{"c":"","l":""},{"c":"","l":"Es muy poco, Señor, lo que vengo a traer"},{"c":"","l":"Es muy poco lo que puedo dar."},{"c":"","l":"Mi trabajo es el agua que quiero ofrecer"},{"c":"","l":"Y mi esfuerzo un pedazo de pan"},{"c":"","l":""},{"c":"","l":"La gente con hambre sentada esperó"},{"c":"","l":"Enel prado que baja hasta el mar"},{"c":"","l":"Concuanto tenía, a Ti se acercó"},{"c":"","l":"Unmuchacho que quiso ayudar"},{"c":"","l":"Tu manoen su frente feliz descansó"},{"c":"","l":"en sus ojostu dulce mirar"},{"c":"","l":"Él puso sus preces, élpuso su pan"},{"c":"","l":"Tú pusiste, Jesús, lodemás"},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', '{"youtube_url":"","autor":"C. Gabarain"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (53, 'Pan de vida y bebida de luz', '[{"c":"","l":"Te ofrecemos, Señor, el pan"},{"c":"","l":"Pan de Vida te harás, y así"},{"c":"","l":"juntos podremos ser como hermanos al fin."},{"c":"","l":"Es el signo de amor que Vos nos pedís."},{"c":"","l":""},{"c":"","l":"Este vino que aquí está"},{"c":"","l":"para que vos Señor, vivas"},{"c":"","l":"es Bebida de Luz, para poder guiar"},{"c":"","l":"a los hombres que hoy buscan tu amistad."},{"c":"","l":""},{"c":"","l":"Con sincera humildad, Señor."},{"c":"","l":"Queremos ofrendar amor"},{"c":"","l":"alegría, dolor, y en nuestra pequeñez"},{"c":"","l":"el cansancio también dejar a tus pies"},{"c":"","l":""}]', 'OFRENDAS', '{"youtube_url":"","autor":"E. Heuguerot"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (54, 'Un espiga', '[{"c":"","l":"Una espiga dorada por el sol"},{"c":"","l":"el racimo que corta el viñador"},{"c":"","l":"se convierten ahora en pan y vino de amor"},{"c":"","l":"en el cuerpo y la sangre del Señor."},{"c":"","l":""},{"c":"","l":"Compartimos la misma comunión"},{"c":"","l":"somos trigos del mismo sembrador"},{"c":"","l":"un molino la vida nos tritura con dolor"},{"c":"","l":"Dios nos hace eucaristía en el amor."},{"c":"","l":""},{"c":"","l":"Como granos que han hecho el mismo pan"},{"c":"","l":"como notas que tejen un cantar"},{"c":"","l":"como gotas de agua que se funden en el mar"},{"c":"","l":"los cristianos un cuerpo formaran."},{"c":"","l":""},{"c":"","l":"En la mesa de Dios se sentaran"},{"c":"","l":"como hijos su pan comulgaran"},{"c":"","l":"una misma esperanza caminando cantaran"},{"c":"","l":"en la vida como hermanos se amaran"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', '{"youtube_url":"","autor":"C. Gabarain"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (55, 'Recibe, oh Dios eterno', '[{"c":"","l":"Recibe, oh Dios eterno"},{"c":"","l":"la hostia inmaculada"},{"c":"","l":"que luego a ti inmolada"},{"c":"","l":"va a ser en este altar."},{"c":"","l":"Con ella te pedimos"},{"c":"","l":"que aceptes nuestros dones"},{"c":"","l":"son fieles corazones"},{"c":"","l":"que a ti sólo han de amar. (2)"},{"c":"","l":""},{"c":"","l":"Oh Dios, que reformaste"},{"c":"","l":"la humanidad caída"},{"c":"","l":"confunde nuestra vida"},{"c":"","l":"con tu divinidad"},{"c":"","l":"lo mismo que se mezcla"},{"c":"","l":"en esta ofrenda pura"},{"c":"","l":"el agua que es figura"},{"c":"","l":"de nuestra humanidad. (2)"},{"c":"","l":""},{"c":"","l":"El vino de la uva"},{"c":"","l":"y el trigo en blanco grano"},{"c":"","l":"son frutos de las manos"},{"c":"","l":"son hijos del dolor"},{"c":"","l":"esfuerzos y trabajos"},{"c":"","l":"que en Cristo se agigantan"},{"c":"","l":"y por su medio alcanzan"},{"c":"","l":"valor de Redención. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (56, 'Zamba del grano de trigo', '[{"c":"","l":"Zamba del grano de trigo"},{"c":"","l":"mañana yo he de ser pan;"},{"c":"","l":"no le tengo miedo al surco,"},{"c":"","l":"algún día he de brotar."},{"c":"","l":""},{"c":"","l":"Barbecho de terrón fresco"},{"c":"","l":"tu sangre yo he de mamar;"},{"c":"","l":"tierra que serás mi madre,"},{"c":"","l":"un nuevo ser me has de dar."},{"c":"","l":""},{"c":"","l":"*Silencio y noche en mi tumba"},{"c":"","l":"espigas germinarán;"},{"c":"","l":"ciento por uno y molienda"},{"c":"","l":"mañana voy a ser pan. *"},{"c":"","l":""},{"c":"","l":"La muerte aguarda en el surco,"},{"c":"","l":"cálido abrazo nupcial;"},{"c":"","l":"muerte, sabrás un secreto:"},{"c":"","l":"cuando matas, vida das."},{"c":"","l":""},{"c":"","l":"Me enterraré en tus entrañas"},{"c":"","l":"y el mundo me olvidará;"},{"c":"","l":"es doloroso tu abrazo,"},{"c":"","l":"pero yo quiero ser pan."},{"c":"","l":""},{"c":"","l":"*Tallo verde en dos hojitas"},{"c":"","l":"mi espiga despuntará;"},{"c":"","l":"ciento por uno y molienda,"},{"c":"","l":"mañana voy a ser pan. *"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (57, 'Al Altar del Señor', '[{"c":"","l":"Al altar del Señor, vamos con amor"},{"c":"","l":"a entregar al Señor, lo que Él nos dio."},{"c":"","l":""},{"c":"","l":"Pan le traemos, trigo de Dios"},{"c":"","l":"para la mesa que Él nos preparó."},{"c":"","l":"Vino traemos, viña de Dios"},{"c":"","l":"para la fiesta de la comunión."},{"c":"","l":""},{"c":"","l":"Luces traemos, para alumbrar"},{"c":"","l":"la mesa santa de nuestro altar."},{"c":"","l":"Flores traemos para alegrar"},{"c":"","l":"esta comida de la amistad."},{"c":"","l":""},{"c":"","l":"Ropa y comida, juguetes también"},{"c":"","l":"Libros, remedios, son para Él."},{"c":"","l":"En los que sufren Cristo está"},{"c":"","l":"Darle queremos lo que Él nos da."},{"c":"","l":""},{"c":"","l":"Hoy nuestro juego, nuestro dolor,"},{"c":"","l":"nuestros estudios, traemos al Señor."},{"c":"","l":"Toda la vida vamos a dar,"},{"c":"","l":"para la ofrenda de Cristo en el altar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (58, 'Pan de vida y bebida de luz', '[{"c":"","l":"Te ofrecemos, Señor, el pan,"},{"c":"","l":"Pan de Vida te harás, y así"},{"c":"","l":"juntos podremos ser como hermanos al fin."},{"c":"","l":"Es el signo de amor que vos nos pedís."},{"c":"","l":""},{"c":"","l":"Este vino que aquí está"},{"c":"","l":"para que Vos, Señor, vivas,"},{"c":"","l":"es Bebida de Luz para poder guiar"},{"c":"","l":"a los hombres que hoy buscan tu amistad."},{"c":"","l":""},{"c":"","l":"Con sincera humildad, Señor,"},{"c":"","l":"queremos ofrendar amor,"},{"c":"","l":"alegría y dolor, y en nuestra pequeñez"},{"c":"","l":"el cansancio también dejar a tus pies."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (59, 'Pan de nuestras vidas', '[{"c":"","l":"Este es el momento de alegrar la mesa"},{"c":"","l":"con el vino y con el pan"},{"c":"","l":"que consagraremos y que ofreceremos"},{"c":"","l":"y que hemos de comulgar"},{"c":"","l":""},{"c":"","l":"Este es el momento de llegar confiados"},{"c":"","l":"a la mesa del altar,"},{"c":"","l":"porque tu palabra vivificadora"},{"c":"","l":"nos acaba de llamar."},{"c":"","l":""},{"c":"","l":"*Padre de Jesús bendice"},{"c":"","l":"lo que presentamos hoy"},{"c":"","l":"y que al preparar tu mesa"},{"c":"","l":"se renueve el gozo de saber tu amor*"},{"c":"","l":""},{"c":"","l":"Pan de nuestra vida, Pan de nuestras manos, Pan de nuestra juventud."},{"c":"","l":"Pan que entregaremos juntos como hermanos"},{"c":"","l":"en señal de gratitud"},{"c":"","l":""},{"c":"","l":"Vino de la tierra buena y generosa"},{"c":"","l":"vino que ofrecemos hoy"},{"c":"","l":"Lleva nuestra lucha, lleva nuestras penas"},{"c":"","l":"lleva nuestra sed de amor"},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (60, 'Siervo por amor', '[{"c":"","l":"Una noche de sudor"},{"c":"","l":"con la barca en altamar"},{"c":"","l":"con el primer rayo de sol"},{"c":"","l":"ves tus redes nada hay"},{"c":"","l":"Y Su vos que dentro te habla"},{"c":"","l":"otro mar te mostrará"},{"c":"","l":"y al corazón de cada hombre"},{"c":"","l":"tus redesarrojarás."},{"c":"","l":""},{"c":"","l":"Ofrece tu vida,"},{"c":"","l":"como María de pie junto a la cruz"},{"c":"","l":"Y serás siervo de cada hombre"},{"c":"","l":"siervo por amor"},{"c":"","l":"Sacerdote de la humanidad"},{"c":"","l":""},{"c":"","l":"Avanzabas en silencio"},{"c":"","l":"entre lágrimas, y surcos"},{"c":"","l":"y esperabas que en la tierra"},{"c":"","l":"tu semilla se haga fruto"},{"c":"","l":"hoy tu casa es una fiesta"},{"c":"","l":"porque el trigo hondea ya"},{"c":"","l":"ha madurado bajo el sol"},{"c":"","l":"ya lo puedes cosechar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (61, 'Te presentamos la vida Señor', '[{"c":"","l":"Te presentamos la vida, Señor"},{"c":"","l":"vida del pueblo, de fiesta y dolor,"},{"c":"","l":"Campo y desierto, vida y silencio"},{"c":"","l":"te presentamos, Señor. (2)"},{"c":"","l":""},{"c":"","l":"Te presentamos la vida, Señor"},{"c":"","l":"el pan y el vino en tu mesa estarán"},{"c":"","l":"Pan compartido, vino de fiesta"},{"c":"","l":"tu Cuerpo y Sangre serán. (2)"},{"c":"","l":""},{"c":"","l":"Te presentamos la vida, Señor"},{"c":"","l":"Todos unidos vamos a alabar"},{"c":"","l":"Somos tus hijos, en Ti confiamos"},{"c":"","l":"Que se haga Tu voluntad (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (62, 'Queremos ofrecerte', '[{"c":"","l":"Queremos ofrecerte con nuestra oración,"},{"c":"","l":"junto al pan y al vino nuestro corazón."},{"c":"","l":"Te ofrecemos la alegría"},{"c":"","l":"de vivir en tu presencia,"},{"c":"","l":"la dicha de congregarnos"},{"c":"","l":"nuevamente hoy en tu mesa."},{"c":"","l":""},{"c":"","l":"Te ofrecemos Señor todo, todo lo que somos"},{"c":"","l":""},{"c":"","l":"Nuestro pan y vino se convertirán,"},{"c":"","l":"en tu Cuerpo y Sangre que nos salvará."},{"c":"","l":"Al comer hoy de tu Cuerpo,"},{"c":"","l":"beber tu preciosa Sangre,"},{"c":"","l":"Él será en nuestras vidas"},{"c":"","l":"la Gracia santificante."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (63, 'Con amor te presento', '[{"c":"","l":"Con amor te presento Señor"},{"c":"","l":"lo mejor de mi vida,"},{"c":"","l":"te presento, Señor, mi amistad."},{"c":"","l":"Con amor te presento Señor,"},{"c":"","l":"para ser mi manjar,"},{"c":"","l":"la viña, el racimo, el trigal"},{"c":"","l":"el pan de mi hogar,"},{"c":"","l":"te presento con amor."},{"c":"","l":""},{"c":"","l":"Con mis manos abiertas a Ti"},{"c":"","l":"contemplando tu lámpara,"},{"c":"","l":"te presento señor mi esperanza,"},{"c":"","l":"Hacia Ti se dirige mi barca,"},{"c":"","l":"hacia el cielo se va,"},{"c":"","l":"es largo, el camino, el remar,"},{"c":"","l":"punta pascual,"},{"c":"","l":"Dios me guía al caminar."},{"c":"","l":""},{"c":"","l":"Con mi ofrenda también yo te doy"},{"c":"","l":"lo mejor de mis lágrimas."},{"c":"","l":"Te presento Señor mi dolor."},{"c":"","l":"Te presento Señor mi oración,"},{"c":"","l":"ofertorio de amor,"},{"c":"","l":"el grano, el terrado, la flor,"},{"c":"","l":"la espiga oblación,"},{"c":"","l":"la semilla redención."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (64, 'Resurrección', '[{"c":"","l":"Quiero caer en tierra y morir,"},{"c":"","l":"sino quedaré solo."},{"c":"","l":"Soy un grano de trigo,"},{"c":"","l":"quiero dar mucho fruto"},{"c":"","l":"ser tu testigo por el mundo."},{"c":"","l":""},{"c":"","l":"Si amo mi vida, la perderé,"},{"c":"","l":"si doy mi vida la ganaré"},{"c":"","l":"donde tú estás Jesús,  allí estoy yo."},{"c":"","l":"Te sigo soy tu servidor"},{"c":"","l":""},{"c":"","l":"Padre ha llegado la hora,"},{"c":"","l":"glorifica a tu nombre"},{"c":"","l":"es mi ser, que muere,"},{"c":"","l":"para que seas tú el Rey."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (65, 'Padre nuestro recibid', '[{"c":"","l":"Padre nuestro, recibid"},{"c":"","l":"el humilde don del pan"},{"c":"","l":"de ese pan que se convertirá"},{"c":"","l":"en el Cuerpo de Jesús."},{"c":"","l":"Recibid también, Señor"},{"c":"","l":"los racimos de la vid,"},{"c":"","l":"de la vid que se convertirá"},{"c":"","l":"en la Sangre de Jesús."},{"c":"","l":""},{"c":"","l":"Con el vino y con el pan"},{"c":"","l":"ofrecemos nuestro don"},{"c":"","l":"nuestra pobre vida de dolor"},{"c":"","l":"entregada con amor."},{"c":"","l":""},{"c":"","l":"Gloria al Padre y al Amor"},{"c":"","l":"y a Jesús, nuestro Señor"},{"c":"","l":"bendigamos el Nombre de Dios"},{"c":"","l":"siempre y en todo lugar. Amén."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (66, 'Sobre tu altar', '[{"c":"","l":"Sobre tu altar lo más preciado Señor"},{"c":"","l":"sobre tu Altar mi pan y vino de amor."},{"c":"","l":"Sobre tu Altar mi vida entera."},{"c":"","l":""},{"c":"","l":"Mi pasado te lo doy"},{"c":"","l":"mi presente contodo mi amor"},{"c":"","l":"mi futuro lo pongo en tusmanos."},{"c":"","l":""},{"c":"","l":"Confiaré, no temeré"},{"c":"","l":"Confiare, me entregaré"},{"c":"","l":"Confiaré en Ti Señor"},{"c":"","l":"Consagraré mi corazón a Tu amor"},{"c":"","l":"A Dios mi Rey."},{"c":"","l":""},{"c":"","l":"Sobre tu altar te dejo mi corazón"},{"c":"","l":"Sobretu altar te dejo mi voluntad"},{"c":"","l":"sobre tu Altar mi vida entera."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (67, 'Ofrenda de amor', '[{"c":"","l":"Por los niños que empiezan la vida,"},{"c":"","l":"por los hombres sin techo ni hogar;"},{"c":"","l":"Por los pueblos que sufren la guerra,"},{"c":"","l":"te ofrecemos el vino y le pan."},{"c":"","l":""},{"c":"","l":"Pan y vino sobre el altar,"},{"c":"","l":"son ofrendas de amor,"},{"c":"","l":"pan y vino serán después,"},{"c":"","l":"tu cuerpo y sangre Señor."},{"c":"","l":""},{"c":"","l":"Por los hombres que viven unidos,"},{"c":"","l":"por los hombres que buscan la paz;"},{"c":"","l":"por los pueblos que no te conocen,"},{"c":"","l":"te ofrecemos el vino y el pan."},{"c":"","l":""},{"c":"","l":"Por aquellos a quienes queremos,"},{"c":"","l":"por nosotros y nuestra amistad;"},{"c":"","l":"por los vivos y por los difuntos,"},{"c":"","l":"te ofrecemos el vino y el pan"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (68, 'Mira nuestra ofrenda', '[{"c":"","l":"Mira esta ofrenda, mírala, Señor"},{"c":"","l":"todo te ofrecemos, para unirnos más."},{"c":"","l":""},{"c":"","l":"Porque tu misa, es nuestra misa"},{"c":"","l":"Porque tu vida, es nuestra vida (2)"},{"c":"","l":""},{"c":"","l":"¿Qué podemos darte, nuestro Creador?"},{"c":"","l":"Sólo nuestra nada, tómala, Señor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (69, 'Ofrece tu vida', '[{"c":"","l":"Una noche de sudor"},{"c":"","l":"y la barca enaltamar"},{"c":"","l":"Con el primer rayo de sol"},{"c":"","l":"Vestus redes nada hay"},{"c":"","l":"Pero la voz quedentro te habla"},{"c":"","l":"otro mar te mostrará"},{"c":"","l":""},{"c":"","l":"Y al corazón de cada hombre"},{"c":"","l":"tus redes arrojarás."},{"c":"","l":"Ofrece tu vida"},{"c":"","l":"como María de pie junto a la cruz"},{"c":"","l":"Y serás, siervo de cada hombre"},{"c":"","l":"Siervo por amo,"},{"c":"","l":"sacerdote de la humanidad."},{"c":"","l":""},{"c":"","l":"Avanzabas en silencio"},{"c":"","l":"entre lágrimas ysurcos"},{"c":"","l":"Esperando que en la tierra"},{"c":"","l":"Tusemilla se haga fruto"},{"c":"","l":"Hoy tu casa esuna fiesta"},{"c":"","l":"porque el trigo que ondea ya"},{"c":"","l":"Ya ha madurado bajo el sol"},{"c":"","l":"ya sepuede cosechar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (70, 'Te ofrecemos, oh Señor', '[{"c":"","l":"Te ofrecemos, oh Señor"},{"c":"","l":"Este pan y este vino"},{"c":"","l":"Recíbelos, es nuestro don."},{"c":"","l":"Recíbelos, de nuestras manos, Señor"},{"c":"","l":""},{"c":"","l":"Es trigo de nuestros campos"},{"c":"","l":"racimos de nuestras viña."},{"c":"","l":"Este pan será tu Cuerpo,"},{"c":"","l":"y este vino tu Sangre."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (71, 'Vasijas de barro', '[{"c":"","l":"Señor ante Ti, hoy vengo a dejar"},{"c":"","l":"mis proyectos mi vida, mis sueños, mi libertad.  Señor desde hoy, mi felicidad"},{"c":"","l":"será amarte y servirte buscando"},{"c":"","l":"hacer Tu voluntad."},{"c":"","l":""},{"c":"","l":"Recibe señor en tus manos"},{"c":"","l":"la ofrenda que hoy vengo a traer ante ti."},{"c":"","l":"Reviste con tu fortaleza mi débil pobreza"},{"c":"","l":"que hoy te dice sí."},{"c":"","l":"Y nunca permitas que crea"},{"c":"","l":"que serte fiel solo depende de mí."},{"c":"","l":"Hoy traigo en vasijas de barro"},{"c":"","l":"el tesoro que sin merecer recibí."},{"c":"","l":""},{"c":"","l":"Señor aquí estoy, Tu sabes cómo soy"},{"c":"","l":"con Tu gracia transforma mi alma"},{"c":"","l":"limpia mi corazón."},{"c":"","l":"Señor haz que en mí,"},{"c":"","l":"siempre crezca esta sed,"},{"c":"","l":"de querer que en tus aguas profundas,"},{"c":"","l":"pueda un día beber."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (72, 'Los frutos de la tierra', '[{"c":"","l":"Elegiste, Señor, para quedarte"},{"c":"","l":"Frutossimples surgidos de la tierra:"},{"c":"","l":"pan y vinosembrados por el hombre"},{"c":"","l":"y que puedenestar en cualquier mesa."},{"c":"","l":""},{"c":"","l":"¡Que sepamos, Señor, ser tu pan bueno"},{"c":"","l":"Nacido de la espiga verdadera!"},{"c":"","l":""},{"c":"","l":"Hoy trayendo espigas y racimos"},{"c":"","l":"Nosllegamos, Señor, hasta tu mesa"},{"c":"","l":"Para unir a la ofrenda de tu Hijo"},{"c":"","l":"el gozo y eldolor de la cosecha."},{"c":"","l":""},{"c":"","l":"¡Que sepamos, Señor, ser vino bueno"},{"c":"","l":"Y apagar en el mundo la tristeza!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (73, 'Te presentamos el vino y el pan', '[{"c":"","l":"Te presentamos el vino y el pan"},{"c":"","l":"Bendito seas, por siempre Señor."},{"c":"","l":""},{"c":"","l":"Bendito seas, Señor,"},{"c":"","l":"por este pan quenos diste"},{"c":"","l":"fruto de la tierra y del trabajo de los hombres"},{"c":"","l":""},{"c":"","l":"Bendito seas, Señor, el vino tú nos lodiste"},{"c":"","l":"fruto de la tierra y del trabajo de los hombres"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (74, 'Te ofrecemos Padre nuestro', '[{"c":"","l":"Te ofrecemos, Padre nuestro"},{"c":"","l":"este vino yeste pan,"},{"c":"","l":"junto con ellos te damos"},{"c":"","l":"eltrabajo y el dolor,"},{"c":"","l":"la dicha de ser tushijos,"},{"c":"","l":"la alegría del amor."},{"c":"","l":""},{"c":"","l":"Te lo ofrecemos por Cristo"},{"c":"","l":"que entrenosotros está,"},{"c":"","l":"este pan será su Cuerpo,"},{"c":"","l":"el vino sangre se hará;"},{"c":"","l":"perdonanuestros pecados"},{"c":"","l":"y haz que vivamos enpaz."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (75, 'Recibe, oh Dios, el pan', '[{"c":"","l":"Recibe, oh Dios, el pan que te ofrecemos"},{"c":"","l":"luego será el cuerpo de Jesús."},{"c":"","l":"Tambiénacepta nuestro sacrificio"},{"c":"","l":"nuestra oración y nuestro corazón."},{"c":"","l":""},{"c":"","l":"Recibe, oh Dios, el vino que ofrecemos"},{"c":"","l":"luego será la sangre de Jesús."},{"c":"","l":"También acepta nuestro sacrificio"},{"c":"","l":"nuestra oraciónynuestro corazón."},{"c":"","l":""},{"c":"","l":"Recíbelos, Señor, por nuestras faltas"},{"c":"","l":"Porlos que están aquí junto al altar"},{"c":"","l":"por loscristianos vivos y difuntos"},{"c":"","l":"por todo el mundo por su salvación"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (76, 'Esta mesa', '[{"c":"","l":"Esta mesa será bendecida"},{"c":"","l":"Porque el Señor derramará todo su amor."},{"c":"","l":""},{"c":"","l":"Derrama Señor, derrama Señor,"},{"c":"","l":"Derrama Señor tu bendición"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (77, 'Esto que soy eso te doy', '[{"c":"","l":"A veces te pregunto \"¿por qué yo?\""},{"c":"","l":"y solo me respondes \"porque quiero\","},{"c":"","l":"es un misterio grande que nos llames,"},{"c":"","l":"así, tal como somos, a tu encuentro."},{"c":"","l":"Entonces redescubro una verdad:"},{"c":"","l":"mi vida, nuestra vida es un tesoro."},{"c":"","l":"Se trata entonces sólo de ofrecerte,"},{"c":"","l":"con todo nuestro amor, esto que somos."},{"c":"","l":""},{"c":"","l":"*¿Qué te daré? ¿Qué te daremos?"},{"c":"","l":"¡Si todo, todo, es tu regalo!"},{"c":"","l":"Te ofreceré, te ofreceremos"},{"c":"","l":"Esto que somos..."},{"c":"","l":"Esto que soy, ¡Eso te doy!*"},{"c":"","l":""},{"c":"","l":"Esto que soy, esto es lo que te doy."},{"c":"","l":"Esto que somos, es lo que te damos."},{"c":"","l":"Tú no desprecias nuestra vida humilde,"},{"c":"","l":"se trata de poner todo en tus manos."},{"c":"","l":"Aquí van mis trabajos y mi fe,"},{"c":"","l":"mis mates, mis bajones y mis sueños,"},{"c":"","l":"y todas las personas que me diste"},{"c":"","l":"desde mi corazón te las ofrezco."},{"c":"","l":""},{"c":"","l":"Vi tanta gente un domingo de sol,"},{"c":"","l":"me conmovió el latir de tantas vidas..."},{"c":"","l":"Y adiviné tu abrazo gigantesco,"},{"c":"","l":"y sé que sus historias recibías."},{"c":"","l":"Por eso tu altar luce vino y pan:"},{"c":"","l":"son signo y homenaje de la vida,"},{"c":"","l":"misterio de ofrecerte y recibirnos,"},{"c":"","l":"humanidad que Cristo diviniza."}]', 'OFRENDAS', '{"youtube_url":"","autor":"Eduardo Meana"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (78, 'Cinco panes', '[{"c":"","l":"Un niño se te acercó, aquella tarde,"},{"c":"","l":"sus cinco panes te dio para ayudarte."},{"c":"","l":"Los dos hicieron que ya no hubiera hambre."},{"c":"","l":""},{"c":"","l":"La tierra, el aire y el sol, son tu regalo,"},{"c":"","l":"y mil estrellas de luz sembró tu mano."},{"c":"","l":"El hombre pone su amor y su trabajo."},{"c":"","l":""},{"c":"","l":"También yo quiero poner sobre tu mesa,"},{"c":"","l":"mis cinco panes que son una promesa,"},{"c":"","l":"de darte todo mi amor y mi pobreza."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (79, 'Haciéndote Pan', '[{"c":"","l":"Comenzaste a hacerte pan en Belén"},{"c":"","l":"sol pequeñito en esta noche."},{"c":"","l":"Aprendiste en Nazaret de ellos dos"},{"c":"","l":"el gesto manso de la entrega."},{"c":"","l":""},{"c":"","l":"Pibe que en Jerusalén"},{"c":"","l":"te entregaste de una vez"},{"c":"","l":"a las cosas de tu padre."},{"c":"","l":"Debe tu cuerpo crecer,"},{"c":"","l":"para poderse ofrecer"},{"c":"","l":"como pan a nuestro hambre."},{"c":"","l":""},{"c":"","l":"Mi cuerpo es esto,"},{"c":"","l":"Mi sangre es esta"},{"c":"","l":"Que por ustedes doy"},{"c":"","l":"Coman y vivan, crean y vivan"},{"c":"","l":"Que para siempre soy"},{"c":"","l":"Soy yo,  soy yo."},{"c":"","l":""},{"c":"","l":"Se multiplicó tu amor, se partió"},{"c":"","l":"todos saciados aún sobraba."},{"c":"","l":"Se mostró tu intimidad eres pan"},{"c":"","l":"que sólo vive por donarse."},{"c":"","l":""},{"c":"","l":"Noches de Jerusalén"},{"c":"","l":"Cristo-Pan entrégate"},{"c":"","l":"eres tú nuestro cordero."},{"c":"","l":"Cena, huerto,"},{"c":"","l":"beso y cruz"},{"c":"","l":"y tu entrega"},{"c":"","l":"Pan-Jesús"},{"c":"","l":"fue más fuerte"},{"c":"","l":"que el madero."}]', 'OFRENDAS', '{"youtube_url":"","autor":"Eduardo Meana"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (80, 'Canción del grano de trigo', '[{"c":"","l":"Sé cómo el grano de trigo"},{"c":"","l":"que cae en tierra y desaparece,"},{"c":"","l":"y aunque te duela la muerte de hoy,"},{"c":"","l":"mira la espiga que crece."},{"c":"","l":""},{"c":"","l":"Un trigal será la Iglesia"},{"c":"","l":"que guardará mis entregas,"},{"c":"","l":"fecundadas por la sangre de Aquél"},{"c":"","l":"que dio su vida por ella."},{"c":"","l":"Ciudad nueva del amor"},{"c":"","l":"donde vivirá el pueblo"},{"c":"","l":"que en los brazos de su dueño nació,"},{"c":"","l":"sostenido de un madero."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (81, 'Santo', '[{"c":"","l":"Santo es el señor mi Dios"},{"c":"","l":"digno de alabanza"},{"c":"","l":"a Él el poder, el honor y la gloria"},{"c":"","l":""},{"c":"","l":"Hosanna, hosanna,"},{"c":"","l":"Hosanna oh Señor"},{"c":"","l":""},{"c":"","l":"Bendito es el que viene"},{"c":"","l":"en nombre del Señor"},{"c":"","l":"con todos los santos"},{"c":"","l":"cantamos para Él"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (82, 'Santo', '[{"c":"","l":"Santo, santo, santo es el Señor"},{"c":"","l":"Dios del universo."},{"c":"","l":"Llenos están, el cielo y la tierra"},{"c":"","l":"de su gloria"},{"c":"","l":""},{"c":"","l":"Hosanna en el cielo"},{"c":"","l":"hosanna en las alturas."},{"c":"","l":"Bendito es el que viene"},{"c":"","l":"en nombre del Señor"},{"c":"","l":""}]', 'SANTO', '{"youtube_url":"","autor":"Daniel Poli"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (83, 'Sanctus (Misa Criolla)', '[{"c":"","l":"Santo, Santo, Santo,"},{"c":"","l":"Señor Dios Del Universo"},{"c":"","l":"Santo, Santo, Santo,"},{"c":"","l":"Señor Dios Del Universo"},{"c":"","l":""},{"c":"","l":"Llenos Están los Cielos,"},{"c":"","l":"Y La Tierra De Tu Gloria"},{"c":"","l":"Llenos Están los Cielos,"},{"c":"","l":"Y La Tierra De Tu Gloria"},{"c":"","l":""},{"c":"","l":"Hosanna En Las Alturas"},{"c":"","l":"Bendito El Que Viene,"},{"c":"","l":"En Nombre Del Señor"},{"c":"","l":"Hosanna En Las Alturas"},{"c":"","l":"Hosanna En Las Alturas"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (84, 'Santo', '[{"c":"","l":"Santo es el señor mi Dios digno de alabanza"},{"c":"","l":"a Él el poder, el honor y la gloria"},{"c":"","l":""},{"c":"","l":"Hosanna, hosanna, Hosanna oh Señor"},{"c":"","l":""},{"c":"","l":"Bendito es el que viene en nombre del Señor"},{"c":"","l":"con todos los santos cantamos para Él"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (85, 'Santo II', '[{"c":"","l":"Santo, santo, santo"},{"c":"","l":"Santo es el señor"},{"c":"","l":"Dios del universo"},{"c":"","l":"Santo es el Señor"},{"c":"","l":""},{"c":"","l":"Hosanna en el cielo"},{"c":"","l":"hosanna en las alturas"},{"c":"","l":"bendito el que viene"},{"c":"","l":"en nombre del Señor"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (86, 'Santo III', '[{"c":"","l":"Santo, santo, santo"},{"c":"","l":"Santo es el señor"},{"c":"","l":"Santo, santo, santo"},{"c":"","l":"Dios del universo"},{"c":"","l":""},{"c":"","l":"El cielo, la tierra"},{"c":"","l":"están llenos de su gloria."},{"c":"","l":"Hosanna, hosanna, en el cielo"},{"c":"","l":""},{"c":"","l":"Y bendito es el que viene"},{"c":"","l":"en el nombre del Señor."},{"c":"","l":"Hosanna, hosanna, en el cielo"},{"c":"","l":""},{"c":"","l":""}]', 'SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (87, 'Santo es el Señor', '[{"c":"","l":"Santo es el Señor, Dios del universo (x3)"},{"c":"","l":"Porque Santo es"},{"c":"","l":""},{"c":"","l":"Bendito es, bendito es el que viene (x3)"},{"c":"","l":"En nombre de Dios"},{"c":"","l":""},{"c":"","l":"Ho-ho-ho Hosanna en el cielo (x3)"},{"c":"","l":"Porque Santo es."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (88, 'Santo (Country)', '[{"c":"","l":"Santo, oh, oh, oh, oh, oh, Santo oh oh"},{"c":"","l":"Santo es el Señor!"},{"c":"","l":""},{"c":"","l":"*Hosanna eh, hosanna ah"},{"c":"","l":"Hosanna Cristo el Señor *"},{"c":"","l":""},{"c":"","l":"Los cielos y la tierra están llenos,"},{"c":"","l":"tu gloria Señor."},{"c":"","l":""},{"c":"","l":"Bendito el que viene en el nombre,"},{"c":"","l":"en el nombre del Señor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (89, 'Sagrado corazón, eterna alianza', '[{"c":"","l":"Sagrado Corazón, eterna alianza"},{"c":"","l":"Endonde escribe Dios la Ley de gracia."},{"c":"","l":""},{"c":"","l":"Sagrado corazón"},{"c":"","l":"Oh víctima de amor"},{"c":"","l":"En ti confío, en ti confío"},{"c":"","l":""},{"c":"","l":"¿Quién no ha de amarlo si Él amó primero"},{"c":"","l":"y dio en la Cruz su vida al mundoentero?"},{"c":"","l":"Por tan inmenso amor retribuyamos"},{"c":"","l":"amor, reparación y desagravio."},{"c":"","l":"En Él descansen nuestras esperanzas"},{"c":"","l":"en Él reposen siempre nuestras almas."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (90, 'Hambre de Dios', '[{"c":"","l":"No podemos caminar"},{"c":"","l":"Con hambre bajo el sol"},{"c":"","l":"Danos siempre el mismo pan"},{"c":"","l":"Tu cuerpo y tu sangre, Señor."},{"c":"","l":""},{"c":"","l":"Comamos todos de este Pan,"},{"c":"","l":"el Pan de launidad"},{"c":"","l":"en un cuerpo nos unió el Señor,"},{"c":"","l":"por medio del Amor."},{"c":"","l":""},{"c":"","l":"Señor, yo tengo sed de ti"},{"c":"","l":"sediento estoyde Dios."},{"c":"","l":"Pero pronto llegaré a ver el"},{"c":"","l":"rostro del Señor."},{"c":"","l":""},{"c":"","l":"Por el desierto el pueblo va"},{"c":"","l":"cantando sudolor"},{"c":"","l":"en la noche brillará tu luz,"},{"c":"","l":"nosguía la verdad."}]', 'COMUNION', '{"youtube_url":"","autor":"J.Espinosa"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (91, 'Oh, buen Jesús', '[{"c":"","l":"¡Oh, buen Jesús! Yo creo firmemente"},{"c":"","l":"que por mi bien estás en el altar,"},{"c":"","l":"que das tu cuerpo y sangre juntamente"},{"c":"","l":"al alma fiel en celestial manjar,"},{"c":"","l":""},{"c":"","l":"Indigno soy, confieso avergonzado,"},{"c":"","l":"Derecibir la santa Comunión;"},{"c":"","l":"Jesús queves mi nada y mi pecado,"},{"c":"","l":"prepara Tú mipobre corazón. (2)"},{"c":"","l":""},{"c":"","l":"Pequé Señor, ingrato te he ofendido;"},{"c":"","l":"infiel te fui, confieso mi maldad;"},{"c":"","l":"mepesa ya; perdón, Señor, te pido,"},{"c":"","l":"eres miDios, apelo a tu bondad. (2)"},{"c":"","l":""},{"c":"","l":"Espero en Ti, piadoso Jesús mío;"},{"c":"","l":"oigo tuvoz que dice “ven a mí”,"},{"c":"","l":"porque eres fiel,por eso en Ti confío;"},{"c":"","l":"todo Señor,espérolo de Ti. (2)"},{"c":"","l":"¡Oh, buen pastor, amable y fino amante!"},{"c":"","l":"Mi corazón se abraza en santo ardor;"},{"c":"","l":"Site olvidé, hoy juro que constante"},{"c":"","l":"he devivir tan sólo de tu amor. (2)"},{"c":"","l":""},{"c":"","l":"Dulce maná y celestial comida,"},{"c":"","l":"gozo ysalud de quien te come bien;"},{"c":"","l":"ven sintardar, mi Dios, mi luz, mi vida,"},{"c":"","l":"desciende a mí, hasta mi pecho ven. (2)"}]', 'COMUNION', '{"youtube_url":"","autor":"Hno. León de H.E.C."}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (92, 'Jesucristo Señor de la historia', '[{"c":"","l":"Jesucristo, Señor de la Historia"},{"c":"","l":"Queestuviste, estás y estarás"},{"c":"","l":"SosPresencia, Esperanza y Memoria"},{"c":"","l":"SoselDios de la Vida, hecho Pan."},{"c":"","l":""},{"c":"","l":"Soselmismo Jesús que estuviste"},{"c":"","l":"junto al lagodeGenesaret"},{"c":"","l":"y ante el hambre elPueblo exigiste"},{"c":"","l":"“¡Denles ustedes, porDios, de comer!”"},{"c":"","l":""},{"c":"","l":"¡Quédate con nosotros, Jesús"},{"c":"","l":"Que da miedo tanta oscuridad"},{"c":"","l":"No es posible morirse de hambre"},{"c":"","l":"En la patria bendita del pan!"},{"c":"","l":"¡Quédate con nosotros Señor"},{"c":"","l":"Que hace falta un nuevo Emaús"},{"c":"","l":"La propuesta será compartir como vos"},{"c":"","l":"Y en tu nombre, Jesús!"},{"c":"","l":""},{"c":"","l":"Primitivo ritual de pastores"},{"c":"","l":"que fue luego banquete pascual"},{"c":"","l":"homenaje denuestros mayores"},{"c":"","l":"al Dios vivo de su libertad."},{"c":"","l":""},{"c":"","l":"Cena santa, signo y profecía"},{"c":"","l":"memorial de Jesús servidor"},{"c":"","l":"Nueva alianza de la Eucaristía"},{"c":"","l":"que es misteriode Fe y Comunión."},{"c":"","l":""},{"c":"","l":"Sacrificio de la propia vida"},{"c":"","l":"que seofrece y se da a los demás"},{"c":"","l":"Cuerpo ySangre, Comida y Bebida"},{"c":"","l":"que hace ynutre la comunidad."},{"c":"","l":""},{"c":"","l":"Sos la Fiesta decada semana"},{"c":"","l":"que resume y celebra elamor"},{"c":"","l":"el amor que perdona y hermana"},{"c":"","l":"y es sincera reconciliación."},{"c":"","l":""},{"c":"","l":"Jesucristo, Señor de la Historia"},{"c":"","l":"Quepusiste en el Vino y el Pan"},{"c":"","l":"tu presenciareal, tu Victoria"},{"c":"","l":"sobre el tiempo, lamuerte y el mal."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (93, 'El viñador', '[{"c":"","l":"Por los caminos sedientos de luz,"},{"c":"","l":"levantándose antes que el sol,"},{"c":"","l":"hacia loscampos que lejos están,"},{"c":"","l":"muy temprano seva el viñador."},{"c":"","l":""},{"c":"","l":"No se detiene en su caminar,"},{"c":"","l":"no leasusta la sed ni el calor,"},{"c":"","l":"hay una viñaque quiere cuidar,"},{"c":"","l":"una viña que es todosu amor."},{"c":"","l":""},{"c":"","l":"Dios es tu amigo, el viñador"},{"c":"","l":"El que te cuida de sol a sol."},{"c":"","l":"Dios es tu amigo, el viñador"},{"c":"","l":"El que te pide frutos de amor."},{"c":"","l":""},{"c":"","l":"Él te protege con un valladar,"},{"c":"","l":"Levantado en tu derredor,"},{"c":"","l":"quita del alma las piedras del mal"},{"c":"","l":"y ha elegido la cepamejor."},{"c":"","l":""},{"c":"","l":"Limpia los surcos con todo su afán"},{"c":"","l":"y los riega con sangre y sudor,"},{"c":"","l":"dime si puede hacer algo más"},{"c":"","l":"por su viña el viñador."},{"c":"","l":""},{"c":"","l":"Por los caminos sedientos de luz"},{"c":"","l":"levantándose antes que el sol,"},{"c":"","l":"hacia los campos que lejos están,"},{"c":"","l":"muy tempranose va el viñador"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (94, 'Decisión', '[{"c":"","l":"Todo en esta vida, es un decidir"},{"c":"","l":"si me voy contigo, o me quedo aquí."},{"c":"","l":"Romperé los muros, de mi propia casa,"},{"c":"","l":"iré mar adentro y pescaré por Ti"},{"c":"","l":""},{"c":"","l":"Hoy mi pueblo está clamando,"},{"c":"","l":"pide vida, pide amor"},{"c":"","l":"gritan mis hermanos"},{"c":"","l":"y llega hasta el cielo su voz."},{"c":"","l":"La misión que tú me has dado"},{"c":"","l":"debo hacerla realidad"},{"c":"","l":"\\\"Luchar por la vida,"},{"c":"","l":"luchar por un mundo de paz”"},{"c":"","l":""},{"c":"","l":"Me has hablado en mil canciones"},{"c":"","l":"mas no te quise escuchar"},{"c":"","l":"cerré mis oídos"},{"c":"","l":"porque es muy difícil hablar."},{"c":"","l":"Hace tiempo me pregunto,"},{"c":"","l":"Tu respuesta escucho hoy."},{"c":"","l":"Tu voz habla adentro"},{"c":"","l":"y por tu camino ya voy."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (95, 'Consolad', '[{"c":"","l":"Consolad a mi pueblo, dice el Señor"},{"c":"","l":"hablad al corazón del hombre,"},{"c":"","l":"gritad que mi amor ha vencido,"},{"c":"","l":"preparad el camino,"},{"c":"","l":"que viene tu redentor."},{"c":"","l":""},{"c":"","l":"Yo te he elegido para amar"},{"c":"","l":"te doy mi fuerza y luz para guiar,"},{"c":"","l":"yo soy consuelo en tu mirar,"},{"c":"","l":"gloria a Dios."},{"c":"","l":""},{"c":"","l":"Consolad a mi pueblo dice el Señor"},{"c":"","l":"sacad de la ceguera a mi pueblo,"},{"c":"","l":"yo he sellado contigo"},{"c":"","l":"alianza perpetua,"},{"c":"","l":"yo soy el único Dios."},{"c":"","l":""},{"c":"","l":"Consolad a mi pueblo dice el Señor  mostradle el camino de libertad,"},{"c":"","l":"yo os daré fuertes alas,"},{"c":"","l":"transformaré sus pisadas"},{"c":"","l":"en sendas de eternidad."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (96, 'En memoria tuya', '[{"c":"","l":"Llegada la hora de retorno al Padre,"},{"c":"","l":"sabiendo que iba camino a su cruz,"},{"c":"","l":"reunió a sus amigos en última cena"},{"c":"","l":"ynos dio su Cuerpo el Señor Jesús."},{"c":"","l":""},{"c":"","l":"En memoria tuya, Cristo redentor"},{"c":"","l":"Vamos a tu mesa, en señal de amor"},{"c":"","l":""},{"c":"","l":"Profundo misterio de amor y ternura,"},{"c":"","l":"Dequerer quedarse antes de partir,"},{"c":"","l":"Dedejar su Sangre como Alianza nueva,"},{"c":"","l":"Dedarla en bebida antes de morir."},{"c":"","l":""},{"c":"","l":"“Tómenlo y coman, pues esto es miCuerpo”, les dijo, rompiendo en su manoun pan."},{"c":"","l":"“Tómenla y beban, pues ésta esmi Sangre,"},{"c":"","l":"la que por ustedes he dederramar”."},{"c":"","l":""},{"c":"","l":"“Y hagan lo mismo cuando se reúnan, sabiendo que un día he de retornar,"},{"c":"","l":"Paraconvidarlos a beber unidos"},{"c":"","l":"de aquelvino nuevo que el Padre ha de dar”."},{"c":"","l":""},{"c":"","l":"Por eso, inclinados, su Cuerpo adoramos,"},{"c":"","l":"y aunque nada vemos, nos basta creer."},{"c":"","l":"El antiguo rito ha dejado paso"},{"c":"","l":"a suSacramento, misterio de fe."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (97, 'Sois la semilla', '[{"c":"","l":"Sois la semilla que ha de crecer"},{"c":"","l":"Sois la estrella que ha de brillar"},{"c":"","l":"Sois levadura, sois granos de sal"},{"c":"","l":"antorcha que ha de alumbrar."},{"c":"","l":""},{"c":"","l":"Sois la mañana que vuelve a nacer"},{"c":"","l":"Sois espiga que empieza a granar"},{"c":"","l":"Sois aguijón y caricia a la vez"},{"c":"","l":"testigos que voy a enviar."},{"c":"","l":""},{"c":"","l":"Id amigos por el mundo"},{"c":"","l":"Anunciando el amo"},{"c":"","l":"Mensajeros de la vida"},{"c":"","l":"De la paz y el perdón"},{"c":"","l":"Sed amigos los testigos"},{"c":"","l":"De mi resurrección"},{"c":"","l":"Id llevando mi presencia"},{"c":"","l":"Con ustedes estoy"},{"c":"","l":""},{"c":"","l":"Sois una llama que ha de encender"},{"c":"","l":"resplandores de fe y caridad."},{"c":"","l":"Sois los pastores que han de guiar"},{"c":"","l":"al mundo por sendas de paz."},{"c":"","l":""},{"c":"","l":"Sois los amigos que quise escoger"},{"c":"","l":"Sois palabra que intenta gritar"},{"c":"","l":"sois reino nuevo que empieza a engendrar justicia, amor y verdad"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (98, 'Alma misionera', '[{"c":"","l":"Señor toma mi vida nueva,"},{"c":"","l":"antes de que la espera,"},{"c":"","l":"desgaste años en mí."},{"c":"","l":"Estoy dispuesto a lo que quieras,"},{"c":"","l":"no importa lo que sea,"},{"c":"","l":"tú llámame a servir."},{"c":"","l":""},{"c":"","l":"*Llévame donde los hombres"},{"c":"","l":"necesiten tu palabra, necesiten"},{"c":"","l":"mis ganas de vivir."},{"c":"","l":"Donde falte la esperanza,"},{"c":"","l":"donde todo sea triste, simplemente"},{"c":"","l":"por no saber de Ti.*"},{"c":"","l":""},{"c":"","l":"Te doy mi corazón sincero,"},{"c":"","l":"para gritar sin miedo,"},{"c":"","l":"lo hermoso que es tu amor."},{"c":"","l":"Señor tengo alma misionera,"},{"c":"","l":"condúceme a la tierra,"},{"c":"","l":"que tenga sed de Vos."},{"c":"","l":""},{"c":"","l":"Y así en marcha iré cantando,"},{"c":"","l":"por pueblos predicando,"},{"c":"","l":"tu grandeza Señor."},{"c":"","l":"Tendré mis manos sin cansancio,"},{"c":"","l":"tu historia entre mis labios,"},{"c":"","l":"tu fuerza en la oración."},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', '{"youtube_url":"","autor":""}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (99, 'Si yo no tengo amor', '[{"c":"","l":"Si yo no tengo amor,"},{"c":"","l":"Yo nada soy, Señor (2)"},{"c":"","l":""},{"c":"","l":"El amor es compasivo, el amor es servicial"},{"c":"","l":"el amor no tiene envidia, el amor no busca el mal."},{"c":"","l":""},{"c":"","l":"El amor nunca se irrita, el amor no es descortés"},{"c":"","l":"el amor no es egoísta, el amor nunca es doblez."},{"c":"","l":""},{"c":"","l":"El amor disculpa todo, el amor es caridad"},{"c":"","l":"no se alegra en la injusticia, solo goza en la verdad."},{"c":"","l":""},{"c":"","l":"El amor soporta todo, el amor todo lo cree"},{"c":"","l":"el amor todo lo espera, el amor es siempre fiel."},{"c":"","l":""},{"c":"","l":"Nuestra fe y nuestra esperanza junto a Dios terminarán"},{"c":"","l":"el amor es algo eterno, nunca, nunca pasará."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (100, 'Hoy te quiero contar Jesús amigo', '[{"c":"","l":"Hoy te quiero contar, Jesús amigo"},{"c":"","l":"Que contigo soy feliz"},{"c":"","l":"si tengo tu amistad lo tengo todo"},{"c":"","l":"pues estas dentro de mi"},{"c":"","l":""},{"c":"","l":"Después de comulgar me haces como Tú"},{"c":"","l":"me llenas con tu paz"},{"c":"","l":"en cada pedacito de este pan completo estás"},{"c":"","l":"y así te das."},{"c":"","l":""},{"c":"","l":"Estas ahí por mi porque conoces"},{"c":"","l":"Que sin ti pequeño soy"},{"c":"","l":"de ahora en adelante nada nos separará"},{"c":"","l":"ya lo verás"},{"c":"","l":""},{"c":"","l":"Te escondes en el pan"},{"c":"","l":"Y aunque no te pueda ver"},{"c":"","l":"Te puedo acompañar, es mi lugar preferido"},{"c":"","l":"Hoy quiero comulgar, Abrirte mi corazón"},{"c":"","l":"Así de par en par, eres mi mejor amigo"},{"c":"","l":""},{"c":"","l":"Dos mil años atrás a tus amigos"},{"c":"","l":"invitaste a cenar"},{"c":"","l":"y ahí les prometiste que con ellos"},{"c":"","l":"por siempre ibas a estar"},{"c":"","l":""},{"c":"","l":"Y ahora cada vez que el sacerdote"},{"c":"","l":"Eleva el pan en el Altar"},{"c":"","l":"me pongo de rodillas porque"},{"c":"","l":"se que en esa hostia tu estas."},{"c":"","l":""},{"c":"","l":"Me vuelves a salvar"},{"c":"","l":"Como lo hiciste en la cruz"},{"c":"","l":"En cada misa tu repites tu sacrificio"},{"c":"","l":"Hoy quiero comulgar, Abrirte mi corazón"},{"c":"","l":"Así de par en par, eres mi mejor amigo"},{"c":"","l":"Jesús"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (101, 'Jesús te seguiré', '[{"c":"","l":"Jesús te seguiré, donde me lleves iré."},{"c":"","l":"muéstrame ese lugar donde vives,"},{"c":"","l":"quiero quedarme contigo allí."},{"c":"","l":""},{"c":"","l":"Escuchando tus palabras,"},{"c":"","l":"algo nuevo nació en mí,"},{"c":"","l":"es que nunca nadie nos"},{"c":"","l":"había venido a hablar así."},{"c":"","l":"Ahora veo claro la verdad está en Ti"},{"c":"","l":"Hoy he visto cómo se aman"},{"c":"","l":"los que viven junto a Ti,"},{"c":"","l":"hace tiempo que sediento"},{"c":"","l":"había querido amar así."},{"c":"","l":"Ahora siento que tu amor viene hacia mí."},{"c":"","l":""},{"c":"","l":"Hoy he visto a los leprosos"},{"c":"","l":"sanos y a los ciegos  ver,"},{"c":"","l":"hasta el pan multiplicaste"},{"c":"","l":"para darnos de comer."},{"c":"","l":"Oh Maestro mío, todo lo haces bien."}]', 'COMUNION', '{"youtube_url":"","autor":"Daniel Poli"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (102, 'Como Cristo nos amó', '[{"c":"","l":"Como Cristo nos amó"},{"c":"","l":"nadie pudo amar jamás."},{"c":"","l":"&Eacute;l nos guía como estrella"},{"c":"","l":"por la inmensa oscuridad,"},{"c":"","l":"al partir con &Eacute;l el pan,"},{"c":"","l":"alimenta nuestro amor:"},{"c":"","l":"es el pan de la amistad, el pan de Dios."},{"c":"","l":""},{"c":"","l":"*Es mi Cuerpo, vengan a comer."},{"c":"","l":"Es mi Sangre, vengan a beber."},{"c":"","l":"Porque Yo soy la vida, Yo soy el amor."},{"c":"","l":"¡A tu amor eterno, llévanos, Señor!*"},{"c":"","l":""},{"c":"","l":"Como Cristo nos amó"},{"c":"","l":"nadie pudo amar jamás:"},{"c":"","l":"en su pueblo es un obrero"},{"c":"","l":"como todos los demás,"},{"c":"","l":"con sus manos gana el pan,"},{"c":"","l":"trabajando con amor:"},{"c":"","l":"El conoce la pobreza y el dolor."},{"c":"","l":""},{"c":"","l":"*Es mi Cuerpo, vengan a comer."},{"c":"","l":"Es mi Sangre, vengan a beber."},{"c":"","l":"Porque Yo soy la vida, Yo soy el amor."},{"c":"","l":"¡A tu amor eterno, llévanos, Señor!*"},{"c":"","l":""},{"c":"","l":"Como Cristo nos amó"},{"c":"","l":"nadie pudo amar jamás:"},{"c":"","l":"al morir en una cruz"},{"c":"","l":"nos dio su paz y libertad;"},{"c":"","l":"pero al fin resucitó"},{"c":"","l":"por la fuerza de su amor"},{"c":"","l":"y salió de su sepulcro vencedor."},{"c":"","l":""},{"c":"","l":"*Es mi Cuerpo, vengan a comer."},{"c":"","l":"Es mi Sangre, vengan a beber."},{"c":"","l":"Porque Yo soy la vida, Yo soy el amor."},{"c":"","l":"¡A tu amor eterno, llévanos, Señor!*"},{"c":"","l":""},{"c":"","l":"Como Cristo nos amó"},{"c":"","l":"nadie pudo amar jamás:"},{"c":"","l":"&Eacute;l nos une como hermanos"},{"c":"","l":"en su reino de bondad;"},{"c":"","l":"para siempre junto a El"},{"c":"","l":"viviremos sin temor,"},{"c":"","l":"nada puede separarnos de su amor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (103, 'Ni el pan es pan, ni el vino es vino', '[{"c":"","l":"Tu Señor que te quedaste,"},{"c":"","l":"de manera tan sencilla,"},{"c":"","l":"nuestro trigo se hizo pan"},{"c":"","l":"y la mesa está tendida."},{"c":"","l":"Este pan que ya es Tu Cuerpo,"},{"c":"","l":"la verdadera comida,"},{"c":"","l":"que da fe a los que esperan"},{"c":"","l":"y da fuerza al que camina."},{"c":"","l":""},{"c":"","l":"*Ni el pan es pan, ni el vino es vino,"},{"c":"","l":"tu cuerpo y sangre hoy compartimos."},{"c":"","l":"Y quédate, la noche es larga,"},{"c":"","l":"te necesito, aquí en mi casa,"},{"c":"","l":"aquí en mi casa.*"},{"c":"","l":""},{"c":"","l":"Tu Señor que te quedaste,"},{"c":"","l":"de manera tan sencilla,"},{"c":"","l":"nuestra vid se hizo vino"},{"c":"","l":"y la mesa está tendida."},{"c":"","l":"Este vino ya es tu Sangre,"},{"c":"","l":"la verdadera bebida,"},{"c":"","l":"fuente de todo sediento"},{"c":"","l":"de verdad, de luz, de vida"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (104, 'Bendigamos al Señor', '[{"c":"","l":"Bendigamos al Señor"},{"c":"","l":"que nos une en caridad"},{"c":"","l":"y nos nutre con su amor"},{"c":"","l":"en el Pan de la unidad."},{"c":"","l":"¡Oh Padre nuestro!"},{"c":"","l":""},{"c":"","l":"Conservemos la unidad"},{"c":"","l":"que el Maestro nos mandó"},{"c":"","l":"donde hay guerra que hayapaz,"},{"c":"","l":"donde hay odio que haya amor."},{"c":"","l":"¡OhPadre nuestro!"},{"c":"","l":""},{"c":"","l":"El Señor nos ordenó"},{"c":"","l":"devolver el bien pormal"},{"c":"","l":"ser testigos de su amor,"},{"c":"","l":"perdonando de verdad."},{"c":"","l":"¡Oh Padrenuestro!"},{"c":"","l":""},{"c":"","l":"Al que vive en el dolor"},{"c":"","l":"y al que sufresoledad"},{"c":"","l":"entreguemos nuestro amor"},{"c":"","l":"yconsuelo fraternal."},{"c":"","l":"¡Oh Padre nuestro!"},{"c":"","l":""},{"c":"","l":"El Señor que nos llamó"},{"c":"","l":"a vivir en unidad"},{"c":"","l":"nos congregue con su amor"},{"c":"","l":"en felizeternidad."},{"c":"","l":"¡Oh Padre nuestro!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (105, 'Cristo te necesita', '[{"c":"","l":"Cristo te necesita para amar, para amar."},{"c":"","l":"Cristo te necesita para amar. (2)"},{"c":"","l":""},{"c":"","l":"No te importe la raza ni el color de la piel"},{"c":"","l":"Ama a todos como hermanos y haz el bien(2)"},{"c":"","l":""},{"c":"","l":"Al que sufre y al triste, dale amor, daleamor. Al humilde y al pobre, dale amor.(2)"},{"c":"","l":""},{"c":"","l":"Al que vive a tu lado, dale amor, daleamor."},{"c":"","l":"Al que viene de lejos, dale amor.(2)"},{"c":"","l":""},{"c":"","l":"Al que habla otra lengua, dale amor, daleamor."},{"c":"","l":"Al que piensa distinto, dale amor.(2)"},{"c":"","l":""},{"c":"","l":"Al amigo de siempre dale amor, daleamor."},{"c":"","l":"Al que no te saluda, dale amor.(2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (106, 'Pescador de hombres', '[{"c":"","l":"Tú has venido a la orilla;"},{"c":"","l":"no has buscado ni a sabios ni a ricos."},{"c":"","l":"¡Tan solo quieres que yo te siga!"},{"c":"","l":""},{"c":"","l":"¡Señor, me has mirado a los ojos!"},{"c":"","l":"Sonriendo has dicho mi nombre."},{"c":"","l":"En la arena he dejado mi barca,"},{"c":"","l":"junto a Ti, buscaré otro mar."},{"c":"","l":""},{"c":"","l":"Tú sabes bien lo que tengo:"},{"c":"","l":"en mi barca no hay oro ni espadas..."},{"c":"","l":"¡Tan solo redes y mi trabajo!"},{"c":"","l":""},{"c":"","l":"Tú necesitas mis manos,"},{"c":"","l":"mi cansancio que a otros descanse,"},{"c":"","l":"amor que quieras seguir amando!"},{"c":"","l":""},{"c":"","l":"Tú, pescador de otros lagos,"},{"c":"","l":"ansia eterna de almas que esperan,"},{"c":"","l":"amigo bueno que así me llamas!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (107, 'Un nuevo sol', '[{"c":"","l":"Una tierra que no tiene fronteras"},{"c":"","l":"si no manos que juntas formarán"},{"c":"","l":"una cadena más fuerte"},{"c":"","l":"que la guerra y que la muerte,"},{"c":"","l":"lo sabemos, el camino es el amor..."},{"c":"","l":"Una patria más justa y más fraterna"},{"c":"","l":"donde todos construyamos la unidad,"},{"c":"","l":"donde nadie es desplazado"},{"c":"","l":"porque todos son llamados,"},{"c":"","l":"lo sabemos, el camino es el amor..."},{"c":"","l":""},{"c":"","l":"Un nuevo sol se levanta"},{"c":"","l":"sobre la nueva civilización que nace hoy,"},{"c":"","l":"Una cadena más fuerte"},{"c":"","l":"que el odio y que la muerte."},{"c":"","l":"Lo sabemos, el camino es el amor."},{"c":"","l":""},{"c":"","l":"La justicia es la fuerza de la paz,"},{"c":"","l":"el amor quien hace perdonar,"},{"c":"","l":"la verdad es la fuerza que nos da liberación,"},{"c":"","l":"lo sabemos, el camino es el amor..."},{"c":"","l":""},{"c":"","l":"El que tiene comparte su riqueza"},{"c":"","l":"y el que sabe no impone su verdad,"},{"c":"","l":"el que manda entiende"},{"c":"","l":"que el poder es un servicio,"},{"c":"","l":"lo sabemos, el camino es el amor..."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (108, 'Quiero ser pan', '[{"c":"","l":"Es joven el que espera,"},{"c":"","l":"el que sabe caminar,"},{"c":"","l":"el que lucha por el Reino"},{"c":"","l":"sin volver la vista atrás."},{"c":"","l":""},{"c":"","l":"El que da su mano a otro,"},{"c":"","l":"el que sabe transformar,"},{"c":"","l":"el que es pan para los pobres,"},{"c":"","l":"defendiendo la verdad."},{"c":"","l":""},{"c":"","l":"*Quiero ser pan,"},{"c":"","l":"para el hambre ser el pan,"},{"c":"","l":"de mi pueblo y construir"},{"c":"","l":"el escándalo de compartir.*"},{"c":"","l":""},{"c":"","l":"Es joven el que arriesga,"},{"c":"","l":"el que sabe caminar,"},{"c":"","l":"el que siempre pregunta"},{"c":"","l":"sin volver la vista atrás."},{"c":"","l":""},{"c":"","l":"El que sabe hacer historia,"},{"c":"","l":"el que sabe transformar,"},{"c":"","l":"el que es voz de los pequeños,"},{"c":"","l":"defendiendo la verdad."},{"c":"","l":""},{"c":"","l":"*Quiero ser pan,"},{"c":"","l":"para el hambre ser el pan,"},{"c":"","l":"de mi pueblo y construir"},{"c":"","l":"el escándalo de compartir.*"},{"c":"","l":""},{"c":"","l":"El que sigue a Jesús pobre,"},{"c":"","l":"el que sabe caminar,"},{"c":"","l":"el que apoya la justicia"},{"c":"","l":"sin volver la vista atrás."},{"c":"","l":""},{"c":"","l":"El que vive siempre abierto,"},{"c":"","l":"el que sabe transformar,"},{"c":"","l":"el que canta con los otros,"},{"c":"","l":"defendiendo la verdad."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (109, 'El camino de Emaús', '[{"c":"","l":"¿Qué venías conversando?"},{"c":"","l":"me dijiste buen amigo"},{"c":"","l":"y me detuve asombrado"},{"c":"","l":"a la vera del camino."},{"c":"","l":"¿No sabes lo que ha pasado"},{"c":"","l":"allá en Jerusalén?"},{"c":"","l":"¿De Jesús de Nazaret"},{"c":"","l":"a quien clavaron en Cruz?"},{"c":"","l":"Por eso me vuelvo triste"},{"c":"","l":"a mi aldea de Emaús."},{"c":"","l":""},{"c":"","l":"Por el camino de Emaús"},{"c":"","l":"Un peregrino iba conmigo"},{"c":"","l":"No lo conocí al caminar"},{"c":"","l":"Ahora sí, en la fracción del pan."},{"c":"","l":""},{"c":"","l":"Van tres días que se ha muerto"},{"c":"","l":"y seacaba mi esperanza."},{"c":"","l":"Dicen que algunasmujeres"},{"c":"","l":"al sepulcro fueron de alba;"},{"c":"","l":"Pedro, Juan y algunos otros"},{"c":"","l":"Hoytambién allá buscaron."},{"c":"","l":"Más se acabami confianza"},{"c":"","l":"no encontraron a Jesús:"},{"c":"","l":"Por eso me vuelvo triste"},{"c":"","l":"a mi aldea deEmaús."},{"c":"","l":"Oh, tardíos corazones"},{"c":"","l":"que ignoráis a losprofetas."},{"c":"","l":"En la ley ya está anunciado"},{"c":"","l":"que el Mesías padeciera"},{"c":"","l":"y por llegar asu gloria"},{"c":"","l":"eligiera la aflicción."},{"c":"","l":"En latarde de aquel día"},{"c":"","l":"yo sentí que porJesús"},{"c":"","l":"nuestro corazón ardía"},{"c":"","l":"a la vistade Emaús."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (110, 'Cuerpo y sangre de Jesús', '[{"c":"","l":"Cuerpo y sangre de Jesús, pan de Vida"},{"c":"","l":"Cáliz del Señor en la Eucaristía"},{"c":"","l":""},{"c":"","l":"Redimidos por su amor,"},{"c":"","l":"bautizados ensu muerte"},{"c":"","l":"renovemos las promesas"},{"c":"","l":"antes de comer su Cuerpo y su Sangre."},{"c":"","l":""},{"c":"","l":"El Espíritu de Dios"},{"c":"","l":"confirmó nuestrobautismo"},{"c":"","l":"y hoy imprime en nuestrasalmas"},{"c":"","l":"el sello de unión en la Eucaristía."},{"c":"","l":""},{"c":"","l":"Por la carne de Jesús"},{"c":"","l":"Dios nos hace desu raza"},{"c":"","l":"y en el pueblo de elegidos"},{"c":"","l":"somos parte fiel de su sacerdocio."},{"c":"","l":""},{"c":"","l":"Como granos de la vid"},{"c":"","l":"como granos enla espiga"},{"c":"","l":"un Cuerpo todos formamos"},{"c":"","l":"en la gran unión del amor cristiano."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (111, 'El profeta', '[{"c":"","l":"Antes que te formarás"},{"c":"","l":"dentro del vientre de tu madre,"},{"c":"","l":"antes que tu nacieras"},{"c":"","l":"te conocía y te consagré."},{"c":"","l":"Para ser mi profeta"},{"c":"","l":"de las naciones, yo te escogí."},{"c":"","l":"Iras donde te envíe,"},{"c":"","l":"lo que te digas proclamarás."},{"c":"","l":""},{"c":"","l":"*Tengo que gritar, tengo que arriesgar,"},{"c":"","l":"¡hay de mí si no lo hago!"},{"c":"","l":"¿Cómo escapar de ti?¿Cómo no hablar?"},{"c":"","l":"si tu voz me quema dentro."},{"c":"","l":"Tengo que andar, tengo que luchar,"},{"c":"","l":"¡hay de mí si no lo hago!"},{"c":"","l":"¿Cómo escapar de ti?¿Cómo no hablar?,"},{"c":"","l":"si tu voz me quema dentro.*"},{"c":"","l":""},{"c":"","l":"No temas arriesgarte"},{"c":"","l":"porque contigo yo estaré."},{"c":"","l":"No temas anunciarme"},{"c":"","l":"porque en tu boca yo hablaré."},{"c":"","l":"Te encargo hoy mi pueblo"},{"c":"","l":"para arrancar y derribar,"},{"c":"","l":"para edificar"},{"c":"","l":"destruirás y plantarás."},{"c":"","l":""},{"c":"","l":"Deja a tus hermanos,"},{"c":"","l":"deja a tu padre y a tu madre."},{"c":"","l":"Abandona tu casa"},{"c":"","l":"porque la tierra gritando está."},{"c":"","l":"Nada traigas contigo"},{"c":"","l":"porque a tu lado yo estaré."},{"c":"","l":"Es hora de luchar"},{"c":"","l":"porque mi pueblo sufriendo está"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (112, 'Yo soy el camino', '[{"c":"","l":"Yo soy la Luz del mundo,"},{"c":"","l":"no hay tinieblas junto a mí"},{"c":"","l":"tendrán la luz de la Vida"},{"c":"","l":"por la Palabra que les di."},{"c":"","l":""},{"c":"","l":"*Yo soy el camino firme*"},{"c":"","l":"*Yo soy la Vida y la Verdad*"},{"c":"","l":"*Por mi llegarán al Padre*"},{"c":"","l":"*Y el Santo Espíritu tendrán.*"},{"c":"","l":""},{"c":"","l":"Yo soy el Pan de Vida"},{"c":"","l":"y con ustedes me quedé"},{"c":"","l":"me entrego como alimento,"},{"c":"","l":"soy el misterio de la Fe."},{"c":"","l":""},{"c":"","l":"Yo soy el Buen Pastor"},{"c":"","l":"y por amor mi vida doy"},{"c":"","l":"yo quiero un sólo rebaño,"},{"c":"","l":"soy para todos Salvador."},{"c":"","l":""},{"c":"","l":"Yo soy la vid verdadera,"},{"c":"","l":"mi Padre Dios el viñador"},{"c":"","l":"produzcan fruto abundante"},{"c":"","l":"permaneciendo en mi Amor."},{"c":"","l":""},{"c":"","l":"Yo soy Señor y Maestro"},{"c":"","l":"y un mandamiento nuevo doy"},{"c":"","l":"que se Amén unos a otros"},{"c":"","l":"como los he amado yo."}]', 'COMUNION', '{"youtube_url":"","autor":"Aguilera González"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (113, 'Nueva generación', '[{"c":"","l":"Yo vengo del Sur y del Norte,"},{"c":"","l":"del Este y Oeste, de todo lugar."},{"c":"","l":"Caminos y vidas recorro,"},{"c":"","l":"llevando socorro, queriendo ayudar."},{"c":"","l":"Mensaje de paz es mi canto,"},{"c":"","l":"y cruzo montañas y voy hasta el fin."},{"c":"","l":"El mundo no me satisface"},{"c":"","l":"lo que busco es paz, lo que quiero es vivir."},{"c":"","l":""},{"c":"","l":"*Al pecho llevo una cruz"},{"c":"","l":"y en mi corazón lo que dice Jesús.*"},{"c":"","l":""},{"c":"","l":"Yo sé que no tengo la edad"},{"c":"","l":"ni la madurez de quien ya vivió,"},{"c":"","l":"mas sé que es de mi propiedad"},{"c":"","l":"buscar la verdad y gritar con mi voz."},{"c":"","l":"El mundo va herido y cansado"},{"c":"","l":"de un negro pasado de guerras sin fin,"},{"c":"","l":"hoy teme a la bomba que hizo"},{"c":"","l":"y a la fe que deshizo, y espera por mí."},{"c":"","l":""},{"c":"","l":"Yo quiero dejar mi recado"},{"c":"","l":"no tengo pasado pero tengo amor."},{"c":"","l":"El mismo de un crucificado"},{"c":"","l":"que quiso dejarnos un mundo mejor."},{"c":"","l":"Yo digo a los indiferentes"},{"c":"","l":"que soy de la gente que cree en la cruz."},{"c":"","l":"Y creo en la fuerza del hombre"},{"c":"","l":"que sigue el camino de Cristo Jesús."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (114, 'Contra toda esperanza', '[{"c":"","l":"Hoy al fin tenemos que seguir, caminando en paz,"},{"c":"","l":"esperamos contra toda esperanza."},{"c":"","l":"Al saber que todo va a cambiar"},{"c":"","l":"resucitarás,"},{"c":"","l":"esperamos contra toda esperanza."},{"c":"","l":""},{"c":"","l":"Vos sos la vida, sos la paz,"},{"c":"","l":"vos sos nuestra esperanza."},{"c":"","l":"Sos el camino para andar,"},{"c":"","l":"sos fuerzas y sos confianza."},{"c":"","l":""},{"c":"","l":"No aflojar, seguirte hasta el final, tu cruz abrazar,"},{"c":"","l":"esperamos contra toda esperanza."},{"c":"","l":"Al saber que vos vas a volver"},{"c":"","l":"a resucitar,"},{"c":"","l":"esperamos contra toda esperanza."},{"c":"","l":""},{"c":"","l":"Al sentir, Jesús estas aquí, esperándonos,"},{"c":"","l":"esperamos contra toda esperanza."},{"c":"","l":"Esperar también es transformar"},{"c":"","l":"un sueño en realidad,"},{"c":"","l":"esperamos contra toda esperanza."},{"c":"","l":""},{"c":"","l":"Hay un sol, la noche ya aclaró, ven a caminar,"},{"c":"","l":"esperamos contra toda esperanza."},{"c":"","l":"Estarás sonriente a nuestra par,"},{"c":"","l":"no nos dejarás,"},{"c":"","l":"esperamos contra toda esperanza."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (115, 'Cristo vale la pena', '[{"c":"","l":"Yo sé que me necesitas"},{"c":"","l":"que necesitas mi amor,"},{"c":"","l":"me llamas para que luche"},{"c":"","l":"en este mundo de hoy."},{"c":"","l":""},{"c":"","l":"Yo sé que diste la vida"},{"c":"","l":"para nuestra salvación,"},{"c":"","l":"hoy quiero amar sin medida"},{"c":"","l":"quiero jugarme por vos."},{"c":"","l":""},{"c":"","l":"Cristo vale la pena"},{"c":"","l":"luchemos con fe."},{"c":"","l":"María será la estrella"},{"c":"","l":"que nos guíe hasta El."},{"c":"","l":""},{"c":"","l":"María dame la fuerza"},{"c":"","l":"para poderles mostrar"},{"c":"","l":"a todos mis hermanos"},{"c":"","l":"lo hermoso que es amar."},{"c":"","l":""},{"c":"","l":"Para poder con mis labios"},{"c":"","l":"tu palabra proclamar"},{"c":"","l":"haz de mí un instrumento"},{"c":"","l":"y así tu amor sembrar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (116, 'Canción de Zaqueo', '[{"c":"","l":"El día es hoy, la hora ya,"},{"c":"","l":"pronto, Jesús por mi vida pasarás."},{"c":"","l":"Sé que tu amor es fuerte,"},{"c":"","l":"quiero trepar y verte."},{"c":"","l":""},{"c":"","l":"Ven a mi casa, ven a mi hogar,"},{"c":"","l":"que hace tiempo guardo un lugar"},{"c":"","l":"y llevo dentro tantos deseos"},{"c":"","l":"de conversar."},{"c":"","l":"Ven a mi casa, ven a mi hogar,"},{"c":"","l":"que con vos se va a iluminar,"},{"c":"","l":"y ese rincón oscuro y cerrado"},{"c":"","l":"abre de par y en par,"},{"c":"","l":"y sea tuyo lo que es mío,"},{"c":"","l":"tuyo mi hogar."},{"c":"","l":""},{"c":"","l":"No sé por qué, estoy aquí,"},{"c":"","l":"quiero guardar tus ojos dentro de mí,"},{"c":"","l":"porque miraste hondo,"},{"c":"","l":"lo comprendiste todo."},{"c":"","l":""},{"c":"","l":"Él que me amó, sin despreciar,"},{"c":"","l":"y me miró y me vino a visitar."},{"c":"","l":"Le devolvió a mis manos"},{"c":"","l":"un latido de hermano."}]', 'COMUNION', '{"youtube_url":"","autor":"Eduardo Meana"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (117, 'Un mandamiento nuevo', '[{"c":"","l":"Un mandamiento nuevo nos da el Señor"},{"c":"","l":"Que nos amemos todos, como Él amó."},{"c":"","l":""},{"c":"","l":"La señal de los cristianos,"},{"c":"","l":"es amarnos como hermanos."},{"c":"","l":"Quien a sus hermanos no ama,"},{"c":"","l":"miente si a Dios dice que ama."},{"c":"","l":"Cristo, Luz, Verdad y Vida,"},{"c":"","l":"al perdón y amor invita."},{"c":"","l":"Perdonemos al hermano,"},{"c":"","l":"como Cristo ha perdonado."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (118, 'Cristo Jesús', '[{"c":"","l":"Cristo Jesús, en Ti la Patria espera"},{"c":"","l":"gloria, buscando con intenso ardor."},{"c":"","l":"Guíala Tú, bendice su bandera"},{"c":"","l":"dando a su faz magnífico esplendor."},{"c":"","l":""},{"c":"","l":"Salve divino, foco de amor"},{"c":"","l":"Salva al pueblo Argentino,"},{"c":"","l":"escucha su clamor"},{"c":"","l":"Salva al pueblo Argentino,"},{"c":"","l":"Sagrado Corazón."},{"c":"","l":""},{"c":"","l":"Cristo Jesús, altar donde se ofrece"},{"c":"","l":"Todo el amor que el mundo tiene a Dios"},{"c":"","l":"Haz que el amor nos una en esta vida"},{"c":"","l":"Para formar un sólo corazón."},{"c":"","l":""},{"c":"","l":"Cristo Jesús, por quien la Patria espera"},{"c":"","l":"ser un hogar de paz y libertad"},{"c":"","l":"haz que por Ti, la Patria en que vivimos"},{"c":"","l":"sea un anuncio de la celestial."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (119, 'Jesucristo danos de este pan', '[{"c":"","l":"*Jesucristo, danos de este pan."},{"c":"","l":"Que tu pueblo crezca en la unidad. *"},{"c":"","l":""},{"c":"","l":"Siendo Dios hombre te hiciste para"},{"c":"","l":"poderte entregar."},{"c":"","l":"En la cruz sangriento altar,"},{"c":"","l":"donde a los hombre te diste."},{"c":"","l":"Al morir te diste todo,"},{"c":"","l":"ofreciéndote en la cruz,"},{"c":"","l":"y era el cielo, buen Jesús,"},{"c":"","l":"que nos dabas de este modo."},{"c":"","l":""},{"c":"","l":"*Jesucristo, danos de este pan."},{"c":"","l":"Que tu pueblo crezca en la unidad. *"},{"c":"","l":""},{"c":"","l":"Cuando eres celebrado,"},{"c":"","l":"en cada misa te das."},{"c":"","l":"Pero ya no mueres más,"},{"c":"","l":"porque estás resucitado."},{"c":"","l":"Una vez todo te diste,"},{"c":"","l":"y es cada misa esa vez,"},{"c":"","l":"hasta que vuelvas después,"},{"c":"","l":"como Tú lo prometiste."},{"c":"","l":""},{"c":"","l":"*Jesucristo, danos de este pan."},{"c":"","l":"Que tu pueblo crezca en la unidad. *"},{"c":"","l":""},{"c":"","l":"Tu Señor has visto el hambre,"},{"c":"","l":"que tenemos de hermandad"},{"c":"","l":"y nos brindad la unidad"},{"c":"","l":"con tu cuerpo y con tu sangre."},{"c":"","l":"Y tu Cuerpo nos congrega"},{"c":"","l":"en eterna comunión,"},{"c":"","l":"y la Sangre del perdón"},{"c":"","l":"hasta el corazón nos llega."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (120, 'Danos siempre de este pan', '[{"c":"","l":"Danos siempre de este pan,"},{"c":"","l":"que nos une en comunión,"},{"c":"","l":"pan de vida y esperanza"},{"c":"","l":"verdadero pan de Dios."},{"c":"","l":""},{"c":"","l":"Somos todos invitados"},{"c":"","l":"a la mesa del Señor,"},{"c":"","l":"donde el mismo se ha entregado"},{"c":"","l":"para darse en comunión."},{"c":"","l":"Comeremos de su carne"},{"c":"","l":"que nos une en amistad;"},{"c":"","l":"beberemos de su sangre"},{"c":"","l":"con sabor a eternidad."},{"c":"","l":""},{"c":"","l":"Como granos de la espiga"},{"c":"","l":"que se han hecho un solo pan"},{"c":"","l":"estrechemos nuestras vidas,"},{"c":"","l":"y busquemos la unidad."},{"c":"","l":"Todos nuestros sentimientos"},{"c":"","l":"sean solo para Dios;"},{"c":"","l":"que seamos instrumentos"},{"c":"","l":"en las manos del Señor."},{"c":"","l":""},{"c":"","l":"Este pan que compartimos"},{"c":"","l":"y este cáliz de amistad,"},{"c":"","l":"son también un anticipo"},{"c":"","l":"del banquete celestial."},{"c":"","l":"Mientras tanto como iglesia"},{"c":"","l":"caminamos hacia Dios;"},{"c":"","l":"esperando la venida"},{"c":"","l":"que Jesús nos prometió."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (121, 'Te amo, Señor', '[{"c":"","l":"Te amo, Señor a Ti elevo la voz"},{"c":"","l":"Para adorarte con toda mi alma."},{"c":"","l":"Te alabo, mi Rey goza mi corazón"},{"c":"","l":"dulce Señor, divino Redentor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (122, 'Ámame Señor', '[{"c":"","l":"Ámame Señor, quiero recibir"},{"c":"","l":"ese gran amor que es para mí"},{"c":"","l":"ven tu sobre mí y hazme al fin sentir"},{"c":"","l":"esa vida dulce, vida en ti Señor."},{"c":"","l":""},{"c":"","l":"Ven y ámame, ven y ámame"},{"c":"","l":"Quiero recibir todo tu amor"},{"c":"","l":"Ven y ámame, ven y ámame"},{"c":"","l":"Te abro a Ti las puertas de mi corazón"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (123, 'Creo', '[{"c":"","l":"Creo, aunque todo se oculte a mi fe."},{"c":"","l":"Creo, aunque todo me grite que no."},{"c":"","l":"Porque he basado mi vida"},{"c":"","l":"en un Dios Inmutable"},{"c":"","l":"en un Dios que no cambia,"},{"c":"","l":"enun Dios que es amor."},{"c":"","l":""},{"c":"","l":"Creo, aunque todo parezca morir."},{"c":"","l":"Creo,aunque ya no quisiera vivir."},{"c":"","l":"Porque hebasado mi vida"},{"c":"","l":"en palabras sinceras"},{"c":"","l":"Enpalabras de amigo,"},{"c":"","l":"en palabras de Dios."},{"c":"","l":""},{"c":"","l":"Creo, aunque todo subleve mi ser."},{"c":"","l":"Creo,aunque sienta muy solo el dolor."},{"c":"","l":"Porqueun cristiano que tiene"},{"c":"","l":"al Señor por amigo"},{"c":"","l":"no vacila en la duda,"},{"c":"","l":"se mantiene en lafe."},{"c":"","l":""},{"c":"","l":"Creo, aunque veo a los hombres odiar."},{"c":"","l":"Creo, aunque veo a los niños llorar."},{"c":"","l":"Porque aprendí con certeza"},{"c":"","l":"que Él sale alencuentro"},{"c":"","l":"en las horas más duras,"},{"c":"","l":"consu amor y su luz."},{"c":"","l":""},{"c":"","l":"Creo, pero aumenta mife."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (124, 'Te agradezco Señor', '[{"c":"","l":"Te agradezco, Señor, tu Palabra"},{"c":"","l":"Teagradezco tu Verbo de amor"},{"c":"","l":"meditar ensilencio tus cosas"},{"c":"","l":"aprender lo que es elamor."},{"c":"","l":""},{"c":"","l":"Te agradezco tu vivo silencio"},{"c":"","l":"este ratopara hablar con Vos"},{"c":"","l":"encarnarme en tusabiduría"},{"c":"","l":"y vivir tu Palabra, Señor."},{"c":"","l":""},{"c":"","l":"GRACIAS, GRACIAS, GRACIAS, SEÑOR (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (125, 'Vaso nuevo', '[{"c":"","l":"Gracias quiero darte por amarme"},{"c":"","l":"Gracias quiero darte yo a ti, Señor."},{"c":"","l":"Hoysoy feliz porque te conocí."},{"c":"","l":"Gracias poramarme a mí también."},{"c":"","l":""},{"c":"","l":"Yo quiero ser, Señor amado"},{"c":"","l":"Como el barro"},{"c":"","l":"En manos del alfarero."},{"c":"","l":"Toma mi vida y hazla de nuevo."},{"c":"","l":"Yo quiero ser un vaso nuevo (2)"},{"c":"","l":""},{"c":"","l":"Te conocí y te amé."},{"c":"","l":"Te pedí perdón y meescuchaste."},{"c":"","l":"Si, te ofendí, perdóname,Señor"},{"c":"","l":"pues te amo y nunca te olvidaré."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (126, 'Tan cerca de mi', '[{"c":"","l":"Tan cerca de mí, tan cerca de mi"},{"c":"","l":"Que hasta lo puedo tocar,"},{"c":"","l":"Jesús está aquí"},{"c":"","l":""},{"c":"","l":"No busques a Cristo en lo alto"},{"c":"","l":"ni lo busques en la oscuridad"},{"c":"","l":"muy dentro de ti, en tu corazón"},{"c":"","l":"puedes encontrar a tu Señor."},{"c":"","l":""},{"c":"","l":"Le hablaré sin miedo y al oído"},{"c":"","l":"le contaré las cosas que hay en mi"},{"c":"","l":"y que solo a Él, le interesarán"},{"c":"","l":"Él es más que amigo para mí"},{"c":"","l":""},{"c":"","l":"Míralo a tu lado por la calle"},{"c":"","l":"caminando entre la multitud"},{"c":"","l":"muchos ciegos van"},{"c":"","l":"sin quererlo ver"},{"c":"","l":"llenos de ceguera espiritual."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (127, 'Alma de Cristo', '[{"c":"","l":"Alma de Cristo, santifícame."},{"c":"","l":"Cuerpo de Cristo, sálvame."},{"c":"","l":"Sangre de Cristo, embriágame."},{"c":"","l":"Agua de su costado, lávame."},{"c":"","l":"Pasión de Cristo, confórtame."},{"c":"","l":"Oh, Buen Jesús, óyeme."},{"c":"","l":""},{"c":"","l":"Dentro de tus llagas, escóndeme"},{"c":"","l":"no permitas que me aparte de Ti"},{"c":"","l":"Del maligno enemigo, defiéndeme,"},{"c":"","l":"en la hora de mi muerte, llámame"},{"c":"","l":"Y mándame ir a Ti"},{"c":"","l":"para que con tus Santos te alabe"},{"c":"","l":"por los siglos de los siglos"},{"c":"","l":"amén."}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Moser"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (128, 'Ven y sígueme', '[{"c":"","l":"Tú quieres Señor que yo te siga"},{"c":"","l":"me pides que me ponga a caminar"},{"c":"","l":"difícil para mí es complacerte"},{"c":"","l":"es mucho lo que tengo que dejar."},{"c":"","l":""},{"c":"","l":"Me llamas Señor a ser tu apóstol"},{"c":"","l":"y sabes que es mucho para mí"},{"c":"","l":"quisiera algún día yo seguirte"},{"c":"","l":"pero es mucho lo que tengo que dejar."},{"c":"","l":""},{"c":"","l":"Ven y sígueme, no esperes más"},{"c":"","l":"Yo junto a ti siempre estaré"},{"c":"","l":"No temas que palabras tendrás que decir"},{"c":"","l":"Yo por tu boca hablaré"},{"c":"","l":""},{"c":"","l":"¿Por qué cuidas Tú de mi persona"},{"c":"","l":"habiendo otros mejores que yo?"},{"c":"","l":"Me pides que emprenda algo grande"},{"c":"","l":"soy débil para estar de pie."},{"c":"","l":""},{"c":"","l":"Señor quiero decirte otra cosa:"},{"c":"","l":"“Mis amigos de mí se reirán"},{"c":"","l":"dame más fuerza y valentía"},{"c":"","l":"dame la vida y la fe”."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (129, 'Dios mi amigo', '[{"c":"","l":"A veces en algunos días grises"},{"c":"","l":"cuando pierdo la esperanza"},{"c":"","l":"cuando no encuentro la paz"},{"c":"","l":"me pregunto, si es verdad que existes"},{"c":"","l":"si realmente eres mi amigo"},{"c":"","l":"si lo eres dónde estás"},{"c":"","l":"Es ése el momento cuando dudo"},{"c":"","l":"un momento de vacío"},{"c":"","l":"y de fría oscuridad"},{"c":"","l":"porque pienso que si en verdad no existes"},{"c":"","l":"mi vida sería vana"},{"c":"","l":"como un libro sin final."},{"c":"","l":""},{"c":"","l":"Pero una voz, siento surgir dentro de mi"},{"c":"","l":"Que me devuelve toda mi fe"},{"c":"","l":"Es la voz de Dios mi amigo."},{"c":"","l":"Y es esa voz,"},{"c":"","l":"que con dulzura me habla de paz"},{"c":"","l":"La que me dice que Dios será"},{"c":"","l":"Siempre nuestro amigo"},{"c":"","l":""},{"c":"","l":"A veces me contás que estás perdido"},{"c":"","l":"que no encuentras el camino"},{"c":"","l":"que te devuelva la Fe"},{"c":"","l":"y me dices, que Dios está muy lejos"},{"c":"","l":"que no sabes acercarte"},{"c":"","l":"quieres que se acerque Él."},{"c":"","l":""},{"c":"","l":"Ahora que yo encontré de nuevo"},{"c":"","l":"a ese amigo que me cuida"},{"c":"","l":"y que me enseña a amar"},{"c":"","l":"te invito, a que intentes encontrarlo"},{"c":"","l":"veas que no está muy lejos"},{"c":"","l":"y que Él te espera ya."},{"c":"","l":""},{"c":"","l":"Y tú también has de escuchar la dulce voz"},{"c":"","l":"Que te hablará llena de amor"},{"c":"","l":"Es la voz de Dios tu amigo"},{"c":"","l":"Y es esa voz,"},{"c":"","l":"que con dulzura te habla de paz"},{"c":"","l":"La que te dice que Dios será"},{"c":"","l":"Siempre nuestro amigo"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (130, 'Oh Santo Dios', '[{"c":"","l":"Ho santo Dios, Jesús Señor,"},{"c":"","l":"tu mano me tocó."},{"c":"","l":"Me amaste a mí, un pecador,"},{"c":"","l":"tu gracia me salvó."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (131, 'Gloria', '[{"c":"","l":"Gloria, gloria, gloria, gloria"},{"c":"","l":"A Jesús el Señor, al Cordero de Dios"},{"c":"","l":"al Nombre sobre todo Nombre (2)"},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Martin Valverde"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (132, 'Mi pensamiento eres tu', '[{"c":"","l":"Mi pensamiento eres tu Señor (x3)"},{"c":"","l":"Mi pensamiento eres tú."},{"c":"","l":""},{"c":"","l":"Porque tú me has dado la vida"},{"c":"","l":"Porque tú me has dado el existir"},{"c":"","l":"Porque tú me has dado cariño"},{"c":"","l":"Me has dado amor"},{"c":"","l":""},{"c":"","l":"Mi fortaleza eres tú, Señor…"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (133, 'Nadie te ama como yo', '[{"c":"","l":"cuanto he esperado que estuvieras así; cuanto he esperado que me hablaras,"},{"c":"","l":"cuanto he esperado que vinieras a Mí."},{"c":"","l":"Yo sé bien lo que has vivido."},{"c":"","l":"Yo sé bien porque has llorado."},{"c":"","l":"Yo sé bien lo que has sufrido,"},{"c":"","l":"pues de tu lado no me ido."},{"c":"","l":""},{"c":"","l":"Pues nadie te ama, como yo"},{"c":"","l":"pues nadie te ama, como yo."},{"c":"","l":"Mira la cruz,esa es mi más grande prueba"},{"c":"","l":"pues nadie te ama, como yo."},{"c":"","l":"Pues nadie te ama como yo,"},{"c":"","l":"pues nadie te ama como yo."},{"c":"","l":"Mira la cruz,fue por ti fue porque te amo,"},{"c":"","l":"nadie te ama, como yo."},{"c":"","l":""},{"c":"","l":"Yo sé bien lo que me dices,"},{"c":"","l":"aunque a veces no me hablas."},{"c":"","l":"Yo sé bien lo que en ti sientes,"},{"c":"","l":"aunque nunca lo compartas."},{"c":"","l":"A tú lado he caminado"},{"c":"","l":"junto a ti Yo siempre he ido,"},{"c":"","l":"aun a veces te he cargado."},{"c":"","l":"Yo he sido tu mejor amigo"},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Martin Valverde"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (134, 'Milagro de amor', '[{"c":"","l":"Jesús, aquí presente en forma real"},{"c":"","l":"Te pido un poco más de fe y de humildad"},{"c":"","l":"Quisiera poder ser digna de compartir"},{"c":"","l":"Contigo el milagro más grande de amor"},{"c":"","l":""},{"c":"","l":"*Milagro de amor tan infinito"},{"c":"","l":"En que tú mi Dios te has hecho"},{"c":"","l":"Tan pequeño y tan humilde, para entrar en mi"},{"c":"","l":"Milagro de amor tan infinito"},{"c":"","l":"En que tú mi Dios te olvidas"},{"c":"","l":"De tu gloria y de tu majestad por mi*"},{"c":"","l":""},{"c":"","l":"Y hoy vengo lleno de alegría"},{"c":"","l":"A recibirte en esta eucaristía"},{"c":"","l":"Te doy gracias por llamarme a esta cena"},{"c":"","l":"Porque aunque no soy digno"},{"c":"","l":"Visitas tú mi alma."},{"c":"","l":""},{"c":"","l":"*Milagro de amor tan infinito"},{"c":"","l":"En que tú mi Dios te has hecho"},{"c":"","l":"Tan pequeño y tan humilde, para entrar en mi"},{"c":"","l":"Milagro de amor tan infinito"},{"c":"","l":"En que tú mi Dios te olvidas"},{"c":"","l":"De tu gloria y de tu majestad por mi*"},{"c":"","l":""},{"c":"","l":"Gracias Señor, por esta comunión"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (135, 'Padre me pongo en tus manos', '[{"c":"","l":"Padre me pongo en tus manos."},{"c":"","l":"haz de mi lo que quieras"},{"c":"","l":"sea lo que sea, te doy gracias."},{"c":"","l":""},{"c":"","l":"Estoy dispuesto a todo, lo acepto todo"},{"c":"","l":"con tal que tu voluntad se cumpla en mí"},{"c":"","l":"y en todas tus criaturas."},{"c":"","l":""},{"c":"","l":"No deseo más, Padre, Te confío mi alma"},{"c":"","l":"Te la doy con el amor con que soy capaz"},{"c":"","l":"Porque te amo y necesito darme"},{"c":"","l":""},{"c":"","l":"Ponerme en tus manos sin medida"},{"c":"","l":"con una confianza infinita"},{"c":"","l":"porque Tú eres, mi Padre."},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Oración de Foucauld"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (136, 'Ven y sígueme', '[{"c":"","l":"Ven y sígueme,"},{"c":"","l":"y mar adentro echa ya tus redes."},{"c":"","l":"Ven y yo te haré"},{"c":"","l":"pescador de hombres."},{"c":"","l":""},{"c":"","l":"En tus palabras echaré mis redes."},{"c":"","l":"Dejo mi barca y donde quieras iré."},{"c":"","l":"Tú me llamaste, Señor, por mi nombre"},{"c":"","l":"y sólo a Ti, Señor, Señor, te seguiré."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (137, 'Nada te turbe', '[{"c":"","l":"Nada te turbe, que nada te espante."},{"c":"","l":"Que todo se pasa, que Dios no se muda"},{"c":"","l":"Y la paciencia, que todo lo alcanza."},{"c":"","l":"Y quien a Dios tiene ya nada le falta."},{"c":"","l":""},{"c":"","l":"Sólo Dios alcanza, sí, sólo Dios, (sólo Dios)."},{"c":"","l":"Estamos hechos para Dios, para Dios, (para Dios)."},{"c":"","l":"Sólo Dios llena el vacío interior, (Interior)."},{"c":"","l":"Estamos hechos para Dios, para Dios, para Dios."},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Oración atribuida a Santa Teresa de Ávila"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (138, 'Te alabo en verdad', '[{"c":"","l":"Aún en las tormentas,"},{"c":"","l":"aun cuando arrecie el mar;"},{"c":"","l":"te alabo, te alabo en verdad."},{"c":"","l":"Aún lejos de los míos,"},{"c":"","l":"aún en mi soledad;"},{"c":"","l":"te alabo, te alabo en verdad."},{"c":"","l":""},{"c":"","l":"Pues sólo a ti te tengo,"},{"c":"","l":"pues tú eres mi heredad;"},{"c":"","l":"te alabo, te alabo en verdad."},{"c":"","l":""},{"c":"","l":"Aún sin muchas palabras,"},{"c":"","l":"aun cuando no sé alabar;"},{"c":"","l":"te alabo, te alabo en verdad"}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Martín Valverde"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (139, 'Canción del si', '[{"c":"","l":"Llamas y me ofreces con amor"},{"c":"","l":"construir un mundo mejor"},{"c":"","l":"necesitas de mi sí."},{"c":"","l":"Quieres que te siga hasta el fin"},{"c":"","l":"que comprenda que sin mí"},{"c":"","l":"muchos quedarán sin Ti."},{"c":"","l":""},{"c":"","l":"Si no solamente porque si"},{"c":"","l":"Sino porque yo junto a ti"},{"c":"","l":"Encuentro paz, soy muy feliz"},{"c":"","l":"Si, aunque no entienda digo si"},{"c":"","l":"Aunque no vea digo si"},{"c":"","l":"Tú me elegiste, siempre si"},{"c":"","l":""},{"c":"","l":"Sé que Tú no puedes esperar"},{"c":"","l":"tengo que dejar mi plan"},{"c":"","l":"tu camino vale más."},{"c":"","l":"Soy la sal que Tú quieres echar"},{"c":"","l":"luz que debe iluminar"},{"c":"","l":"me elegiste para amar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (140, 'Todo lo espero de Ti', '[{"c":"","l":"Como barro en tus manos me dejo moldear,"},{"c":"","l":"tus caricias me dan libertad."},{"c":"","l":"Con ternura me formas a tu voluntad,"},{"c":"","l":"soy el sueño que plasmarás."},{"c":"","l":""},{"c":"","l":"Por eso yo, todo lo espero de Ti."},{"c":"","l":"Abandonado en tu amor,"},{"c":"","l":"perdido en tu  mirar,"},{"c":"","l":"confiado en tus promesas,"},{"c":"","l":"quiero cantar,"},{"c":"","l":"que si tú estás,"},{"c":"","l":"no necesito nada más."},{"c":"","l":""},{"c":"","l":"Como un niño en los brazos de su mamá,"},{"c":"","l":"tú me llenas de seguridad."},{"c":"","l":"Nada temo a tu lado, me cubres con paz,"},{"c":"","l":"yo confío en tu bondad."},{"c":"","l":""},{"c":"","l":"Tu presencia desborda mi alma Señor,"},{"c":"","l":"la superas con inmensidad."},{"c":"","l":"Contemplando tu rostro en intimidad,"},{"c":"","l":"más te amo, más te quiero amar."},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Pablo Martínez"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (141, 'Hazme un instrumento de tu paz', '[{"c":"","l":"Hazme un instrumento de tu paz"},{"c":"","l":"donde haya odio, lleve yo tu amor,"},{"c":"","l":"donde haya injuria, tu perdón, Señor"},{"c":"","l":"donde haya duda, ponga fe en Ti"},{"c":"","l":""},{"c":"","l":"Maestro, ayúdame a nunca buscar"},{"c":"","l":"El ser consolado si no consolar"},{"c":"","l":"Ser entendido si no entender"},{"c":"","l":"Ser amado si no yo amar"},{"c":"","l":""},{"c":"","l":"Hazme un instrumento de tu paz"},{"c":"","l":"que lleve tu esperanza por doquier"},{"c":"","l":"donde haya oscuridad, lleve tu luz"},{"c":"","l":"donde haya pena, tu gozo, Señor"},{"c":"","l":""},{"c":"","l":"Hazme un instrumento de tu paz"},{"c":"","l":"Es perdonando que nos das perdón"},{"c":"","l":"Es dando a todos lo que Tú nos das"},{"c":"","l":"Y muriendo es que volvemos a nacer"},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Oración de San Francisco de Asís"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (142, 'Yo creo en las promesas', '[{"c":"","l":"Yo creo en las promesas de Dios ,"},{"c":"","l":"yo creo en las promesas de mi Señor."},{"c":"","l":""},{"c":"","l":"Si soy fiel en lo poco, Él me confiará más, si soy fiel en lo poco, mis pasos guiará"},{"c":"","l":""},{"c":"","l":"Yo creo en el Espíritu de Dios……"},{"c":"","l":"Yo creo en la misericordia de Dios……"},{"c":"","l":"Yo creo en el amor de Dios……"},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Daniel Poli"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (143, 'Si conocieras el don de Dios', '[{"c":"","l":"Si conocieras como te amo,"},{"c":"","l":"si conocieras como te amo"},{"c":"","l":"dejarías de vivir sin amor."},{"c":"","l":"Si conocieras como te amo,"},{"c":"","l":"si conocieras como te amo"},{"c":"","l":"dejarías de mendigar cualquier amor."},{"c":"","l":""},{"c":"","l":"Si conocieras como te amo, como te amo."},{"c":"","l":"Serias más feliz."},{"c":"","l":""},{"c":"","l":"Si conocieras como te busco,"},{"c":"","l":"si conocieras como te busco."},{"c":"","l":"Dejarías que te alcanzara mi voz."},{"c":"","l":"Si conocieras como te busco,"},{"c":"","l":"si conocieras como te busco"},{"c":"","l":"dejarías que te hablara al corazón."},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Hna Glenda"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (144, 'No hay mayor amor', '[{"c":"","l":"No hay mayor amor que dar la vida"},{"c":"","l":"No hay mayor amor, no hay mayor amor (2)"},{"c":"","l":""},{"c":"","l":"Este es mi cuerpo y mi sangre"},{"c":"","l":"todo esto es lo que soy."},{"c":"","l":"Me quedo siempre entre ustedes"},{"c":"","l":"aunque parta no me voy."},{"c":"","l":""},{"c":"","l":"No teman amigos míos"},{"c":"","l":"si algún tiempo no me ven"},{"c":"","l":"que si entre ustedes se quieren"},{"c":"","l":"me verán a mí también."},{"c":"","l":""},{"c":"","l":"El miedo no es sentimiento"},{"c":"","l":"que abriga el que cree en mí"},{"c":"","l":"recuerden estas palabras"},{"c":"","l":"Al mundo yo vencí"},{"c":"","l":""},{"c":"","l":"Si conocieras como te busco, como te busco"},{"c":"","l":"escucharías más mi voz."},{"c":"","l":""},{"c":"","l":"Si conocieras como te sueño,"},{"c":"","l":"si conocieras como te sueño."},{"c":"","l":"Me preguntarías lo que espero de ti."},{"c":"","l":"Si conocieras como te sueño,"},{"c":"","l":"si conocieras como te sueño"},{"c":"","l":"buscarías lo que he pensado para ti."},{"c":"","l":""},{"c":"","l":"Si conocieras como te sueño, como te sueño."},{"c":"","l":"Pensarías más en mí."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (145, 'Vida en abundancia', '[{"c":"","l":"Los lirios del campo y las aves del cielo"},{"c":"","l":"no se preocupan porque están en mis manos"},{"c":"","l":"Tené confianza en mí, acá estoy junto a vos."},{"c":"","l":""},{"c":"","l":"Amá lo que sos y tus circunstancias,"},{"c":"","l":"estoy con vos, con tu cruz en mi espalda."},{"c":"","l":"Todo terminará bien yo hago nuevas todas las cosas"},{"c":"","l":""},{"c":"","l":"Yo vengo a traerte Vida,"},{"c":"","l":"Vida en abundancia, en abundancia."},{"c":"","l":"Yo soy el Camino,"},{"c":"","l":"la Verdad y la Vida,"},{"c":"","l":"Vida en abundancia, en abundancia."},{"c":"","l":""},{"c":"","l":"No hice al hombre para que esté solo."},{"c":"","l":"Caminen juntos como hermanos,"},{"c":"","l":"sopórtense mutuamente ámense unos a otros"},{"c":"","l":""},{"c":"","l":"La felicidad de la Vida Eterna"},{"c":"","l":"empieza conmigo en la tierra."},{"c":"","l":"Sentite vivo, la fiesta del Reino comienza acá"},{"c":"","l":""},{"c":"","l":"Animo tus sueños y tus proyectos,"},{"c":"","l":"todas tus búsquedas y tus anhelos."},{"c":"","l":"Ya oí tu plegaria, arrojate a la esperanza"},{"c":"","l":""},{"c":"","l":"Subí a mi barca, navegá mar adentro,"},{"c":"","l":"en lo profundo está lo verdadero."},{"c":"","l":"Animate a volar, la aventura de confiar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (146, 'Siempre te amaré', '[{"c":"","l":"Te conozco desde antes que nacieras."},{"c":"","l":"Sé tú historia, conozco tus problemas."},{"c":"","l":"Vi tus llantos y tus alegrías"},{"c":"","l":"y aun así te amo."},{"c":"","l":""},{"c":"","l":"Te amo, no importa lo que hagas"},{"c":"","l":"Te amo, no importa donde vayas"},{"c":"","l":"Te amo, no importa lo que digas"},{"c":"","l":"Por siempre te amo"},{"c":"","l":"y siempre te amaré."},{"c":"","l":""},{"c":"","l":"Nunca temas siempre estaré,"},{"c":"","l":"de mi mano yo te sostendré"},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Jonatan Narváez"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (147, 'Jesús eres digno de alabar', '[{"c":"","l":"Levanto mis manos, cierro mis ojos"},{"c":"","l":"Para proclamar túNombre"},{"c":"","l":"Dios de poder"},{"c":"","l":""},{"c":"","l":"Digno de alabar, Señor"},{"c":"","l":"Gloria y majestad sean a Ti"},{"c":"","l":"Rey de la creación, por siempre, Amén!"}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Jonatan Narváez"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (148, 'Temblando de amor', '[{"c":"","l":"En tu cuerpo encuentro mi paz, Señor,"},{"c":"","l":"en Ti descansa mi alma"},{"c":"","l":"y siento la emoción, Amado Mío"},{"c":"","l":"que tiemblo por Ti"},{"c":"","l":""},{"c":"","l":"Estoy temblando de amor, por Ti Señor"},{"c":"","l":"estoy temblando al sentirte en mi interior"},{"c":"","l":"estoy temblando de amor, y el corazón"},{"c":"","l":"se me derrite por Ti,"},{"c":"","l":"Se me derrite por Ti,"},{"c":"","l":"se me derrite por ti, Señor"},{"c":"","l":""},{"c":"","l":"Van tu Cuerpo y Sangre directo al corazón"},{"c":"","l":"te refugias en mi"},{"c":"","l":"y te siento tan vivo en mi interior"},{"c":"","l":"que tiemblo por Ti"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (149, 'Jesús, estoy aquí', '[{"c":"","l":"Jesús estoy aquí,"},{"c":"","l":"Jesús qué esperas de mi"},{"c":"","l":"mis manos están vacías"},{"c":"","l":"que puedo ofrecerte."},{"c":"","l":"Solo sé que quiero ser diferente"},{"c":"","l":""},{"c":"","l":"Jesús estoy aquí,"},{"c":"","l":"Jesús qué esperas de mi"},{"c":"","l":"mis ojos temen al mirarte,"},{"c":"","l":"quisiera poder enfrentarte"},{"c":"","l":""},{"c":"","l":"Amar como tu amas"},{"c":"","l":"sentir como tú sientes"},{"c":"","l":"mirar a través de tus ojos, Jesús"},{"c":"","l":"Contigo mi camino es difícil"},{"c":"","l":"te exiges abrir un nuevo horizonte"},{"c":"","l":"en la soledad de mi noche, Jesús"},{"c":"","l":""},{"c":"","l":"No, no puedo abandonarte,"},{"c":"","l":"Jesús en mi penetraste"},{"c":"","l":"me habitaste, triunfaste"},{"c":"","l":"y hoy vives en mi"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (150, 'No pongas tu fe', '[{"c":"","l":"No pongas tu fe, en nadie más que en Él"},{"c":"","l":"no pongas tu fe, en nadie más que en Él"},{"c":"","l":"no pongas tu fe, en nadie más"},{"c":"","l":"no pongas tu fe, en nadie más"},{"c":"","l":"no pongas tu fe, en nadie más que en Él."},{"c":"","l":""},{"c":"","l":"Porque solo Él, te puede salvar"},{"c":"","l":"porque solo Él, te puede salvar"},{"c":"","l":"no pongas tu fe, en nadie más"},{"c":"","l":"no pongas tu fe, en nadie más"},{"c":"","l":"no pongas tu fe, en nadie más que en Él."},{"c":"","l":""},{"c":"","l":"No pongas tu vida en nadie más que enÉl"},{"c":"","l":"no pongas tu vida, en nadie más que en Él"},{"c":"","l":"no pongas tu vida, en nadie más"},{"c":"","l":"no pongas tu vida, en nadie más"},{"c":"","l":"no pongas tu vida, en nadie más que en Él"},{"c":"","l":""},{"c":"","l":"Porque solo Él, te puede amar así"},{"c":"","l":"porque solo Él, te puede amar así"},{"c":"","l":"no pongas tu vida, en nadie más"},{"c":"","l":"no pongas tu vida, en nadie más, no"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (151, 'Hasta la locura', '[{"c":"","l":"Me puede faltar todo en la vida,"},{"c":"","l":"me puede faltar hasta la vida,"},{"c":"","l":"pero nunca quiero que me falte"},{"c":"","l":"el deseo de amarte hasta el final..."},{"c":"","l":""},{"c":"","l":"Hasta la locura te amo, Señor,"},{"c":"","l":"ya no quedan dudas en mi corazón"},{"c":"","l":"de que te amo, de que te amo, Señor."},{"c":"","l":""},{"c":"","l":"Quiero amarte hasta el extremo,"},{"c":"","l":"sin reservas darme por entero."},{"c":"","l":"Como los que se han enamorado,"},{"c":"","l":"yo te canto, mi amado, hasta el final..."},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=kC2UNjs3xHE&list=RDkC2UNjs3xHE","autor":"Pablo Martínez"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (152, 'Sonríe que Jesús te ama', '[{"c":"","l":"Sonríe que Jesús te ama"},{"c":"","l":"Sonríe que Jesús te quiere"},{"c":"","l":"Sonríe que Jesús te da la vida"},{"c":"","l":"Sonríele a Jesús de Nazareth (2)"},{"c":"","l":""},{"c":"","l":"Canta, canta para El"},{"c":"","l":"porque el Señor ya te salvó. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (153, 'Necesito de tu amor', '[{"c":"","l":"Necesito estar más cerca"},{"c":"","l":"cerca de tu compasión."},{"c":"","l":"¡Tengo que jugarme todo"},{"c":"","l":"sé que eres el Señor!"},{"c":"","l":"Todo, todo lo he perdido"},{"c":"","l":"y mi pena sigue abierta"},{"c":"","l":"pero espero un signo, y mi fe está alerta."},{"c":"","l":""},{"c":"","l":"Sentirás al lado tuyo"},{"c":"","l":"que hay un pobre que se acerca"},{"c":"","l":"muy pequeño, y que te toca"},{"c":"","l":"con los ojos en la tierra"},{"c":"","l":"pero lleno de esperanza"},{"c":"","l":"de esperanza y decisión"},{"c":"","l":"de alcanzarte y alcanzar tu corazón."},{"c":"","l":""},{"c":"","l":"¡NECESITO DE TU AMOR! (2)"},{"c":"","l":""},{"c":"","l":"Toda mi fragilidad"},{"c":"","l":"y mis años lastimados"},{"c":"","l":"esta historia que no cesa"},{"c":"","l":"de sangrar y de mancharnos"},{"c":"","l":"esta herida que no cierra"},{"c":"","l":"es herida en cuerpo y alma"},{"c":"","l":"tocará tu cuerpo santo y tendrá calma."},{"c":"","l":""},{"c":"","l":"Porque creo que sos Vos"},{"c":"","l":"nuestra fuente escondida"},{"c":"","l":"y alcanzarte es alcanzar"},{"c":"","l":"como el centro de la vida."},{"c":"","l":"Toco el borde de tu alma"},{"c":"","l":"y es un nuevo nacimiento"},{"c":"","l":"¡Y se está curando el centro de mi centro!"},{"c":"","l":""},{"c":"","l":"¡NECESITO DE TU AMOR! (2)"},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Eduardo Meana"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (154, 'Quiero cantar', '[{"c":"","l":"Quiero cantar una linda canción"},{"c":"","l":"De aquel que mi vida cambió"},{"c":"","l":"Quiero cantar una linda canción"},{"c":"","l":"De aquel que me transformó"},{"c":"","l":""},{"c":"","l":"Es mi amigo Jesús, Es mi amigo más fiel"},{"c":"","l":"Él es Dios, Él es Rey, Es amor y verdad."},{"c":"","l":"Sólo en Él encontré, Esa paz que busqué"},{"c":"","l":"Sólo en ÉlEncontré, la felicidad"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (155, 'Oh cuan hermoso', '[{"c":"","l":"¡Oh, cuán hermoso!"},{"c":"","l":"es dar gracias al Señor. (2)"},{"c":"","l":"¡Oh, cuán hermoso!"},{"c":"","l":"es alabar al Señor. (2)"},{"c":"","l":"Bueno es cantarte a Ti."},{"c":"","l":"Tu nombre glorificar, ¡oh, Altísimo! (2)"},{"c":"","l":"De mañana proclamar"},{"c":"","l":"Tu amor y fidelidad, mi delicia es.(2)"},{"c":"","l":"Bueno es cantarte a Ti."},{"c":"","l":"Tu nombre glorificar, ¡oh, Altísimo! (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (156, 'Hay una luz', '[{"c":"","l":"Hay una luz, delante de ti"},{"c":"","l":"que espera por ti, que espera por mí."},{"c":"","l":"Hay una luz, la luz de Jesús"},{"c":"","l":"que espera por ti, que espera por mí."},{"c":"","l":""},{"c":"","l":"Te va a llenar de paz, te va a llenar de amor"},{"c":"","l":"Es esa luz, la luz de Jesús"},{"c":"","l":"Ya no habrá Soledad, tu vida va a cambiar"},{"c":"","l":"Es esa luz, la luz de Jesús"},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=8HqLqiytGno&list=RD8HqLqiytGno","autor":"Rafael Moreno"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (157, 'Bienvenida tu misericordia', '[{"c":"","l":"Bienvenida tu misericordia"},{"c":"","l":"Bienvenida tu consolación"},{"c":"","l":"Bienvenida tu dulce presencia."},{"c":"","l":"Bienvenido seas Señor."},{"c":"","l":""},{"c":"","l":"Tú no te tardarás"},{"c":"","l":"Tú nos defenderás"},{"c":"","l":"Tú nuestras lágrimas enjugarás"},{"c":"","l":"Tú nos sorprenderás"},{"c":"","l":"Tú buen refugió serás"},{"c":"","l":"Tú nuestras lágrimas enjugarás."},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=idQtFf7m4xw&list=RDidQtFf7m4xw","autor":"Pablo Martínez"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (158, 'La tierra canta', '[{"c":"","l":"Se abren los cielos"},{"c":"","l":"se escucha un sonido celestial"},{"c":"","l":"unido a la voces"},{"c":"","l":"de tu pueblo que te quiere adorar"},{"c":"","l":""},{"c":"","l":"El espíritu de Dios"},{"c":"","l":"se mueve libre en este lugar"},{"c":"","l":"el Padre alegre está"},{"c":"","l":"al ver la novia unida y adorar"},{"c":"","l":"se escucha"},{"c":"","l":""},{"c":"","l":"La tierra canta, el cielo adora"},{"c":"","l":"Y todos gritan, que Tu eres Santo"},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=BuBcOc_PiMw&list=RDBuBcOc_PiMw&start_radio=1","autor":"Barak"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (159, 'Tantum Ergo', '[{"c":"","l":"Tan sublime Sacramento"},{"c":"","l":"adoremos enverdad"},{"c":"","l":"que los ritos ya pasados"},{"c":"","l":"den al nuevo su lugar."},{"c":"","l":"Que la fe preste a los ojos"},{"c":"","l":"la visión con quemirar."},{"c":"","l":"Bendición y gloria eterna"},{"c":"","l":"a Dios Padrecreador"},{"c":"","l":"a su Hijo Jesucristo,"},{"c":"","l":"y al Espíritu de Amor"},{"c":"","l":"demos siempre igual gloria,"},{"c":"","l":"alabanza yhonor. Amén."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (160, 'Cantemos al amor de los amores', '[{"c":"   C         G            Am","l":"Cantemos al amor de los amores"},{"c":"   F          Em","l":"cantemos al Señor"},{"c":"C       A7 Dm","l":"Dios está aquí"},{"c":"    C        G    Am Em","l":"¡Venid adoradores adoremos"},{"c":"  B7        Em G","l":"a Cristo Redentor!"},{"c":"","l":""},{"c":" C        A7      Dm","l":"¡Gloria a Cristo Jesús!"},{"c":"G         D           Am        G","l":"Cielos y tierra, bendecid al Señor"},{"c":"  F       G      C    E         Am","l":"Honor y gloria a Ti, Rey de la Gloria"},{"c":"Am        G        C     Dm   G    C","l":"Amor por siempre a Ti, ¡Dios del amor!"},{"c":"","l":""},{"c":"","l":"Unamos nuestra voz a los cantares"},{"c":"","l":"del coro celestial"},{"c":"","l":"Dios está aquí"},{"c":"","l":"al Dios de los altares alabemos"},{"c":"","l":"con gozo angelical."},{"c":"","l":""},{"c":"","l":"Cantemos al amor de los amores"},{"c":"","l":"cantemos sin cesar."},{"c":"","l":"Dios está aquí."},{"c":"","l":"Venid, adoradores, adoremos"},{"c":"","l":"a Cristo en el altar."},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=qmCGbcN6zjM&list=RDqmCGbcN6zjM&start_radio=1","autor":"Sagastizábal"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (161, 'Alabado sea el Santísimo', '[{"c":"","l":"Alabado sea el Santísimo"},{"c":"","l":"Sacramento del altar"},{"c":"","l":"y la Virgen concebida sin pecado original (2)"},{"c":"","l":""},{"c":"","l":"El manjar más regalado"},{"c":"","l":"de este suelo terrenal"},{"c":"","l":"es Jesús sacramentado, Dios eterno einmortal (2)"},{"c":"","l":""},{"c":"","l":"Celebremos con fe viva"},{"c":"","l":"este pan angelical"},{"c":"","l":"y la Virgen concebida sin pecado original (2)"},{"c":"","l":""},{"c":"","l":"Es el Dios que da la vida"},{"c":"","l":"y nació en un portal"},{"c":"","l":"de la Virgen concebida sin pecado original(2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (162, 'Te adoramos Hostia divina', '[{"c":"","l":"Te adoramos, Hostia divina"},{"c":"","l":"te adoramos, Hostia de amor."},{"c":"","l":"Tú del ángel eres delicia"},{"c":"","l":"Tú del hombre eres honor."},{"c":"","l":""},{"c":"","l":"Te adoramos, hostia divina"},{"c":"","l":"Te adoramos hostia de amor"},{"c":"","l":""},{"c":"","l":"Te adoramos, Hostia divina"},{"c":"","l":"te adoramos, Hostia de amor."},{"c":"","l":"Tú del fuerte eres dulzura"},{"c":"","l":"Tú del débil eres vigor."},{"c":"","l":""},{"c":"","l":"Te adoramos, Hostia divina"},{"c":"","l":"te adoramos, Hostia de amor."},{"c":"","l":"En la vida eres consuelo"},{"c":"","l":"en la muerte dulce solaz."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (163, 'En Espíritu y en verdad', '[{"c":"","l":"Señor yo quiero ser,"},{"c":"","l":"un verdadero adorador"},{"c":"","l":"en espíritu y en verdad"},{"c":"","l":"yo te quiero adorar"},{"c":"","l":""},{"c":"","l":"Dame un corazón sencillo."},{"c":"","l":"Dame un  corazón sencillo."},{"c":"","l":"Dame un corazón sencillo. Señor,"},{"c":"","l":"para entrar en tu presencia"},{"c":"","l":""},{"c":"","l":"Quiero ser agradecido..."},{"c":"","l":"Quiero dejarlo todo..."},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"","autor":"Daniel Poli"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (164, 'Gloria al Rey', '[{"c":"","l":"Gloria al Rey, Rey Santo y justo."},{"c":"","l":"Gloria al Maestro,"},{"c":"","l":"Que en su trono está."},{"c":"","l":"Digno Maestro, digno de alabanza"},{"c":"","l":"Santo, santo, gloria y honra al Rey."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (165, 'Ya no eres pan y vino', '[{"c":"","l":"Ya no eres pan y vino"},{"c":"","l":"ahora que eres cuerpo y sangre, vives en mí"},{"c":"","l":"de rodillas yo caigo al contemplar tu bondad"},{"c":"","l":"como no te voy a adorar"},{"c":"","l":""},{"c":"","l":"Mientras te pierdes en mis labios"},{"c":"","l":"tu gracia va inundando todo mi corazón"},{"c":"","l":"por esa paz que me llena de alegría mi ser"},{"c":"","l":"como no te voy a adorar"},{"c":"","l":""},{"c":"","l":"Señor Jesús, mi salvador"},{"c":"","l":"Amor eterno, amor divino"},{"c":"","l":"Ya no falta, lo tengo todo, te tengo a Ti"},{"c":"","l":""},{"c":"","l":"Dueño y Rey del universo"},{"c":"","l":"como puede ser posible que busques mi amor"},{"c":"","l":"Tú tan grande y yo pequeño y te fijas en mi"},{"c":"","l":"como no te voy a adorar"},{"c":"","l":"De rodillas yo te pido"},{"c":"","l":"que el día cuando tú me llames sea como hoy"},{"c":"","l":"para mirarte a los ojos y poderte decir"},{"c":"","l":"que como no te voy a adorar"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (166, 'Jesús eucaristía', '[{"c":"","l":"Aunque pase por las turbias aguas"},{"c":"","l":"y me sienta débil o en soledad"},{"c":"","l":"a tu lado yo tengo confianza"},{"c":"","l":"Tu firmeza me acompañará."},{"c":"","l":""},{"c":"","l":"Yo creo en Ti, Jesús eucaristía"},{"c":"","l":"La inmensidad presente en el altar"},{"c":"","l":"Tu amor por mí me vuelve a la alegría"},{"c":"","l":"De mano de María, aquí estoy para adorar"},{"c":"","l":""},{"c":"","l":"No hace falta que diga palabras / conoces mis pensamientos. / Ante ti se desnuda mi alma / me rindo a ti Dios eterno."},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=k1sT9SarM24&list=RDk1sT9SarM24","autor":"Mayra A Barajas"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (167, 'Llévame a tus pies', '[{"c":"","l":"Llévame, a tus pies, en adoración"},{"c":"","l":"sacrificio de alabanza"},{"c":"","l":"Jesús, te ofrezco hoy"},{"c":"","l":"Con todo mi ser te adoro"},{"c":"","l":"Con todo mi ser te alabo"},{"c":"","l":"Con todo mi ser te doy mi amor (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (168, 'Alábenlo cielos y tierra', '[{"c":"","l":"Esta es la luz, que brilla eternamente"},{"c":"","l":"este es Jesús, quien ha resucitado"},{"c":"","l":"es el poder, el que venció a la muerte"},{"c":"","l":"y nos salvó."},{"c":"","l":""},{"c":"","l":"Alábenlo, cielos y tierra"},{"c":"","l":"Adórenlo, luz y tinieblas"},{"c":"","l":"Un canto nuevo, entonen al Señor"},{"c":"","l":"Dios es amor (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (169, 'En ti confía mi corazón', '[{"c":"","l":"En Ti confía mi corazón,"},{"c":"","l":"en Ti, reposa mi alma"},{"c":"","l":"mi ser, descansa en Ti,"},{"c":"","l":"puedo ser feliz."},{"c":"","l":""},{"c":"","l":"Porque sé que estás obrando,"},{"c":"","l":"tu perfecta Voluntad"},{"c":"","l":"en mi vida estás obrando,"},{"c":"","l":"tu perfecta Voluntad."},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=4iL18zeir_4&list=RD4iL18zeir_4","autor":"Marcos Barrientos"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (170, 'Cristo reina', '[{"c":"","l":"Mi corazón quiere alabar, alabarte"},{"c":"","l":"mi corazón quiere adorar, adorarte (2)"},{"c":"","l":""},{"c":"","l":"*Cristo reina, Cristo reina, Cristo reina"},{"c":"","l":"Con poder*"},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=5Sj83Y0-_a8&list=RD5Sj83Y0-_a8","autor":"AthenasVenica"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (171, 'Eres Santo', '[{"c":"","l":"Cuando estoy, a tus pies"},{"c":"","l":"puedo ver tu grandeza y mi pequeñez"},{"c":"","l":"cuando tu Espíritu Santo"},{"c":"","l":"infunde tu amor, me quema por dentro."},{"c":"","l":""},{"c":"","l":"Solo quiero, alabarte"},{"c":"","l":"y darte gracias Señor"},{"c":"","l":"levantando, yo mis brazos"},{"c":"","l":"te entrego mi adoración."},{"c":"","l":""},{"c":"","l":"Eres Santo Señor, eres Santo, Santo"},{"c":"","l":"Te doy Gloria Señor, te doy Gloria, Gloria"},{"c":"","l":""},{"c":"","l":"Rey de Reyes, Señor de Señores"},{"c":"","l":"toda mi vida, te pertenece (2)"},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=gkQH4XhaD0o&list=RDgkQH4XhaD0o","autor":"AthenasVenica"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (172, 'Ven Señor Jesús', '[{"c":"","l":"Ven Señor Jesús porque sin ti ya no hay paisaje"},{"c":"","l":"Ven Señor Jesús porque sin ti no hay melodías"},{"c":"","l":"Ven Señor Jesús porque sin ti no encuentro paz en nada"},{"c":"","l":"sin ti mis ojos no brillan"},{"c":"","l":"la vida es poca cosa sin ti"},{"c":"","l":"sin ti, sin ti, sin ti,"},{"c":"","l":"la vida es poca cosa"},{"c":"","l":""},{"c":"","l":"Ven Señor Jesús, ven pronto a mi vida."},{"c":"","l":"Ven pronto Señor, ven pronto"},{"c":"","l":""},{"c":"","l":"porque sin ti"},{"c":"","l":"yo no quiero la vida"},{"c":"","l":"ya no canto con alma"},{"c":"","l":"ya mis manos no sirven"},{"c":"","l":"ya no escucho latidos, ya no abrazo con fuerza"},{"c":"","l":"micorazón no se ensancha"},{"c":"","l":"mi sonrisa no es plena"},{"c":"","l":"y todo sin ti"},{"c":"","l":"nada vale la pena"},{"c":"","l":"porque sin ti ya no me llena nada"},{"c":"","l":""},{"c":"","l":"porque sin ti"},{"c":"","l":"todo suena vacío"},{"c":"","l":"sin ti todo me deja tristeza"},{"c":"","l":"porque sin ti yo no respiro hondo"},{"c":"","l":"porque sin ti todo me cansa"},{"c":"","l":"porque sin ti me falta todo"},{"c":"","l":"y me sobra todo"},{"c":"","l":"todo sin ti"},{"c":"","l":""},{"c":"","l":"Ven Señor Jesús. Ven pronto a mi vida"},{"c":"","l":"Ven pronto Señor, ven pronto"},{"c":"","l":""},{"c":"","l":"porque sin ti"},{"c":"","l":"no me importa mi hermano"},{"c":"","l":"no me importa el que sufre"},{"c":"","l":"porque sin ti"},{"c":"","l":"mi corazón es de piedra"},{"c":"","l":"a quien todo resbala"},{"c":"","l":"acostumbrada a los pobres"},{"c":"","l":"acomodada a su casa"},{"c":"","l":"sin jugarse la vida"},{"c":"","l":"sin gastarla por nada"},{"c":"","l":"sin gastarla por nada"},{"c":"","l":"Ven Señor Jesús ven pronto a mi vida"},{"c":"","l":"ven pronto Señor ven pronto"},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=THWtg46yyPw&list=RDTHWtg46yyPw","autor":"Hermana Glenda"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (173, 'Yo te busco', '[{"c":"","l":"Yo te busco, yo te busco"},{"c":"","l":"Recibe mi adoración"},{"c":"","l":"Yo te busco, yo te busco"},{"c":"","l":"Con fuego en, mi corazón"},{"c":"","l":""},{"c":"","l":"Te anhelo, te necesito"},{"c":"","l":"Te amo, más que a mi ser."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (174, 'Vive Jesús', '[{"c":"","l":"Vive Jesús, el Señor."},{"c":"","l":"Vive Jesús, el Señor (bis)"},{"c":"","l":""},{"c":"","l":"*&Eacute;l vive, vive."},{"c":"","l":"&Eacute;l vive, vive."},{"c":"","l":"Vive Jesús, el Señor.* (bis)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (175, 'Toma mi mano', '[{"c":"","l":"Dame tu mano, Toma mi mano"},{"c":"","l":"Dame un abrazo, Jesús (2)"},{"c":"","l":""},{"c":"","l":"Guíame, Tú tienes la dirección"},{"c":"","l":"Tómame, Te entrego todo el control"},{"c":"","l":"Y a donde voy"},{"c":"","l":"Y es fácil si tú me llevas de tu mano"},{"c":"","l":""},{"c":"","l":"Guíame, Tú tienes la dirección"},{"c":"","l":"Tómame, Conoces mi corazón"},{"c":"","l":"Y lo que soy"},{"c":"","l":"Y es fácil si tú me llevas de tu mano"},{"c":"","l":""},{"c":"","l":"Toma mi vida, Hazla de nuevo"},{"c":"","l":"Tu mi alfarero, Jesús (2)"},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=X1CRHbMyapU&list=RDX1CRHbMyapU","autor":"Alfareros"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (176, 'Dios está aquí', '[{"c":"","l":"Como sientes el aire que respiras,"},{"c":"","l":"Como sientes el canto de un gorrión,"},{"c":"","l":"Si lo sientes, a tu lado está el Señor,"},{"c":"","l":"Si lo sientes, canta esta canción."},{"c":"","l":""},{"c":"","l":"Dios está aquí,"},{"c":"","l":"Tan cierto como el aire que respiro"},{"c":"","l":"Tan cierto como la mañana se levanta"},{"c":"","l":"Tan cierto como que le hablo"},{"c":"","l":"y me puede oír"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (177, 'Tu fidelidad', '[{"c":"","l":"Tu fidelidad es grande"},{"c":"","l":"Tu misericordia, incomparable es."},{"c":"","l":"Nadie como tú, bendito Dios"},{"c":"","l":"Grande es tu fidelidad."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (178, 'En tu presencia', '[{"c":"","l":"Es tuyo este momento de adoración,"},{"c":"","l":"no hay palabra alguna para expresar."},{"c":"","l":"El brillo de esa luz que hay en tu mirar,"},{"c":"","l":"encuentro mi abrigo mi lugar."},{"c":"","l":""},{"c":"","l":"Y cuando estamos juntos te dejas sentir,"},{"c":"","l":"pasando entre nosotros"},{"c":"","l":"para  bendecir."},{"c":"","l":"Y tocas con ternura dando tu perdón, a todo el que te abre el corazón."},{"c":"","l":""},{"c":"","l":"Mis manos se elevan,"},{"c":"","l":"con mi voz te adoro,"},{"c":"","l":"y mi ser se alegra"},{"c":"","l":"cuando estoy, aquí en tu presencia,"},{"c":"","l":"Señor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (179, 'Hay una fuente', '[{"c":"","l":"Hay una fuente en mí, que está brotando,"},{"c":"","l":"que está fluyendo dentro de mí."},{"c":"","l":""},{"c":"","l":"Es un río de alabanza"},{"c":"","l":"y de adoración"},{"c":"","l":"Dirigido hacia Ti, Señor Jesús;"},{"c":"","l":"recíbelo"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (180, 'Señor aquí estoy', '[{"c":"","l":"Señor, aquí estoy"},{"c":"","l":"otra vez postrado a tus pies"},{"c":"","l":"para entregarte"},{"c":"","l":"toda mi vida lo que tengo y lo que soy"},{"c":"","l":"lo pongo en tus manos"},{"c":"","l":"porque no hay lugar mejor"},{"c":"","l":"para mí."},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=jjM30Vt5xT8&list=RDjjM30Vt5xT8","autor":"Daniel Poli"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (181, 'Quiero levantar mis manos', '[{"c":"","l":"Quiero levantar mis manos,"},{"c":"","l":"quiero levantar mi voz."},{"c":"","l":"Ofreciendo a ti mi vida"},{"c":"","l":"en santidad y amor."},{"c":"","l":"Padre sólo a Ti te ofrezco,"},{"c":"","l":"mi vida y mi corazón"},{"c":"","l":"y me postro en tu presencia"},{"c":"","l":"en adoración."},{"c":"","l":""},{"c":"","l":"Hijo de Dios, recibe hoy"},{"c":"","l":"toda la gloria, la honra y honor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (182, 'Sigue aun confiando', '[{"c":"","l":"Sigue aun confiando, me dice Jesús, no te desalientes sí té falta luz."},{"c":"","l":"Para que amanezca"},{"c":"","l":"hay un tiempo que esperar,"},{"c":"","l":"que pase la noche y nada más."},{"c":"","l":""},{"c":"","l":"Siempre soy el mismo, no debes dudar,"},{"c":"","l":"Yo soy el que calma toda tempestad. Si estás afanoso, no te dejes arrastrar, ven a Mí, descarga tu ansiedad."},{"c":"","l":""},{"c":"","l":"Por qué no miras lo que hice"},{"c":"","l":"allá en la cruz,"},{"c":"","l":"cuando hasta el cielo para mí se oscureció."},{"c":"","l":"Dije a mi padre: hágase tu voluntad,"},{"c":"","l":"y amaneció."},{"c":"","l":""},{"c":"","l":"Tienes que esforzarte y ser valiente aquí,"},{"c":"","l":"que siempre a tu lado Yo estaré hasta el fin."},{"c":"","l":"Tengo que probarte sólo por la adversidad,"},{"c":"","l":"éste es el camino a mi ciudad."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (183, 'Cuan bello es el Señor', '[{"c":"","l":"Cuan bello es el Señor,"},{"c":"","l":"cuan hermoso es el Señor."},{"c":"","l":"Cuan bello es el Señor,"},{"c":"","l":"hoy le quiero adorar."},{"c":"","l":""},{"c":"","l":"La belleza de mi Señor, nunca se agotará,"},{"c":"","l":"la hermosura de mi Señor, siempre permanecerá."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (184, 'Un amor', '[{"c":"","l":"Un amor que siempre está a tu lado,"},{"c":"","l":"y que no te exige nunca nada."},{"c":"","l":"Ese es el amor de mi Dios"},{"c":"","l":""},{"c":"","l":"*Un amor que va de puerta en puerta"},{"c":"","l":"que bajo sonrisas él te espera."},{"c":"","l":"Un amor que siempre está esperando,"},{"c":"","l":"sin importar quién es ni hasta cuándo.*"},{"c":"","l":""},{"c":"","l":"Un amor que sufre cuando sufres,"},{"c":"","l":"un amor que ríe cuando ríes."},{"c":"","l":"Ese es el amor de mi Dios"},{"c":"","l":""},{"c":"","l":"Un amor que vive en el silencio,"},{"c":"","l":"un amor tan suave como el viento."},{"c":"","l":"Ese es el amor de mi Dios"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (185, 'Yo el Señor', '[{"c":"","l":"Yo el Señor, del cielo y del mar"},{"c":"","l":"he escuchado a mi pueblo llorar."},{"c":"","l":"A todo aquel que vive en el pecado."},{"c":"","l":"Mi mano salvará."},{"c":"","l":""},{"c":"","l":"Yo que hice las estrellas brillar"},{"c":"","l":"Yo haré tus tinieblas borrar"},{"c":"","l":"Pero ¿quién mi luz le llevará?"},{"c":"","l":"¿A quién he de enviar?"},{"c":"","l":""},{"c":"","l":"Aquí estoy, Señor,"},{"c":"","l":"Dime si soy yo Señor."},{"c":"","l":"He escuchado, llamándome tu voz."},{"c":"","l":"Yo iré Señor, si me guías"},{"c":"","l":"Guardaré, a los tuyos en mi corazón."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (186, 'Al estar aquí', '[{"c":"","l":"Al estar en la presencia"},{"c":"","l":"de tu divinidad"},{"c":"","l":"y al contemplar la hermosura"},{"c":"","l":"de tu santidad,"},{"c":"","l":"mi espíritu se alegra"},{"c":"","l":"en tu majestad."},{"c":"","l":"Te adoro a Ti te adoro a Ti."},{"c":"","l":""},{"c":"","l":"Cuando veo la grandeza"},{"c":"","l":"de tu dulce amor"},{"c":"","l":"y compruebo la pureza"},{"c":"","l":"de tu corazón,"},{"c":"","l":"mi espíritu se alegra en tu majestad."},{"c":"","l":"Te adoro a ti ."},{"c":"","l":""},{"c":"","l":"Al estar aquí, delante de ti,"},{"c":"","l":"te adoraré."},{"c":"","l":"Postrado ante ti"},{"c":"","l":"mi corazón te adora, oh Dios."},{"c":"","l":"Y siempre quiero estar para adorar"},{"c":"","l":"Y contemplar tu santidad."},{"c":"","l":"Te adoro a ti, Señor, te adoro a ti."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (187, 'Tú estás aquí', '[{"c":"","l":"Aunque mis ojos no te puedan ver"},{"c":"","l":"te puedo sentir, sé que estás aquí."},{"c":"","l":"Aunque mis manos no puedan tocar"},{"c":"","l":"tu rostro, Señor, sé que estás aquí."},{"c":"","l":""},{"c":"","l":"Mi corazón puede sentir tu presencia,"},{"c":"","l":"Tú estás aquí, Tú estás aquí."},{"c":"","l":"Puedo sentir, tu majestad,"},{"c":"","l":"Tú estás aquí, Tú estás aquí."},{"c":"","l":""},{"c":"","l":"Mi corazón puede mirar tu hermosura,"},{"c":"","l":"Tú estás aquí, Tú estás aquí."},{"c":"","l":"Puedo sentir tu gran amor,"},{"c":"","l":"Tú estás aquí, Tú estás aquí."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (188, 'Tengo un perfume', '[{"c":"","l":"Tengo un perfume que,"},{"c":"","l":"solo es para Ti"},{"c":"","l":"Es mi alabanza es mi adoración."},{"c":"","l":""},{"c":"","l":"No puedo más resistir este amor,"},{"c":"","l":"que está dentro de mi corazón."},{"c":"","l":"Recibe mi adoración"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (189, 'Enciende una luz', '[{"c":"","l":"Enciende una luz, déjala brillar,"},{"c":"","l":"la luz de Jesús,"},{"c":"","l":"que brille en todo lugar."},{"c":"","l":"No la puedes esconder, no la puedes callar,"},{"c":"","l":"ante tal necesidad,"},{"c":"","l":"enciende una luz en la oscuridad."},{"c":"","l":""},{"c":"","l":"¿Cómo pues invocaran,"},{"c":"","l":"a aquel en el cual no han creído?"},{"c":"","l":""},{"c":"","l":"¿Y cómo creerán"},{"c":"","l":"en aquel de quien no han oído?"},{"c":"","l":"¿Y cómo oirán si nadie les predica?"},{"c":"","l":"Hermosos son los pies"},{"c":"","l":"de los que anuncian la paz."},{"c":"","l":"Las buenas nuevas de Jesús."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (190, 'Mi lámpara encendida', '[{"c":"","l":"Señor aquí tienes,"},{"c":"","l":"mi lámpara encendida,"},{"c":"","l":"enséñame a llevar tu luz"},{"c":"","l":"por toda mi vida."},{"c":"","l":"Para que cuando vengas"},{"c":"","l":"a mi puerta a golpear,"},{"c":"","l":"yo pueda tu rostro contemplar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (191, 'Siento tu amor', '[{"c":"","l":"Siento Tu amor que viene sobre mi"},{"c":"","l":"Siento que una nube desciende"},{"c":"","l":""},{"c":"","l":"Llévame a Tu hogar, arriba."},{"c":"","l":"Que mi lámpara este siempreencendida."},{"c":"","l":"Quiero adorarte, bendecirte, Señor"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (192, 'Rindo mi corazón', '[{"c":"","l":"Rindo mi corazón"},{"c":"","l":"sobre tu altar Señor, rindo mi vida."},{"c":"","l":"Sin nada que ocultar,"},{"c":"","l":"sin nada más que dar rindo mi vida."},{"c":"","l":""},{"c":"","l":"Rasgo mi corazón"},{"c":"","l":"y me acerco a tu presencia"},{"c":"","l":"ruego por tu perdón y tu amor."},{"c":"","l":"Vuelve tu rostro a mi"},{"c":"","l":"muéstrame sublime gracia"},{"c":"","l":"rindo hoy mi corazón"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (193, 'Tengo hambre de ti', '[{"c":"","l":"Por un momento en tu presencia"},{"c":"","l":"por un instante de tu amor."},{"c":"","l":"Por un destello de tu gloria"},{"c":"","l":"por un minuto nada más."},{"c":"","l":"Todo daría, no importaría,"},{"c":"","l":"lo que tenga que pasar"},{"c":"","l":"o que tenga que esperar"},{"c":"","l":""},{"c":"","l":"Tengo hambre de ti, de tu presencia,"},{"c":"","l":"de tu fragancia de tu poder."},{"c":"","l":"Hambre que duele, que debilita"},{"c":"","l":"que desespera, por Ti."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (194, 'Tu amor por mi', '[{"c":"","l":"Tu amor por mí,"},{"c":"","l":"es más dulce que la miel"},{"c":"","l":"y tu misericordia es nueva cada día."},{"c":"","l":""},{"c":"","l":"Es por eso que te alabo,"},{"c":"","l":"es por eso que te sirvo,"},{"c":"","l":"es por eso que te doy todo mi amor"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (195, 'Digno eres de gloria', '[{"c":"","l":"Digno eres de gloria, y alabanzas."},{"c":"","l":"Levantamos nuestras manos."},{"c":"","l":"Te exaltamos oh Señor."},{"c":"","l":""},{"c":"","l":"Grande eres tú, maravillas haces tú,"},{"c":"","l":"no hay otro como tú,"},{"c":"","l":"no hay otro como tú."},{"c":"","l":"Maravillas haces tú,"},{"c":"","l":"no hay otro como tú,"},{"c":"","l":"no hay otro como tú."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (196, 'Más(Pablo Martínez)', '[{"c":"","l":"No temas hijo mío, estoy aquí,"},{"c":"","l":"junto a ti pequeño,"},{"c":"","l":"en mis brazos te llevo."},{"c":"","l":"Si miras en mis manos,"},{"c":"","l":"verás ahí, tu nombre así grabado,"},{"c":"","l":"en la palma tatuado."},{"c":"","l":""},{"c":"","l":"Más de lo que puedas pensar,"},{"c":"","l":"te amo eso y más,"},{"c":"","l":"de lo que logres imaginar."},{"c":"","l":"Busco me des un lugar,"},{"c":"","l":"para que pueda morar"},{"c":"","l":"y tú mi amor probar."},{"c":"","l":""},{"c":"","l":"Te llamo por tu nombre,"},{"c":"","l":"sé más de ti que tú de mí, precioso"},{"c":"","l":"eres a mis ojos."},{"c":"","l":"Por ti muevo montañas"},{"c":"","l":"y se estremecen mis entrañas si pienso"},{"c":"","l":"dejar de quererte."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (197, 'Tus caminos son una locura(Pablo Martínez)', '[{"c":"","l":"Permites que estremezca todo mi ser."},{"c":"","l":"En los momentos culmines pregunto"},{"c":"","l":"“por qué”."},{"c":"","l":"Mi humanidad, verás, resiste,"},{"c":"","l":"aunque Tú más allá mis límites estás."},{"c":"","l":""},{"c":"","l":"Cuestiono tan solo porque mi debilidad"},{"c":"","l":"requiere una respuesta, más sabe, que estás."},{"c":"","l":"Mi corazón, que a Ti te siente,"},{"c":"","l":"y siente como eres todo amor..."},{"c":"","l":""},{"c":"","l":"Tus caminos son una locura,"},{"c":"","l":"pero son los que yo quiero recorrer."},{"c":"","l":"Tus caminos son una locura,"},{"c":"","l":"rompen mi humanidad,"},{"c":"","l":"pero son los que yo quiero recorrer."},{"c":"","l":""},{"c":"","l":"Qué raras que son tus sendas para mí."},{"c":"","l":"Te muestras incomprensible,"},{"c":"","l":"mi Señor,"},{"c":"","l":"pero lo más grande de todo"},{"c":"","l":"es quien se muestre seas Tú a mí."},{"c":"","l":""},{"c":"","l":"Procuro poder sentir que estás en mí,"},{"c":"","l":"y a Dios poderle decir que lo quiero."},{"c":"","l":""},{"c":"","l":"Qué incomprensible yo y mi nada"},{"c":"","l":"en ese todo que eres Tú, Señor..."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (198, 'Movimiento(Pablo Martínez)', '[{"c":"","l":"Necesito de tu aire para respirar,"},{"c":"","l":"Necesito de tu viento para continuar,"},{"c":"","l":"Ven y sóplame tu aliento"},{"c":"","l":"que devuelva el movimiento,"},{"c":"","l":"de mi transitar hacia tu lugar."},{"c":"","l":""},{"c":"","l":"Ven y dame de tu aire"},{"c":"","l":"y devuélvele la vida a estos"},{"c":"","l":"huesos que están secos."},{"c":"","l":"Ven y dame de tu aire,"},{"c":"","l":"y transforma lo que es piedra"},{"c":"","l":"en un corazón con un latido nuevo."},{"c":"","l":""},{"c":"","l":"Necesito de tu aire para reavivar,"},{"c":"","l":"Necesito de tu viento para regresar,"},{"c":"","l":"Ven y sóplame tu aliento"},{"c":"","l":"que devuelva el movimiento,"},{"c":"","l":"de mi transitar hacia tu lugar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (199, 'Alianza de amor(hna Glenda)', '[{"c":"","l":"En la pobreza o en la riqueza, te amare"},{"c":"","l":"En la salud o en la enfermedad, yo te amare"},{"c":"","l":"En la tristeza o en la alegría,"},{"c":"","l":"en la tormenta o en la paz"},{"c":"","l":"Ante todo y sobre todo, te amare"},{"c":"","l":""},{"c":"","l":"Tú me amaras, yo te amare"},{"c":"","l":"alianza eterna entre tú y yo"},{"c":"","l":"Tú me amaras, yo te amare"},{"c":"","l":"hasta que la muerte nos una más"},{"c":"","l":""},{"c":"","l":"En las buenas o en las malas te amare"},{"c":"","l":"En el pecado o en la gracia te amare"},{"c":"","l":"En la noche o en el día,"},{"c":"","l":"en la fuerza o la debilidad"},{"c":"","l":"Ante todo y sobre todo te amare"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (200, 'Señor tú me conoces(Metanoia)', '[{"c":"","l":"Señor tú conoces mi mal,"},{"c":"","l":"como podré pedir algo que tú ya sabes."},{"c":"","l":"Tu que conoces mi inquietud,"},{"c":"","l":"conoces cada entrega en mi cada tropiezo."},{"c":"","l":""},{"c":"","l":"Me cuesta mantener el rumbo"},{"c":"","l":"vacila mi fe al andar,"},{"c":"","l":"pero el amor que en mi provocas"},{"c":"","l":"me hace continuar."},{"c":"","l":"En noches cuando el miedo llega"},{"c":"","l":"me cubre tu amanecer,"},{"c":"","l":"“Sigue caminando -me dices-"},{"c":"","l":"No te dejaré perder.”"},{"c":"","l":""},{"c":"","l":"Debo aceptar mi condición,"},{"c":"","l":"soy un hombre que está preso de sus pecados."},{"c":"","l":"Tu Jesús me liberarás,"},{"c":"","l":"sólo me pides que ame y seré perdonado."},{"c":"","l":""},{"c":"","l":"Te daré gracias de aquí en más,"},{"c":"","l":"mi corazón solo quiere alabar tu nombre."},{"c":"","l":"Pastor, Señor, Dios, Hombre y Rey,"},{"c":"","l":"tú me bendices al pedirme que te siga."},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (201, 'Supe que me amabas(Marcela Gandara)', '[{"c":"","l":"Desde el principio cuando te necesite."},{"c":"","l":"Desde el momento cuando la mirada alce."},{"c":"","l":"Desde ese día cuando sola me encontraba,"},{"c":"","l":"cuando tu mirada en mí se fue a poner."},{"c":"","l":""},{"c":"","l":"Supe que me amabas, lo entendí."},{"c":"","l":"Supe que buscabas más de mí."},{"c":"","l":"Que mucho tiempo me esperaste"},{"c":"","l":"y no llegué."},{"c":"","l":""},{"c":"","l":"Supe que me amabas, aunque hui."},{"c":"","l":"Lejos de tu casa yo me fui."},{"c":"","l":"Y con un beso y con amor,"},{"c":"","l":"me regalaste tu perdón"},{"c":"","l":"y estoy aquí."},{"c":"","l":""},{"c":"","l":"Y cuando lejos me encontraba te sentí."},{"c":"","l":"Sabía que entonces me cuidabas y te oí,"},{"c":"","l":"como un susurro fue tu voz en el silencio."},{"c":"","l":"Cada día me atraías hacia Ti."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (202, 'Lo que agrada a Dios', '[{"c":"","l":"Lo que agrada a Dios"},{"c":"","l":"de mi pequeña alma,"},{"c":"","l":"es que ame mi pequeñez"},{"c":"","l":"y mi pobreza."},{"c":"","l":""},{"c":"","l":"Es la esperanza, ciega,"},{"c":"","l":"que tengo, en su misericordia."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (203, 'Largo viaje(Marcela Gandara)', '[{"c":"","l":"Ha sido largo el viaje pero al fin llegué"},{"c":"","l":"La luz llegó a mis ojos aunque lo dude"},{"c":"","l":"Fueron muchos valles de inseguridad"},{"c":"","l":"los que cruce."},{"c":"","l":"Fueron muchos días de tanto dudar"},{"c":"","l":"pero al fin llegué, llegué a entender"},{"c":"","l":""},{"c":"","l":"Que para esta hora he llegado,"},{"c":"","l":"para este tiempo nací,"},{"c":"","l":"en sus propósitos eternos yo me vi."},{"c":"","l":"Para esta hora he llegado,"},{"c":"","l":"aunque me ha costado creer"},{"c":"","l":"entre sus planes para hoy me encontré."},{"c":"","l":""},{"c":"","l":"Y nunca imagine que dentro de su amor,"},{"c":"","l":"y dentro de sus planes me encontraba yo."},{"c":"","l":"Fueron muchas veces que la timidez,"},{"c":"","l":"me lo impidió."},{"c":"","l":"Fueron muchos días de tanto dudar,"},{"c":"","l":"pero al fin llegué, llegué a entender."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (204, 'Cara a cara(Marcos Vidal)', '[{"c":"","l":"Solamente una palabra,"},{"c":"","l":"solamente una oración"},{"c":"","l":"cuando llegue a tu presencia, oh Señor"},{"c":"","l":"no me importa en qué lugar"},{"c":"","l":"de la mesa me hagas sentar"},{"c":"","l":"o el color de mi corona"},{"c":"","l":"si la llego a ganar"},{"c":"","l":""},{"c":"","l":"Solamente una palabra,"},{"c":"","l":"si es que aún me queda voz"},{"c":"","l":"y si logro articularla en tu presencia"},{"c":"","l":"no te quiero hacer preguntas,"},{"c":"","l":"sólo una petición"},{"c":"","l":"y si puede ser a solas, mucho mejor"},{"c":"","l":""},{"c":"","l":"Sólo déjame mirarte cara a cara"},{"c":"","l":"y perderme como un niño en tu mirada"},{"c":"","l":"y que pase mucho tiempo,"},{"c":"","l":"y que nadie diga nada"},{"c":"","l":"porque estoy viendo al maestro"},{"c":"","l":"cara a cara"},{"c":"","l":"Que se ahogue mi recuerdo en tu mirada"},{"c":"","l":"quiero amarte en el silencio y sin palabras"},{"c":"","l":"y que pase mucho tiempo"},{"c":"","l":"y que nadie diga nada"},{"c":"","l":"sólo déjame mirarte cara a cara"},{"c":"","l":""},{"c":"","l":"Sólo déjame mirarte cara a cara"},{"c":"","l":"aunque caiga derretido en tu mirada"},{"c":"","l":"derrotado y desde el suelo,"},{"c":"","l":"tembloroso y sin aliento"},{"c":"","l":"aún te seguiré mirando, mi maestro"},{"c":"","l":"Cuando caiga ante tus plantas, de rodillas"},{"c":"","l":"déjame llorar pegado a tus heridas"},{"c":"","l":"y que pase mucho tiempo"},{"c":"","l":"y que nadie me lo impida"},{"c":"","l":"que he esperado este momento.."},{"c":"","l":"toda mi vida"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'DESPEDIDA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (205, 'Danos un corazón(J. Espinosa)', '[{"c":"","l":"Danos un corazón grande para amar"},{"c":"","l":"Danos un corazón fuerte para luchar"},{"c":"","l":""},{"c":"","l":"Hombres nuevos creadores de la historia"},{"c":"","l":"constructores de nueva humanidad"},{"c":"","l":"hombres nuevos que viven la existencia"},{"c":"","l":"como riesgo de un largo caminar."},{"c":"","l":""},{"c":"","l":"Hombres nuevos luchando en esperanza"},{"c":"","l":"caminantes sedientos de verdad"},{"c":"","l":"hombres nuevos, sin frenos ni cadenas"},{"c":"","l":"hombres libres que exigen libertad."},{"c":"","l":""},{"c":"","l":"Hombres nuevos amando sin fronteras"},{"c":"","l":"por encima de razas y lugar"},{"c":"","l":"hombres nuevos al lado de los pobres"},{"c":"","l":"compartiendo con ellos techo y pan."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'DESPEDIDA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (206, 'Mar adentro', '[{"c":"","l":"Es hora de partir, mar adentro"},{"c":"","l":"y no voy a esperar."},{"c":"","l":"&Eacute;l vendrá para ir"},{"c":"","l":"mar adentro y lo voy a esperar."},{"c":"","l":""},{"c":"","l":"&Eacute;l ya está junto a mí,"},{"c":"","l":"Y sus ojos derraman ternura."},{"c":"","l":"&Eacute;l espera mi sí,"},{"c":"","l":"y yo no quiero hacerlo esperar."},{"c":"","l":""},{"c":"","l":"*Quiero sentir tu amor, y volver a nacer"},{"c":"","l":"Quiero decirte &ldquo;Ven, mi barca es tuya&rdquo;"},{"c":"","l":"Es tan inmenso el mar, pero yo voy con Vos"},{"c":"","l":"No temo navegar si está mi Dios*"},{"c":"","l":""},{"c":"","l":"Quiero ser como vos,"},{"c":"","l":"y ser Pan que se deja comer."},{"c":"","l":"Quiero que los demás"},{"c":"","l":"Vean en mí tu sonrisa, Señor."},{"c":"","l":""},{"c":"","l":"Quiero ser manantial"},{"c":"","l":"que da vida donde quieras que vaya."},{"c":"","l":"Quiero llevar tu luz"},{"c":"","l":"a ese mundo que no habla de Dios."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'DESPEDIDA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (207, 'Esta es la luz de Cristo', '[{"c":"","l":"Ésta es la luz de Cristo, yo la haré brillar(3)"},{"c":"","l":""},{"c":"","l":"Brillará, brillará, sin cesar"},{"c":"","l":""},{"c":"","l":"Soy cristiano y esta luz yo la haré brillar(3)"},{"c":"","l":"Llevo mi luz por la ciudad yo la harébrillar (3)"},{"c":"","l":"Nunca la ocultaré, yo la haré brillar (3)"},{"c":"","l":"Siempre la defenderé, yo la haré brillar (3)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'DESPEDIDA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (208, 'Tu llamado (Ariel Glaser)', '[{"c":"","l":"Como cualquier otra historia de amor,"},{"c":"","l":"tu vida fue encendiéndose de a poco,"},{"c":"","l":"te basta sólo con cerrar los ojos,"},{"c":"","l":"para sentir que está en tu corazón"},{"c":"","l":""},{"c":"","l":"Buscas una respuesta en tu interior,"},{"c":"","l":"porque todos te dicen que estás loco,"},{"c":"","l":"y tu alma te responde: síguelo"},{"c":"","l":"a Jesús, tu Señor&hellip;"},{"c":"","l":""},{"c":"","l":"*Tú, puedes seguirlo, puedes amarlo"},{"c":"","l":"y abandonar en El tu vida."},{"c":"","l":"Es tu momento, te está llamando,"},{"c":"","l":"puedes dejarlo, todo por &Eacute;l.*"},{"c":"","l":""},{"c":"","l":"Quizás tú digas &ldquo;nada tengo yo&rdquo;"},{"c":"","l":"pero tienes todo lo que &Eacute;l te ha dado,"},{"c":"","l":"tus manos, tus oídos y tu voz,"},{"c":"","l":"para hacer instrumento de su amor."},{"c":"","l":""},{"c":"","l":"Los hombres necesitan de tu sí,"},{"c":"","l":"de tu fidelidad a su Palabra,"},{"c":"","l":"de que te hagas pequeño y Cristo así,"},{"c":"","l":"crezca en ti, crezca en ti"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (209, 'Madre hoy quiero hablarte', '[{"c":"","l":"Madre, hoy quiero hablarte una vez más,"},{"c":"","l":"estar cerca de tu corazón, junto a vos."},{"c":"","l":"Y quiero contarte que ya estoy"},{"c":"","l":"en la lucha diaria por lograr la santidad."},{"c":"","l":""},{"c":"","l":"Quiero que tú me vayas guiando"},{"c":"","l":"por ese camino que escogí, ser como el Padre."},{"c":"","l":"Pero tengo miedo de caer,"},{"c":"","l":"y en la oscuridad no ver,"},{"c":"","l":"pero Madre, tú estarás allí."},{"c":"","l":""},{"c":"","l":"El mal va dejando huellas tras de sí,"},{"c":"","l":"pero el joven quiere construir un mundo nuevo,"},{"c":"","l":"donde el hombre tenga que luchar"},{"c":"","l":"para que Cristo pueda reinar junto a su Padre."},{"c":"","l":""},{"c":"","l":"Ser respuesta para el mundo es la misión,"},{"c":"","l":"y yo, Madre, me consagro a vos, por entero."},{"c":"","l":"Sos la Reina de mi corazón, Madre humilde esclava del Señor,"},{"c":"","l":"hazme fuerte en la Alianza de amor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (210, 'El ángel vino de los cielos', '[{"c":"","l":"El Ángel vino de los cielos"},{"c":"","l":"y a María le anunció"},{"c":"","l":"el gran misterio de Dios hombre"},{"c":"","l":"que a los cielos admiró."},{"c":"","l":""},{"c":"","l":"Virgen Madre, Señora nuestra"},{"c":"","l":"recordando la encarnación"},{"c":"","l":"te cantamos tus hijos todos"},{"c":"","l":"como Estrella de Salvación."},{"c":"","l":""},{"c":"","l":"Yo soy la esclava del Señor, mi Dios,"},{"c":"","l":"la Virgen dijo al contestar"},{"c":"","l":"que se haga en mí según has dicho,"},{"c":"","l":"se cumpla en mí tu voluntad."},{"c":"","l":""},{"c":"","l":"Y el Verbo para redimimos"},{"c":"","l":"tomó su carne virginal"},{"c":"","l":"vivió hecho hombre entre nosotros"},{"c":"","l":"librándonos de eterno mal."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (211, 'Cantad a María(P.Catena-Perosi)', '[{"c":"","l":"Cantad a María, la reina del Cielo,"},{"c":"","l":"del hombre consuelo, de Dios alegría."},{"c":"","l":""},{"c":"","l":"Cantad, cantad, cantad a María"},{"c":"","l":""},{"c":"","l":"Cantad a María, la Virgen sin mancha,"},{"c":"","l":"la llena de Gracia, por Dios elegida."},{"c":"","l":""},{"c":"","l":"Cantad a María, la estrella del alba"},{"c":"","l":"que anuncia a las almas el sol de alegría."},{"c":"","l":""},{"c":"","l":"Cantad a María, que dio de su carne"},{"c":"","l":"el cuerpo y la sangre al Verbo de Vida."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (212, 'Bendita sea tu pureza', '[{"c":"","l":"Bendita sea tu pureza"},{"c":"","l":"y eternamente lo sea"},{"c":"","l":"pues todo un Dios se recrea"},{"c":"","l":"en tan graciosa belleza."},{"c":"","l":"A tí celestial princesa"},{"c":"","l":"Virgen sagrada María"},{"c":"","l":"yo te ofrezco en éste día"},{"c":"","l":"alma, vida y corazón."},{"c":"","l":"Mírame con compasión,"},{"c":"","l":"no me dejes madre mía."},{"c":"","l":"Morir sin tu bendición"},{"c":"","l":"sería mi perdición."},{"c":"","l":"Por eso a vos te canto"},{"c":"","l":"mi niña, mi niña mía,"},{"c":"","l":"por eso a vos te canto"},{"c":"","l":"con todo mi corazón."},{"c":"","l":""},{"c":"","l":"Todito mi ser lo pongo a tus pies,"},{"c":"","l":"por ti llegaré a Jesús contemplar."},{"c":"","l":"Oh Virgen gaucha te voy a pedir"},{"c":"","l":"que vos nunca me dejes."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (213, 'Santa María del camino', '[{"c":"","l":"Mientras recorres la vida,"},{"c":"","l":"tú nunca solo estás"},{"c":"","l":"contigo por el camino,"},{"c":"","l":"Santa María va."},{"c":"","l":""},{"c":"","l":"Ven con nosotros a caminar,"},{"c":"","l":"Santa María, ven."},{"c":"","l":""},{"c":"","l":"Aunque digan algunos"},{"c":"","l":"que nada puede cambiar"},{"c":"","l":"lucha por un mundo nuevo,"},{"c":"","l":"lucha por la verdad."},{"c":"","l":""},{"c":"","l":"Si por el mundo los hombres"},{"c":"","l":"sin conocerse van,"},{"c":"","l":"no niegues nunca tu mano"},{"c":"","l":"al que contigo está."},{"c":"","l":""},{"c":"","l":"Aunque parezcan tus pasos"},{"c":"","l":"inútil caminar"},{"c":"","l":"tú vas haciendo caminos,"},{"c":"","l":"otros los seguirán."},{"c":"","l":""}]', 'MARIA', '{"youtube_url":"","autor":"J. Espinoza"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (214, 'La elegida', '[{"c":"","l":"Una entre todas fue la escogida"},{"c":"","l":"fuiste tú María, la elegida,"},{"c":"","l":"Madre del Señor, Madre del Salvador."},{"c":"","l":""},{"c":"","l":"María, llena de gracia y consuelo"},{"c":"","l":"ven a caminar con el pueblo,"},{"c":"","l":"nuestra madre eres tú."},{"c":"","l":""},{"c":"","l":"Ruega por nosotros, pecadores de la tierra,"},{"c":"","l":"ruega por el pueblo que en su Dios espera,"},{"c":"","l":"Madre del Señor,"},{"c":"","l":"Madre del Salvador."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (215, 'Canto de María', '[{"c":"","l":"Mi alma canta el amor de Dios."},{"c":"","l":"Y mi espíritu al Salvador."},{"c":"","l":"Porque Él miró mi humildad,"},{"c":"","l":"todo el mundo me aclamará."},{"c":"","l":""},{"c":"","l":"Y la Virgen santa le cantó al Señor,"},{"c":"","l":"dándole las gracias por su gran amor."},{"c":"","l":""},{"c":"","l":"Al humilde Dios levantará."},{"c":"","l":"Al soberbio lo derribará,"},{"c":"","l":"al hambriento le dará su pan"},{"c":"","l":"y a los ricos los despedirá."},{"c":"","l":""},{"c":"","l":"Desde siempre Dios nos eligió,"},{"c":"","l":"para ser testigos de su amor."},{"c":"","l":"Su misericordia y su bondad,"},{"c":"","l":"con nosotros siempre estará."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (216, 'Madre del Señor', '[{"c":"","l":"Virgen Nazarena, muéstranos a Jesús,"},{"c":"","l":"nadie supo amarlo como Tú."},{"c":"","l":"Madre del silencio háblanos del Señor,"},{"c":"","l":"déjanos entrar en tu oración."},{"c":"","l":""},{"c":"","l":"Conservabas todo dentro de tu corazón, fiel al hombre, fiel a Dios."},{"c":"","l":"Madre nuestra, María del Señor."},{"c":"","l":""},{"c":"","l":"María del huerto, llévanos sin temor,"},{"c":"","l":"tras los pasos del hijo del Dios."},{"c":"","l":"Servidora atenta enséñanos a guardar,"},{"c":"","l":"la Palabra ardiendo hasta el final."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (217, 'Nuestra Señora del buen viaje', '[{"c":"","l":"Estamos vivos y vivimos,"},{"c":"","l":"amar es nuestro destino,"},{"c":"","l":"aunque este viaje es distinto,"},{"c":"","l":"sólo hay un solo camino,"},{"c":"","l":"llegar a vos"},{"c":"","l":"Sólo quedó hierba seca"},{"c":"","l":"por dónde antes pisamos,"},{"c":"","l":"hoy hay flores de pureza,"},{"c":"","l":"porque hacia ti caminamos"},{"c":"","l":"espéranos"},{"c":"","l":""},{"c":"","l":"Dulce doncella, te seguiré,"},{"c":"","l":"tú eres mi estrella,"},{"c":"","l":"te alcanzaré, yo sé que sí"},{"c":"","l":""},{"c":"","l":"En la ruta de mis días"},{"c":"","l":"el viaje fue muy pesado"},{"c":"","l":"hasta que vi una doncella"},{"c":"","l":"y así juntos caminamos,"},{"c":"","l":"para llegar"},{"c":"","l":"Me demostró que en la vida"},{"c":"","l":"el amor es necesario"},{"c":"","l":"el que hasta ayer se evadía"},{"c":"","l":"al fin al puente ha llegado"},{"c":"","l":"lo cruzará"},{"c":"","l":""},{"c":"","l":"A veces se siente sola"},{"c":"","l":"por los que aún no han llegado"},{"c":"","l":"pero no los abandona,"},{"c":"","l":"sus huellas les va dejando"},{"c":"","l":"las seguirán"},{"c":"","l":"El amor que nos ha dado"},{"c":"","l":"es la mejor comprensión,"},{"c":"","l":"la realidad fue pasado,"},{"c":"","l":"el presente es nuestro Dios,"},{"c":"","l":"es caminar"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (218, 'Mi alma glorifica(Mejia)', '[{"c":"","l":"Mi alma glorifica al Señor, mi Dios"},{"c":"","l":"Gozase mi Espíritu en mi Salvador"},{"c":"","l":"Él es mi alegría, es mi plenitud"},{"c":"","l":"Él es todo para mí."},{"c":"","l":""},{"c":"","l":"Ha mirado la bajeza de su sierva"},{"c":"","l":"Muy dichosa me dirán todos los pueblos"},{"c":"","l":"porque en mí ha hecho grandes maravillas"},{"c":"","l":"el que todo puede cuyo nombre es santo."},{"c":"","l":""},{"c":"","l":"Su clemencia se derrama por los siglos"},{"c":"","l":"sobre aquellos que le temen y le aman"},{"c":"","l":"desplegó el gran poder de su Derecha"},{"c":"","l":"dispersó a los que piensan que son algo."},{"c":"","l":""},{"c":"","l":"Derribó a los potentados de sus tronos"},{"c":"","l":"y ensalzó a los humildes y a los pobres."},{"c":"","l":"Los hambrientos se saciaron de sus bienes"},{"c":"","l":"y alejó de si vacíos a los ricos."},{"c":"","l":""},{"c":"","l":"Socorrió a Israel su humilde siervo"},{"c":"","l":"acordándose de su misericordia"},{"c":"","l":"como había prometido a nuestros padres"},{"c":"","l":"a Abraham y descendencia para siempre."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (219, 'La virgen de Guadalupe', '[{"c":"","l":"La virgen de Guadalupe,"},{"c":"","l":"estrella de la mañana"},{"c":"","l":"ojos negros, piel morena,"},{"c":"","l":"mi virgencita americana."},{"c":"","l":"Protectora de los pobres,"},{"c":"","l":"crisol de todas las razas"},{"c":"","l":"transformaste nuestra tierra"},{"c":"","l":"en continente de esperanza"},{"c":"","l":""},{"c":"","l":"Juan Diego no se explica, como pudo pasar"},{"c":"","l":"la reina de los cielos, lo vino a visitar"},{"c":"","l":"Está llorando el indio, el rosal floreció"},{"c":"","l":"Dios le ha dado una madre"},{"c":"","l":"de su mismo color"},{"c":"","l":""},{"c":"","l":"Ya no son enemigos, indio con español:"},{"c":"","l":"a través de su gracia la Virgen los unió."},{"c":"","l":"Y a través de los siglos aún perdura esa fe,"},{"c":"","l":"de América que gritaque quiere renacer."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (220, 'Junto a ti María', '[{"c":"","l":"Junto a ti María,"},{"c":"","l":"como un niño quiero estar."},{"c":"","l":"Tómame en tus brazos,"},{"c":"","l":"guíame en mi caminar."},{"c":"","l":"Quiero que me eduques,"},{"c":"","l":"que me enseñes a rezar,"},{"c":"","l":"hazme transparente, lléname de paz."},{"c":"","l":""},{"c":"","l":"Madre, Madre, Madre, Madre"},{"c":"","l":""},{"c":"","l":"Gracias Madre mía,"},{"c":"","l":"por llevarnos a Jesús,"},{"c":"","l":"haznos más humilde,"},{"c":"","l":"tan sencillos como tú."},{"c":"","l":"Gracias Madre mía"},{"c":"","l":"por abrir tu corazón,"},{"c":"","l":"porque nos congregas y nos das tu amor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (221, 'Feliz de ti, María(P. Catena)', '[{"c":"","l":"Feliz de ti, María, hija santa de Israel"},{"c":"","l":"toda la Antigua Alianza"},{"c":"","l":"revive con tu fe."},{"c":"","l":""},{"c":"","l":"QUEREMOS HOY HONRARTE / COMO EL"},{"c":"","l":"MISMO DIOS TE HONRÓ / Y QUEREMOS"},{"c":"","l":"AMARTE / COMO JESÚS TE AMÓ"},{"c":"","l":""},{"c":"","l":"Feliz de ti, María, Madre santa y virginal"},{"c":"","l":"Dios mismo se ha prendado"},{"c":"","l":"de tu fidelidad."},{"c":"","l":""},{"c":"","l":"Feliz de ti María, que creíste al Señor"},{"c":"","l":"se cumplirá en tu vida"},{"c":"","l":"la voluntad de Dios."},{"c":"","l":""},{"c":"","l":"Feliz de ti, María, que engendraste al Salvador"},{"c":"","l":"eres aún más dichosa"},{"c":"","l":"por tu obediencia a Dios."},{"c":"","l":""},{"c":"","l":"Feliz de ti, María, Dios te puso por señal,"},{"c":"","l":"para anunciar al mundo"},{"c":"","l":"la Redención total."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (222, 'La fe de María', '[{"c":"","l":"Que hubiese pasado"},{"c":"","l":"Si ella hubiese dicho que no"},{"c":"","l":"o ignorado o dilatado"},{"c":"","l":"el anuncio de tu ángel de amor"},{"c":"","l":"En cambio creyó, en tu palabra"},{"c":"","l":"Y se hizo tu esclava"},{"c":"","l":"en un acto perfecto y de fe"},{"c":"","l":"Y hoy, quiero ser como ella"},{"c":"","l":"Y amarte aunque duelan"},{"c":"","l":"las espinas y el camino de la cruz."},{"c":"","l":""},{"c":"","l":"Dame la fe Señor, la fe de María"},{"c":"","l":"Para decirte si, un si sin medidas"},{"c":"","l":"Dame la fe Señor, la fe de María"},{"c":"","l":"Para renunciar a mi, y entregarte m vida"},{"c":"","l":"Mi vida."},{"c":"","l":""},{"c":"","l":"Aunque traspasaron"},{"c":"","l":"con una espada su corazón"},{"c":"","l":"Y su alma lloro,  el dolor de tus heridas"},{"c":"","l":"A los pies del madero se quedó"},{"c":"","l":"Y por creer, ella es reina y Señora"},{"c":"","l":"Y tú nos incorporas"},{"c":"","l":"a tu eterna familia de amor"},{"c":"","l":"Y yo en tu amor quiero permanecer"},{"c":"","l":"Postrado a tus pies"},{"c":"","l":"Es lo único que un día Llevaré."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (223, 'María es esa mujer', '[{"c":"","l":"¿Quién será la mujer que a tantos inspiró"},{"c":"","l":"poemas bellos de amor?"},{"c":"","l":"Le rinden honor la música y la luz"},{"c":"","l":"el mármol, la palabra y el color."},{"c":"","l":"¿Quién será la mujer que el rey y el labrador"},{"c":"","l":"invocan en su dolor?"},{"c":"","l":"El sabio, el ignorante, el pobre y el Señor"},{"c":"","l":"el santo al igual que el pecador."},{"c":"","l":""},{"c":"","l":"María es, esa mujer"},{"c":"","l":"Que desde siempre el Señor se preparó"},{"c":"","l":"Para nacer, como una flor"},{"c":"","l":"En el jardín que a Dios enamoró"},{"c":"","l":""},{"c":"","l":"¿Quién será la mujer radiante como el sol"},{"c":"","l":"vestida de resplandor?"},{"c":"","l":"La luna a sus pies, el cielo en derredor"},{"c":"","l":"y ángeles cantándole su amor."},{"c":"","l":"¿Quién será la mujer humilde que vivió"},{"c":"","l":"en un pequeño taller?"},{"c":"","l":"Amando sin milagros, viviendo de su fe"},{"c":"","l":"la esposa siempre alegre de José."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (224, 'María de Nazaret', '[{"c":"","l":"Dulce muchacha humilde de Palestina"},{"c":"","l":"a vos por Madre suya Dios te eligió,"},{"c":"","l":"y cuando desde el cielo"},{"c":"","l":"te mandó un ángel"},{"c":"","l":"para pedir tu consentimiento"},{"c":"","l":"vos le dijiste  tu esclava soy ."},{"c":"","l":""},{"c":"","l":"Por eso voy a darte mi corazón"},{"c":"","l":"y cantando repetiré tu nombre"},{"c":"","l":"María de Nazareth"},{"c":"","l":""},{"c":"","l":"Fue tu materna espera luz de esperanza"},{"c":"","l":"hasta que el guricito nació en Belén,"},{"c":"","l":"y vinieron los pobres y peregrinos"},{"c":"","l":"para adorarlo y él sonreía"},{"c":"","l":"Dios con nosotros: el Emmanuel"},{"c":"","l":""},{"c":"","l":"En aquel tallercito de carpintero"},{"c":"","l":"Dios aprendió el oficio del buen José,"},{"c":"","l":"y vos yendo y viniendo de la cocina"},{"c":"","l":"guardabas cosas dentro del alma"},{"c":"","l":"que te sirvieron para después."},{"c":"","l":""},{"c":"","l":"Viendo morir a tu Hijo sobre el Calvario"},{"c":"","l":"te hiciste nuestra Madre junto a la cruz,"},{"c":"","l":"y quedaste esperando porque sabías"},{"c":"","l":"que volvería resucitado"},{"c":"","l":"de entre los muertos el buen Jesús."},{"c":"","l":""},{"c":"","l":"Ahora que en cuerpo y alma estás en el cielo"},{"c":"","l":"sentimos tu plegaria junto al Señor,"},{"c":"","l":"y que vas caminando con el que sufre,"},{"c":"","l":"con el que llora, con el que sueña,"},{"c":"","l":"con la justicia, con el amor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (225, 'Te vengo a pedir', '[{"c":"","l":"Te vengo a pedir, te vengo a pedir"},{"c":"","l":"oh Madre de Dios,"},{"c":"","l":"que ruegues por mí, que ruegues por mi"},{"c":"","l":"a Nuestro Señor."},{"c":"","l":""},{"c":"","l":"Te vengo a pedir, te vengo a pedir"},{"c":"","l":"por tu intercesión,"},{"c":"","l":"amar como tú, llevar a Jesús"},{"c":"","l":"en mi corazón."},{"c":"","l":""},{"c":"","l":"Yo quiero crecer, yo quiero crecer"},{"c":"","l":"en fe y oración;"},{"c":"","l":"yo quiero vivir, yo quiero vivir"},{"c":"","l":"la vida de Dios."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (226, 'Oh María', '[{"c":"","l":"Oh María, Madre mía"},{"c":"","l":"oh consuelo del mortal"},{"c":"","l":"Amparadme y guiadme"},{"c":"","l":"a la patria celestial. (2)"},{"c":"","l":""},{"c":"","l":"Con el ángel de María"},{"c":"","l":"las grandezas celebrad"},{"c":"","l":"transportados de alegría,"},{"c":"","l":"sus finezas publicad. (2)"},{"c":"","l":""},{"c":"","l":"Quien a ti ferviente clama"},{"c":"","l":"halla alivio en el pesar"},{"c":"","l":"pues tu nombre luz derrama,"},{"c":"","l":"gozo y bálsamo sin par. (2)"},{"c":"","l":""},{"c":"","l":"Pues te llamo con fe viva"},{"c":"","l":"muestra, oh Madre, tu bondad"},{"c":"","l":"a mí vuelve compasiva"},{"c":"","l":"esos ojos de piedad. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (227, 'María', '[{"c":"","l":"Contigo en tu camino, el nuestro es seguro"},{"c":"","l":"contigo cada paso conduce a la meta"},{"c":"","l":"y también en la noche, estás junto a nosotros"},{"c":"","l":"transformas cada temor en certeza."},{"c":"","l":""},{"c":"","l":"María (4)"},{"c":"","l":"Somos tus hijos queremos amarte"},{"c":"","l":"Como ninguno te ha amado jamás (2)"},{"c":"","l":""},{"c":"","l":"Tu corona de rosas, queremos ser nosotros"},{"c":"","l":"una corona de hijos todos tuyos"},{"c":"","l":"que tu presencia en el mundo"},{"c":"","l":"vuelva a través de nosotros"},{"c":"","l":"como un canto de amor sin fin"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (228, 'Virgen de la esperanza', '[{"c":"","l":"Virgen de la esperanza,"},{"c":"","l":"en nuestra marcha danos tu luz"},{"c":"","l":"queremos ir contigo"},{"c":"","l":"por el camino que abre la cruz."},{"c":"","l":""},{"c":"","l":"Madre del pueblo, condúcenos"},{"c":"","l":"Por el camino de salvación"},{"c":"","l":"Que en nuestra patria reine la paz"},{"c":"","l":"En la justicia y la libertad"},{"c":"","l":""},{"c":"","l":"Cielo y Tierra nueva"},{"c":"","l":"esa es la meta de nuestro andar."},{"c":"","l":"Somos la Iglesia en marcha"},{"c":"","l":"que hacia la Pascua cantando va."},{"c":"","l":""},{"c":"","l":"Sobre cerros y pampas"},{"c":"","l":"despunta el alba de nueva luz"},{"c":"","l":"es la luz que trajiste"},{"c":"","l":"cuando nos diste a tu Hijo, Jesús."},{"c":"","l":""},{"c":"","l":"Afirma nuestros pasos"},{"c":"","l":"da a nuestros brazos fuerza y valor"},{"c":"","l":"para luchar unidos"},{"c":"","l":"como instrumentos de salvación."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (229, 'Una madre no se cansa de esperar', '[{"c":"","l":"Cuántas veces siendo niño te recé"},{"c":"","l":"Con mis besos te decía que te amaba."},{"c":"","l":"Poco a poco con el tiempo,"},{"c":"","l":"olvidándome de Ti,"},{"c":"","l":"por caminos que se alejan me perdí."},{"c":"","l":""},{"c":"","l":"Hoy he vuelto, Madre, a recordar"},{"c":"","l":"cuántas cosas dije ante tu altar"},{"c":"","l":"y al rezarte puedo comprender"},{"c":"","l":"que una Madre no se cansa de esperar."},{"c":"","l":""},{"c":"","l":"Al regreso, me encendías una luz"},{"c":"","l":"sonriendo desde lejos me esperabas."},{"c":"","l":"En la mesa, la comida"},{"c":"","l":"aún caliente y el mantel"},{"c":"","l":"y tu abrazo en mi alegría de volver."},{"c":"","l":""},{"c":"","l":"Aunque el hijo se alejara del hogar"},{"c":"","l":"Una madre siempre espera su regreso."},{"c":"","l":"Que el regalo más hermoso"},{"c":"","l":"que a los hijos da el Señor"},{"c":"","l":"es su madre y el milagro de su amor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (230, 'Ave María te quiero', '[{"c":"","l":"Ave, ave, ave María te quiero (2)"},{"c":"","l":""},{"c":"","l":"Llena de Espíritu Santo,"},{"c":"","l":"tu vientre de amor lleno"},{"c":"","l":"dile a Jesús que yo digo"},{"c":"","l":"ese que te ama soy yo."},{"c":"","l":""},{"c":"","l":"Como la arena en el mar"},{"c":"","l":"con estrellas en el cielo"},{"c":"","l":"infinita es tu pureza"},{"c":"","l":"Ave María te quiero."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (231, 'María mírame', '[{"c":"","l":"María mírame,María mírame"},{"c":"","l":"si tú me miras, Él también me mirará."},{"c":"","l":"Madre mía mírame de la mano llévame"},{"c":"","l":"muy cerca de Él, ahí me quiero quedar"},{"c":"","l":""},{"c":"","l":"María cúbreme con tu manto"},{"c":"","l":"que tengo miedo no se rezar"},{"c":"","l":"que por tus ojos misericordiosos"},{"c":"","l":"tendré la fuerza tendré la paz"},{"c":"","l":""},{"c":"","l":"Madre consuélame de mis penas"},{"c":"","l":"es que no quiero ofenderle más"},{"c":"","l":"que por tus ojos misericordiosos"},{"c":"","l":"quiero ir al cielo y verlos ya"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (232, 'Himno María Auxiliadora', '[{"c":"","l":"Quiero llegar hasta tus pies benditos"},{"c":"","l":"para implorar sobre mi vida entera"},{"c":"","l":"la bendición que ampare mi alegría"},{"c":"","l":""},{"c":"","l":"*¡Auxiliadora madre mía!*"},{"c":"","l":""},{"c":"","l":"Por ti viví los años de inocencia"},{"c":"","l":"porque aprendí de labios de mi madre"},{"c":"","l":"a invocar tu nombre cada día"},{"c":"","l":""},{"c":"","l":"*¡Auxiliadora madre mía!*"},{"c":"","l":""},{"c":"","l":"Tuya será mi juventud inquieta"},{"c":"","l":"frágil barquilla en borrascosos mares"},{"c":"","l":"porque serás su brújula y su guía"},{"c":"","l":""},{"c":"","l":"*¡Auxiliadora madre mía!*"},{"c":"","l":""},{"c":"","l":"Y hasta el postrer momento de mi vida"},{"c":"","l":"ruego que ayudes con materna mano"},{"c":"","l":"al pecador que solo en ti confía"},{"c":"","l":""},{"c":"","l":"*¡Auxiliadora madre mía!*"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SALMOS Y CANTICOS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (233, 'Rendid a Yahvé(Salmo 29)', '[{"c":"","l":"Rendid a Yahvé, Santos del Señor,"},{"c":"","l":"gloria y poder al que hace la creación"},{"c":"","l":"rendid honor al glorioso nombre del Señor"},{"c":"","l":"y adoradle en su santo esplendor."},{"c":"","l":""},{"c":"","l":"*Sobre los mares resuena la voz de Dios,"},{"c":"","l":"glorioso es Dios su voz hace temblar"},{"c":"","l":"Que poderosa es la voz del altísimo,"},{"c":"","l":""},{"c":"","l":"Aleluya,"},{"c":"","l":"su voz desgaja los cedros del Líbano,"},{"c":"","l":"Aleluya,"},{"c":"","l":"la voz del señor lanza llamas de fuego,"},{"c":"","l":"Aleluya,"},{"c":"","l":"sacude los montes la voz del altísimo,"},{"c":"","l":"Aleluya,"},{"c":"","l":"y en su santuario gritan ¡Gloria!*"},{"c":"","l":""},{"c":"","l":"Sentado está Dios sobre la tempestad,"},{"c":"","l":"sentado está Yahvé cual Rey eterno,"},{"c":"","l":"la fuerza da al que pone su confianza en &Eacute;l"},{"c":"","l":"Yahvé bendice a su pueblo con paz."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SALMOS Y CANTICOS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (234, 'Mi fortaleza(Salmo 18)', '[{"c":"","l":"Yo te amo Señor mi fortaleza,"},{"c":"","l":"mi roca mi baluarte mi liberador"},{"c":"","l":"Tú eres la roca en quien me amparo,"},{"c":"","l":"mi escudo y mi fuerza, mi Salvador."},{"c":"","l":""},{"c":"","l":"En el templo se escuchó mi voz,"},{"c":"","l":"clamé por ti en mi angustia."},{"c":"","l":"Extendiste tu mano y no caí,"},{"c":"","l":"tu poder del enemigo me libró."},{"c":"","l":""},{"c":"","l":"Las olas de la muerte me envolvían,"},{"c":"","l":"me aguardaba la ruina, pero el Señor venció."},{"c":"","l":"Tú eres la luz que me ilumina,"},{"c":"","l":"quien abre mis caminos, Tú eres mi Dios."},{"c":"","l":""},{"c":"","l":"Cuando yo invoqué tu nombre,"},{"c":"","l":"con mano poderosa, me salvó tu Amor."},{"c":"","l":"Son perfectos tus caminos,"},{"c":"","l":"tu mano me sostiene, Tú eres mi Rey."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SALMOS Y CANTICOS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (235, 'Mi Dios(Salmo 139)', '[{"c":"","l":"Mi Dios tú me conoces"},{"c":"","l":"entiendes desde lejos mi pensar."},{"c":"","l":"Adviertes mi andar y mi reposo,"},{"c":"","l":"conoces todos mis caminos"},{"c":"","l":"pues aún no está la palabra,"},{"c":"","l":"en mi voz y tú la sabes..."},{"c":"","l":""},{"c":"","l":"Delante y detrás tú me rodeaste"},{"c":"","l":"Pusiste sobre mi tu amor."},{"c":"","l":"Alto es... y no lo puedo comprender..."},{"c":"","l":""},{"c":"","l":"¿A dónde me iré, de tu Espíritu?"},{"c":"","l":"¿A dónde huiré, de tu presencia?"},{"c":"","l":"Porque si fuera a los cielos, te hallaré"},{"c":"","l":"y si tomara las alas del alba"},{"c":"","l":"te encontraré"},{"c":"","l":"Aunque habitaras"},{"c":"","l":"en el extremo del mar,"},{"c":"","l":"tu mano me guiará conmigo estarás."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SALMOS Y CANTICOS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (236, 'El Señor es mi Pastor(Salmo 22)', '[{"c":"","l":"El Señor es mi pastor"},{"c":"","l":"que no me priva de nada"},{"c":"","l":"en las praderas fresquitas"},{"c":"","l":"de pasto verde me sacia"},{"c":"","l":"y me lleva a los arroyos"},{"c":"","l":"donde el agüita es más clara."},{"c":"","l":""},{"c":"","l":"Como una cuestión de honor"},{"c":"","l":"se preocupa de mi vida,"},{"c":"","l":"me lleva por buena senda"},{"c":"","l":"y me asiste en las fatigas,"},{"c":"","l":"y yendo con Él no temo"},{"c":"","l":"las quebradas más ariscas."},{"c":"","l":""},{"c":"","l":"El Señor es mi pastor"},{"c":"","l":"nada me puede faltar…"},{"c":"","l":"nada me puede faltar."},{"c":"","l":""},{"c":"","l":"Saber que Él marca mi rumbo"},{"c":"","l":"me sosiega y tranquiliza"},{"c":"","l":"Él me brinda su confianza"},{"c":"","l":"hasta entre gente enemiga,"},{"c":"","l":"me hace sentar a su mesa"},{"c":"","l":"y en su copa me convida."},{"c":"","l":""},{"c":"","l":"Qué lindo saber que tengo"},{"c":"","l":"su cariño y su alegría,"},{"c":"","l":"que siempre vendrán conmigo"},{"c":"","l":"a la largo de la vida"},{"c":"","l":"y un día será mi casa"},{"c":"","l":"la casa donde Él habita."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SALMOS Y CANTICOS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (237, 'Cantico de las creaturas II', '[{"c":"","l":"Creaturas del Señor, Bendecid al Señor."},{"c":"","l":"Todo con himnos... Bendecid al Señor"},{"c":"","l":"Ángeles del Señor... Bendecid al Señor"},{"c":"","l":""},{"c":"","l":"Todos los cielos... Bendecid al Señor"},{"c":"","l":"Aguas del espacio... Bendecid al Señor"},{"c":"","l":"Ejércitos del Señor... Bendecid al Señor"},{"c":"","l":""},{"c":"","l":"Canten, conmigo canten fuerte"},{"c":"","l":"Que el amor venció a la muerte"},{"c":"","l":"La vida venció en la cruz"},{"c":"","l":""},{"c":"","l":"Sol y luna... Astros del cielo... Lluvia y rocío..."},{"c":"","l":"Vientos todos... Fuego y calor... Fríos y heladas..."},{"c":"","l":""},{"c":"","l":"Rocíos y nevadas... Témpanos y hielos... Escarchas y nieves..."},{"c":"","l":"Noches y días... Luz y tinieblas... Rayos y nubes..."},{"c":"","l":""},{"c":"","l":"Toda la tierra... Todos con himnos... Montes y cumbres..."},{"c":"","l":"Plantas de la tierra... Los manantiales... Mares y ríos..."},{"c":"","l":""},{"c":"","l":"Peces de las aguas... Pájaros del cielo... Fieras y ganados..."},{"c":"","l":"Hijos de los hombres... Pueblo de Israel... Grandes y pequeños"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SALMOS Y CANTICOS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (238, 'Salmo de la creación', '[{"c":"","l":"Por tu océano azul"},{"c":"","l":"y las aguas del mar,"},{"c":"","l":"por todo continente"},{"c":"","l":"y los ríos que van,"},{"c":"","l":"por el fuego que viste"},{"c":"","l":"como arbusto ardiente,"},{"c":"","l":"por el ala del viento,"},{"c":"","l":"quiero gritar"},{"c":"","l":""},{"c":"","l":"Mi Dios, tú eres grande y hermoso,"},{"c":"","l":"Dios viviente e inmenso,"},{"c":"","l":"tu eres el Dios de amor."},{"c":"","l":"Mi Dios tu eres grande y hermoso,"},{"c":"","l":"Dios viviente e inmenso"},{"c":"","l":"Dios presente en toda creación."},{"c":"","l":""},{"c":"","l":"Y por los animales"},{"c":"","l":"de la tierra y el agua,"},{"c":"","l":"por el canto del ave"},{"c":"","l":"y el cantar de la vida,"},{"c":"","l":"por el hombre que hiciste"},{"c":"","l":"semejante a ti,"},{"c":"","l":"y por todos tus hijos,"},{"c":"","l":"quiero gritar"},{"c":"","l":""},{"c":"","l":"Por la mano tendida"},{"c":"","l":"que te invita a la danza,"},{"c":"","l":"por el beso que brota"},{"c":"","l":"al surgir la esperanza,"},{"c":"","l":"la mirada de amor"},{"c":"","l":"que levanta y reanima,"},{"c":"","l":"por el vino y pan,"},{"c":"","l":"quiero gritar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SALMOS Y CANTICOS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (239, 'Cántico de las creaturas(P.Catena-Levoratti)', '[{"c":"","l":"Obras del Señor, bendigan al Señor"},{"c":"","l":"ángeles de Dios, bendigan al Señor"},{"c":"","l":"luna y sol, bendigan al Señor,"},{"c":"","l":"estrellas del cielo, bendigan al Señor."},{"c":"","l":""},{"c":"","l":"Todo el universo es obra del Señor"},{"c":"","l":"Todo nos invita a bendecir a Dios"},{"c":"","l":""},{"c":"","l":"Lluvias y vientos, bendigan al Señor,"},{"c":"","l":"fuego y calor, bendigan al Señor"},{"c":"","l":"fríos y heladas, bendigan al Señor,"},{"c":"","l":"nieve y escarcha, bendigan al Señor."},{"c":"","l":""},{"c":"","l":"Noches y días, bendigan al Señor,"},{"c":"","l":"luz y tinieblas, bendigan al Señor"},{"c":"","l":"nubes y rayos, bendigan al Señor,"},{"c":"","l":"toda la tierra, bendiga al Señor."},{"c":"","l":""},{"c":"","l":"Montañas y cerros, bendigan al Señor,"},{"c":"","l":"plantas de la tierra, bendigan al Señor"},{"c":"","l":"fuentes y vertientes, bendigan al Señor"},{"c":"","l":"mares y ríos, bendigan al Señor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SALMOS Y CANTICOS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (240, 'Tu palabra Señor es la verdad(Salmo 18)', '[{"c":"","l":"Tu palabra Señor es la verdad"},{"c":"","l":"Y la luz de mis ojos"},{"c":"","l":""},{"c":"","l":"La ley del Señor es perfecta"},{"c":"","l":"Reconforta el alma;"},{"c":"","l":"el testimonio del Señor es verdadero sabiduría del humilde."},{"c":"","l":""},{"c":"","l":"Los preceptos del Señor son justos"},{"c":"","l":"alegran el corazón;"},{"c":"","l":"la Palabra del Señor es pura"},{"c":"","l":"ilumina los ojos."},{"c":"","l":""},{"c":"","l":"Los mandamientos del Señor son santos"},{"c":"","l":"permanecen para siempre;"},{"c":"","l":"los juicios del Señor son la verdad"},{"c":"","l":"y siempre justos."},{"c":"","l":""},{"c":"","l":"Su Palabra es más valiosa"},{"c":"","l":"que el oro más fino;"},{"c":"","l":"sus preceptos son más dulces que la miel"},{"c":"","l":"que fluye del panal"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'SALMOS Y CANTICOS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (241, 'El Señor es mi pastor', '[{"c":"","l":"El Señor es mi pastor,"},{"c":"","l":"Nada me puede faltar"},{"c":"","l":"Nada me puede faltar"},{"c":"","l":""},{"c":"","l":"El Señor es mi Pastor,"},{"c":"","l":"no me priva denada"},{"c":"","l":"en las praderas fresquitas,"},{"c":"","l":"depasto verde me sacia"},{"c":"","l":"y me lleva a losarroyos"},{"c":"","l":"donde el agüita es más clara."},{"c":"","l":""},{"c":"","l":"Como una cuestión de honor,"},{"c":"","l":"Sepreocupa de mi vida"},{"c":"","l":"me lleva por buenasenda"},{"c":"","l":"y me asiste en las fatigas"},{"c":"","l":"yyendo con Él"},{"c":"","l":"no temo las quebradas másariscas."},{"c":"","l":""},{"c":"","l":"Saber que Él marca mi rumbo,"},{"c":"","l":"Mesosiega y tranquiliza"},{"c":"","l":"Él me brinda suconfianza,"},{"c":"","l":"hasta entre gente enemiga"},{"c":"","l":"me hace sentar a su mesa"},{"c":"","l":"y en su copame convida."},{"c":"","l":""},{"c":"","l":"Qué lindo saber que tengo,"},{"c":"","l":"su cariño y sualegría"},{"c":"","l":"que siempre vendrán conmigo"},{"c":"","l":"alo largo de la vida"},{"c":"","l":"y un día será mi casa"},{"c":"","l":"la casa donde Él habita."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (242, 'Despertemos llega Cristo', '[{"c":"","l":"Despertemos, llega Cristo, Ven, Señor"},{"c":"","l":"Acudamos a su encuentro, Ven, Señor."},{"c":"","l":"La Iglesia espera tu venida: ¡Ven, Señor!"},{"c":"","l":"Y llena de alegría canta: ¡Ven, Señor!"},{"c":"","l":"Palabra eterna y creadora, ¡Ven, Señor!"},{"c":"","l":"A renovar todas las cosas, ¡Ven, Señor!"},{"c":"","l":"Imagen de la luz eterna, ¡Ven, Señor!"},{"c":"","l":"A iluminar nuestras tinieblas, ¡Ven, Señor!"},{"c":"","l":"Pastor y Rey de nuestro pueblo, ¡Ven, Señor!"},{"c":"","l":"a conducirnos a tu Reino, ¡Ven, Señor!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (243, 'Volverás(J.Boudette)', '[{"c":"","l":"Eres el Hijo de Dios vivo"},{"c":"","l":"viniste al mundo trayéndonos su amor."},{"c":"","l":"Mueres en una cruz clavado,"},{"c":"","l":"te matan tus hermanos entre ellos estoy yo."},{"c":"","l":""},{"c":"","l":"Pero sé que un día volverás"},{"c":"","l":"Vendrás a compartir, Tu reino con los pobres"},{"c":"","l":"Pero sé que un día volverás"},{"c":"","l":"Vendrás para reinar, Trayéndonos paz"},{"c":"","l":""},{"c":"","l":"Sigues muriendo cada día"},{"c":"","l":"en todos los hermanos que sufren opresión."},{"c":"","l":"Vives en medio de nosotros"},{"c":"","l":"en cada gesto nuevo de amor liberador."},{"c":"","l":""},{"c":"","l":"Siento que debo ser distinto,"},{"c":"","l":"dar todo lo que tengo, mi propio corazón."},{"c":"","l":"Quiero brindarme todo entero"},{"c":"","l":"uniéndome a tu Causa de amor y salvación."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (244, 'Despertemos llega Cristo', '[{"c":"","l":"Despertemos, llega Cristo, Ven, Señor"},{"c":"","l":"Acudamos a su encuentro, Ven, Señor."},{"c":"","l":"La Iglesia espera tu venida: ¡Ven, Señor!"},{"c":"","l":"Y llena de alegría canta: ¡Ven, Señor!"},{"c":"","l":"Palabra eterna y creadora, ¡Ven, Señor!"},{"c":"","l":"A renovar todas las cosas, ¡Ven, Señor!"},{"c":"","l":"Imagen de la luz eterna, ¡Ven, Señor!"},{"c":"","l":"A iluminar nuestras tinieblas, ¡Ven, Señor!"},{"c":"","l":"Pastor y Rey de nuestro pueblo, ¡Ven, Señor!"},{"c":"","l":"a conducirnos a tu Reino, ¡Ven, Señor!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (245, 'Ven a nuestro mundo', '[{"c":"","l":"*Ven a nuestro mundo, que tu amor nos salve"},{"c":"","l":"Ven a redimirnos, ven Señor, no tardes (2)*"},{"c":"","l":""},{"c":"","l":"Que larga es la noche, como el centinela"},{"c":"","l":"que aguarda la aurora, los hombres te esperan"},{"c":"","l":"con la Virgen Madre, te espera la Iglesia"},{"c":"","l":""},{"c":"","l":"Que bella es la noche, cuajada de estrellas"},{"c":"","l":"si voy de Tu mano, las veo más bellas"},{"c":"","l":"ya pronto se cumplen, Señor Tus promesas"},{"c":"","l":""},{"c":"","l":"Levanta los ojos, del sueño despierta"},{"c":"","l":"que baja El Mesías del cielo a la tierra"},{"c":"","l":"prepara el camino, al Rey que se acerca."},{"c":"","l":""},{"c":"","l":"La noche ha pasado, el día se acerca"},{"c":"","l":"El &ldquo;Dios con Nosotros&rdquo;, ya está en nuestra tierra"},{"c":"","l":"¡el Hijo del Padre, es Hombre de veras!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (246, 'Arriba los corazones', '[{"c":"","l":"¡Arriba los corazones,"},{"c":"","l":"cerca está la salvación!"},{"c":"","l":"El tiempo ya ha madurado"},{"c":"","l":"es la hora del Señor."},{"c":"","l":"Hoy el mundo te reclama"},{"c":"","l":"¡Ven, Señor Jesús!"},{"c":"","l":""},{"c":"","l":"*¡Qué venga Tu Reino, el Reino de amor!*"},{"c":"","l":""},{"c":"","l":"Sin ti los hombres"},{"c":"","l":"perecen por el hambre y la opresión"},{"c":"","l":"sin ti los pueblos se hunden"},{"c":"","l":"en la guerra y en la ambición."},{"c":"","l":"Hoy los pueblos te reclaman"},{"c":"","l":"¡Ven, Señor Jesús!"},{"c":"","l":""},{"c":"","l":"Tú eres nuestra esperanza,"},{"c":"","l":"eres vida y verdad"},{"c":"","l":"libertador de los pobres,"},{"c":"","l":"mensajero de la paz."},{"c":"","l":"Hoy los hombres te reclaman"},{"c":"","l":"¡Ven, Señor Jesús!"},{"c":"","l":""},{"c":"","l":"Tu Reino ya está muy cerca,"},{"c":"","l":"con nosotros Dios está"},{"c":"","l":"que broten pronto"},{"c":"","l":"tus frutos de justicia y libertad."},{"c":"","l":"Hoy la Iglesia te reclama"},{"c":"","l":"¡Ven, Señor Jesús!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (247, 'Abran las puertas', '[{"c":"","l":"*Abran las puertas"},{"c":"","l":"abran las puertas"},{"c":"","l":"ábranlas al Redentor* (x2)"},{"c":"","l":""},{"c":"","l":"Bendecid al Señor"},{"c":"","l":"todos los Hijos de Dios"},{"c":"","l":"alcemos las manos"},{"c":"","l":"en el Santuario."},{"c":"","l":"y bendecid al Señor."},{"c":"","l":""},{"c":"","l":"Alabad al Señor"},{"c":"","l":"todos los Hijos de Dios"},{"c":"","l":"alcemos las manos"},{"c":"","l":"en el Santuario."},{"c":"","l":"y alabad al Señor."},{"c":"","l":""},{"c":"","l":"Seguid al Señor"},{"c":"","l":"todos los Hijos de Dios"},{"c":"","l":"alcemos las manos"},{"c":"","l":"en el Santuario"},{"c":"","l":"y seguid al Señor."},{"c":"","l":""},{"c":"","l":"Cantad al Señor"},{"c":"","l":"todos los Hijos de Dios"},{"c":"","l":"alcemos las manos"},{"c":"","l":"en el Santuario."},{"c":"","l":"y cantad al Señor."},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (248, 'Mi alma se llena', '[{"c":"","l":"*Mi alma se llena de gozo"},{"c":"","l":"porque el Señor pronto vendrá"},{"c":"","l":"prepararé un pesebre en mi corazón"},{"c":"","l":"despojándome de toda maldad.*"},{"c":"","l":""},{"c":"","l":"Señor, yo quiero que nazcas en mí"},{"c":"","l":"En silencio estaré esperándote"},{"c":"","l":"Como viento que espera su descanso"},{"c":"","l":"Como fuego que arde sin fin."},{"c":"","l":""},{"c":"","l":"Soy un río que espera su reposo"},{"c":"","l":"deseando llegar al mar para poder"},{"c":"","l":"mecerse en sus olas y sumirse en tu paz."},{"c":"","l":""},{"c":"","l":"Es turbia el agua que llevo"},{"c":"","l":"al pasar tu pureza la limpiará y tu amor la"},{"c":"","l":"llevará dulce y suave hasta la mar"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (249, 'Se oye una voz', '[{"c":"","l":"Se oye una voz, que clama en el desierto"},{"c":"","l":"preparad el camino del Señor"},{"c":"","l":"que se allanen todos los montes,"},{"c":"","l":"porque viene la salvación"},{"c":"","l":""},{"c":"","l":"Que se vuelva cada uno, de sus malos caminos"},{"c":"","l":"que se aparte de todo mal"},{"c":"","l":"el tiempo se ha cumplido,"},{"c":"","l":"la salvación está aquí"},{"c":"","l":""},{"c":"","l":"*Para el que cree, para el que espera"},{"c":"","l":"Para el que tiene hambre y sed"},{"c":"","l":"Para el que llora, para el que sufre"},{"c":"","l":"Ya está aquí la salvación*"},{"c":"","l":""},{"c":"","l":"Dios se ha regalado, a todos los hombres"},{"c":"","l":"en Cristo nuestro Señor"},{"c":"","l":"la promesa de salvación se ha cumplido"},{"c":"","l":"en Jesús, hijo de Dios."},{"c":"","l":""},{"c":"","l":"&Eacute;l te está buscando, &Eacute;l te está tocando"},{"c":"","l":"A la puerta de tu corazón"},{"c":"","l":"y quiere ofrecerte"},{"c":"","l":"el camino de salvación."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (250, 'Toda la tierra espera', '[{"c":"","l":"Toda la tierra espera al Salvador,"},{"c":"","l":"y el surco abierto, a la obra del Señor;"},{"c":"","l":"es el mundo que lucha por la libertad,"},{"c":"","l":"reclama justicia y busca la verdad."},{"c":"","l":""},{"c":"","l":"Dice el profeta al pueblo de Israel:"},{"c":"","l":"“De Madre virgen ya viene el Emmanuel”,"},{"c":"","l":"será \\\"Diosconnosotros\\\", hermano será,"},{"c":"","l":"con Él la esperanza al mundo volverá."},{"c":"","l":""},{"c":"","l":"Cerros y valles habrá que preparar,"},{"c":"","l":"nuevos caminos tenemos que trazar;"},{"c":"","l":"el Señor está cerca, hay que irlo a encontrar,"},{"c":"","l":"y todas las puertas abrir de par en par."},{"c":"","l":""},{"c":"","l":"En mi pesebre, Jesús apareció"},{"c":"","l":"pero en el mundo es donde nace hoy,"},{"c":"","l":"vive en nuestros hermanos, con ellos está,"},{"c":"","l":"y vuelve de nuevo a darnos libertad."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (251, 'Baguala de la conversión', '[{"c":"","l":"Una voz grita en el llano"},{"c":"","l":"abran camino al Señor"},{"c":"","l":"que rellenen las quebradas"},{"c":"","l":"y rebajen los cerros."},{"c":"","l":""},{"c":"","l":"*La flor se marchita, se seca el cardón"},{"c":"","l":"Convertite hermano que llega el Señor*"},{"c":"","l":""},{"c":"","l":"Enderecen las picadas,"},{"c":"","l":"los valles allánenlos"},{"c":"","l":"porque ya llega la gloria,"},{"c":"","l":"ya está viniendo el Señor."},{"c":"","l":""},{"c":"","l":"Subí, mensajero, al cerro,"},{"c":"","l":"gritá con toda tu voz"},{"c":"","l":"&ldquo;salgan con gozo a su encuentro,"},{"c":"","l":"está llegando el Señor&rdquo;."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (252, 'Anímate familia', '[{"c":"","l":"Llegando a Nazareth a un carpintero vi"},{"c":"","l":"Mostrándole a su hijo cómo cuesta subsistir"},{"c":"","l":"También a una mujer que al amasar el pan"},{"c":"","l":"Cantaba sin dejar de trabajar"},{"c":"","l":""},{"c":"","l":"Anímate familia, no calles tu voz,"},{"c":"","l":"Eleva tu mirada hacia el Señor"},{"c":"","l":"Pues dentro de tu seno surge el resplandor"},{"c":"","l":"Del hombre que descubre un nuevo sol"},{"c":"","l":""},{"c":"","l":"Familia debe ser un camino al amor"},{"c":"","l":"En medio de las luchas y el tropiezo del calor."},{"c":"","l":"Ejemplo de unidad en la desolación"},{"c":"","l":"Semilla de otra civilización."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (253, 'Y tú sí', '[{"c":"","l":"Hace mucho tiempo, allá en Nazaret"},{"c":"","l":"Vivía una niña que a Dios era fiel"},{"c":"","l":"Elegida desde siempre, casta y sencilla;"},{"c":"","l":"Que halló la gracia a los ojos de Dios."},{"c":"","l":"Siempre junto a Él, del principio al fin"},{"c":"","l":"Desde el día aquel en que el ángel Gabriel;"},{"c":"","l":"Le anunció con alegría:"},{"c":"","l":"“llega de gracia eres María..."},{"c":"","l":"Serás la madre del Hijo de Dios”"},{"c":"","l":""},{"c":"","l":"Y tú sí cambió la historia,"},{"c":"","l":"de tu sí nació la esperanza."},{"c":"","l":"Y tu si, le dio a la humanidad,"},{"c":"","l":"una nueva oportunidad."},{"c":"","l":"Y tú sí cambió la historia,"},{"c":"","l":"de tu sí nació la esperanza."},{"c":"","l":"Y de tu corazón"},{"c":"","l":"brotó la más linda canción"},{"c":"","l":"que nunca nadie pudo cantar a Dios"},{"c":"","l":""},{"c":"","l":"“Engrandece mi alma al Señor mi Dios"},{"c":"","l":"y mi espíritu se alegra en Dios mi Salvador"},{"c":"","l":"porque a puesto en mí sus ojos,"},{"c":"","l":"soy su humilde esclava..."},{"c":"","l":"bienaventurada por siempre me llamarán.”"},{"c":"","l":""},{"c":"","l":"Y tú sí cambió la historia,"},{"c":"","l":"de tu sí nació la esperanza."},{"c":"","l":"Y tú sí le dio a la humanidad"},{"c":"","l":"una nueva oportunidad."},{"c":"","l":"Enséñame, a decirle sí,"},{"c":"","l":"a Jesús que quiere que yo sea feliz"},{"c":"","l":"Y en su amor, me quiere regalar,"},{"c":"","l":"Otra mamá que me cuidará."},{"c":"","l":"Y que eres tú"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (254, 'Qué hermoso sueño soñé', '[{"c":"","l":"María soñé que tu niño,"},{"c":"","l":"que Jesús de Nazareth"},{"c":"","l":"había nacido en mi pago"},{"c":"","l":"qué hermoso sueño soñé."},{"c":"","l":""},{"c":"","l":"Y vi a mis campesinos,"},{"c":"","l":"ponerle al niño a sus pies"},{"c":"","l":"con la humildad de mi pueblo"},{"c":"","l":"ofrendas de amor y fe."},{"c":"","l":""},{"c":"","l":"Yo le traigo leche de cabra,"},{"c":"","l":"y al burrito alfalfa azul,"},{"c":"","l":"también un pan de algarrobo"},{"c":"","l":"para el niñito Jesús"},{"c":"","l":""},{"c":"","l":"María soñé que tu niño,"},{"c":"","l":"que Jesús de Nazareth"},{"c":"","l":"había nacido en mi pago"},{"c":"","l":"qué hermoso sueño soñé."},{"c":"","l":""},{"c":"","l":"Yo soy chayero María"},{"c":"","l":"busco en el río mi pan"},{"c":"","l":"le traigo un bagre de plata"},{"c":"","l":"y una flor de espuma y sal."},{"c":"","l":""},{"c":"","l":"Yo soy melero María,"},{"c":"","l":"traigo un payaso de miel"},{"c":"","l":"y un ramillete de trigo"},{"c":"","l":"que en el monte me encontré"},{"c":"","l":""},{"c":"","l":"Yo me llamo Juan Silencio"},{"c":"","l":"soy hachero  el Niño Dios"},{"c":"","l":"le hice una cruz de quebracho"},{"c":"","l":"y un caballito de sol"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ADVIENTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (255, 'Camino a Belén', '[{"c":"","l":"José, descendiente de David,"},{"c":"","l":"emprende su tu camino hacia Belén."},{"c":"","l":"Te espera la tristeza de no poder encontrar,"},{"c":"","l":"un lugar para que el niño nazca bien,"},{"c":"","l":"nazca bien."},{"c":"","l":""},{"c":"","l":"Camino a Belén, María con José,"},{"c":"","l":"las puertas se cierran a la llegada del rey,"},{"c":"","l":"no cierres las puertas, déjalo nacer,"},{"c":"","l":"no dejes que sufran nunca más,"},{"c":"","l":"María y José."},{"c":"","l":""},{"c":"","l":"María de la estirpe de David,"},{"c":"","l":"que llevas en tu vientre un manantial,"},{"c":"","l":"no temas al camino, porque Dios contigo está."},{"c":"","l":"No importa cuánto quede por llegar,"},{"c":"","l":"por llegar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (256, 'La peregrinación', '[{"c":"","l":"A la huella, a la huella, José y María,"},{"c":"","l":"por las pampas heladas, cardos y ortigas."},{"c":"","l":"A la huella, a la huella, cortando campo,"},{"c":"","l":"no hay cobijo ni fondas, sigan andando."},{"c":"","l":""},{"c":"","l":"Florecita del campo, clavel del aire,"},{"c":"","l":"si ninguno te aloja, adonde naces?"},{"c":"","l":"Dónde naces florcita que estas creciendo,"},{"c":"","l":"palomita asustada, grillo sin sueño."},{"c":"","l":""},{"c":"","l":"A la huella, a la huella,  José y María,"},{"c":"","l":"con un Dios escondido... nadie sabía!"},{"c":"","l":""},{"c":"","l":"A la huella, a la huella, los peregrinos."},{"c":"","l":"Préstenme una tapera, para mi niño."},{"c":"","l":"A la huella, a la huella, soles y lunas,"},{"c":"","l":"dos ojitos de almendra, piel de aceituna."},{"c":"","l":""},{"c":"","l":"Ay, burrito del campo! Ay, buey barcino!"},{"c":"","l":"mi niño ya viene, háganle sitio."},{"c":"","l":"Un ranchito de quincha solo me ampara"},{"c":"","l":"dos alientos amigos, la luna clara."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (257, 'Navidad', '[{"c":"","l":"Navidad, Navidad, mañana será Navidad"},{"c":"","l":"esta noche es la noche buena,"},{"c":"","l":"mañana será la Navidad."},{"c":"","l":""},{"c":"","l":"Niño Dios, niño Dios,"},{"c":"","l":"niño Dios de los changuitos,"},{"c":"","l":"que como ellos muy pobrecitos"},{"c":"","l":"en un ranchito vas a nacer."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (258, 'Los pastores', '[{"c":"","l":"Vengan pastores del campo"},{"c":"","l":"que el rey de los reyes ha nacido ya"},{"c":"","l":"Vengan antes que amanezca"},{"c":"","l":"que ya apunta el día y la noche se va"},{"c":"","l":""},{"c":"","l":"Albahaca y cedrón"},{"c":"","l":"tomillo y laurel,"},{"c":"","l":"que el niño se duerme"},{"c":"","l":"al amanecer."},{"c":"","l":""},{"c":"","l":"Lleguen de pinchas y chuqui,"},{"c":"","l":"de aminga y san Pedro, de arauco y poman."},{"c":"","l":"Antes que nadie lo adore"},{"c":"","l":"Que sirios y flores le van a llevar."},{"c":"","l":""},{"c":"","l":"Pídanle a julio romero"},{"c":"","l":"caballos de paso y su mula de andar"},{"c":"","l":"Con cajas y con guitarras"},{"c":"","l":"iremos cantando por el olivar."},{"c":"","l":""},{"c":"","l":"Hay navidad y hay mogasta,"},{"c":"","l":"hay ñapa y aloja no habrán de faltar"},{"c":"","l":"Mientras la luna riojana"},{"c":"","l":"se muere de ganas de participar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (259, 'La anunciación', '[{"c":"","l":"Jinete de un rayo rojo"},{"c":"","l":"Viene volando el ángel Gabriel"},{"c":"","l":"Con sable punta de estrella"},{"c":"","l":"Espuela  e plata estaba cate."},{"c":"","l":""},{"c":"","l":"Que dios te salve maría"},{"c":"","l":"La más bonita cuñatai"},{"c":"","l":"La flor está floreciendo"},{"c":"","l":"Crece en la sangre tu cunumi."},{"c":"","l":""},{"c":"","l":"Soy la esclava del señor"},{"c":"","l":"Que el haga su voluntad"},{"c":"","l":"Capullo que se hace flor"},{"c":"","l":"Y se abrirá en navidad."},{"c":"","l":""},{"c":"","l":"El ángel Gabriel ya vuelve"},{"c":"","l":"Al pago donde se encuentra dios."},{"c":"","l":"¿mamó parehó angelito"},{"c":"","l":"Que tan contento te vuelves vos?"},{"c":"","l":""},{"c":"","l":"He visto a la reina  el mundo"},{"c":"","l":"La más hermosa cuñataí;"},{"c":"","l":"Sus ojos son dos estrellas"},{"c":"","l":"Su voz el canto del yerutí"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (260, 'Noche anunciada', '[{"c":"","l":"Noche anunciada, noche de amor,"},{"c":"","l":"Dios ha nacido, pétalo y flor."},{"c":"","l":"Todo es silencio y serenidad"},{"c":"","l":"paz a los hombres: es Navidad."},{"c":"","l":""},{"c":"","l":"En el pesebre mi Redentor"},{"c":"","l":"es mensajero de paz y amor,"},{"c":"","l":"cuando sonríe se hace la luz,"},{"c":"","l":"y en sus bracitos crece una cruz."},{"c":"","l":""},{"c":"","l":"Ángeles canten sobre el portal,"},{"c":"","l":"Dios ha nacido, es Navidad"},{"c":"","l":""},{"c":"","l":"Esta es la noche que prometió."},{"c":"","l":"Dios a los hombres y ya llegó."},{"c":"","l":"Es Nochebuena, no hay que dormir."},{"c":"","l":"Dios ha nacido, Dios está aquí."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (261, 'Noche de paz', '[{"c":"","l":"Noche de paz, noche de amor,"},{"c":"","l":"todo duerme en derredor,"},{"c":"","l":"entre los astros que expanden su luz,"},{"c":"","l":"brilla anunciando al Niñito Jesús,"},{"c":"","l":"brilla la estrella de paz"},{"c":"","l":""},{"c":"","l":"Noche de amor, noche de paz,"},{"c":"","l":"Jesús nace en un portal,"},{"c":"","l":"llena la tierra la paz del Señor,"},{"c":"","l":"llena las almas la gracia de Dios."},{"c":"","l":"Porque nació el Redentor"},{"c":"","l":""},{"c":"","l":"Noche de paz, noche de amor,"},{"c":"","l":"todo canta en derredor."},{"c":"","l":"Clara se escucha la voz celestial,"},{"c":"","l":"llamando al hombre al pobre portal."},{"c":"","l":"Dios nos ofrece su amor"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (262, 'Vamos pastorcitos', '[{"c":"","l":"Vamos pastorcillos, vamos a Belén,"},{"c":"","l":"que en Belén acaba Jesús de nacer."},{"c":"","l":""},{"c":"","l":"Vamos pastorcillo, vamos a Belén,"},{"c":"","l":"que Dios ha nacido para nuestro bien."},{"c":"","l":""},{"c":"","l":"Esta feliz nueva debemos honrar,"},{"c":"","l":"y llenos de gozo a Dios alabar."},{"c":"","l":""},{"c":"","l":"Pobre, humilde‚ nace nuestro Redentor,"},{"c":"","l":"temblando de frío, por el pecador."},{"c":"","l":""},{"c":"","l":"¡Suenen las campanas, cante el corazón!"},{"c":"","l":"¡Todos a ser buenos que Cristo nació!"},{"c":"","l":""},{"c":"","l":"Un rústico techo, abrigo le da;"},{"c":"","l":"por cuna un pesebre, por templo un portal"},{"c":"","l":""},{"c":"","l":"Su madre en los brazos, meciéndolo está"},{"c":"","l":"y quiere dormirlo con dulce cantar"},{"c":"","l":""},{"c":"","l":"Un ángel responde al mismo compás:"},{"c":"","l":"Gloria en las alturas y en la tierra paz"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (263, 'Navidad II', '[{"c":"","l":"Campanas por doquier, resuenan sin cesar"},{"c":"","l":"proclaman con placer,  que hoy es Navidad"},{"c":"","l":"Los niños con canción,  la grata nueva dan"},{"c":"","l":"de este día de amor y buena voluntad."},{"c":"","l":""},{"c":"","l":"Navidad, navidad, hoy es navidad"},{"c":"","l":"Es un día de alegría y felicidad (2)"},{"c":"","l":""},{"c":"","l":"El niño de Belén, nos trae la salvación"},{"c":"","l":"con júbilo sin par, se entona la canción"},{"c":"","l":"Yo te amo, mi Señor, tus glorias cantaré"},{"c":"","l":"en este día tan feliz me regocijaré."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (264, 'Cristianos vayamos', '[{"c":"","l":"Cristianos vayamos, jubilosa el alma."},{"c":"","l":"Laestrella nos llama junto a Belén."},{"c":"","l":"Hoy ha nacido el Rey de los Cielos."},{"c":"","l":""},{"c":"","l":"¡Cristianos adoremos!"},{"c":"","l":"¡Cristianos adoremos!"},{"c":"","l":"¡Cristianos adoremos!"},{"c":"","l":"A nuestro Dios"},{"c":"","l":""},{"c":"","l":"Humildes pastores dejan su rebaño,"},{"c":"","l":"Y llevan sus dones al Niño Dios."},{"c":"","l":"Nuestrasofrendas con amor llevemos."},{"c":"","l":""},{"c":"","l":"Bendita la noche que nos trajo el Día."},{"c":"","l":"Bendita la noche de Navidad."},{"c":"","l":"Desde unpesebre el Señor nos llama."},{"c":"","l":""},{"c":"","l":"El Dios invisible vístese de carne."},{"c":"","l":"El Reyde la Gloria llorando está."},{"c":"","l":"Viene a latierra a darnos el Cielo."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (265, 'Virgen de la navidad', '[{"c":"","l":"Virgen María de la navidad"},{"c":"","l":"Danos el gozo, danos la paz"},{"c":"","l":"Danos un mundo de luz y amistad"},{"c":"","l":"Danos, oh madre, una navidad."},{"c":"","l":""},{"c":"","l":"En un mundo sembrado de odio"},{"c":"","l":"el Amorha querido habitar"},{"c":"","l":"una Virgen nos da laalegría,"},{"c":"","l":"una Virgen nos trae Navidad."},{"c":"","l":""},{"c":"","l":"A los pobres que velan sus penas,"},{"c":"","l":"Alque llora sin techo ni pan,"},{"c":"","l":"ha llegadouna luz de esperanza,"},{"c":"","l":"y con ella llegóNavidad."},{"c":"","l":""},{"c":"","l":"Cuando el hombre abandone la guerra,"},{"c":"","l":"cuando el odio se vuelva amistad"},{"c":"","l":"cuando todo sonría cantando,"},{"c":"","l":"cuandoamemos habrá Navidad."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (266, 'Llegaron ya los reyes eran tres', '[{"c":"","l":"Llegaron ya los reyes eran tres"},{"c":"","l":"Melchor,Gaspar y el negro Baltasar."},{"c":"","l":"Arrope ymiel, le llevaran"},{"c":"","l":"y un poncho blanco dealpaca real."},{"c":"","l":""},{"c":"","l":"Changos y chinitas duérmanse"},{"c":"","l":"Que ya Melchor, Gaspar y Baltasar"},{"c":"","l":"Todos los regalos traerán"},{"c":"","l":"Para jugar mañana al despertar"},{"c":"","l":""},{"c":"","l":"El niño Dios muy bien lo agradeció"},{"c":"","l":"comió la miel y el poncho, lo abrigó"},{"c":"","l":"yfue después, que sonrió"},{"c":"","l":"y a media noche el sol relumbró."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (267, 'Guachito torito', '[{"c":"","l":"Del árbol nació la rama"},{"c":"","l":"De la rama nació la flor"},{"c":"","l":"De la flor nació María,"},{"c":"","l":"De María el Señor."},{"c":"","l":""},{"c":"","l":"Huachito torito"},{"c":"","l":"torito del corralito"},{"c":"","l":"Huachito torito"},{"c":"","l":"torito del corralito."},{"c":"","l":"Al niño recién nacido"},{"c":"","l":"todos le ofrecen su done"},{"c":"","l":"yo soy pobre nada tengo"},{"c":"","l":"Le ofrezco mi corazone"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (268, 'Burrito sabanero', '[{"c":"","l":"Con mi burrito sabanero"},{"c":"","l":"voy camino de Belén"},{"c":"","l":""},{"c":"","l":"Si me ven, si me ven"},{"c":"","l":"voy camino de Belén"},{"c":"","l":""},{"c":"","l":"El lucerito mañanero"},{"c":"","l":"ilumina mi sendero"},{"c":"","l":""},{"c":"","l":"En mi burrito voy cantando,"},{"c":"","l":"mi burrito va trotando"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (269, 'Si cada día es navidad', '[{"c":"","l":"Si cada día es navidad, si cada día nace Dios"},{"c":"","l":"Nace la paz al corazón"},{"c":"","l":"Que sabe abrirse a los demás"},{"c":"","l":""},{"c":"","l":"Cuando acompañas al amigo"},{"c":"","l":"Quemarcha solo en el camino"},{"c":"","l":"Cuandoiluminas las tinieblas"},{"c":"","l":"del que va enbusca de una estrella"},{"c":"","l":"Tu corazónflorecerá"},{"c":"","l":"en una nueva Navidad. (2)"},{"c":"","l":""},{"c":"","l":"Cuando tú sientas sin falsía"},{"c":"","l":"del bienajeno la alegría"},{"c":"","l":"cuando sus lágrimas túsientas"},{"c":"","l":"y las compartas plenamente"},{"c":"","l":"Tu corazón florecerá"},{"c":"","l":"en una nuevaNavidad. (2)"},{"c":"","l":""},{"c":"","l":"Cuando eres fuente cristalina"},{"c":"","l":"Quedistribuye sin medida"},{"c":"","l":"cuando alhermano que te ofende"},{"c":"","l":"mano de amigotú le tiendes"},{"c":"","l":"Tu corazón florecerá"},{"c":"","l":"en una nuevaNavidad. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (270, 'Pregón navideño', '[{"c":"","l":"Oigan todos, esta buena,"},{"c":"","l":"que yo lesvengo a traer"},{"c":"","l":"hoy ha nacido unaestrella,"},{"c":"","l":"en la portal de Belén"},{"c":"","l":"hoy hanacido una estrella,"},{"c":"","l":"en el portal de Belén."},{"c":"","l":""},{"c":"","l":"Toda la esperanza de la humanidad"},{"c":"","l":"toda la esperanza de la Salvación"},{"c":"","l":"nosconducen a Ti, divino niño de Belén."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (271, 'Din don dan', '[{"c":"","l":"Din don dan, din don dan, vamos a cantar"},{"c":"","l":"La alegría de este día hay que festejar"},{"c":"","l":""},{"c":"","l":"Navidad llegó, y llegó la paz"},{"c":"","l":"En los corazones hay felicidad"},{"c":"","l":""},{"c":"","l":"Navidad llegó, y llegó el amor"},{"c":"","l":"En los corazones brilla la emoción"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (272, 'En el portal de Belén', '[{"c":"","l":"En el portal de Belén"},{"c":"","l":"hay estrellas, sol y luna,"},{"c":"","l":"la Virgen y San José"},{"c":"","l":"y el Niño que está en la cuna."},{"c":"","l":""},{"c":"","l":"Bailad pastorcillos,"},{"c":"","l":"bailad en Belén"},{"c":"","l":"que Dios ha nacido"},{"c":"","l":"para nuestro bien"},{"c":"","l":""},{"c":"","l":"En el portal de Belén"},{"c":"","l":"hay un arca chiquitita"},{"c":"","l":"donde se viste el Señor"},{"c":"","l":"para salir de visita."},{"c":"","l":""},{"c":"","l":"En el portal de Belén"},{"c":"","l":"hay un espejo dorado,"},{"c":"","l":"donde se mira el Señor"},{"c":"","l":"con la Virgen a su lado."},{"c":"","l":""},{"c":"","l":"Campanitas de Belén"},{"c":"","l":"a la madrugada suenan"},{"c":"","l":"para despertar al Niño"},{"c":"","l":"que ha nacido en Nochebuena."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (273, 'Hosanna eh', '[{"c":"","l":"*Hosanna eh! Hosanna ah!*"},{"c":"","l":""},{"c":"","l":"&Eacute;l es el Santo, es el hijo de María,"},{"c":"","l":"es el Dios de Israel,"},{"c":"","l":"es el hijo de David."},{"c":"","l":""},{"c":"","l":"Vamos a &Eacute;l, con espigas de mil trigos,"},{"c":"","l":"y con mil ramas de olivo,"},{"c":"","l":"siempre alegres, siempre en paz"},{"c":"","l":""},{"c":"","l":"&Eacute;l es el Cristo, es el unificador,"},{"c":"","l":"es Hosanna en las alturas,"},{"c":"","l":"es Hosanna en el amor."},{"c":"","l":""},{"c":"","l":"Es la alegría, la razón de mi existir,"},{"c":"","l":"es la vida de mis días,"},{"c":"","l":"es consuelo en mi sufrir"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (274, 'Mantos y palmas', '[{"c":"","l":"Mantos y palmas desplegando va"},{"c":"","l":"alegre el pueblo de Jerusalén"},{"c":"","l":"cuando a lo lejos se comienza a ver"},{"c":"","l":"a Cristo montado que llegando está."},{"c":"","l":""},{"c":"","l":"*Y mientras mil voces resuenan por ahí"},{"c":"","l":"hosanna al que viene en el nombre del Señor"},{"c":"","l":"y como un estruendo de gran aclamación"},{"c":"","l":"prorrumpen en voz triunfal."},{"c":"","l":""},{"c":"","l":"Hosanna, hosanna al rey*"},{"c":"","l":""},{"c":"","l":"En la mañana de Jerusalén"},{"c":"","l":"un día nosotros vamos a cantar"},{"c":"","l":"a Jesucristo que vendrá otra vez"},{"c":"","l":"para llevarnos a su eterno hogar."},{"c":"","l":""},{"c":"","l":"Como a la entrada de Jerusalén"},{"c":"","l":"Un día nosotros vamos a cantar"},{"c":"","l":"A Jesucristo que vendrá otra vez"},{"c":"","l":"Para llevarnos a su eterno hogar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (275, 'Ustedes son mis amigos', '[{"c":"","l":"Hijos míos,"},{"c":"","l":"voy a estar poco tiempo entre ustedes."},{"c":"","l":"Me buscarán,"},{"c":"","l":"mas donde voy no podrán venir."},{"c":"","l":"*Les doy un mandamiento nuevo:"},{"c":"","l":"&ldquo;ámense unos a otros,&rdquo;"},{"c":"","l":"así como los amé,"},{"c":"","l":"en esto todos verán:"},{"c":"","l":"que ustedes son mis amigos*"},{"c":"","l":""},{"c":"","l":"Si alguien me ama,"},{"c":"","l":"guardará todas mis palabras;"},{"c":"","l":"y mi Padre les hablará"},{"c":"","l":"y volveremos a él."},{"c":"","l":"*Les dejo la paz, les doy mi paz,"},{"c":"","l":"no como la da el mundo."},{"c":"","l":"No teman, ni se acobarden,"},{"c":"","l":"oyeron lo que les dije: me voy, pero volveré*"},{"c":"","l":""},{"c":"","l":"Ya no son"},{"c":"","l":"como el siervo que ignora a su dueño;"},{"c":"","l":"conocen bien lo que mi Padre"},{"c":"","l":"me ha dicho a mí."},{"c":"","l":"*Ustedes son mis amigos,"},{"c":"","l":"si hacen lo que les mando."},{"c":"","l":"Recuerden que los amé,"},{"c":"","l":"no me eligieron a mí,"},{"c":"","l":"soy Yo quien los ha elegido*"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (276, 'Niños hebreos(Francisco Palazón)', '[{"c":"","l":"Los niños hebreos, llevando ramos de olivo"},{"c":"","l":"salieron al encuentro del Señor aclamando"},{"c":"","l":"hosanna en el cielo,"},{"c":"","l":"hosanna en el cielo"},{"c":"","l":"hosanna en el cielo."},{"c":"","l":""},{"c":"","l":"Portones abrid los dinteles"},{"c":"","l":"que se alcen las puertas eternas."},{"c":"","l":"Va a entrar el rey de la gloria"},{"c":"","l":"el valeroso y Dios de Israel."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (277, 'Caminaré(J.Espinoza)', '[{"c":"","l":"Caminaré en presencia del Señor"},{"c":"","l":""},{"c":"","l":"Amo al Señor"},{"c":"","l":"porque escucha mi voz suplicante"},{"c":"","l":"porque inclina su oído hacia mí"},{"c":"","l":"el día que lo invoco."},{"c":"","l":""},{"c":"","l":"Me envolvían redes de muerte,"},{"c":"","l":"caí en tristeza y en angustia"},{"c":"","l":"invoqué el Nombre el Señor"},{"c":"","l":"Señor, salva mi vida."},{"c":"","l":""},{"c":"","l":"El Señor es benigno y justo"},{"c":"","l":"nuestro Dios es compasivo"},{"c":"","l":"el Señor guarda a los sencillos"},{"c":"","l":"estando yo sin fuerzas me salvó."},{"c":"","l":""},{"c":"","l":"Alma mía, recobra tu calma"},{"c":"","l":"que el Señor fue bueno contigo"},{"c":"","l":"arrancó mi alma de la muerte"},{"c":"","l":"mis ojos de las lágrimas,"},{"c":"","l":"mis pies de la caída."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (278, 'Sí, me levantaré(L.Deiss)', '[{"c":"","l":"Sí, me levantaré. Volveré junto a mi Padre"},{"c":"","l":""},{"c":"","l":"A ti, Señor, elevo mi alma."},{"c":"","l":"Tú eres mi Dios y mi Salvador."},{"c":"","l":""},{"c":"","l":"Mira mi angustia, mira mi pena"},{"c":"","l":"dame la gracia de tu perdón."},{"c":"","l":""},{"c":"","l":"Mi corazón busca tu Rostro"},{"c":"","l":"oye mi voz, Señor, ten piedad!"},{"c":"","l":""},{"c":"","l":"A Ti, Señor, te invoco y te llamo"},{"c":"","l":"Tú eres mi Roca, oye mi voz!"},{"c":"","l":""},{"c":"","l":"No pongas fin a tu ternura"},{"c":"","l":"haz que me guarde siempre tu amor."},{"c":"","l":""},{"c":"","l":"Sana mi alma y mi corazón"},{"c":"","l":"Porque pequé, Señor, contra Ti."},{"c":"","l":""},{"c":"","l":"Piedad de mí, oh Dios de ternura"},{"c":"","l":"lava mis culpas, oh Salvador!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (279, 'Me amo y se entregó por mi', '[{"c":"","l":"Tantas veces me he sentido mal."},{"c":"","l":"Es que no veía la verdad"},{"c":"","l":"que en la Cruz está Jesús crucificado"},{"c":"","l":"y murió cargando todos mis pecados."},{"c":"","l":""},{"c":"","l":"Y si yo tuviera que elegir"},{"c":"","l":"vivir ciego o mirarte a Ti"},{"c":"","l":"elegiría vivir lo que aprendí"},{"c":"","l":"que Jesús me amó y se entregó por mí."},{"c":"","l":""},{"c":"","l":"Esta pascua descubrí"},{"c":"","l":"una nueva entrega por amor"},{"c":"","l":"Que revive como el fuego que"},{"c":"","l":"Me enciende el corazón"},{"c":"","l":"Ilumina mi camina y me doy cuenta"},{"c":"","l":"Fuiste vos quien me amó y se entregó por mi"},{"c":"","l":"Él me amó y se entregó por mi"},{"c":"","l":"Y ahora yo me entrego a Ti"},{"c":"","l":""},{"c":"","l":"Cada vez que vuelva a dudar"},{"c":"","l":"sé que ahora voy a recordar"},{"c":"","l":"que Jesús vive y está resucitado"},{"c":"","l":"Él me salvó y tengo ganas de gritarlo."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (280, 'En la cruz', '[{"c":"","l":"Cuando yo te veo inmóvil en la Cruz"},{"c":"","l":"Siento tu mirada penetrar muy dentro"},{"c":"","l":"siento tu dolor caer sobre mi pecho"},{"c":"","l":"siento esos clavos hundiendo tus manos."},{"c":"","l":""},{"c":"","l":"Yo soy la cruz que te costó la vida"},{"c":"","l":"Por favor te ruego perdóname"},{"c":"","l":"Quisiera hoy bañar todo tu cuerpo"},{"c":"","l":"Con mi sangre pero es tan poca"},{"c":"","l":""},{"c":"","l":"A la sombra de este amor que día a día"},{"c":"","l":"Tú me quieres siempre brindar"},{"c":"","l":"te veo ypienso que yo mismo"},{"c":"","l":"con pequeñascosas voy matándote."},{"c":"","l":""},{"c":"","l":"Quisiera que recojas estas lágrimas"},{"c":"","l":"y conellas cures tus heridas."},{"c":"","l":"Pero sé queaunque yo te sienta lejos"},{"c":"","l":"escuchas micorazón que grita"},{"c":"","l":"Señor, ayúdame,ayúdame."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (281, 'Soy peregrino', '[{"c":"","l":"Soy peregrino en esta tierra"},{"c":"","l":"Marchocontento hacia Dios."},{"c":"","l":"Soy ciudadano desu Reino"},{"c":"","l":"voy anunciando su amor."},{"c":"","l":""},{"c":"","l":"Hay una estrella en mi camino"},{"c":"","l":"la luzdivina de la fe"},{"c":"","l":"ella señala mi destino"},{"c":"","l":"llegar a ti, Jerusalén."},{"c":"","l":""},{"c":"","l":"Soy peregrino y caminante"},{"c":"","l":"Soymensajero de la paz"},{"c":"","l":"traigo a loshombres el mensaje"},{"c":"","l":"que con nosotrosDios está."},{"c":"","l":""},{"c":"","l":"Soy luchador y peregrino"},{"c":"","l":"construir elmundo es mi misión"},{"c":"","l":"y completar así eldesignio"},{"c":"","l":"de nuestro Padre creador."},{"c":"","l":""},{"c":"","l":"Jerusalén el mundo nuevo"},{"c":"","l":"ciudad depaz y libertad"},{"c":"","l":"que va surgiendo desde elseno"},{"c":"","l":"de nuestra vida terrenal."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (282, 'Señor quien puede entrar', '[{"c":"","l":"¿Señor, quién puede entrar"},{"c":"","l":"en tu Santuario para adorar? (2)"},{"c":"","l":"“El de manos limpias y corazón puro"},{"c":"","l":"que no es vanidoso y sabe amar”. (2)"},{"c":"","l":""},{"c":"","l":"Señor, yo quiero entrar"},{"c":"","l":"en tu Santuario para adorar. (2)"},{"c":"","l":"Oh, limpia mis manos y mi corazón"},{"c":"","l":"mi vanidad quita y dame tu amor. (2)"},{"c":"","l":""},{"c":"","l":"Señor, ya puedo entrar"},{"c":"","l":"en tu Santuario para adorar. (2)"},{"c":"","l":"Tu Sangre me limpia, me otorga el perdón"},{"c":"","l":"tu Espíritu Santo me llena de amor. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (283, 'Oh victima inmolada', '[{"c":"","l":"Oh víctima inmolada"},{"c":"","l":"por nuestra redención"},{"c":"","l":"de cuyas llagas brotan"},{"c":"","l":"lasaguas del perdón."},{"c":"","l":""},{"c":"","l":"Con mis frecuentes culpas mil veces te ofendí."},{"c":"","l":"Perdona mis pecados Y ten piedad de mi"},{"c":"","l":""},{"c":"","l":"¡Oh, cuánto amor respira"},{"c":"","l":"tu abierto corazón!"},{"c":"","l":"tu muerte fue mi vida"},{"c":"","l":"tu Cruz, mi salvación."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (284, 'Abrazando el árbol de la cruz(Eduardo Meana)', '[{"c":"","l":"El Árbol de la Cruz de lejos te da miedo."},{"c":"","l":"El Árbol de la cruz te parece funesto."},{"c":"","l":"Sufría desnudez intimida tu carne."},{"c":"","l":"Surigidez mortal ¿quién puede acariciar?"},{"c":"","l":""},{"c":"","l":"Aquí, la áspera cruz, terrible, misteriosa."},{"c":"","l":"El silencio de Dios la envuelve y hacehermosa."},{"c":"","l":"El corazón de Dios estácrucificado."},{"c":"","l":"Aquí la humanidad cayó yse levantó."},{"c":"","l":""},{"c":"","l":"¡Oh árbol de muerte que Cristo abrazó"},{"c":"","l":"En árbol de vida te transfiguró!"},{"c":"","l":"Extiendo mis brazos y abrazo a mi Dios"},{"c":"","l":"Con Él doy el paso, mi pascua llegó"},{"c":"","l":"¡En el árbol de la cruz del Señor!"},{"c":"","l":""},{"c":"","l":"Aquí está el noble altar donde el dolor se ofrece."},{"c":"","l":"el signo sanador del mal de la serpiente."},{"c":"","l":"tabla de salvación que al náufrago ha salvado."},{"c":"","l":"leño de extremo amor y puente del perdón."},{"c":"","l":""},{"c":"","l":"¡Apiádate, oh Cruz, y tus ramas ablanda!"},{"c":"","l":"¡Doblega tu rigor, pues tan dulce es tu carga!"},{"c":"","l":"¡Suavízate y sostén al que lucha la Vida!"},{"c":"","l":"Y muestra a Aquél que está traspasado de Amor."},{"c":"","l":""},{"c":"","l":"Para entender la Cruz no basta con mirarla:"},{"c":"","l":"has de postrar tu amor, tu llaga tu esperanza."},{"c":"","l":"Misterio de la Cruz, que sólo al abrazarla"},{"c":"","l":"libera su poder y da Resurrección."},{"c":"","l":""},{"c":"","l":"Aquí descubrirás, con los brazos abiertos"},{"c":"","l":"que el Árbol se apiadó y se amoldó a tu cuerpo."},{"c":"","l":"Llevada con amor, su peso es llevadero."},{"c":"","l":"Árbol medicinal donde te cura Dios."},{"c":"","l":""},{"c":"","l":"Para el mundo es locura esta Sabiduría:"},{"c":"","l":"La Cruz de Cristo Puerta de nuestra Alegría."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (285, 'Quien quiera saber vivir', '[{"c":"","l":"Sabiendo que se acercaba"},{"c":"","l":"la hora de La Pasión,"},{"c":"","l":"Jesús con sus doce amigos,"},{"c":"","l":"por última vez comió…"},{"c":"","l":"En medio de aquella Cena,"},{"c":"","l":"les quiso mostrar Su amor:"},{"c":"","l":"Lavando los pies a todos,"},{"c":"","l":"lo mismo que un servidor…"},{"c":"","l":""},{"c":"","l":"Quien quiera saber vivir,"},{"c":"","l":"que viva para servir,"},{"c":"","l":"Quien quiera el primer lugar,"},{"c":"","l":"que aprenda a ser servicial."},{"c":"","l":""},{"c":"","l":"-“Señor, no te lo permito."},{"c":"","l":"No puedes lavar mis pies!!!”"},{"c":"","l":"-“Simón, lo que haré contigo,"},{"c":"","l":"muy pronto vas a entender;"},{"c":"","l":"Tu parte tendrás conmigo"},{"c":"","l":"si dejas lavar tus pies…”"},{"c":"","l":"-“Entonces mi cuerpo entero,"},{"c":"","l":"Señor, te lo entregaré!”"},{"c":"","l":""},{"c":"","l":"-“Si Yo que Soy El Maestro"},{"c":"","l":"les quise lavar los pies,"},{"c":"","l":"Fue sólo por dar ejemplo"},{"c":"","l":"de lo que tendrán que hacer."},{"c":"","l":"En el Reino de los Cielos,"},{"c":"","l":"las cosas son al revés:"},{"c":"","l":"Quien quiera ser el primero,"},{"c":"","l":"que sirva con sencillez…”"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (286, 'Madre del Mundo', '[{"c":"","l":"De este nuevo amanecer,"},{"c":"","l":"tú fuiste el crepúsculo mujer,"},{"c":"","l":"tú si fue la respuesta,"},{"c":"","l":"con que el Hombre Dios pudo nacer."},{"c":"","l":"En tu candoroso andar,"},{"c":"","l":"las heridas Cristo no sufrió,"},{"c":"","l":"tus brazos fueron cunas de sonrisas"},{"c":"","l":"y de algodón."},{"c":"","l":""},{"c":"","l":"Madre del mundo Virgen paciente,"},{"c":"","l":"tímido umbral que abres paso al cielo,"},{"c":"","l":"dicen que hoy muere en la cruz,"},{"c":"","l":"tu hijo Jesús."},{"c":"","l":""},{"c":"","l":"Crece un niño hasta los treinta,"},{"c":"","l":"como una hoja junto a ti, rama vital"},{"c":"","l":"pero este crudo otoño,"},{"c":"","l":"los hubo de separar."},{"c":"","l":"Pero llegará pronto el día,"},{"c":"","l":"en que lo vuelvas a ver María"},{"c":"","l":"en la gloria del reino celestial."},{"c":"","l":""},{"c":"","l":"De este triste amanecer,"},{"c":"","l":"tú fuiste el crepúsculo mujer."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (287, 'Resucitaré (Pablo Osow)', '[{"c":"","l":"Voy hacia el calvario, gente en el camino"},{"c":"","l":"la cruz en mi espalda, ganas de llorar."},{"c":"","l":"Siento las espinas, me hacen salir sangre, para eso he venido, no voy a parar."},{"c":"","l":""},{"c":"","l":"Rostros que me miran, los conozco a todos"},{"c":"","l":"veo a los que han muerto"},{"c":"","l":"y a los que vendrán,"},{"c":"","l":"leo sus historias, las cargo en mis hombros"},{"c":"","l":"pesan los pecados de la humanidad."},{"c":"","l":""},{"c":"","l":"Resucitaré, caminaré bajo el sol."},{"c":"","l":"Resucitaré, con el poder del amor. Resucitaré,"},{"c":"","l":"soy la semilla que muere por vos,"},{"c":"","l":"por vos, yo resucitaré,"},{"c":"","l":"pronto me levantaré."},{"c":"","l":"Resucitaré, rozará el viento mi piel."},{"c":"","l":"Resucitaré"},{"c":"","l":"y aunque el dolor atraviese mi ser"},{"c":"","l":"en la batalla final ganaré."},{"c":"","l":""},{"c":"","l":"Caigo pero sigo, sufro pero aguanto,"},{"c":"","l":"allí está mi madre, me quiere abrazar,"},{"c":"","l":"quisiera aferrarme fuerte de su mano,"},{"c":"","l":"su voz me conmueve, debo continuar."},{"c":"","l":"Algunos me ayudan, algunos se burlan,"},{"c":"","l":"otros ni me miran, por ellos también"},{"c":"","l":"por todos los hombres clavarán mis manos"},{"c":"","l":"y elevado en alto yo los atraeré."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (288, 'Hasta dar la vida (Eduardo Meana)', '[{"c":"","l":"Háblame ya amigo al corazón"},{"c":"","l":"descansa en vos mi frente mi vida en vos."},{"c":"","l":"Porque me rescataste del fatal secuestro,"},{"c":"","l":"porque me liberaste de mi eterna tumba."},{"c":"","l":""},{"c":"","l":"*Porque me amaste hasta dar la vida* x2"},{"c":"","l":""},{"c":"","l":"Tan asombrado miro todo acabó"},{"c":"","l":"manso te has dormido hermano y Dios."},{"c":"","l":"Muriendo descuajaste mi árbol más sombrío,"},{"c":"","l":"muriendo conquistaste el centro de mí mismo."},{"c":"","l":""},{"c":"","l":"*Porque me amaste hasta dar la vida* x2"},{"c":"","l":""},{"c":"","l":"Partir en una mesa y no guardar"},{"c":"","l":"amar y echar a vuelo, ya no aferrar."},{"c":"","l":"Yo recibí al nacer mi moneda dorada,"},{"c":"","l":"no la atesoraré quiero verla entregada."},{"c":"","l":""},{"c":"","l":"*Porque me amaste hasta dar la vida* x2"},{"c":"","l":""},{"c":"","l":"Cruzaré este mar, hasta dar la vida"},{"c":"","l":"Me levantaré, hasta dar la vida"},{"c":"","l":"Y saldré de mi, hasta dar la vida"},{"c":"","l":""},{"c":"","l":"*Porque me amaste hasta dar la vida* x2"},{"c":"","l":""},{"c":"","l":"Vos amigo fiel, hasta dar la vida"},{"c":"","l":"Precio del amor, hasta dar la vida"},{"c":"","l":"Cristo mi Señor, hasta dar la vida"},{"c":"","l":""},{"c":"","l":"*Porque me amaste hasta dar la vida* x2"},{"c":"","l":""},{"c":"","l":"Cristo buen pastor, hasta dar la vida"},{"c":"","l":"Espina y dolor, hasta dar la vida"},{"c":"","l":"Coraje y pasión, hasta dar la vida"},{"c":"","l":""},{"c":"","l":"*Porque me amaste hasta dar la vida* x2"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (289, 'Las siete palabras(Eduardo Meana)', '[{"c":"","l":"Jesús nazareno, rey de los judíos"},{"c":"","l":"Jesús de las siete palabras y un grito"},{"c":"","l":""},{"c":"","l":"Corazón amigo, corazón herido"},{"c":"","l":"Corazón de Cristo Jesús, yo confío en Vos."},{"c":"","l":""},{"c":"","l":"Ahí está tu madre, ahí está tu hijo,"},{"c":"","l":"conmigo estarás hoy en el paraíso."},{"c":"","l":""},{"c":"","l":"Perdónalos padre no saben lo que hacen,"},{"c":"","l":"Dios mío por qué me abandonaste."},{"c":"","l":""},{"c":"","l":"Dijo tengo sed lanzó un fuerte grito:"},{"c":"","l":"en tus manos padre encomiendo mi espíritu."},{"c":"","l":""},{"c":"","l":"Todo está cumplido y entrega su aliento,"},{"c":"","l":"y mana agua y sangre del costado abierto."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (290, 'Padre danos tu perdón', '[{"c":"","l":"Silencioso se le vio pasar, la gente le miraba."},{"c":"","l":"Con un gesto de dolor le vi llorar,"},{"c":"","l":"no sé porque lo odiaban."},{"c":"","l":""},{"c":"","l":"*Como a un ladrón lo condenaron a morir"},{"c":"","l":"y en su agonía con amor le oí decir."},{"c":"","l":"Padre pido por favor,"},{"c":"","l":"que perdones nuestro error,"},{"c":"","l":"Padre danos tu perdón.*"},{"c":"","l":""},{"c":"","l":"Multitudes lo siguieron hasta el fin,"},{"c":"","l":"algunos sollozaban."},{"c":"","l":"Más ninguno lo ayudaba en su sufrir,"},{"c":"","l":"más nadie hizo nada."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (291, 'En mi Getsemaní(Eduardo Meana)', '[{"c":"","l":"Para que mi amor no sea un sentimiento"},{"c":"","l":"tan sólo de deslumbramiento pasajero"},{"c":"","l":"para no gastar mis palabras más mías,"},{"c":"","l":"ni vaciar de contenido mi te quiero."},{"c":"","l":""},{"c":"","l":"Quiero hundir más hondo mi raíz en Ti"},{"c":"","l":"y cimentar en solidez éste mi afecto,"},{"c":"","l":"pues mi corazón que es inquieto y es frágil"},{"c":"","l":"sólo acierta si se abraza a tu proyecto."},{"c":"","l":""},{"c":"","l":"*Más allá de mis miedos,"},{"c":"","l":"más allá de mi inseguridad,"},{"c":"","l":"quiero darte mi respuesta."},{"c":"","l":"Aquí estoy para hacer tu voluntad,"},{"c":"","l":"para que mi amor sea decirte sí"},{"c":"","l":"hasta el final.*"},{"c":"","l":""},{"c":"","l":"Duermen su sopor y temen en el huerto"},{"c":"","l":"ni sus amigos acompañan al maestro,"},{"c":"","l":"si es hora de cruz, es de fidelidades"},{"c":"","l":"pero el mundo nunca quiere aceptar esto."},{"c":"","l":""},{"c":"","l":"Dame comprender Señor tu amor tan puro,"},{"c":"","l":"amor que persevera en cruz, amor perfecto,"},{"c":"","l":"dame serte fiel cuando todo está oscuro,"},{"c":"","l":"para que mi amor no sea un sentimiento."},{"c":"","l":""},{"c":"","l":"No es en las palabras ni es en las promesas"},{"c":"","l":"donde la historia tiene su motor secreto,"},{"c":"","l":"solo es el amor, en la cruz madurado,"},{"c":"","l":"el amor que mueve a todo el universo."},{"c":"","l":""},{"c":"","l":"Pongo mi pequeña vida hoy en tus manos"},{"c":"","l":"por sobre mis seguridades y mis miedos,"},{"c":"","l":"y para elegir tu querer y no el mío"},{"c":"","l":"hazme en mi Getsemaní fiel y despierto."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (292, 'Cristo calla', '[{"c":"","l":"Si pudiera preguntarte tantas cosas,"},{"c":"","l":"aquellas que por hombre no comprendo,"},{"c":"","l":"¿cómo pudiste abrigar un sentimiento"},{"c":"","l":"de tan inmenso amor y estar muriendo?"},{"c":"","l":"Y como soportar que no entendieran"},{"c":"","l":"todo el dolor del mundo a tus espaldas"},{"c":"","l":"si hasta sudaste sangre en aquel huerto,"},{"c":"","l":"sintiendo la traición de aquel que amabas."},{"c":"","l":""},{"c":"","l":"*Te dolió, te dolió tanto"},{"c":"","l":"que golpearan tu cuerpo hasta cansarse"},{"c":"","l":"pero quizás te doliera más el alma"},{"c":"","l":"pensar que no entendieron tu mensaje.*"},{"c":"","l":""},{"c":"","l":"Porque callaste Cristo tantas veces,"},{"c":"","l":"porque dejaste al hombre no escucharte"},{"c":"","l":"acaso fue tu amor tan infinito"},{"c":"","l":"que pudo con la angustia confortarte."},{"c":"","l":"Hoy llevas esa cruz y es por mi culpa,"},{"c":"","l":"no pude levantar en su momento"},{"c":"","l":"por culpa día a día de mi ofensa,"},{"c":"","l":"tienes que soportar el sufrimiento"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (293, 'Diario de María', '[{"c":"","l":"Te miro a los ojos, y entre tanto llanto,"},{"c":"","l":"parece mentira que te hayan clavado."},{"c":"","l":"Que seas el pequeño a quien yo acunaba,"},{"c":"","l":"el que se dormía tan pronto en mis brazos."},{"c":"","l":"El que se reía al mirar el cielo,"},{"c":"","l":"y cuando rezaba, se ponía serio."},{"c":"","l":""},{"c":"","l":"Sobre este madero veo al pequeño"},{"c":"","l":"que entre los doctores hablaba en el templo."},{"c":"","l":"Cuando pregunte, respondió con calma"},{"c":"","l":"que de los asuntos de Dios se encargaba."},{"c":"","l":"Ese mismo hombre, el que está en la cruz,"},{"c":"","l":"el Dios de los hombres, se llama Jesús."},{"c":"","l":""},{"c":"","l":"Ese mismo hombre ya no era el niño"},{"c":"","l":"que en aquellas bodas, le pedí más vino."},{"c":"","l":"Que dio de comer, a un millón de gente,"},{"c":"","l":"y a pobres y enfermos los miró de frente."},{"c":"","l":"Que rió con aquellos a quienes más quiso,"},{"c":"","l":"y lloró en silencio, al morir su amigo"},{"c":"","l":""},{"c":"","l":"Cae ya la tarde, se nublan los cielos,"},{"c":"","l":"pronto volverás con tu Padre eterno."},{"c":"","l":"Duérmete pequeño, duérmete mi niño,"},{"c":"","l":"que yo te daré todo mi cariño."},{"c":"","l":"Como en Nazaret aquella mañana"},{"c":"","l":"he aquí tu sierva, he aquí tu esclava."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (294, 'Martillé', '[{"c":"","l":"La cabeza colgando,"},{"c":"","l":"y las manos destrozadas,"},{"c":"","l":"y los pies sangrando."},{"c":"","l":"Una cruz, varios clavos"},{"c":"","l":"y una corona de espinas"},{"c":"","l":"para mi hermano."},{"c":"","l":""},{"c":"","l":"Yo, Señor, con estas manos martillé"},{"c":"","l":"y me mirabas, y me lo dejabas hacer."},{"c":"","l":""},{"c":"","l":"Te ofendí en tu cara,"},{"c":"","l":"cómo puede ser Señor"},{"c":"","l":"que me digas que me amas"},{"c":"","l":"y que le pidas al Padre"},{"c":"","l":"que perdone lo que estoy haciendo"},{"c":"","l":"en vez de odiarme."},{"c":"","l":""},{"c":"","l":"Y tus ojos se cierran"},{"c":"","l":"Pero en vez de condenarme"},{"c":"","l":"me miran en forma tierna."},{"c":"","l":"Y se hiela mi sangre"},{"c":"","l":"porque he matado a mi hermano"},{"c":"","l":"que vino para salvarme."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (295, 'Él vive(Metanoia)', '[{"c":"","l":"No se enciende una luz"},{"c":"","l":"para no dejarla brillar."},{"c":"","l":"Ni se emprende un camino"},{"c":"","l":"que luego no has de seguir."},{"c":"","l":"No se escucha del cielo"},{"c":"","l":"un mensaje para callar."},{"c":"","l":"Ni se puede ser libre"},{"c":"","l":"si piensas que has de morir."},{"c":"","l":"No se puede creer en Cristo,"},{"c":"","l":"sólo por lo que oyes o has visto."},{"c":"","l":"Tú debes creer porque Él se entregó,"},{"c":"","l":"con todo su ser, por ti por amor."},{"c":"","l":""},{"c":"","l":"Él vive en ti y en mí, y en aquel"},{"c":"","l":"que cree en su nombre y practica el bien, sabe esperar, aun sin ver"},{"c":"","l":"pone su confianza en Dios."},{"c":"","l":"Él vive, Él no está allí, mira bien,"},{"c":"","l":"la tumba vacía nos dejó,"},{"c":"","l":"el amor venció al final,"},{"c":"","l":"y en la cruz selló su victoria Él vive"},{"c":"","l":""},{"c":"","l":"Puede caerse del cielo"},{"c":"","l":"o cubrirnos la tempestad,"},{"c":"","l":"y hasta puede que miedo llegue a nuestro corazón."},{"c":"","l":"Pero ten la certeza que no existe oscuridad,"},{"c":"","l":"que haga cesar el fuego,"},{"c":"","l":"que alumbra la salvación."},{"c":"","l":"No existe sombra ni penumbra,"},{"c":"","l":"que empañe su amor que deslumbra."},{"c":"","l":"De Él es el poder, la gloria y la verdad,"},{"c":"","l":"el que crea en Él nunca morirá"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (296, 'Vive Jesús', '[{"c":"","l":"Vive Jesús, el Señor."},{"c":"","l":"Vive Jesús, el Señor"},{"c":"","l":""},{"c":"","l":"Él vive, Él vive, vive!"},{"c":"","l":"Vive Jesús, el Señor!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (297, 'Suenen campanas', '[{"c":"","l":"Suenen campanas, suenen tambores,"},{"c":"","l":"suenen guitarras y hosannas a Dios,"},{"c":"","l":"renace el día, surge la luz,"},{"c":"","l":"cantemos hermanos, un himno a Jesús."},{"c":"","l":""},{"c":"","l":"¡Porque Cristo resucitó,"},{"c":"","l":"porque Cristo resucitó,"},{"c":"","l":"porque Cristo resucitó!"},{"c":"","l":""},{"c":"","l":"Canta el ave, brinca el ganado,"},{"c":"","l":"toda tristeza ya es del pasado,"},{"c":"","l":"hoy la alegría inunda a los hombres,"},{"c":"","l":"del niño al más grande, del rico al más pobre."},{"c":"","l":""},{"c":"","l":"El hombre nuevo surge en el mundo,"},{"c":"","l":"hay en las cosas un cambio profundo;"},{"c":"","l":"Pascua de Cristo, resurrección,"},{"c":"","l":"paso del hombre a la Vida de Dios."},{"c":"","l":""},{"c":"","l":"Desde hoy la muerte ha sido vencida,"},{"c":"","l":"y es nuestra fe un canto a la vida;"},{"c":"","l":"suenen campanas, suenen tambores,"},{"c":"","l":"suenen guitarras y hosannas a Dios."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (298, 'Haces nuevas todas las cosas', '[{"c":"","l":"Hey!, que haces nuevas todas las cosas"},{"c":"","l":"que haces nuevas todas las cosas."},{"c":"","l":""},{"c":"","l":"Es vida que brota en la vida"},{"c":"","l":"es fruto que crece en amor"},{"c":"","l":"es vida que vence a la muerte"},{"c":"","l":"es vida que viene de Dios."},{"c":"","l":""},{"c":"","l":"Dejaste el sepulcro vacío"},{"c":"","l":"la muerte no te derrotó"},{"c":"","l":"la piedra que te detenía"},{"c":"","l":"el día tercero cayó."},{"c":"","l":""},{"c":"","l":"Me ofreces una nueva vida"},{"c":"","l":"renuevo en ti el amor"},{"c":"","l":"me das una nueva esperanza"},{"c":"","l":"ya todo lo viejo pasó."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (299, 'Reina del Cielo alégrate', '[{"c":"","l":"Reina del Cielo alégrate, aleluya!"},{"c":"","l":"Porque el Señor,"},{"c":"","l":"a quien mereciste llevar, aleluya!"},{"c":"","l":"resucitó según su palabra, aleluya!"},{"c":"","l":"Ruega al Señor por nosotros, aleluya!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (300, 'Reina del Cielo', '[{"c":"","l":"Virgen María alégrate."},{"c":"","l":"Reina del cielo,alégrate."},{"c":"","l":"Alégrate, alégrate"},{"c":"","l":"salta degozo, alégrate."},{"c":"","l":""},{"c":"","l":"Alégrate, alégrate, virgen María alégrate"},{"c":"","l":""},{"c":"","l":"Brilla una luz, alégrate"},{"c":"","l":"en las tinieblas,alégrate."},{"c":"","l":"Alégrate, alégrate"},{"c":"","l":"Porquebrilló la luz de Dios."},{"c":"","l":""},{"c":"","l":"Vive el Señor, alégrate"},{"c":"","l":"vive en nosotros,alégrate."},{"c":"","l":"Alégrate, alégrate"},{"c":"","l":"porque elSeñor resucitó."},{"c":"","l":""},{"c":"","l":"Virgen María alégrate"},{"c":"","l":"somos tus hijosalégrate."},{"c":"","l":"Alégrate, alégrate"},{"c":"","l":"somos tushijos protégenos."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (301, 'Regina coeli(P.Catena)', '[{"c":"","l":"Alégrate, María, aleluia,"},{"c":"","l":"la pascua estácumplida, aleluia."},{"c":"","l":""},{"c":"","l":"Oye, madre, nuestra voz"},{"c":"","l":"Por nosotros ruega a Dios"},{"c":"","l":"¡Salve, salve, salve María!"},{"c":"","l":""},{"c":"","l":"Resucitó tu Hijo, aleluia"},{"c":"","l":"según Él lopredijo, aleluia."},{"c":"","l":""},{"c":"","l":"Sufriste con tu Hijo, aleluia"},{"c":"","l":"hoy gozasde su triunfo, aleluia."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (302, 'Esta es el agua(P.Catena)', '[{"c":"","l":"Esta es el agua pura"},{"c":"","l":"Que el creador nos dio"},{"c":"","l":"Esta es el agua nueva"},{"c":"","l":"Que de la cruz brotó"},{"c":"","l":""},{"c":"","l":"Del agua y del Espíritu la vida comenzó"},{"c":"","l":"por el agua del bautismo la nuevacreación."},{"c":"","l":""},{"c":"","l":"El agua de nuestros ríos, vida y salud nosda"},{"c":"","l":"y las aguas del bautismo vida eternadan."},{"c":"","l":""},{"c":"","l":"Por el paso del mar, Rojo Dios a Israel libró"},{"c":"","l":"en el agua del bautismo nace el Pueblo de Dios."},{"c":"","l":""},{"c":"","l":"Jesús recibió el Espíritu en el río Jordán"},{"c":"","l":"nuestro pueblo en el bautismo nace a lalibertad."},{"c":"","l":""},{"c":"","l":"Del pecho abierto de Cristo sangre y aguabrotó"},{"c":"","l":"es el agua del bautismo que da lasalvación."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (303, 'Jesús está vivo', '[{"c":"","l":"Jesús está vivo, Jesús es Señor."},{"c":"","l":"Por eso proclamo, proclamo su amor. (2)"},{"c":"","l":"En mi vida puedo ver su amor."},{"c":"","l":"El correr de su agua viva, que calma mi sed. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (304, 'Cristo nuestro hermano', '[{"c":"","l":"Porque Cristo nuestro hermano"},{"c":"","l":"Ha resucitado, Iglesia alégrate."},{"c":"","l":"Porque Cristo nuestro hermano"},{"c":"","l":"ha resucitado, Iglesia alégrate."},{"c":"","l":""},{"c":"","l":"¡Aleluya! (6)"},{"c":"","l":""},{"c":"","l":"Porque Cristo nuestro hermano"},{"c":"","l":"nos ha redimido, Iglesia alégrate."},{"c":"","l":"Porque Cristo nuestro hermano"},{"c":"","l":"nos ha redimido, Iglesia alégrate."},{"c":"","l":""},{"c":"","l":"Porque en Cristo nuestro hermano"},{"c":"","l":"hemos renacido, Iglesia alégrate."},{"c":"","l":"Porque en Cristo nuestro hermano"},{"c":"","l":"hemos renacido, Iglesia alégrate."},{"c":"","l":""},{"c":"","l":"Porque en Cristo nuestro hermano"},{"c":"","l":"todos somos hijos, Iglesia alégrate."},{"c":"","l":"Porque en Cristo nuestro hermano"},{"c":"","l":"todos somos hijos, Iglesia alégrate."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (305, 'Hoy la Iglesia victoriosa', '[{"c":"","l":"Hoy la Iglesia victoriosa canta y goza."},{"c":"","l":"Cristo surge bello y fuerte de la muerte"},{"c":"","l":"hoy es día de victoria y de gloria"},{"c":"","l":"todosjuntos celebremos y cantemos"},{"c":"","l":"aleluia, aleluia, aleluia."},{"c":"","l":""},{"c":"","l":"Sobre el tronco desechado del pecado"},{"c":"","l":"nueva savia reverdece y florece;"},{"c":"","l":"porJesús es redimida nuestra vida."},{"c":"","l":"Elredime con su muerte, nuestra muerte"},{"c":"","l":"aleluia, aleluia, aleluia."},{"c":"","l":""},{"c":"","l":"Renaciendo a nuestra vida, nos convida"},{"c":"","l":"a vivir ya, desde el suelo para el cielo"},{"c":"","l":"esla gloria del maestro, triunfo nuestro"},{"c":"","l":"surgiremos jubilosos y gloriosos"},{"c":"","l":"aleluia,aleluia,aleluia."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (306, 'La gran noticia', '[{"c":"","l":"Esta es la gran noticia:"},{"c":"","l":"“que Jesúsresucitó"},{"c":"","l":"que no hay muerte sólo hayvida"},{"c":"","l":"vida plena nos da Dios”."},{"c":"","l":""},{"c":"","l":"Por la Pascua Dios nos llama"},{"c":"","l":"a vivir enplenitud;"},{"c":"","l":"el camino está marcado"},{"c":"","l":"es elpaso de Jesús"},{"c":"","l":"por la muerte a la vida"},{"c":"","l":"de la sombra a su luz."},{"c":"","l":""},{"c":"","l":"Alegría en el cielo"},{"c":"","l":"y en la tierra gozo ypaz"},{"c":"","l":"porque Cristo ha vencido"},{"c":"","l":"parasiempre todo mal;"},{"c":"","l":"con su graciacaminamos"},{"c":"","l":"a la fiesta celestial."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (307, 'Cristo es la luz', '[{"c":"","l":"De la sombra de la muerte (2)"},{"c":"","l":"SurgeCristo, nueva vida, (2)"},{"c":"","l":"de la sombra delpecado (2)"},{"c":"","l":"un nuevo hombre resucita.(2)"},{"c":"","l":""},{"c":"","l":"Cristo es la luz, Cristo es el sol"},{"c":"","l":"Cristo esel resplandor"},{"c":"","l":"Cristo es la luz, Cristo esel sol"},{"c":"","l":"que a la noche venció."},{"c":"","l":""},{"c":"","l":"Las tinieblas de la noche (2)"},{"c":"","l":"se hanrasgado con el día. (2)"},{"c":"","l":"Las tinieblas dela muerte (2)"},{"c":"","l":"en Jesús quedanvencidas. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (308, 'Muévete en mi', '[{"c":"","l":"El Espíritu de Dios está en este lugar"},{"c":"","l":"El Espíritu de Dios se mueve en este lugar."},{"c":"","l":"Está aquí para consolar,"},{"c":"","l":"está aquí para liberar,"},{"c":"","l":"está aquí para guiar,"},{"c":"","l":"el Espíritu de Dios está aquí"},{"c":"","l":""},{"c":"","l":"Muévete en mí, muévete en mi"},{"c":"","l":"toca mi mente y mi corazón"},{"c":"","l":"Llena mi vida de tu amor"},{"c":"","l":"Muévete en mí, Dios Espíritu,"},{"c":"","l":"muévete en mi."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (309, 'Me quiero sumergir', '[{"c":"","l":"Quiero sumergirme en lo profundo"},{"c":"","l":"del Espíritu de Dios"},{"c":"","l":"y descubrir Su riqueza"},{"c":"","l":"en mi corazón"},{"c":"","l":""},{"c":"","l":"Es tan lindo, tan simple"},{"c":"","l":"Brisa leve tan suave dulce Espíritu"},{"c":"","l":"Santo de Dios"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (310, 'Espíritu de Dios', '[{"c":"","l":"Espíritu de Dios, ven a mi vida,"},{"c":"","l":"Ven a mi alma, ven a mi ser."},{"c":"","l":"Lléname con tu presencia,"},{"c":"","l":"con tu poder, con tu bondad."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (311, 'Bautízame Señor', '[{"c":"","l":"Bautízame Señor con tu Espíritu"},{"c":"","l":""},{"c":"","l":"Y déjame sentir, el fuego de tu amor"},{"c":"","l":"aquí en mi corazón Señor"},{"c":"","l":""},{"c":"","l":"Úngeme…Sáname…Límpiame…"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (312, 'Maranatha(Ariel Glaser)', '[{"c":"","l":"Ven Espíritu de Dios,"},{"c":"","l":"Inúndame de amor,"},{"c":"","l":"ayúdame a seguir."},{"c":"","l":"Ven y dame Tu calor,"},{"c":"","l":"quema mi corazón,"},{"c":"","l":"Enséñame a servir."},{"c":"","l":""},{"c":"","l":"Ven Espíritu de Dios,"},{"c":"","l":"ven a mi ser, ven a mi vida."},{"c":"","l":"Ven Espíritu de amor,"},{"c":"","l":"ven a morar, Maranatha."},{"c":"","l":""},{"c":"","l":"Hoy la vida que me das,"},{"c":"","l":"Te invoca en mi dolor"},{"c":"","l":"Y clama: “ven Señor”."},{"c":"","l":"Ven y cambia mi existir"},{"c":"","l":"Transforma mi penar,"},{"c":"","l":"En glorias hacia Ti."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (313, 'Recibirán(Pablo Martínez)', '[{"c":"","l":"Espíritu que nos da la vida,"},{"c":"","l":"y fortaleza para vivir,"},{"c":"","l":"el Evangelio que tú nos diste,"},{"c":"","l":"y nos animas a compartir!"},{"c":"","l":"Espíritu que nos da audacia,"},{"c":"","l":"y la fuerza para seguir,"},{"c":"","l":"el camino de Jesucristo,"},{"c":"","l":"y así su querer cumplir."},{"c":"","l":""},{"c":"","l":"Recibirán la fuerza de lo alto,"},{"c":"","l":"el Espíritu Santo, con ustedes estará."},{"c":"","l":"Recibirán la fuerza del alto,"},{"c":"","l":"y serán mis testigos,"},{"c":"","l":"cerca o lejos, hasta el final!"},{"c":"","l":""},{"c":"","l":"Espíritu que nos prometiste,"},{"c":"","l":"y lo enviaste a conducir,"},{"c":"","l":"que nos oriente en el camino,"},{"c":"","l":"de ser testigos de tu amor."},{"c":"","l":"Que saque el miedo que nos retiene,"},{"c":"","l":"y no nos deja salir y andar."},{"c":"","l":"Que nos sacuda y nos de coraje,"},{"c":"","l":"para a todos anunciar!"},{"c":"","l":""},{"c":"","l":"Espíritu que lo enviaste,"},{"c":"","l":"y así la Iglesia supo nacer,"},{"c":"","l":"Cambió las vidas, se abrieron puertas,"},{"c":"","l":"soltaron voces y de Dios se habló."},{"c":"","l":"Necesitamos de nuevo Fuego,"},{"c":"","l":"y así encienda nuestra pasión."},{"c":"","l":"Necesitamos de un nuevo viento,"},{"c":"","l":"Yque nos mueva el corazón"},{"c":"","l":""},{"c":"","l":"Espíritu que eres el Maestro,"},{"c":"","l":"que nos enseñas a como orar,"},{"c":"","l":"que tú nos unas y nos reúnas,"},{"c":"","l":"para formar la comunidad."},{"c":"","l":"Sabemos que somos hoy tu templo,"},{"c":"","l":"y como sello grabado estás."},{"c":"","l":"Regálanos en los sacramentos,"},{"c":"","l":"alcanzar la santidad."},{"c":"","l":""},{"c":"","l":"Espíritu que quieres al Joven,"},{"c":"","l":"y que lo invitas a ser feliz."},{"c":"","l":"Hoy te pedimos por nuestros pares,"},{"c":"","l":"que al no tenerte, vemos sufrir."},{"c":"","l":"Una misión nueva nos espera,"},{"c":"","l":"llevarte hoy a la juventud,"},{"c":"","l":"contarles con sus propias palabras,"},{"c":"","l":"que lo que buscan es a Jesús."},{"c":"","l":""},{"c":"","l":"Y nos ponemos hoy al servicio,"},{"c":"","l":"aquí nos tienes, aquí Señor."},{"c":"","l":"Testimoniando con alegría,"},{"c":"","l":"la Fe y la Vida que tus nos das."},{"c":"","l":"Espíritu que te derramaste,"},{"c":"","l":"aquel domingo en Jerusalén,"},{"c":"","l":"para la Iglesia y el mundo entero,"},{"c":"","l":"regala un nuevo Pentecostés"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (314, 'Enséñame a orar', '[{"c":"","l":"Santo, Espíritu Santo,"},{"c":"","l":"enséñame a orar"},{"c":"","l":"y a confiar en Ti."},{"c":"","l":"Llena de gozo mi alma,"},{"c":"","l":"y afianza tu amor,"},{"c":"","l":"tu amor en mí."},{"c":"","l":""},{"c":"","l":"Me dijiste que las aguas"},{"c":"","l":"que sean amargas se convertirán,"},{"c":"","l":"que al mezclarse con tu rio,"},{"c":"","l":"con tu dulce rio,"},{"c":"","l":"más dulces se harán."},{"c":"","l":""},{"c":"","l":"Quizás las aguas amargas"},{"c":"","l":"que están en mi alma, me hacen dudar"},{"c":"","l":"hazme beber de tu rio,"},{"c":"","l":"de tu dulce rio,"},{"c":"","l":"y enséñame a amar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (315, 'Si tú no vienes(Eduardo Meana)', '[{"c":"","l":"Si Tú no vienes"},{"c":"","l":"nos faltarán las alas para la plegaria,"},{"c":"","l":"desgastaremos el silencio y las palabras,"},{"c":"","l":"si en lo escondido tu voz no clama."},{"c":"","l":""},{"c":"","l":"Si Tú no vienes"},{"c":"","l":"será imposible el abrazo del reencuentro,"},{"c":"","l":"con el hermano que la ofensa puso lejos,"},{"c":"","l":"si Tú no enciendes de nuevo el fuego."},{"c":"","l":""},{"c":"","l":"Pero si vienes a recrearnos"},{"c":"","l":"y como un soplo das vida al barro,"},{"c":"","l":"como un artista    irás plasmando"},{"c":"","l":"un rostro nuevo de hijos y hermanos."},{"c":"","l":"Por eso ven"},{"c":"","l":""},{"c":"","l":"Espíritu Santo ven,"},{"c":"","l":"Espíritu Santo ven."},{"c":"","l":""},{"c":"","l":"Si Tú no vienes"},{"c":"","l":"olvidaremos la esperanza que llevamos,"},{"c":"","l":"sucumbiremos al desánimo y al llanto,"},{"c":"","l":"si Tú no vienes a consolarnos."},{"c":"","l":""},{"c":"","l":"Si Tú no vienes"},{"c":"","l":"evitaremos el camino aconsejado,"},{"c":"","l":"por el Señor de las espinas y el calvario,"},{"c":"","l":"si Tú no vienes a recordarlo."},{"c":"","l":""},{"c":"","l":"Pero si vienes a sostenernos"},{"c":"","l":"y nos conduces como maestro,"},{"c":"","l":"en nuestra carne se irá escribiendo"},{"c":"","l":"cada palabra del evangelio."},{"c":"","l":"Por eso ven"},{"c":"","l":""},{"c":"","l":"Espíritu Santo ven,"},{"c":"","l":"Espíritu Santo ven."},{"c":"","l":""},{"c":"","l":"Si Tú no vienes"},{"c":"","l":"nuestra mirada será ciega ante tus rastros,"},{"c":"","l":"la poca fe dominará lo cotidiano,"},{"c":"","l":"si no nos donas el ser más sabios."},{"c":"","l":""},{"c":"","l":"Si Tú no vienes"},{"c":"","l":"y no sacudes con tu viento nuestras casas,"},{"c":"","l":"y con un sello de profetas nos consagras,"},{"c":"","l":"tendremos miedo si no nos cambias."},{"c":"","l":""},{"c":"","l":"Pero si vienes y en el silencio"},{"c":"","l":"del alma escribes renglones nuevos,"},{"c":"","l":"entre nosotros se irá tejiendo"},{"c":"","l":"la historia cierta del nuevo reino."},{"c":"","l":"Por eso ven"},{"c":"","l":""},{"c":"","l":"Espíritu Santo ven,"},{"c":"","l":"Espíritu Santo ven."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (316, 'Cierva', '[{"c":"","l":"Así como la cierva,"},{"c":"","l":"suspira por las aguas."},{"c":"","l":"Así suspira mi alma,"},{"c":"","l":"Espíritu de Dios."},{"c":"","l":""},{"c":"","l":"Oh lléname Espíritu, lléname Espíritu,"},{"c":"","l":"lléname Espíritu de Dios"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (317, 'Espíritu desciende', '[{"c":"","l":"Espíritu de Dios, desciende."},{"c":"","l":"Espíritu de Dios ven a mi ser."},{"c":"","l":"Ven a mi alma,"},{"c":"","l":"con tu presencia transfórmame."},{"c":"","l":""},{"c":"","l":"Espíritu de Dios, desciende."},{"c":"","l":"Espíritu de Dios ven a mi interior."},{"c":"","l":"Llena mi alma,"},{"c":"","l":"con tu consuelo dame tu amor"},{"c":"","l":""},{"c":"","l":"Suave brisa, suave fuego,"},{"c":"","l":"huésped divino de mi Señor."},{"c":"","l":"Llena mi alma,"},{"c":"","l":"con tu consuelo dame tu amor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (318, 'Sumérgeme', '[{"c":"","l":"Cansado del camino, sediento de Ti,"},{"c":"","l":"un desierto he cruzado,"},{"c":"","l":"sin fuerzas he quedado, vengo a Ti."},{"c":"","l":"Luché como un soldado,"},{"c":"","l":"y a veces sufrí,"},{"c":"","l":"y aunque la lucha he ganado,"},{"c":"","l":"mi armadura he desgastado,"},{"c":"","l":"vengo a Ti."},{"c":"","l":""},{"c":"","l":"Sumérgeme, en el río de tu Espíritu,"},{"c":"","l":"necesito refrescar este seco corazón,"},{"c":"","l":"sediento de Ti."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (319, 'Fuego suave', '[{"c":"","l":"Tus dedos tocan mi pensar"},{"c":"","l":"cariño en mi alma."},{"c":"","l":"Tú tranquilizas y calmas"},{"c":"","l":"mi vida agitada."},{"c":"","l":"Tu presencia me acoge"},{"c":"","l":"ya no me voy"},{"c":"","l":"es tuya esta hora, estoy naciendo."},{"c":"","l":""},{"c":"","l":"Te adoraré, Espíritu Santo"},{"c":"","l":"fuego suave, abrazador"},{"c":"","l":"dulce huésped del alma."},{"c":"","l":""},{"c":"","l":"Mis ojos cantan al llorar"},{"c":"","l":"arrepentida,"},{"c":"","l":"oveja perdida"},{"c":"","l":"queriendo volver."},{"c":"","l":"Aprecia el canto que te doy"},{"c":"","l":"toma las palabras"},{"c":"","l":"pesar del alma sedienta de Amor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (320, 'Ven Espíritu ven', '[{"c":"","l":"Ven Espíritu ven, y lléname Señor,"},{"c":"","l":"con tu preciosa unción."},{"c":"","l":""},{"c":"","l":"Purifícame y lávame, renuévame,  restáurame, Señor, con tu poder."},{"c":"","l":"Purifícame y lávame, renuévame,"},{"c":"","l":"restáurame, Señor, te quiero conocer."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (321, 'Dios de pentecostés(Pablo Martínez)', '[{"c":"","l":"Que de tu sueño brotó la vida,"},{"c":"","l":"y que en tu vida están los sueños."},{"c":"","l":"Que por tu aliento somos tu imagen, nos haces templo de tu promesa."},{"c":"","l":"Y ahora te clamamos: ¡escúchanos!"},{"c":"","l":""},{"c":"","l":"Dios de aquel Pentecostés,"},{"c":"","l":"date a tus hijos otra vez."},{"c":"","l":"Regálanos tu Espíritu, Señor."},{"c":"","l":""},{"c":"","l":"Sé como viento que libremente"},{"c":"","l":"mueve y anima, dándonos fuerza."},{"c":"","l":"Reaviva el fuego que dio tu llama"},{"c":"","l":"y convencenos de tu Palabra."},{"c":"","l":"Y danos coraje para salir..."},{"c":"","l":""},{"c":"","l":"Hacenos uno para tu gloria,"},{"c":"","l":"y que tu gloria nos transfigure."},{"c":"","l":"Que con tus dones nos acompañes"},{"c":"","l":"en el camino de ser testigos."},{"c":"","l":"Danos de alimento a Cristo..."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (322, 'Hay una unción', '[{"c":"","l":"Hay una unción aquí, cayendo sobre mi"},{"c":"","l":"mudándome, cambiando mi ser"},{"c":"","l":""},{"c":"","l":"Mi espíritu y mi alma"},{"c":"","l":"se están llenando"},{"c":"","l":"con el poder del Espíritu Santo"},{"c":"","l":"mi vida nunca más será igual."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (323, 'Incendia mi alma', '[{"c":"","l":"Espíritu Santo ven a hablar en mi"},{"c":"","l":"Espíritu Santo ven a orar en mi"},{"c":"","l":""},{"c":"","l":"Ven a curar ven a liberar"},{"c":"","l":"nuestros corazones de toda opresión."},{"c":"","l":"Ven a transformar, ven a incendiar,"},{"c":"","l":"trae el fuego del cielo en este lugar"},{"c":"","l":""},{"c":"","l":"Incendia hoy mi alma! (x3) Señor!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (324, 'Fuego santo', '[{"c":"","l":"Ven, fuego santo ven."},{"c":"","l":"Luz divina ven, fuego santo ven."},{"c":"","l":""},{"c":"","l":"Fuego santo ven y arde,"},{"c":"","l":"fuego santo ven y arde,"},{"c":"","l":"de mi barro haz tu nueva creación"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (325, 'Como la brisa', '[{"c":"","l":"Abro el corazón y las ventanas"},{"c":"","l":"cuando empieza la mañana"},{"c":"","l":"por si quieres hoy venir."},{"c":"","l":"Eres como el viento que no avisa"},{"c":"","l":"cuando sopla y trae la brisa"},{"c":"","l":"ven y sopla sobre mí."},{"c":"","l":""},{"c":"","l":"Y mi corazón vuelve a latir"},{"c":"","l":"y se renueva si estás aquí."},{"c":"","l":"Y mi corazón vela por ti"},{"c":"","l":"porque te espera vuelve a venir."},{"c":"","l":""},{"c":"","l":"Espíritu de Dios ven a mi vida"},{"c":"","l":"Como lluvia que tardo, Y al desierto vida dio"},{"c":"","l":"Desciende sobre mí como la brisa"},{"c":"","l":"Que destile sobre mí, Tú poder en mi haz fluir"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (326, 'Espíritu de comunidad', '[{"c":"","l":"Danos Señor de tu luz,"},{"c":"","l":"y danos Señor de Tu verdad;"},{"c":"","l":"y llénanos de tu Espíritu de amor"},{"c":"","l":"que nos hace comunidad."},{"c":"","l":""},{"c":"","l":"Danos Señor el compartir,"},{"c":"","l":"acrecienta hoy nuestra hermandad,"},{"c":"","l":"y llénanos de Tu Espíritu de amor"},{"c":"","l":"que nos hace comunidad."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (327, 'Fruto nuevo de tu cielo(Metanoia)', '[{"c":"","l":"Sopla Señor, te lo pido,"},{"c":"","l":"quédate esta noche en mi alma"},{"c":"","l":"pues solo tu amor y abrigo"},{"c":"","l":"me darán consuelo y calma..."},{"c":"","l":"sopla Señor, sopla fuerte,"},{"c":"","l":"envolveme con tu brisa,"},{"c":"","l":"y en tu Espíritu renovame,"},{"c":"","l":"hazme libre en tu sonrisa."},{"c":"","l":"A pesar de mis caídas"},{"c":"","l":"hazme fiel a tus promesas,"},{"c":"","l":"sopla Señor en mi vida,"},{"c":"","l":"y arrancame ésta tristeza..."},{"c":"","l":""},{"c":"","l":"Sopla, sopla Señor tu grandeza,"},{"c":"","l":"sopla, hazme fiel en mi pobreza, sopla."},{"c":"","l":""},{"c":"","l":"Sopla Señor en mi oído,"},{"c":"","l":"sopla fuerte, arranca el miedo,"},{"c":"","l":"pues sin ti me hallo perdido,"},{"c":"","l":"sin tu luz me encuentro ciego."},{"c":"","l":"Sopla Señor, haz de viento y"},{"c":"","l":"bautízame en tu Nombre,"},{"c":"","l":"llámame a servir, Maestro,"},{"c":"","l":"hazme fiel entre los hombres."},{"c":"","l":"Toma mi vida en tus manos,"},{"c":"","l":"mis sueños, mi amor, mi todo,"},{"c":"","l":"mi cansancio, mis pecados,"},{"c":"","l":"y moldeame a tu modo."},{"c":"","l":""},{"c":"","l":"Sopla y bautízame en tu brisa, sopla,"},{"c":"","l":"renovame en tu sonrisa, sopla."},{"c":"","l":""},{"c":"","l":"Sopla Señor tu caricia"},{"c":"","l":"sobre mis sentimientos,"},{"c":"","l":"que sea el ángel de tu Misa"},{"c":"","l":"quien obre en todo momento."},{"c":"","l":"sopla Señor y hazte canto,"},{"c":"","l":"pon tu Palabra en mis manos,"},{"c":"","l":"en ellas tu Providencia"},{"c":"","l":"y bendice a mis hermanos."},{"c":"","l":"Quiero ser de tu árbol rama,"},{"c":"","l":"fruto nuevo de tu cielo"},{"c":"","l":"que madure en tu Palabra"},{"c":"","l":"como un ave a pleno vuelo"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (328, 'Ven creador(Adaptación F.L. Bernardez)', '[{"c":"","l":"Ven Creador, Espíritu Divino"},{"c":"","l":"a visitar lasalmas de tus fieles"},{"c":"","l":"y concede quenuestros corazones"},{"c":"","l":"se alimenten condádivas celestes."},{"c":"","l":""},{"c":"","l":"Eres testigo fiel de los cristianos"},{"c":"","l":"sublime don de Dios omnipotente"},{"c":"","l":"caridad, fuente viva, eterno fuego"},{"c":"","l":"quedas vida divina a nuestras mentes."},{"c":"","l":""},{"c":"","l":"Con siete dones Tú nos santificas"},{"c":"","l":"Lavoluntad divina nos señalas"},{"c":"","l":"Prometidodel Padre Sempiterno"},{"c":"","l":"nos ofreces eldon de la Palabra."},{"c":"","l":""},{"c":"","l":"Con luz divina, aclara los sentidos"},{"c":"","l":"infunde amor profundo en nuestros pechos"},{"c":"","l":"con tu gracia infinita fortalece"},{"c":"","l":"la flaqueza carnal de nuestros cuerpos."},{"c":"","l":""},{"c":"","l":"Con tu poder, rechaza al enemigo"},{"c":"","l":"Danosla paz que todos esperamos"},{"c":"","l":"y guiandoseguro nuestras vidas"},{"c":"","l":"te pedimos noslibres del pecado."},{"c":"","l":""},{"c":"","l":"Haz que por Ti, al Padre conozcamos"},{"c":"","l":"Y al Verbo eterno, su Hijo, Jesucristo"},{"c":"","l":"Y creamos por siempre, en todo tiempo"},{"c":"","l":"EnTi, que eres su Espíritu Divino."},{"c":"","l":""},{"c":"","l":"Gloria sin fin al Padre y a su Hijo"},{"c":"","l":"Queresurgió triunfante de la muerte"},{"c":"","l":"y al Espíritu Santo, que los une"},{"c":"","l":"desdesiempre, por siempre y para siempre"},{"c":"","l":"Amén."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (329, 'Secuencia de pentecostés(P. Gallego)', '[{"c":"","l":"Ven, Espíritu Santo,"},{"c":"","l":"y envía desde el cieloun rayo de tu luz."},{"c":"","l":""},{"c":"","l":"Ven Espíritu Santo, ven,"},{"c":"","l":"que tu Iglesia no vive sin Ti"},{"c":"","l":""},{"c":"","l":"Ven Padre de los pobres,"},{"c":"","l":"ven a darnostus dones, ven a darnos tu luz."},{"c":"","l":""},{"c":"","l":"Consolador lleno de bondad,"},{"c":"","l":"Dulcehuésped del alma,"},{"c":"","l":"suave alivio de loshombres."},{"c":"","l":""},{"c":"","l":"Tú eres descanso en el trabajo,"},{"c":"","l":"templanza en las pasiones,"},{"c":"","l":"alegría ennuestro llanto."},{"c":"","l":""},{"c":"","l":"Penetra con tu santa luz"},{"c":"","l":"en lo más íntimodel corazón de tus fieles."},{"c":"","l":""},{"c":"","l":"Sin tu ayuda divina no hay nada en elhombre, nada que sea inocente."},{"c":"","l":""},{"c":"","l":"Lava nuestras manchas,"},{"c":"","l":"riega nuestraaridez, cura nuestras heridas."},{"c":"","l":""},{"c":"","l":"Suaviza nuestra dureza,"},{"c":"","l":"elimina con tucalor nuestra frialdad,"},{"c":"","l":"corrige nuestrosdesvíos."},{"c":"","l":""},{"c":"","l":"Concede a tus fieles,"},{"c":"","l":"que confían en Ti,tus siete sagrados dones."},{"c":"","l":""},{"c":"","l":"Premia nuestra virtud, salva nuestrasalmas,"},{"c":"","l":"danos la eterna alegría. ¡Amén,aleluya!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (330, 'Pentecostés', '[{"c":"","l":"Pentecostés día de fiesta"},{"c":"","l":"Pentecostés día de gozo"},{"c":"","l":"Pentecostés día de la Iglesia"},{"c":"","l":"De la Iglesia del Señor (2)"},{"c":"","l":""},{"c":"","l":"Ya se derrama, ya se derrama"},{"c":"","l":"ya sederrama el Espíritu de Dios (2)"},{"c":"","l":""},{"c":"","l":"Ya se siente, ya se siente"},{"c":"","l":"ya se siente elEspíritu de Dios (2)"},{"c":"","l":""},{"c":"","l":"Aleluya, aleluya"},{"c":"","l":"aleluya al Espíritu deDios (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (331, 'Soplo de Dios viviente(P.Catena)', '[{"c":"","l":"Soplo de Dios viviente"},{"c":"","l":"que en elprincipio cubriste el agua."},{"c":"","l":"Soplo de Diosviviente"},{"c":"","l":"que fecundaste la creación."},{"c":"","l":""},{"c":"","l":"Ven hoy a nuestras almas"},{"c":"","l":"Infúndenos tus dones"},{"c":"","l":"Soplo de Dios viviente"},{"c":"","l":"Oh Santo Espíritu del Señor"},{"c":"","l":""},{"c":"","l":"Soplo de Dios viviente"},{"c":"","l":"por quien el Hijose hizo hombre"},{"c":"","l":"soplo de Dios viviente"},{"c":"","l":"que renovaste la creación."},{"c":"","l":""},{"c":"","l":"Soplo de Dios viviente"},{"c":"","l":"por quiennacemos en el Bautismo"},{"c":"","l":"soplo de Diosviviente"},{"c":"","l":"que consagraste la creación"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (332, 'Muévete', '[{"c":"","l":"Espíritu Santo, Espíritu Santo,"},{"c":"","l":"muévete eneste lugar (2)"},{"c":"","l":"Que haya paz, que haya paz,"},{"c":"","l":"que hayapaz en este lugar (2)"},{"c":"","l":"Que haya amor, que haya amor,"},{"c":"","l":"que hayaamor en este lugar (2)"},{"c":"","l":"Que haya unción, que haya unción,"},{"c":"","l":"Quehaya unción en este lugar (2)"},{"c":"","l":"Sanación, sanación, sanación,"},{"c":"","l":"en estelugar (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (333, 'Haz morada en mi', '[{"c":"","l":"Te abro la puerta de mi corazón"},{"c":"","l":"Tedoy mi maldad, Te entrego mi dolor (2)"},{"c":"","l":""},{"c":"","l":"Haz morada en mi Señor"},{"c":"","l":"Haz morada en mi Señor"},{"c":"","l":"Haz morada en mi Señor"},{"c":"","l":"Quédate (2)"},{"c":"","l":""},{"c":"","l":"Mi debilidad, a ti te la doy"},{"c":"","l":"Y mi voluntad, Te entrego Señor (2)"},{"c":"","l":""},{"c":"","l":"Quiero que te quedes, En mi corazón"},{"c":"","l":"Y nunca me dejes, Fuera de tu amor (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (334, 'Espíritu de los cuatro vientos', '[{"c":"","l":"Santo Espíritu de los cuatro vientos"},{"c":"","l":"sopla en este cuerpo para que viva. (6)"},{"c":"","l":""},{"c":"","l":"Te cantamos Espíritu"},{"c":"","l":"te llamamos Espíritu de Dios. (2)"},{"c":"","l":""},{"c":"","l":"Espíritu de vida, Espíritu de fuego"},{"c":"","l":"Espíritu de los cuatro vientos (2)"},{"c":"","l":""},{"c":"","l":"Concédenos al Padre conocer"},{"c":"","l":"Espíritu de los cuatro vientos."},{"c":"","l":""},{"c":"","l":"Sopla sobre mí"},{"c":"","l":"Espíritu de los cuatro vientos."},{"c":"","l":""},{"c":"","l":"Abre los ojos de mi alma."},{"c":"","l":"Espíritu de los cuatro vientos."},{"c":"","l":""},{"c":"","l":"Dame tu voz dame tu aliento"},{"c":"","l":"Espíritu de los cuatro vientos."},{"c":"","l":""},{"c":"","l":"Santo espíritu de los cuatro vientos"},{"c":"","l":"sopla en este cuerpo para que viva. (6)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (335, 'Desciende', '[{"c":"","l":"Desciende, Espíritu, desciende (2)"},{"c":"","l":"Te necesito, te necesito (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (336, 'Sopla sobre mi', '[{"c":"","l":"Sopla sobre mí, dulce huésped de mi alma"},{"c":"","l":"Ven sopla sobre mí,"},{"c":"","l":"Suave brisa de los cielos (2)"},{"c":"","l":""},{"c":"","l":"Quiero descansar en tu presencia"},{"c":"","l":"Quieroabandonarme en Ti, en Ti, en Ti"},{"c":"","l":"Derrámate Espíritu en mi"},{"c":"","l":"cura todas misheridas"},{"c":"","l":"consuélame y sumérgeme en tuamor,"},{"c":"","l":"en tu amor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (337, 'Ven, ven, ven (apodérate)', '[{"c":"","l":"Ven, ven, ven. Espíritu Divino"},{"c":"","l":"ven, ven,ven, acércate a mí. (2)"},{"c":"","l":"Apodérate,apodérate"},{"c":"","l":"apodérate de todo mi ser. (2)"},{"c":"","l":""},{"c":"","l":"Aquí se siente la presencia de Dios. (2)"},{"c":"","l":"Siento el fuego del Espíritu Santo. (2)"},{"c":"","l":""},{"c":"","l":"Siento gozo, siento paz"},{"c":"","l":"siento el amorque Dios me da."},{"c":"","l":"Aquí se siente lapresencia de Dios. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (338, 'Jesús es el mesías', '[{"c":"","l":"Jesús es el mesías, alábalo que vive"},{"c":"","l":""},{"c":"","l":"Alábalo, alábalo, alábalo que vive"},{"c":"","l":""},{"c":"","l":"Jesús hijo de Dios…"},{"c":"","l":"Jesús es nuestro hermano…"},{"c":"","l":"Presente en el altar…"},{"c":"","l":"Jesús nos lleva al Padre…"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (339, 'El amor de Dios es maravilloso', '[{"c":"","l":"El amor de Dios es maravilloso (3)"},{"c":"","l":"Grande es el amor de Dios"},{"c":"","l":""},{"c":"","l":"Tan alto que no puedo estar más alto que Él"},{"c":"","l":"Tan bajo que no puedo estar más bajo que Él"},{"c":"","l":"Tan ancho que no puedo estar afuera de Él"},{"c":"","l":"Grande es el amor de Dios"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (340, 'Hay un rio de vida', '[{"c":"","l":"Hay un rio de vida corriendo por mi ser,"},{"c":"","l":"que hace a los enfermos caminar y ver."},{"c":"","l":"Libera a los oprimidos y les da felicidad."},{"c":"","l":"Hay un rio de vida corriendo por mi ser"},{"c":"","l":""},{"c":"","l":"Está el amor del Padre…"},{"c":"","l":"Está el poder del Hijo…"},{"c":"","l":"Está el Espíritu Santo…"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (341, 'Esta es la gente', '[{"c":"","l":"Esta es la gente que alaba al Señor"},{"c":"","l":"Esta es la gente que tiene gozo"},{"c":"","l":"que tiene fe y que alaba al Señor"},{"c":"","l":""},{"c":"","l":"Manos arriba, manos abajo"},{"c":"","l":"moviendo de lado a lado"},{"c":"","l":""},{"c":"","l":"Cabeza…"},{"c":"","l":"Rodilla…"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (342, 'Hoy he venido', '[{"c":"","l":"Hoy he venido para cantarle a mi Señor"},{"c":"","l":"quiero alabarle"},{"c":"","l":"y darle gracias por su amor."},{"c":"","l":""},{"c":"","l":"*Por eso canta, canta, canta"},{"c":"","l":"Baila, baila, baila"},{"c":"","l":"Como lo hacía el Rey David*"},{"c":"","l":""},{"c":"","l":"Mueve tu cuerpo, todo tu Espíritu para &Eacute;l"},{"c":"","l":"Grítale fuerte,"},{"c":"","l":"grítale fuerte &Eacute;l te escuchará"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (343, 'Jesucristo está pasando por aquí', '[{"c":"","l":"*Jesucristo está pasando por aquí*"},{"c":"","l":""},{"c":"","l":"Cuando &Eacute;l pasa todo se transforma,"},{"c":"","l":"la alegría viene, la tristeza va (bis)"},{"c":"","l":""},{"c":"","l":"*Nuestro Padre está pasando por aquí*"},{"c":"","l":""},{"c":"","l":"Cuando &Eacute;l pasa todo se transforma,"},{"c":"","l":"la alegría viene, la tristeza va (bis)"},{"c":"","l":""},{"c":"","l":"*Nuestra Madre está pasando por aquí*"},{"c":"","l":""},{"c":"","l":"Cuando ella pasa todo se transforma,"},{"c":"","l":"la alegría viene, la tristeza va (bis)"},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (344, 'Hoy me siento feliz', '[{"c":"","l":"Hoy me siento feliz"},{"c":"","l":"ya Cristo está en mí, me llena de amor"},{"c":"","l":""},{"c":"","l":"Canto, canto, canto, porque me llena de gozo"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (345, 'El Señor de Galilea', '[{"c":"","l":"Pon tus manos en las manos del Señor"},{"c":"","l":"de Galilea"},{"c":"","l":"Pon tus manos en las manos del Señor"},{"c":"","l":"que calma el mar"},{"c":"","l":""},{"c":"","l":"Es Jesús el que te va a cuidar,"},{"c":"","l":"noche y día sin cesar"},{"c":"","l":"Pon ……. del Señor"},{"c":"","l":"que calma el mar."},{"c":"","l":""},{"c":"","l":"Pon tus pies en las huellas del Señor…"},{"c":"","l":"Pon tu cuerpo al servicio del Señor…"},{"c":"","l":"Pon tu fe en las palabras del Señor…"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (346, 'Mi mano', '[{"c":"","l":"Mi mano está llena de su bendición"},{"c":"","l":"Y al hermano que toque bendito será"},{"c":"","l":"Mi mano está llena, de su bendición."},{"c":"","l":""},{"c":"","l":"Mi brazo…Mi boca…"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (347, 'Mi Dios está vivo', '[{"c":"","l":"Mi Dios está vivo, Él no está muerto"},{"c":"","l":"Lo siento en las manos."},{"c":"","l":"Lo siento en los pies."},{"c":"","l":"Lo siento en el alma."},{"c":"","l":"Lo siento en todo mi ser!"},{"c":"","l":""},{"c":"","l":"Oh, oh, oh, oh"},{"c":"","l":"hay que nacer del agua,"},{"c":"","l":"Oh, oh, oh, oh"},{"c":"","l":""},{"c":"","l":"hay que nacer del Espíritu de Dios."},{"c":"","l":"Oh, oh, oh, oh"},{"c":"","l":"hay que nacer,"},{"c":"","l":"del agua y del Espíritu de Dios"},{"c":"","l":"hay que nacer del Señor"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (348, 'Granito de mostaza', '[{"c":"","l":"Si tuviera fe como un granito de mostaza"},{"c":"","l":"Eso dice el Señor"},{"c":"","l":""},{"c":"","l":"Yo le diría, a las montañas"},{"c":"","l":"Muévanse, muévanse, muévanse!"},{"c":"","l":""},{"c":"","l":"Y las montañas se moverán,"},{"c":"","l":"Se moverán, se moverán"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (349, 'Te alabaré mi buen Jesús', '[{"c":"","l":"Eres Tú la única razón"},{"c":"","l":"de mi adoración oh Jesús."},{"c":"","l":"Eres Tú la esperanza que"},{"c":"","l":"anhelé tener oh Jesús."},{"c":"","l":"Confié en Ti me has ayudado,"},{"c":"","l":"tu salvación me has regalado."},{"c":"","l":"Hoy hay gozo en mi corazón,"},{"c":"","l":"con mi canto te alabaré"},{"c":"","l":""},{"c":"","l":"Te alabaré, te glorificaré"},{"c":"","l":"Te alabaré, mi buen Jesús"},{"c":"","l":""},{"c":"","l":"En todo tiempo te alabaré."},{"c":"","l":"En todo tiempo te adoraré."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (350, 'Que viva Cristo', '[{"c":"","l":"Que viva Cristo,que viva, que viva Cristo"},{"c":"","l":"que viva Él"},{"c":"","l":""},{"c":"","l":"Viva la fe, viva la esperanza, viva el amor (3)"},{"c":"","l":"Que viva Cristo, que viva Cristo, que viva Él"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (351, 'La alegría', '[{"c":"","l":"La alegría está en el corazón"},{"c":"","l":"de quien ya conoce a Jesús,"},{"c":"","l":"la verdadera paz la tiene aquel"},{"c":"","l":"que ya conoce a Jesús."},{"c":"","l":"El sentimiento más precioso"},{"c":"","l":"que viene del Señor,"},{"c":"","l":"es amor"},{"c":"","l":"que sólo tiene quien conoce a Jesús."},{"c":"","l":""},{"c":"","l":"Aleluya, aleluya, aleluya, aleluya."},{"c":"","l":"El sentimiento más precioso"},{"c":"","l":"que viene del señor es amor,"},{"c":"","l":"que sólo tiene quien conoce a Jesús."},{"c":"","l":""},{"c":"","l":"Puedo aplastar una tropa"},{"c":"","l":"y saltar las murallas, aleluya, aleluya . Él es la roca de mi salvación,"},{"c":"","l":"con Él no hay más condenación."},{"c":"","l":"Puedo aplastar una roca"},{"c":"","l":"y saltar las murallas, aleluya, aleluya"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (352, 'Hasta que baje su bendición', '[{"c":"","l":"Los cristianos vamos a mostrar"},{"c":"","l":"como se alaba a nuestro Señor"},{"c":"","l":""},{"c":"","l":"Alzando las manos, moviendo el cuerpo, una vueltita, hasta que baje su Bendición"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (353, 'El Señor es rey', '[{"c":"","l":"El Señor es rey,"},{"c":"","l":"el Señor es mi pastor y rey."},{"c":"","l":""},{"c":"","l":"El Señor está en el cielo,"},{"c":"","l":"el Señor está en el mar"},{"c":"","l":"y en la extensión del infinito."},{"c":"","l":""},{"c":"","l":"Está en el cielo, está en el mar"},{"c":"","l":"y en la extensión del infinito"},{"c":"","l":""},{"c":"","l":"Cuando vacilas,"},{"c":"","l":"yo no temeré, no nono,"},{"c":"","l":"pues el Señor está conmigo"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (354, 'En el mar (Padre Nuestro)', '[{"c":"","l":"En el mar he oído hoy,"},{"c":"","l":"Señor tu voz que me llamó"},{"c":"","l":"y me pidió que me entregara"},{"c":"","l":"a mis hermanos."},{"c":"","l":"Esa voz me transformó,"},{"c":"","l":"mi vida entera ya cambió,"},{"c":"","l":"y solo pienso ahora, Señor,"},{"c":"","l":"en repetirte."},{"c":"","l":""},{"c":"","l":"Padre nuestro, en Ti creemos"},{"c":"","l":"Padre nuestro, te ofrecemos"},{"c":"","l":"Padre nuestro, nuestras manos"},{"c":"","l":"de hermanos."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (355, 'Si tú eres cristiano', '[{"c":"","l":"Si tú eres cristiano dí amén"},{"c":"","l":""},{"c":"","l":"Si tú eres cristiano testifica con tu vida"},{"c":"","l":"si tú eres cristiano dí amén."},{"c":"","l":""},{"c":"","l":"Si tú eres cristiano gloria a Dios..."},{"c":"","l":""},{"c":"","l":"Con las palmas..."},{"c":"","l":"Con los pies..."},{"c":"","l":"Todo junto..."},{"c":"","l":"Al revés..."},{"c":"","l":"Ida y vuelta..."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (356, 'Yo tengo un amigo', '[{"c":"","l":"Yo tengo un amigo que me ama"},{"c":"","l":"me ama, me ama."},{"c":"","l":"Yo tengo un amigo que me ama"},{"c":"","l":"su nombre es Jesús."},{"c":"","l":""},{"c":"","l":"Que me ama, que me ama"},{"c":"","l":"Que me ama, con su inmenso amor (2)"},{"c":"","l":""},{"c":"","l":"Tú tienes un amigo que te ama"},{"c":"","l":"te ama, te ama."},{"c":"","l":"tú tienes un amigo que te ama"},{"c":"","l":"su nombre es Jesús."},{"c":"","l":""},{"c":"","l":"Tenemos un amigo que me ama"},{"c":"","l":"nos ama, nos ama."},{"c":"","l":"Tenemos un amigo que me ama"},{"c":"","l":"su nombre es Jesús."},{"c":"","l":""},{"c":"","l":"Tenemos una madre que nos ama"},{"c":"","l":"nos ama, nos ama."},{"c":"","l":"Tenemos una Madre que nos ama"},{"c":"","l":"la madre de Jesús"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (357, 'Mira lo que hizo mi Jesús', '[{"c":"","l":"Mira lo que hizo mi Jesús (2)"},{"c":"","l":"me levantó y me liberó"},{"c":"","l":"mira lo que hizo mi Jesús."},{"c":"","l":""},{"c":"","l":"El enemigo ya vencido está, (2)"},{"c":"","l":"Jesús lo venció,  muriendo en la cruz"},{"c":"","l":"el enemigo ya vencido está."},{"c":"","l":""},{"c":"","l":"Caminando por la senda voy (2)"},{"c":"","l":"de prueba en prueba,  victoria tras victoria"},{"c":"","l":"caminando por la senda voy"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (358, 'Hay victoria', '[{"c":"","l":"Hay victoria, hay victoria,"},{"c":"","l":"hay victoria en la sangre de Jesús (2)"},{"c":"","l":"Y no podrá el enemigo,  ganar las almas."},{"c":"","l":"Porque hay victoria, porque hay victoria"},{"c":"","l":"porque hay victoria, en la sangre de Jesús(2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (359, 'Aquí está tu vaso', '[{"c":"","l":"Aquí está tu vaso, Señor, llénalo de aceite"},{"c":"","l":"Llénalo de aceite, Llénalo de aceite. (2)"},{"c":"","l":""},{"c":"","l":"Llama, llama, llama, llama, llama a Jesúsahora"},{"c":"","l":"¡Jesús! ¡Ven!"},{"c":"","l":"Pide, pide, pide, pide, pide que llegó la hora(2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (360, 'Señor tu eres mi Dios', '[{"c":"","l":"Señor Tú eres mi Dios,"},{"c":"","l":"alabaré y ensalzaré tu Nombre. (3)"},{"c":"","l":"Porque has hecho, maravillas"},{"c":"","l":"alabaré y ensalzaré tu Nombre. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (361, 'Cuando Cristo venga', '[{"c":"","l":"Cuando Cristo venga en Gloria"},{"c":"","l":"yo no me voy a quedar. (2)"},{"c":"","l":""},{"c":"","l":"Seremos levantados con poder (3)"},{"c":"","l":"Para la nueva Jerusalén"},{"c":"","l":"A que tú te vayas, que yo también (3)"},{"c":"","l":"Para la nueva Jerusalén"},{"c":"","l":""},{"c":"","l":"Hay un fuego que me está quemando"},{"c":"","l":"es el Espíritu Santo que está bautizando. (2)"},{"c":"","l":"Aquí se canta, aquí se ora"},{"c":"","l":"se alaba a Cristo a toda hora. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (362, 'Los que esperan', '[{"c":"","l":"Los que esperan, los que esperan en Jesús(4)"},{"c":"","l":"Como las águilas, como las águilas"},{"c":"","l":"sus alas levantarán (2)."},{"c":"","l":""},{"c":"","l":"Caminarán y no se cansarán,"},{"c":"","l":"y correrán, no se fatigarán."},{"c":"","l":"Nueva vida tendrán,  nueva vida tendrán"},{"c":"","l":"los que esperan, los que esperan en Jesús(2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (363, 'Vamos a alabar al Señor', '[{"c":"","l":"Vamos a alabar al Señor"},{"c":"","l":"con panderos y arpas. (2)"},{"c":"","l":"En el cielo se oye, en la tierra se canta. (2)"},{"c":"","l":"Cristo me dijo que luchara otra vez,"},{"c":"","l":"que luchara otra vez, que luchara otra vez(2)"},{"c":"","l":"Que no me desesperara, sino que tuviera fe(2)"},{"c":"","l":"Y yo, y yo, y yo le estoy alabando. (2)"},{"c":"","l":"Nosotros no, Señor, tú eres el que toca. (2)"},{"c":"","l":"Y yo cantaré lo que pongas en mi boca. (2)"},{"c":"","l":"Y así, y así, y así se alaba a Dios. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (364, 'Yo celebraré', '[{"c":"","l":"Yo celebraré,"},{"c":"","l":"delante del Señor cantaré un canto nuevo.(2)"},{"c":"","l":"Yo le alabaré,"},{"c":"","l":"porque Él ha hecho, grandes cosas. (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (365, 'Tomado de la mano', '[{"c":"","l":"Tomado de la mano con Jesús yo voy"},{"c":"","l":"Le sigo como oveja que encontró pastor"},{"c":"","l":"Tomado de la mano con Jesús yo voy"},{"c":"","l":"A donde Él va (2)"},{"c":"","l":""},{"c":"","l":"Si Jesús me dice amigo"},{"c":"","l":"deja todo y ven conmigo"},{"c":"","l":"donde todo es más hermoso y más feliz."},{"c":"","l":"Si Jesús me dice ven conmigo"},{"c":"","l":"deja todo y ven conmigo"},{"c":"","l":"yo mi mano pondré en la suya e iré con Él."},{"c":"","l":""},{"c":"","l":"Yo te llevaré amigo a un lugar conmigo"},{"c":"","l":"donde el sol y las estrellas aún brillan más."},{"c":"","l":"Yo te llevaré amigo a un lugar conmigo"},{"c":"","l":"donde todo es más hermoso más feliz."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (366, 'Estamos de fiesta con Jesús', '[{"c":"","l":"Estamos de fiesta con Jesús"},{"c":"","l":"al cielo queremos ir"},{"c":"","l":"estamos reunidos en la mesa"},{"c":"","l":"y es Cristo quien va a servir."},{"c":"","l":""},{"c":"","l":"Poderoso es nuestro Dios (4)"},{"c":"","l":""},{"c":"","l":"Él sana, Él salva, poderoso es nuestro Dios."},{"c":"","l":"Bautiza, Él viene, poderoso es nuestro Dios."},{"c":"","l":"El Padre, el Hijo, poderoso es nuestro Dios"},{"c":"","l":"Espíritu Santo, poderoso es nuestro Dios."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (367, 'Que suba la alabanza', '[{"c":"","l":"Que suba la alabanza"},{"c":"","l":"que baje la bendición. (2)"},{"c":"","l":"Que baje por aquí, que baje por allá"},{"c":"","l":"que baje la bendición. (2)"},{"c":"","l":"Aleluya, aleluya,"},{"c":"","l":"vinimos a alabar a Dios (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (368, 'Jericó', '[{"c":"","l":"Con las siete vueltas el muro se cayó (2)"},{"c":"","l":"En Jericó el muro se cayó (2)"},{"c":"","l":""},{"c":"","l":"Haciendo palmas, haciendo palmas"},{"c":"","l":"haciendo palmas el muro se cayó (2)"},{"c":"","l":"Y adorando, y adorando"},{"c":"","l":"y adorando el muro se cayó (2)"},{"c":"","l":""},{"c":"","l":"Diciendo gloria, diciendo gloria"},{"c":"","l":"diciendo gloria el muro se cayó (2)"},{"c":"","l":"Y alabando, y alabando"},{"c":"","l":"y alabando el muro se cayó (2)"},{"c":"","l":""},{"c":"","l":"Diciendo Santo, diciendo Santo"},{"c":"","l":"diciendo Santo el muro se cayó (2)"},{"c":"","l":"Y celebrando, y celebrando"},{"c":"","l":"y celebrando el muro se cayó (2)"},{"c":"","l":"Diciendo gracias, diciendo gracias"},{"c":"","l":"diciendo gracias el muro se cayó (2)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (369, 'Canta tu canto', '[{"c":"","l":"Canta tu canto, baila tu danza"},{"c":"","l":"porque tú eres Pueblo de alabanza"},{"c":"","l":"Pueblo escogido, raza de profetas"},{"c":"","l":"porque tú eres una Nación Santa."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (370, '¿Sabes tú que eres templo?', '[{"c":"","l":"¿Sabes tú, sabes tú, que eres templo? (3)"},{"c":"","l":"¡eres el Templo donde habita Dios!"},{"c":"","l":"¡Sí yo sé!, ¡Sí yo sé que soy Templo! (3)"},{"c":"","l":"yo soy el Templo donde habita Dios."},{"c":"","l":"¡Alelu!, ¡alelu!, ¡aleluya! (3)"},{"c":"","l":"somos el Templo donde habita Dios."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (371, 'Hay una promesa en la Biblia', '[{"c":"","l":"Hay una promesa en la Biblia que es para ti,"},{"c":"","l":"que es para mí. (2)"},{"c":"","l":"Cielo nuevo y tierra nueva,"},{"c":"","l":"dónde iremos a vivir. (2)"},{"c":"","l":"Cantando hermano, cantando (3)"},{"c":"","l":"como corderos de la manada."},{"c":"","l":""},{"c":"","l":"Y así, así, así, así se alaba a Dios."},{"c":"","l":"Pero qué lindo que es el Pueblo de Dios"},{"c":"","l":"maravilloso que es el Pueblo de Dios"},{"c":"","l":"pero que hermoso que es el Pueblo de Dios."},{"c":"","l":"Y dando la media vueltita,"},{"c":"","l":"la vuelta de la victoria."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (372, 'Ya llegó, ya llegó', '[{"c":"","l":"Ya llegó ya llegó el Espíritu Santo"},{"c":"","l":"Ya llegó ya llegó el Espíritu Santo ya llegó (2)"},{"c":"","l":""},{"c":"","l":"Lo siento en mis manos lo siento en mis pies"},{"c":"","l":"Lo siento en el alma y todo mi ser (2)"},{"c":"","l":"Aquel que camino sobre las aguas (2)"},{"c":"","l":"Esta aquí está a mi lado (2)"},{"c":"","l":"Como un rayo cayendo sobre mi (2)"},{"c":"","l":"Que quema que quema que quema (4)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (373, 'Alégrate pueblo de Dios', '[{"c":"","l":"Alégrate pueblo de Dios"},{"c":"","l":"Porque el Señor en medio de ti está (2)"},{"c":"","l":""},{"c":"","l":"Alza los brazos, cierra los ojos"},{"c":"","l":"deja que inunde tu corazón."},{"c":"","l":"Su amor derrama cual agua viva"},{"c":"","l":"en lo profundo de nuestro ser."},{"c":"","l":"Alaba al Padre, alaba al Hijo"},{"c":"","l":"alaba al Santo Consolador."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (374, 'Y yo me sigo enamorando', '[{"c":"","l":"Y yo me sigo enamorando,"},{"c":"","l":"me sigo enamorando,"},{"c":"","l":"me sigo enamorando de Dios (2)"},{"c":"","l":"estaba sola y triste más ahora estoy feliz"},{"c":"","l":"porque Cristo ha tomado mi vida"},{"c":"","l":"y no la quiere soltar."},{"c":"","l":"Cristo ha tomado mi vida y no la quiere soltar (2)"},{"c":"","l":"estaba yo perdido pero Cristo me encontró"},{"c":"","l":"y yo me sigo enamorando,"},{"c":"","l":"me sigo enamorando de Dios"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (375, 'Cuando el pueblo alaba a Dios', '[{"c":"","l":"Cuando el pueblo alaba a Dios sucedencosas"},{"c":"","l":"suceden cosas, maravillosas. (2)"},{"c":"","l":"Hay salvación, liberación"},{"c":"","l":"y se siente la bendición. (2)"},{"c":"","l":"Hay santidad, fraternidad"},{"c":"","l":"y se vive la libertad. (2)"},{"c":"","l":"Aquí se siente la presencia de Dios (2)"},{"c":"","l":"Siento el fuego del Espíritu Santo (2)"},{"c":"","l":"Siento gozo, siento paz"},{"c":"","l":"siento el amor que Dios me da"},{"c":"","l":"aquí se siente, al presencia de Dios."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (376, 'Queremos ser', '[{"c":"","l":"Queremos ser, Señor, servidores de verdad"},{"c":"","l":"Testigos de tu amor, instrumentos de tu paz"},{"c":"","l":""},{"c":"","l":"Convéncenos que, por tener"},{"c":"","l":"un Padre Dios, somos hermanos."},{"c":"","l":"Su voluntad es que haya paz;"},{"c":"","l":"justicia y paz, van de la mano."},{"c":"","l":""},{"c":"","l":"Enséñanos a perdonar"},{"c":"","l":"para poder ser perdonados."},{"c":"","l":"Recuérdanos por qué tu amor"},{"c":"","l":"quiso morir crucificado."},{"c":"","l":""},{"c":"","l":"Ayúdanos a comprender"},{"c":"","l":"que la misión del bautizado"},{"c":"","l":"es compartir con los demás"},{"c":"","l":"su fe en Jesús resucitado."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (377, 'Estoy pensando en Dios', '[{"c":"","l":"Estoy pensando en Dios"},{"c":"","l":"Estoy pensando en su amor (2)"},{"c":"","l":""},{"c":"","l":"Olvida el hombre a su Señor"},{"c":"","l":"y poco a poco se desvía"},{"c":"","l":"y entre angustia y cobardía"},{"c":"","l":"va perdiéndose el amor;"},{"c":"","l":"Dios le habla como amigo"},{"c":"","l":"huye el hombre de su voz."},{"c":"","l":""},{"c":"","l":"Yo siento angustia cuando veo"},{"c":"","l":"que después de dos mil años"},{"c":"","l":"y entre tantos desengaños"},{"c":"","l":"pocos viven por amor."},{"c":"","l":"Muchos hablan de esperanza"},{"c":"","l":"más se alejan del Señor."},{"c":"","l":""},{"c":"","l":"Todo podría ser mejor"},{"c":"","l":"si mi pueblo procurase"},{"c":"","l":"caminar sin alejarse"},{"c":"","l":"del camino del Señor."},{"c":"","l":"Pero el hombre no hace suyos"},{"c":"","l":"los senderos del amor."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (378, 'Más allá del sol', '[{"c":"","l":"Aunque en esta vida, no tengo riquezas"},{"c":"","l":"sé que allá en la Gloria, tengo una mansión."},{"c":"","l":"Cual alma perdida, entre las pobrezas"},{"c":"","l":"de mí, Jesucristo, tuvo compasión."},{"c":"","l":""},{"c":"","l":"Más allá del sol, más allá del sol"},{"c":"","l":"Yo tengo un hogar, hogar bello hogar"},{"c":"","l":"Más allá del sol (2)"},{"c":"","l":""},{"c":"","l":"Y así por el mundo, sigo caminando"},{"c":"","l":"rodeado de pruebas, y de tentación"},{"c":"","l":"Pero a mi lado, viene caminando"},{"c":"","l":"mi bendito Cristo, en mi turbación."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (379, 'Hazme pobre  (Pascua Joven)', '[{"c":"","l":"Hazme pobre, siempre pobre"},{"c":"","l":"Por favor jamás permitas"},{"c":"","l":"Que me sienta tan seguro de mí mismo"},{"c":"","l":"Y mantenme como lo que soy"},{"c":"","l":"Una pobre y frágil vasija de barro y hazme dócil"},{"c":"","l":"En tus manos Señor, en tus manos"},{"c":"","l":""},{"c":"","l":"Hazme vulnerable frente a Ti"},{"c":"","l":"y a mis hermanos"},{"c":"","l":"Y mantén, mantén mis manos"},{"c":"","l":"siempre  abiertas para pedir"},{"c":"","l":"Y nunca tan seguras para sólo dar"},{"c":"","l":""},{"c":"","l":"Hazme Tu pequeño cántaro de barro"},{"c":"","l":"Muy contento de llevar"},{"c":"","l":"un gran tesoro dentro de mí"},{"c":"","l":"Mi gran tesoro, Tú, Jesús"},{"c":"","l":""},{"c":"","l":"Porque es Tu grandeza"},{"c":"","l":"que habita en mi pobreza"},{"c":"","l":"Y en mi pequeñez,"},{"c":"","l":"Señor brilla aún más Tu fuerza"},{"c":"","l":"Cuando soy débil, Eres mi firmeza"},{"c":"","l":""},{"c":"","l":"Mándame hermanos"},{"c":"","l":"que me recuerden mi flaqueza"},{"c":"","l":"Cantaré así Tu gloria y Tu poder"},{"c":"","l":"por siempre"},{"c":"","l":"En mi debilidad, Sé fuerte"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (380, 'Tu palabra Señor(P.Gallego)', '[{"c":"","l":"Tu palabra Señor, es palabra de amor"},{"c":"","l":"Que nos habla directo al corazón"},{"c":"","l":"Te pedimos Señor, que tengamos valor"},{"c":"","l":"Para ser hoy el eco de tu voz"},{"c":"","l":""},{"c":"","l":"La Palabra de Dios es fecunda"},{"c":"","l":"ilumina y nos da seguridad."},{"c":"","l":"Como el mar que en la noche profunda"},{"c":"","l":"su murmullo nos hace escuchar"},{"c":"","l":"el Señor con amor y ternura"},{"c":"","l":"nos da muestra de su inmensidad."},{"c":"","l":""},{"c":"","l":"La Palabra de Dios es aliento"},{"c":"","l":"para todo el que quiera ser mejor."},{"c":"","l":"A los hombres que buscan en serio"},{"c":"","l":"encender una llama de amor"},{"c":"","l":"el Señor los invita a su encuentro"},{"c":"","l":"a escuchar en silencio su Voz."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (381, 'Ayúdame Señor', '[{"c":"","l":"Hoy te quiero alabar, Señor,"},{"c":"","l":"y no sé, no sé cómo empezar,"},{"c":"","l":"no encuentro palabras para Ti, Oh Papá."},{"c":"","l":"En mis ojos sólo hay tristeza,"},{"c":"","l":"en mis labios, sólo amarguras,"},{"c":"","l":"en mi vida y en todo mi ser: soledad."},{"c":"","l":""},{"c":"","l":"Ayúdame Señor, tú que eres"},{"c":"","l":"La luz de mi vida, el faro que me guía,"},{"c":"","l":"Por esta oscuridad"},{"c":"","l":"Ayúdame Señor, tú que sanas"},{"c":"","l":"Las heridas de mi alma"},{"c":"","l":"Y llenas mis vacíos"},{"c":"","l":"Colmándolos de amor"},{"c":"","l":""},{"c":"","l":"Te soltaste de mi mano, querido hijo"},{"c":"","l":"y cambiaste, cambiaste de camino,"},{"c":"","l":"buscando otros destinos;"},{"c":"","l":"te volviste a equivocar."},{"c":"","l":"Cuantas veces me engañaste y a"},{"c":"","l":"Mis palabras cerrabas tus oídos"},{"c":"","l":"y hoy vuelves a Mí arrepentido,"},{"c":"","l":"dispuesto a cambiar."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (382, 'Perfume a tus pies(Marcela Gandara)', '[{"c":"","l":"Cuando pienso en tu amor y en tu fidelidad"},{"c":"","l":"No puedo hacer más que posarme y adorar"},{"c":"","l":"Y cuando pienso en cómo he sido"},{"c":"","l":"Y hasta donde me has traído"},{"c":"","l":"Me asombro de ti."},{"c":"","l":""},{"c":"","l":"Y no me quiero conformar"},{"c":"","l":"He probado y quiero más"},{"c":"","l":"Yo quiero enamorarme más de Ti"},{"c":"","l":"Enséñame a amarte y a vivir"},{"c":"","l":"Conforme a tu justicia y tu verdad"},{"c":"","l":"Con mi vida quiero adorar"},{"c":"","l":"Con todo lo que tengo y lo que soy"},{"c":"","l":"Todo lo que he sido te lo doy"},{"c":"","l":"Que mi vida sea para Ti"},{"c":"","l":"Como un perfume a tus pies"},{"c":"","l":""},{"c":"","l":"Cuando pienso en tu cruz"},{"c":"","l":"y en todo lo que has dado"},{"c":"","l":"Tu sangre por mí, por llevar mi pecado"},{"c":"","l":"Y cuando pienso en tu mano"},{"c":"","l":"hasta aquí hemos llegado"},{"c":"","l":"Por tu fidelidad."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (383, 'Signo de amor', '[{"c":"","l":"Tienes que encender una luz aunque sea pequeña"},{"c":"","l":"si ella se apaga este mundo será una tiniebla"},{"c":"","l":"tienes que arriesgarte a creer y no a cerrar más tu puerta"},{"c":"","l":"vale la pena su brillo aunque sea pequeña."},{"c":"","l":""},{"c":"","l":"No permitas que la noche invada tu vida"},{"c":"","l":"ahí mucha belleza en vos para que este escondida"},{"c":"","l":"no le niegues a los otros tus ojos, tu amor, tu voz, tu alegría"},{"c":"","l":"no te quites libertas ni borres tu sonrisa."},{"c":"","l":""},{"c":"","l":"Tienes que atreverte a vivir de una forma distinta"},{"c":"","l":"Llenarte los ojos de amor y sembrar cada día"},{"c":"","l":"Y verás cómo cambia este mundo cuando sin temor abras al fin tu puerta"},{"c":"","l":"Y mantengas prendida tu luz por pequeña que sea"},{"c":"","l":""},{"c":"","l":"Y cuando la oscuridad te lastime te lastime muy dentro"},{"c":"","l":"deja brillar tu candil que puede ser eterno"},{"c":"","l":"solo podrás ser feliz si te atreves a amar sin medida y sin tiempo"},{"c":"","l":"manteniendo la llama encendida a pesar de los vientos."},{"c":"","l":""},{"c":"","l":"Si quieres te ayudo a cuidar tu pequeña chispa"},{"c":"","l":"hasta que sea llamarada que de fuerza y vida"},{"c":"","l":"hasta que tu corazón sea un signo de amor para el que camina"},{"c":"","l":"y seamos muchos los que tengamos la luz encendida."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (384, 'Las huellas de tu amor', '[{"c":"","l":"Padre, qué hermosas son"},{"c":"","l":"las huellas de tuamor en mi vida,"},{"c":"","l":"en mi corazón."},{"c":"","l":"Padre, me pensaste"},{"c":"","l":"y criaste en tu amor"},{"c":"","l":"y mi cielo es contigo estar."},{"c":"","l":""},{"c":"","l":"Tantas personas, tantos gestos de amor"},{"c":"","l":"En mi camino Tú me has dado."},{"c":"","l":"Tanta fuerza y salvación"},{"c":"","l":"Tanta misericordia, tanta compasión"},{"c":"","l":"Que mi alma se estremece por Ti, Señor"},{"c":"","l":""},{"c":"","l":"Padre, Tú sabes que no siempre supe ver cómo en todo intervenías en mi bien."},{"c":"","l":"Padre, agradecida por siempre te alabaré."},{"c":"","l":"Tú has defendido mi pequeñez."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (385, 'Mi 100% (Maxi Largui)', '[{"c":"","l":"Todo para Vos, sólo para Vos"},{"c":"","l":"yo soy para Dios. (2)"},{"c":"","l":""},{"c":"","l":"Mi nombre, el dibujo de la huella digital"},{"c":"","l":"que delinea mi identidad."},{"c":"","l":"Mi historia, el camino que he tenido que abrazar"},{"c":"","l":"mi cansancio y el deseo de llegar"},{"c":"","l":"y mis anhelos, mi más profundo sueño,"},{"c":"","l":"cada suspiro de mi corazón, es tuyo."},{"c":"","l":"Mis manos y el esfuerzo cotidiano por el pan"},{"c":"","l":"la cosecha y la siembra"},{"c":"","l":"mi cuerpo y mi alma, mi salud, mi enfermedad"},{"c":"","l":"mi virtud y mi debilidad"},{"c":"","l":"y mis afectos, a quienes yo más quiero."},{"c":"","l":"Cada mirada que alumbra mi voz, es tuya. Mi Señor"},{"c":"","l":""},{"c":"","l":"Mi todo mi 100%, mi todo mi 100%"},{"c":"","l":"de sol a sol, de enero a enero"},{"c":"","l":"de vientre a vientre, te lo entrego."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (386, 'La niña de tu ojos  (Jesús Adrián Romero)', '[{"c":"","l":"Me viste a mi cuando nadie me vio"},{"c":"","l":"Me amaste a mi cuando nadie me amo"},{"c":"","l":""},{"c":"","l":"Y me diste nombre, yo soy tu niña"},{"c":"","l":"La niña de tus ojos, porque me amaste a mi"},{"c":"","l":"Me amaste a mí, me amaste a mi"},{"c":"","l":"Me amaste a mí, me amaste a mi"},{"c":"","l":""},{"c":"","l":"Te amo más que a mi vida"},{"c":"","l":"te amo más que a mi vida"},{"c":"","l":"Te amo más que a mi vida, más."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (387, 'Misericordioso como el Padre(Ariel Glaser)', '[{"c":"","l":"Cuentan que hace más de dos mil años"},{"c":"","l":"las ovejas del rebaño iban tristes por la vida lejos de un pastor que las guiara"},{"c":"","l":"sus corazones llevaban tanta herida que sanar"},{"c":"","l":""},{"c":"","l":"Fue allí que Dios, rico en misericordia"},{"c":"","l":"nos manifestó su Gloria, desde el vientre de María"},{"c":"","l":"revelándonos su amor de Padre"},{"c":"","l":"en el Verbo hecho carne,"},{"c":"","l":"¡Qué alegría! En verdad"},{"c":"","l":""},{"c":"","l":"Y en un abrazo misericordioso nos unió"},{"c":"","l":"Nos devolvió la dignidad perdida"},{"c":"","l":"Buscó la oveja, que del fiel rebaño se alejó"},{"c":"","l":"Sanó su herida y la rescató (2)"},{"c":"","l":""},{"c":"","l":"Con mirarlo uno veía al Padre"},{"c":"","l":"su ternura era el mensaje, su actitud la cercanía"},{"c":"","l":"Nos llenaba de besos y de abrazos"},{"c":"","l":"y buscaba a cada paso darnos vida y libertad"},{"c":"","l":""},{"c":"","l":"Misericordiosos como el Padre"},{"c":"","l":"nos pedía que seamos frente a tanta hipocresía."},{"c":"","l":"No juzgar para no ser juzgados"},{"c":"","l":"ver en el otro a un hermano con heridas que sanar"},{"c":"","l":""},{"c":"","l":"Jesucristo estas a nuestro lado"},{"c":"","l":"y nos pides que veamos tanta dignidad perdida"},{"c":"","l":"tantos gritos y tantas miradas"},{"c":"","l":"tanta gente postergada y excluida de verdad"},{"c":"","l":""},{"c":"","l":"Enséñanos a estrechar sus manos"},{"c":"","l":"para que juntos sintamos tu grata presencia amiga"},{"c":"","l":"y esa caridad que nos obliga"},{"c":"","l":"a ser signos de alegría y de solidaridad"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (388, 'Haz tu milagro en mi (P. Marcelo Rossi)', '[{"c":"","l":"Como Zaqueo yo quiero subir"},{"c":"","l":"a lo más alto que yo pueda"},{"c":"","l":"solo para verte, mirar hacia Ti"},{"c":"","l":"llamar tu atención para mi"},{"c":"","l":""},{"c":"","l":"Necesito de ti Señor"},{"c":"","l":"necesito de ti oh Padre"},{"c":"","l":"soy pequeño y nada más"},{"c":"","l":"dame Tu paz, dejo todo para seguirte"},{"c":"","l":""},{"c":"","l":"Entra en mi casa, entra en mi vida"},{"c":"","l":"Toca en mi estructura,"},{"c":"","l":"sana todas las heridas"},{"c":"","l":"Dame de tu santidad quiero amarte solo a Ti"},{"c":"","l":"Porque el Señor es mi gran amor"},{"c":"","l":"Haz tu milagro en mi"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (389, 'Esta es el agua pura', '[{"c":"","l":"*Esta es el agua pura que el Creador nos dio."},{"c":"","l":"Esta es el agua nueva que de la cruz brotó.*"},{"c":"","l":""},{"c":"","l":"Del agua y del Espíritu, la vida comenzó,"},{"c":"","l":"por el agua del bautismo, la nueva creación (bis)"},{"c":"","l":""},{"c":"","l":"El agua de nuestro río, vida y salud nos da,"},{"c":"","l":"y las aguas del bautismo vida eterna dan (bis)"},{"c":"","l":""},{"c":"","l":"Por el paso del Mar Rojo, Dios a Israel libró;"},{"c":"","l":"en el agua del bautismo nace el pueblo de Dios (bis)"},{"c":"","l":""},{"c":"","l":"Jesús recibió el Espíritu, en el río Jordán;"},{"c":"","l":"nuestro pueblo en el bautismo nace a la libertad (bis)"},{"c":"","l":""},{"c":"","l":"Del pecho abierto de Cristo, sangre y agua brotó;"},{"c":"","l":"es el agua del bautismo que da la salvación (bis)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (390, 'Este es el día que hizo el Señor', '[{"c":"","l":"Este es el día que hizo el Señor, aleluya!"},{"c":"","l":"Hoy la alegría es de todos, aleluya!"},{"c":"","l":""},{"c":"","l":"Den gracias al Señor, porque es bueno"},{"c":"","l":"Den gracias a su amor, que es eterno"},{"c":"","l":"Que lo diga el pueblo de Israel"},{"c":"","l":"¡Es eterno su amor!"},{"c":"","l":""},{"c":"","l":"La mano del Señor es sublime"},{"c":"","l":"Hace proezas la mano del Señor"},{"c":"","l":"No voy a morir, yo viviré"},{"c":"","l":"Para contar lo que hizo el Señor"},{"c":"","l":""},{"c":"","l":"La piedra que desecharon los constructores"},{"c":"","l":"Se ha convertido en la piedra angular"},{"c":"","l":"Esto ha sido hecho por el Señor"},{"c":"","l":"¡Y es admirable a nuestros ojos!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (391, 'Gloria (Seminario)', '[{"c":"","l":"*Gloria a Dios en el cielo,"},{"c":"","l":"y en la tierra paz a los hombres"},{"c":"","l":"en la tierra paz a los hombres,"},{"c":"","l":"que ama el Señor*"},{"c":"","l":""},{"c":"","l":"Por tu inmensa gloria, te alabamos,"},{"c":"","l":"te bendecimos, te adoramos"},{"c":"","l":"te glorificamos, te damos gracias,"},{"c":"","l":"Señor Dios, Rey Celestial,"},{"c":"","l":"Dios Padre todopoderoso"},{"c":"","l":""},{"c":"","l":"Señor hijo único Jesucristo,"},{"c":"","l":"Señor Dios, cordero de Dios, hijo del Padre."},{"c":"","l":"Tú que quitas el pecado del mundo,"},{"c":"","l":"ten piedad de nosotros."},{"c":"","l":"Tú que quitas el pecado del mundo,"},{"c":"","l":"atiende nuestras súplicas."},{"c":"","l":"Tú que estás sentado a la derecha del Padre,"},{"c":"","l":"ten piedad de nosotros."},{"c":"","l":""},{"c":"","l":"*Gloria a Dios en el cielo,"},{"c":"","l":"y en la tierra paz a los hombres"},{"c":"","l":"en la tierra paz a los hombres,"},{"c":"","l":"que ama el Señor*"},{"c":"","l":""},{"c":"","l":"Porque solo Tú eres santo, solo Tu Señor."},{"c":"","l":"Solo Tú altísimo Jesucristo, con el Espíritu Santo,"},{"c":"","l":"En la gloria de Dios Padre"},{"c":"","l":""},{"c":"","l":"¡Amen, amén!"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (392, 'Glorioso Rey en la Cruz', '[{"c":"","l":"Glorioso Rey en la Cruz"},{"c":"","l":"Tu reino no es de este mundo"},{"c":"","l":"Tus joyas son tus llagas, tu trono es el madero"},{"c":"","l":"Oh, cuán gran misterio"},{"c":"","l":""},{"c":"","l":"Glorioso Rey en la Cruz"},{"c":"","l":"Tu reino es un reino eterno"},{"c":"","l":"Tu manto es tu sangre, las espinas, tu corona"},{"c":"","l":"Tu Pasión es tu victoria"},{"c":"","l":""},{"c":"","l":"*Cuán glorioso fue tu amor en la cruz"},{"c":"","l":"Tu realeza es incomparable, Jesús"},{"c":"","l":"Te alabamos y exaltamos tu poder"},{"c":"","l":"Nos rendimos ante el rey,"},{"c":"","l":"nos rendimos ante el rey*"},{"c":"","l":""},{"c":"","l":"Glorioso Rey en la Cruz"},{"c":"","l":"Nos amaste hasta el extremo"},{"c":"","l":"Siendo Rey del Universo"},{"c":"","l":"Por amor te hiciste esclavo"},{"c":"","l":"Y por eso te cantamos"},{"c":"","l":""},{"c":"","l":"*Cuán glorioso fue tu amor en la cruz"},{"c":"","l":"Tu realeza es incomparable, Jesús"},{"c":"","l":"Te alabamos y exaltamos tu poder"},{"c":"","l":"Nos rendimos ante el rey,"},{"c":"","l":"nos rendimos ante el rey*"},{"c":"","l":""},{"c":"","l":"Tú pagaste con tu muerte el precio"},{"c":"","l":"de nuestra redención, Rey en la cruz"},{"c":"","l":"Por la ofrenda de tu cuerpo y tu sangre"},{"c":"","l":"Nos concedes el perdón"},{"c":"","l":""},{"c":"","l":"*Cuán glorioso fue tu amor en la cruz"},{"c":"","l":"Tu realeza es incomparable, Jesús"},{"c":"","l":"Te alabamos y exaltamos tu poder"},{"c":"","l":"Nos rendimos ante el rey,"},{"c":"","l":"nos rendimos ante el rey*"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (393, 'Ven Espíritu de Santidad', '[{"c":"","l":"*Ven Espíritu de santidad, ven Espíritu de luz."},{"c":"","l":"Ven Espíritu de fuego, ven abrázanos.*"},{"c":"","l":""},{"c":"","l":"Ven Espíritu del padre, se nuestra luz."},{"c":"","l":"Derrama del cielo, tu esplendor de gloria."},{"c":"","l":""},{"c":"","l":"Testimonio cierto, tú nos enseñas"},{"c":"","l":"a proclamar que Jesús resucitó."},{"c":"","l":""},{"c":"","l":"Ven unción celeste, fuego de agua viva,"},{"c":"","l":"danos de beber del cáliz del amor."},{"c":"","l":""},{"c":"","l":"Eres la alegría, fuego de la Iglesia."},{"c":"","l":"Pon en nuestros ojos la mirada del Señor."},{"c":"","l":""},{"c":"","l":"Haznos reconocer, el amor del padre"},{"c":"","l":"y revélanos el rostro de Jesús."},{"c":"","l":""},{"c":"","l":"Fuego que nos quema hasta las entrañas,"},{"c":"","l":"por ti resplandece la luz del amor."},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (394, 'Salmo 103', '[{"c":"","l":"*Envía, Señor tu espíritu"},{"c":"","l":"y renueva toda la tierra (bis)*"},{"c":"","l":""},{"c":"","l":"Bendice al Señor, alma mía:"},{"c":"","l":"Señor, Dios mío, que grande eres!"},{"c":"","l":"¡que variadas son tus obras!"},{"c":"","l":"¡la tierra está llena de tus criaturas!"},{"c":"","l":""},{"c":"","l":"Si le quitas el aliento,"},{"c":"","l":"expiran y vuelven al polvo."},{"c":"","l":"Si envías tu aliento, son creados,"},{"c":"","l":"y renuevas la faz de la tierra."},{"c":"","l":""},{"c":"","l":"¡Gloria al Señor para siempre,"},{"c":"","l":"alégrese El, por sus obras!"},{"c":"","l":"Que mi canto le sea agradable,"},{"c":"","l":"me alegraré en el Señor!"},{"c":"","l":""}]', 'SALMOS Y CANTICOS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (395, 'Caballo y Caballero', '[{"c":"","l":"*Cantemus domino"},{"c":"","l":"Magnificatvs est gloriose enim"},{"c":"","l":"Deiecitit in mare equvm et eqvitatem"},{"c":"","l":""},{"c":"","l":"Cantemos al Señor,"},{"c":"","l":"El ha manifestado su Gloria"},{"c":"","l":"El ha arrojado al agua caballo y caballero*"},{"c":"","l":""},{"c":"","l":"El Señor es mi fuerza"},{"c":"","l":"y el objeto de mi canto, &Eacute;l es mi salvador."},{"c":"","l":""},{"c":"","l":"El Señor es un valiente guerrero,"},{"c":"","l":"Yahvé es su nombre, su mano quebró al enemigo."},{"c":"","l":"Como una piedra cayeron al fondo de las aguas."},{"c":"","l":""},{"c":"","l":"Quién como Tú entre los dioses, oh Señor,"},{"c":"","l":"tendiste tu diestra sobre ellos,"},{"c":"","l":"se hundieron como plomo en las poderosas aguas."},{"c":"","l":""},{"c":"","l":"Tú nos conducirás a la montaña,"},{"c":"","l":"al lugar donde habitas, oh Señor,"},{"c":"","l":"donde reinarás por los siglos de los siglos."},{"c":"","l":""},{"c":"","l":"*Cantemos al Señor,"},{"c":"","l":"El ha manifestado su Gloria"},{"c":"","l":"El ha arrojado al agua caballo y caballero"},{"c":"","l":""},{"c":"","l":"Cantemus domino"},{"c":"","l":"Magnificatvs est gloriose enim"},{"c":"","l":"Deiecitit in mare equvm et eqvitatem*"}]', 'PASCUA', '{"youtube_url":"","autor":"EQVVS ET EQVES"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (396, 'Salmo 18', '[{"c":"","l":"*Señor, tú tienes palabra de vida eterna.*"},{"c":"","l":""},{"c":"","l":"La ley del Señor es perfecta, reconforta el alma;"},{"c":"","l":"el testimonio del Señor es verdadero,"},{"c":"","l":"da sabiduría al simple."},{"c":"","l":"Los preceptos del Señor son rectos,"},{"c":"","l":"alegran el corazón;"},{"c":"","l":"la instrucción del Señor es clara, da luz a los ojos."},{"c":"","l":""},{"c":"","l":"La palabra del Señor es pura,"},{"c":"","l":"permanece para siempre;"},{"c":"","l":"los juicios del Señor son la verdad,"},{"c":"","l":"eternamente justos."},{"c":"","l":"Son más valiosos que el oro, que el oro más fino;"},{"c":"","l":"más dulces que la miel que destila del panal."},{"c":"","l":""}]', 'SALMOS Y CANTICOS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (397, 'Lléname de Ti', '[{"c":"","l":"Como el ciervo busca por las aguas"},{"c":"","l":"así clama mi alma por ti, Señor."},{"c":"","l":"Día y noche yo tengo sed de Ti"},{"c":"","l":"y sólo a Ti buscaré."},{"c":"","l":""},{"c":"","l":"Lléname, lléname Señor."},{"c":"","l":"Dame más, más de tu amor."},{"c":"","l":"Yo tengo sed, sólo de Ti."},{"c":"","l":"Lléname, Señor."}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (398, 'Pequeños y grandes', '[{"c":"","l":"Aleluya, Aleluya a... pequeños y grandes."},{"c":"","l":"Aleluya, Aleluya a... por siempre Señor."},{"c":"","l":"Porque el Señor todo poderoso reina..."},{"c":"","l":"Porque el Señor todo poderoso reina..."}]', 'ALELUYA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (399, 'Debes amar', '[{"c":"","l":"Debes amar, la arcilla que va en tus manos,"},{"c":"","l":"debes amar su arena hasta la locura,"},{"c":"","l":"y si no, no lo emprendas que será en vano."},{"c":"","l":""},{"c":"","l":"*Sólo el amor alumbra lo que perdura,"},{"c":"","l":"sólo el amor convierte en milagro el barro. (bis)*"},{"c":"","l":""},{"c":"","l":"Debes amar, el tiempo de los intentos,"},{"c":"","l":"debes amar la hora que nunca brilla,"},{"c":"","l":"y si no, no pretendas tocar lo cierto."},{"c":"","l":""},{"c":"","l":"*Sólo el amor engendra la maravilla,"},{"c":"","l":"sólo el amor consigue encender lo muerto. (bis)*"}]', 'ACCION DE GRACIAS / ADORACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (400, 'Ofrenda permanente', '[{"c":"","l":"Tómame en tus brazos y prepárame Jesús."},{"c":"","l":"Dame de tu espíritu para abrazar tu cruz."},{"c":"","l":"Te ofrezco mi vida, se Tú señor mi guía"},{"c":"","l":"La noche pasa rápido y mañana he de morir."},{"c":"","l":"Pero como siempre tu calor lo siento en mí."},{"c":"","l":"Me pongo en tus manos, descanso en tus brazos."},{"c":"","l":""},{"c":"","l":"*Hoy vengo a darte todo, lo que hay dentro de mi"},{"c":"","l":"Vengo a entregarte todo, por lo que viví"},{"c":"","l":"Mi juventud señor está en tu altar... Recíbelaaa"},{"c":"","l":"Hoy digo si hoy te respondo con sinceridad"},{"c":"","l":"Estoy dispuesto y me arriesgo este paso a dar"},{"c":"","l":"Aquí estoy, señor hágase en mi, tu voluntad.*"},{"c":"","l":""},{"c":"","l":"Tú has sido bien claro sobre lo que debo dar"},{"c":"","l":"y hoy me has concebido mi vida ofrendar."},{"c":"","l":"Quédate conmigo, quiero ser testigo..."}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (401, 'A tanto amor', '[{"c":"","l":"Hecha un mar de lágrimas al verlo allí en la cruz,"},{"c":"","l":"se acordó del niño que ella misma diera a luz."},{"c":"","l":"Y entre el firmamento y su mirada de dolor,"},{"c":"","l":"bien supo serle fiel, a tanto amor."},{"c":"","l":""},{"c":"","l":"No rompió el silencio cuando el cielo se quebró,"},{"c":"","l":"no volteó sus ojos al final cuando expiró."},{"c":"","l":"Se sintió caer pero así mismo no cayó,"},{"c":"","l":"y amó a pesar de que, el mundo lo entregó."},{"c":"","l":""},{"c":"","l":"*Solo besó sus pies,"},{"c":"","l":"y a Dios se lo ofreció."},{"c":"","l":"Sin preguntar por qué"},{"c":"","l":"a todos perdonó, pues entendió el amor."},{"c":"","l":"Que Jesús predicó,"},{"c":"","l":"que su Hijo predicó."},{"c":"","l":"Ella entendió el amor,"},{"c":"","l":"que &Eacute;l enseñó.*"},{"c":"","l":""},{"c":"","l":"Entre la llovizna, la tristeza y el temor,"},{"c":"","l":"lo tomó en sus brazos cuando ya no respiró."},{"c":"","l":"Junto con su alma le traspasó el corazón,"},{"c":"","l":"la espada que esa cruz todo lo consumó."},{"c":"","l":""},{"c":"","l":"No rompió el silencio cuando el cielo se quebró,"},{"c":"","l":"no volteó sus ojos y el sepulcro se cerró."},{"c":"","l":"Se sintió caer pero su fe permaneció,"},{"c":"","l":"y amó a pesar de que el mundo lo entregó."},{"c":"","l":""}]', 'CUARESMA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (402, 'Un hombre de Dios', '[{"c":"","l":"*Fruto de un lugar,"},{"c":"","l":"fruto de una historia,"},{"c":"","l":"Juan fue un hombre."},{"c":"","l":"Fruto de un llamado,"},{"c":"","l":"fruto de una entrega,"},{"c":"","l":"Juan fue un santo.*"},{"c":"","l":""},{"c":"","l":"Acción de Dios que se hace vida,"},{"c":"","l":"proyecto real de Redención,"},{"c":"","l":"para salvar la juventud"},{"c":"","l":"a Don Bosco suscitó."},{"c":"","l":""},{"c":"","l":"Manos de madre intervinieron"},{"c":"","l":"para formar un corazón"},{"c":"","l":"de Padre y Maestro, capaz"},{"c":"","l":"de una entrega total."},{"c":"","l":""},{"c":"","l":"He prometido siempre a Dios,"},{"c":"","l":"mi último aliento yo daré,"},{"c":"","l":"estoy dispuesto a dar mi vida,"},{"c":"","l":"todo por él yo arriesgaré."},{"c":"","l":""},{"c":"","l":"Hay un proyecto que me mueve:"},{"c":"","l":"Cristo a los jóvenes llevar"},{"c":"","l":"para que el Evangelio sea"},{"c":"","l":"su camino, su verdad."},{"c":"","l":""},{"c":"","l":"San Juan Bosco llegó a mi,"},{"c":"","l":"rescató todo lo bueno."},{"c":"","l":"El en mí a Cristo vio,"},{"c":"","l":"el mi corazón sanó."},{"c":"","l":""},{"c":"","l":"La alegría, el entusiasmo"},{"c":"","l":"y las ganas de vivir,"},{"c":"","l":"todo en Cristo unificó"},{"c":"","l":"y en compromiso transformó."}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (403, 'Pueblo de Reyes', '[{"c":"","l":"*Pueblo de reyes, asamblea santa"},{"c":"","l":"Pueblo sacerdotal, pueblo de Dios"},{"c":"","l":"Bendice a tu Señor*"},{"c":"","l":""},{"c":"","l":"Te cantamos, oh, Hijo amado del Padre"},{"c":"","l":"Te alabamos, eterna palabra salida de Dios"},{"c":"","l":"Te cantamos, oh, Hijo de la Virgen María"},{"c":"","l":"Te alabamos, oh, Cristo nuestro hermano"},{"c":"","l":"Nuestro Salvador"},{"c":"","l":""},{"c":"","l":"Te cantamos a Ti, esplendor de la gloria"},{"c":"","l":"Te alabamos, estrella radiante que anuncias el día"},{"c":"","l":"Te cantamos, oh, luz que iluminas nuestras sombras"},{"c":"","l":"Te alabamos, antorcha de la nueva Jerusalén"},{"c":"","l":""},{"c":"","l":"Te cantamos, Mesías, que anunciaron los profetas"},{"c":"","l":"Te alabamos, oh, hijo de Abraham e hijo de David"},{"c":"","l":"Te cantamos, Mesías, esperado por los pobres"},{"c":"","l":"Te alabamos, oh, Cristo, nuestro rey de humilde corazón"},{"c":"","l":""},{"c":"","l":"Te cantamos, mediador entre Dios y los hombres"},{"c":"","l":"Te alabamos, oh, ruta viviente, camino del cielo"},{"c":"","l":"Te cantamos, sacerdote de la nueva alianza"},{"c":"","l":"Te alabamos, Tú eres nuestra paz por la sangre de la cruz"},{"c":"","l":""},{"c":"","l":"Te cantamos, cordero de la Pascua eterna"},{"c":"","l":"Te alabamos, oh, víctima que borras nuestros pecados"},{"c":"","l":"Te cantamos, oh, templo de la nueva alianza"},{"c":"","l":"Oh, piedra angular y roca de Israel"},{"c":"","l":""},{"c":"","l":""}]', 'PASCUA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (404, 'Acuérdate siempre (Meana)', '[{"c":"","l":"*¿Quién eres tú? \"Yo soy tu madre\"."},{"c":"","l":"¿Quién eres tú? \"Siempre tu auxilio\"."},{"c":"","l":"Acuérdate siempre de mí."},{"c":"","l":"María, aquí tienes a tu hijo."},{"c":"","l":"María, aquí tienes a tu hijo.*"},{"c":"","l":""},{"c":"","l":"Ayer junté las manos inocentes"},{"c":"","l":"y me dormí en tus ojos."},{"c":"","l":"Ayer crucé cien noches solitario"},{"c":"","l":"y me aferré a tus manos."},{"c":"","l":"¿Que sería de mí sin ti,"},{"c":"","l":"mi Señora, sin ti?"},{"c":"","l":""},{"c":"","l":"Hoy atravieso el lago con tu Hijo,"},{"c":"","l":"tú rezas en la barca."},{"c":"","l":"Hoy parto con latido misionero,"},{"c":"","l":"el rumbo tú lo marcas."},{"c":"","l":"¿Qué sería de mí sin ti,"},{"c":"","l":"mi Señora, sin ti?"},{"c":"","l":""},{"c":"","l":"Mañana guardarás, Dulzura nuestra,"},{"c":"","l":"mi viaje en tu manto."},{"c":"","l":"Serás el puerto de nuestra esperanza,"},{"c":"","l":"a Jesús alcánzanos."},{"c":"","l":"¿Qué sería de mí sin ti,"},{"c":"","l":"mi Señora, sin ti?"}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (405, 'Madre mostramos a tu hijo Jesus (Pablo Martinez)', '[{"c":"","l":"Vamos caminando, vamos transitando el tiempo,"},{"c":"","l":"somos peregrinos que buscamos al Dios vivo."},{"c":"","l":"Una sed intensa que nos nace desde adentro,"},{"c":"","l":"es la que nos lleva a querer ver al maestro."},{"c":"","l":"Y con nosotros vas, vos nos acompañás,"},{"c":"","l":"seguro contigo a tu hijo vamos a encontrar."},{"c":"","l":"por eso todos hoy te queremos cantar:"},{"c":"","l":""},{"c":"","l":"*Madre mostranos a tu hijo Jesús,"},{"c":"","l":"Abrí el camino que nos lleve a su luz."},{"c":"","l":"Tu amor nos guía, queremos ver a Jesús.*"},{"c":"","l":""},{"c":"","l":"Vos que lo tuviste en tu seno virginal,"},{"c":"","l":"que lo acompañaste en su vida hasta el final."},{"c":"","l":"Vos que le enseñaste siendo niño a caminar,"},{"c":"","l":"vos que lo escuchaste decir su primer \"mamá\"."},{"c":"","l":"Hoy nosotros también, queremos aprender,"},{"c":"","l":"más de tu hijo y qué mejor si vos nos enseñás."},{"c":"","l":"por eso todos hoy te queremos cantar:"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":"Fiel a sus promesas diste un sí que no cesó,"},{"c":"","l":"se escuchó al inicio y resonó en la pasión."},{"c":"","l":"En la noche de la historia una luz brilló,"},{"c":"","l":"cuando tu hijo amado en la cruz nos redimió."},{"c":"","l":"Al pie estabas vos, y nosotros también,"},{"c":"","l":"fue allí donde tu vida con la nuestra él unió."},{"c":"","l":"Por eso todos hoy te queremos cantar:"},{"c":"","l":""},{"c":"","l":"Madre que nos amas y en el viaje nos animas,"},{"c":"","l":"Madre que nos llamas a vivir la Eucaristía."},{"c":"","l":"Mujer generosa que se ofrece por el Reino,"},{"c":"","l":"Dulce intercesora y consuelo para el pueblo."},{"c":"","l":"Así como en Caná, hacelo una vez más,"},{"c":"","l":"pedí a tu hijo que transforme nuestra vida en más,"},{"c":"","l":"por eso todos hoy te queremos cantar:"},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (406, 'Ya llegó, ya llegó', '[{"c":"","l":"¡Ya llegó ya llegó, el Espíritu Santo ya llegó! ¡Ya llegó ya llegó, el Espíritu Santo ya llegó!"},{"c":"","l":""},{"c":"","l":"Lo siento en mis manos, lo siento en mis pies; lo siento en el alma, en todo mi ser (bis)"},{"c":"","l":""},{"c":"","l":"Aquel que caminó sobre las aguas"},{"c":"","l":"Aquel que caminó sobre las aguas"},{"c":"","l":""},{"c":"","l":"Esta aquí, está a mi lado"},{"c":"","l":"Esta aquí, está a mi lado"},{"c":"","l":""},{"c":"","l":"Como un rayo, cayendo sobre mi"},{"c":"","l":"Como un rayo, cayendo sobre mi"},{"c":"","l":""},{"c":"","l":"Que quema, que quema, que quema"},{"c":"","l":"Que quema, que quema, que quema"},{"c":"","l":"Que quema, que quema, que quema"},{"c":"","l":"Que quema, que quema, que quema"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'ESPIRITU SANTO', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (407, 'Oigo una voz', '[{"c":"","l":"Oigo una voz que llama, oigo una voz cercana,"},{"c":"","l":"eres Tu Señor, ¿qué quieres que yo haga?"},{"c":"","l":"Señor ¿qué puedo darte?, soy pobre e ignorante,"},{"c":"","l":"háblame Señor, ¿qué quieres que yo haga?"},{"c":"","l":""},{"c":"","l":"*Ven, ven y sígueme, contigo yo estaré"},{"c":"","l":"luchando por la paz."},{"c":"","l":"Ven, ven y sígueme, yo te daré una red,"},{"c":"","l":"para poder pescar.*"},{"c":"","l":""},{"c":"","l":"Mis manos están ya prontas, mi corazón esta ardiendo."},{"c":"","l":"Hablamé Señor, ¿qué quieres que yo haga?"},{"c":"","l":"Dispuesto estoy a todo, con mi cruz iré a tu lado,"},{"c":"","l":"vamos ya Señor, te seguiré confiado."}]', 'ENTRADA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (408, 'Ven y reina, Madre de Dios', '[{"c":"","l":""},{"c":"","l":"Madre de misericordia,"},{"c":"","l":"Madre del Salvador,"},{"c":"","l":"Auxilio de los cristianos,"},{"c":"","l":"ruega por nosotros a Dios."},{"c":"","l":""},{"c":"","l":"Virgen fiel y prudente,"},{"c":"","l":"Reina de la Paz,"},{"c":"","l":"Santa Madre de Cristo,"},{"c":"","l":"Que hagamos su voluntad."},{"c":"","l":""},{"c":"","l":"*¡Ven y reina, Madre de Dios,"},{"c":"","l":"Reina y Madre de la Creación!"},{"c":"","l":"¡Ven y reina en nuestro corazón,"},{"c":"","l":"Para que reine el Señor!*"},{"c":"","l":""},{"c":"","l":"*¡Ven y reina, Madre de Dios,"},{"c":"","l":"Reina y Madre de la Creación!"},{"c":"","l":"¡Ven y reina en nuestro corazón,"},{"c":"","l":"Para que reine Jesús, el Señor!*"},{"c":"","l":""},{"c":"","l":"Madre del Buen Consejo,"},{"c":"","l":"Ideal de santidad,"},{"c":"","l":"Reina del Santo Rosario,"},{"c":"","l":"enséñanos a rezar."},{"c":"","l":""},{"c":"","l":"Madre Inmaculada,"},{"c":"","l":"Madre del Creador."},{"c":"","l":"Reina asunta a los cielos,"},{"c":"","l":"llévanos contigo a Dios."},{"c":"","l":""},{"c":"","l":"*¡Ven y reina, Madre de Dios,"},{"c":"","l":"Reina y Madre de la Creación!"},{"c":"","l":"¡Ven y reina en nuestro corazón,"},{"c":"","l":"Para que reine el Señor!*"},{"c":"","l":""},{"c":"","l":"*¡Ven y reina, Madre de Dios,"},{"c":"","l":"Reina y Madre de la Creación!"},{"c":"","l":"¡Ven y reina en nuestro corazón,"},{"c":"","l":"Para que reine Jesús, el Señor!*"},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (409, 'Hay ángeles volando en este lugar', '[{"c":"","l":"Si sientes un murmullo muy cerca de ti"},{"c":"","l":"Es un ángel llegando para recibir"},{"c":"","l":"Todas tus oraciones y llevarlas al cielo"},{"c":"","l":""},{"c":"","l":"Así, abre el corazón y comienza a alabar"},{"c":"","l":"El gozo del cielo todo sobre el altar"},{"c":"","l":"Hay un ángel llegando y bendición en sus manos"},{"c":"","l":""},{"c":"","l":"*Hay ángeles volando en este lugar"},{"c":"","l":"En medio del pueblo y junto al altar"},{"c":"","l":"Subiendo y bajando en todas las direcciones"},{"c":"","l":""},{"c":"","l":"No sé si la iglesia subió o si del cielo bajó"},{"c":"","l":"Sí sé que está lleno de ángeles de Dios"},{"c":"","l":"Porque el mismo Dios está aquí*"},{"c":"","l":""},{"c":"","l":"Cuando los ángeles pasan, la Iglesia se alegra"},{"c":"","l":"Ella canta, ella llora, ella ríe y congrega"},{"c":"","l":"Enfrenta al infierno y se disipa el mal"},{"c":"","l":""},{"c":"","l":"Siente la brisa del vuelo de tu ángel ahora"},{"c":"","l":"Confía, hermano, pues esta es tu hora"},{"c":"","l":"La bendición llegó y te la vas a llevar"}]', 'ALABANZA / ANIMACION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (410, 'Contigo María', '[{"c":"","l":"Quiero caminar contigo María"},{"c":"","l":"Pues tú eres mi madre eres mi guía"},{"c":"","l":"Tú eres para mi el más grande ejemplo"},{"c":"","l":"De santidad de humildad"},{"c":"","l":""},{"c":"","l":"Quiero caminar contigo María"},{"c":"","l":"No solo un momento todos los días"},{"c":"","l":"Necesito tu amor de madre"},{"c":"","l":"Tu intercesión ante el señor"},{"c":"","l":""},{"c":"","l":"*Guía mis pasos llévame al cielo"},{"c":"","l":"Bajo tu manto no tengo miedo"},{"c":"","l":"Llena de gracia, ave María"},{"c":"","l":"Hoy yo te ofrezco toda mi vida*"},{"c":"","l":""},{"c":"","l":"Quiero caminar contigo María"},{"c":"","l":"Madre en el dolor y en la alegría"},{"c":"","l":"Tú que fuiste fiel hasta el extremo"},{"c":"","l":"Fiel en la cruz, fiel a Jesús"},{"c":"","l":""},{"c":"","l":"*Guía mis pasos llévame al cielo"},{"c":"","l":"Bajo tu manto no tengo miedo"},{"c":"","l":"Llena de gracia, ave María"},{"c":"","l":"Hoy yo te ofrezco toda mi vida*"},{"c":"","l":""},{"c":"","l":"Celestial princesa mírame con compasión"},{"c":"","l":"Hoy te doy mi alma, vida y corazón"},{"c":"","l":""},{"c":"","l":"*Guía mis pasos llévame al cielo"},{"c":"","l":"Bajo tu manto no tengo miedo"},{"c":"","l":"Llena de gracia, ave María"},{"c":"","l":"Hoy yo te ofrezco toda mi vida*"}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (411, 'Tu palabra es querendona', '[{"c":"","l":"Cuando nos das tu palabra"},{"c":"","l":"la vida palpita tanto,"},{"c":"","l":"que el pueblo entero te nombra"},{"c":"","l":"con verso, música y canto. (2)"},{"c":"","l":""},{"c":"","l":"*TU PALABRA ES QUERENDONA,"},{"c":"","l":"SUAVE Y DULCE COMO MIEL."},{"c":"","l":"NOS TOCA Y NOS ENAMORA"},{"c":"","l":"Y NOS HACE PUEBLO FIEL*"},{"c":"","l":""},{"c":"","l":"Es que tu palabra es Vida"},{"c":"","l":"que consuela al caminante"},{"c":"","l":"y al débil lo reanima"},{"c":"","l":"pa&rsquo; que siga pa&rsquo; delante. (2)"},{"c":"","l":""},{"c":"","l":"Es agua limpia y fresquita"},{"c":"","l":"que alivia tantos penares,"},{"c":"","l":"es simple porque es clarita,"},{"c":"","l":"serenata de cantares. (2)"},{"c":"","l":""},{"c":"","l":""}]', 'ALELUYA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (412, 'Gloria (Nicolás Glaser)', '[{"c":"","l":"*Gloria a Dios en el cielo"},{"c":"","l":"Gloria a Dios en el cielo"},{"c":"","l":"Y en la tierra paz, y en la tierra paz,"},{"c":"","l":"a los hombres que ama el Señor* (bis)"},{"c":"","l":""},{"c":"","l":"Por tu inmensa gloria"},{"c":"","l":"te alabamos te bendecimos."},{"c":"","l":"Te adoramos, te glorificamos,"},{"c":"","l":"te damos gracias."},{"c":"","l":"Señor Dios, Rey celestial,"},{"c":"","l":"Dios Padre Todopoderoso."},{"c":"","l":"Señor, hijo único,"},{"c":"","l":"Jesucristo"},{"c":"","l":""},{"c":"","l":"Señor Dios, Cordero de Dios,"},{"c":"","l":"hijo del Padre."},{"c":"","l":"Tu que quitas el pecado del mundo,"},{"c":"","l":"ten piedad de nosotros."},{"c":"","l":"Tu que quitas el pecado del mundo,"},{"c":"","l":"atiende nuestra súplica."},{"c":"","l":"Tu que estás sentado a la derecha del Padre,"},{"c":"","l":"ten piedad de nosotros."},{"c":"","l":""},{"c":"","l":"Porque solo tu, eres Santo."},{"c":"","l":"Solo tu, Señor."},{"c":"","l":"Solo tu Altísimo Jesucristo,"},{"c":"","l":"Con el Espíritu Santo,"},{"c":"","l":"en la gloria de Dios Padre."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'GLORIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (413, 'Amor de Dios puesto en acción', '[{"c":"","l":"Sueño de Jesús para el mundo, moción del soplo creador"},{"c":"","l":"Fiesta de cristianos audaces, amor de Dios, puesto en acción."},{"c":"","l":"Primavera del compromiso, amanecer de la oración"},{"c":"","l":"Retazo del cielo en mi vida, amor de Dios puesto en acción"},{"c":"","l":""},{"c":"","l":"*Servicio y Pasión, por amar por vivir,"},{"c":"","l":"El evangelio en la vida, abriendo el corazón,"},{"c":"","l":"Proclama la paz de Cristo en el reino de Cristo"},{"c":"","l":"La paz de Cristo, en el reino de Cristo*"},{"c":"","l":""},{"c":"","l":"Mano hacia los pobres tendida, paso incansable en la misión"},{"c":"","l":"Palabra de vida en los labios, amor de Dios puesto en acción"},{"c":"","l":"Casas, aulas, calles y campos, fábricas y universidad"},{"c":"","l":"Guardan algún rastro de cielo, gracias a tu presencia actual."},{"c":"","l":""},{"c":"","l":"*[Estribillo]*"},{"c":"","l":""},{"c":"","l":"Rostro de entrañables amigos, amistad firme en el Señor,"},{"c":"","l":"Los que están y los se fueron, pero que guarda el corazón"},{"c":"","l":"Yo los vi cruzando caminos, llevando paz y comunión"},{"c":"","l":"Tras sus huellas descubrí el cielo, amor de Dios puesto en acción"},{"c":"","l":""},{"c":"","l":"*[Estribillo]*"},{"c":"","l":""},{"c":"","l":"Brillan como piedras preciosas, santos y santas que con vos"},{"c":"","l":"Siguieron la senda de Cristo, amor de Dios puesto en acción"},{"c":"","l":"No te olvides nunca que existes, para ser signo del amor"},{"c":"","l":"Que al sol mueve y a las estrellas, y que en la cruz se derramo."},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (414, 'La paz es fruto de la justicia', '[{"c":"","l":"*La paz, la paz es fruto de la justicia"},{"c":"","l":"Un don de Dios, que queremos aceptar (bis)*"},{"c":"","l":""},{"c":"","l":"Unidos mano con mano, queremos hacer la paz"},{"c":"","l":"la paz con nuestra conciencia, con Dios y con los demás (bis)"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (415, 'Ha nacido el Rey del Cielo', '[{"c":"","l":"Ha nacido el Rey del Cielo, ha nacido nuestro Dios."},{"c":"","l":"Elevemos nuestros cantos, a Jesús el Salvador."},{"c":"","l":""},{"c":"","l":"*Aleluya, cante el Cielo. Aleluya, cante el suelo."},{"c":"","l":"Gloria a Cristo, nuestro Rey. Gloria al niño de Belén."},{"c":"","l":"En la Tierra, paz y amor. Y en el Cielo, gloria a Dios.*"},{"c":"","l":""},{"c":"","l":"Con los ángeles del Cielo, celebremos Navidad."},{"c":"","l":"Con sus voces anunciemos, gloria a Dios y al hombre de paz."},{"c":"","l":""},{"c":"","l":"El Señor de los señores, el Ungido celestial,"},{"c":"","l":"a salvar los pecadores, vino al seno Virginal."},{"c":"","l":""},{"c":"","l":"Es la noche prometida, es la noche del perdón."},{"c":"","l":"Hoy el Cielo se concilia, con el mundo pecador."}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (416, 'Vayamos y adoremos', '[{"c":"","l":"Vayamos y adoremos al niño que nació"},{"c":"","l":"Vayamos y adoremos al niño que nació"},{"c":"","l":""},{"c":"","l":"*Jesucristo, desde siempre, Jesucristo salvador,"},{"c":"","l":"Nos regala su amistad, gloria a Cristo es navidad*"},{"c":"","l":""},{"c":"","l":"Los magos se postraron y adoraron al Señor"},{"c":"","l":"Los magos se postraron y adoraron al Señor"},{"c":"","l":""},{"c":"","l":"La Virgen, meditaba y lo guardaba en su interior"},{"c":"","l":"La Virgen, meditaba y lo guardaba en su interior"},{"c":"","l":""},{"c":"","l":""}]', 'NAVIDAD', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (417, 'Con que pagaré', '[{"c":"","l":"Vuelve a tu calma, alma mia."},{"c":"","l":"Vuelve y descansa, corazón,"},{"c":"","l":"que el Señor te ha favorecido."},{"c":"","l":"El Señor tu canto escuchó."},{"c":"","l":""},{"c":"","l":"*¿Con qué pagaré todo el bien que me hizo?"},{"c":"","l":"¿Cómo responder tanto amor inmerecido?"},{"c":"","l":"Con que pagaré si, al fin de cuentas,"},{"c":"","l":"todo es gracia.*"},{"c":"","l":""},{"c":"","l":"Alzaré la copa de la salvación,"},{"c":"","l":"y le ofreceré mi alabanza."},{"c":"","l":"Cumpliré mis votos en presencia,"},{"c":"","l":"de su pueblo y en su misma casa."},{"c":"","l":""},{"c":"","l":"*¿Con qué pagaré todo el bien que me hizo?"},{"c":"","l":"¿Cómo responder tanto amor inmerecido?"},{"c":"","l":"Con que pagaré si, al fin de cuentas,"},{"c":"","l":"todo es gracia*"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (418, 'Vayamos a la mesa (Catena)', '[{"c":"","l":"*Vayamos a la mesa del Padre celestial,"},{"c":"","l":"que allí Jesús ofrece el pan de eternidad.*"},{"c":"","l":""},{"c":"","l":"Señor, hoy tu visita queremos recibir,"},{"c":"","l":"y renovar las vidas uniéndonos a ti."},{"c":"","l":""},{"c":"","l":"Tu vienes a nosotros, amigo de verdad,"},{"c":"","l":"que nada nos separe, Señor, de tu amistad."},{"c":"","l":""},{"c":"","l":"Tú sólo eres camino que nos conduce a Dios."},{"c":"","l":"Revélanos al Padre y muéstranos su amor."},{"c":"","l":""},{"c":"","l":"La Santa Eucaristía renueva tu Pasión,"},{"c":"","l":"por ella nuestra vida se asocia a tu dolor."},{"c":"","l":""},{"c":"","l":"Señor, hoy nos congrega la mesa de tu altar;"},{"c":"","l":"nos una para siempre la gloria celestial."}]', 'OFRENDAS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (419, 'Dios te salve (Pascua Joven)', '[{"c":"","l":"Dios te salve María, sagrada, María Señora de nuestro camino."},{"c":"","l":"Llena eres de gracia, llamada entre todas, a ser, la madre de Dios."},{"c":"","l":"El Señor es contigo y tú eres, la sierva dispuesta a cumplir su misión."},{"c":"","l":"Y bendita tu eres, dichosa te llaman a ti, la escogida de Dios."},{"c":"","l":""},{"c":"","l":"Y bendito es el fruto que crece en tu vientre, el Mesías del pueblo de Dios,"},{"c":"","l":"al que tanto esperamos que nazca y que sea nuestro Rey."},{"c":"","l":""},{"c":"","l":"María he mirado hacia el cielo pensando entre nubes tu rostro encontrar,"},{"c":"","l":"y al fin te encontré en un establo entregando la vida, a Jesús Salvador."},{"c":"","l":"María he querido sentirte entre tantos milagros que cuentan de ti,"},{"c":"","l":"al fin te encontré en mi camino en la misma vereda que yo."},{"c":"","l":""},{"c":"","l":"Tenías tu cuerpo cansado, un niño en los brazos durmiendo en tu paz."},{"c":"","l":""},{"c":"","l":"*María, mujer que regalas la vida sin fin. *"},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'MARIA', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (420, 'Más cerca, oh Dios', '[{"c":"","l":"Más cerca, oh Dios, de Ti, más cerca, sí,"},{"c":"","l":"aunque sea una cruz que me lleve a Ti."},{"c":"","l":"Si tiende al sol la flor, si el agua busca el mar,"},{"c":"","l":"a Ti, mi solo Bien, yo he de buscar."},{"c":"","l":""},{"c":"","l":"Mi pobre corazón inquieto está"},{"c":"","l":"hasta que en Ti, Señor, encuentre paz."},{"c":"","l":"Abráceme Tu Amor, oh Luz de eternidad."},{"c":"","l":"Cerca de Ti, Señor, quiero morar."},{"c":"","l":""},{"c":"","l":"Refugio es el Señor, no temeré."},{"c":"","l":"Mi fuerza en el dolor, confío en &Eacute;l."},{"c":"","l":"Si brama y gime el mar, las olas al romper,"},{"c":"","l":"conmigo Dios está, no temeré."},{"c":"","l":""},{"c":"","l":"Yo creo en Ti, Señor, yo creo en Ti."},{"c":"","l":"Dios vivo en el altar, presente en mí."},{"c":"","l":"Si ciegos al mirar, mis ojos no te ven,"},{"c":"","l":"yo creo en Ti, Señor, aumenta mi fe."},{"c":"","l":""},{"c":"","l":""}]', 'COMUNION', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (421, 'Siervo por amor', '[{"c":"","l":"Una noche de sudor con la barca en altamar,"},{"c":"","l":"Mientras amanece ya, tus redes vacías."},{"c":"","l":"Pero la voz que te llama otro mar te enseñará,"},{"c":"","l":"sobre cada corazón sus redes echará."},{"c":"","l":""},{"c":"","l":"*Dona dona tu vida como maría al lado de la cruz"},{"c":"","l":"y serás siervo de todo hombre, siervo por amor,"},{"c":"","l":"sacerdote de la humanidad.*"},{"c":"","l":""},{"c":"","l":"Avanzabas en el silencio, entre lágrimas esperabas"},{"c":"","l":"que la semilla antes sembrada cayera sobre tierra fértil."},{"c":"","l":"Nace el gozo ya en tí viendo el trigo madurar"},{"c":"","l":"y crecido bajo el sol, ya se puede almacenar."},{"c":"","l":""},{"c":"","l":"*Dona dona tu vida como maría al lado de la cruz"},{"c":"","l":"y serás siervo de todo hombre, siervo por amor,"},{"c":"","l":"sacerdote de la humanidad.* (bis)"},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (422, 'Peregrinos de esperanza (Himno jubileo 2025)', '[{"c":"","l":"*Llama viva para mi esperanza,"},{"c":"","l":"que este canto llegue hasta ti,"},{"c":"","l":"seno eterno de infinita vida,"},{"c":"","l":"me encamino, yo confío en ti.*"},{"c":"","l":""},{"c":"","l":"Toda lengua, pueblos y naciones"},{"c":"","l":"hallan luces siempre en tu Palabra."},{"c":"","l":"Hijos, hijas, frágiles, dispersos,"},{"c":"","l":"acogidos en tu Hijo amado."},{"c":"","l":""},{"c":"","l":"Dios nos cuida, tierno y paciente"},{"c":"","l":"nace el día, un futuro nuevo."},{"c":"","l":"Cielos nuevos y una tierra nueva."},{"c":"","l":"Caen muros gracias al Espíritu."},{"c":"","l":""},{"c":"","l":"Una senda tienes por delante,"},{"c":"","l":"paso firme, Dios sale a tu encuentro."},{"c":"","l":"Mira al Hijo que se ha hecho hombre"},{"c":"","l":"para todos, él es el camino."},{"c":"","l":""},{"c":"","l":""},{"c":"","l":""}]', 'OTROS', NULL);
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (423, 'Surja Dios', '[{"c":"","l":"Surja Dios Padre."},{"c":"","l":"se dispersen sus enemigos"},{"c":"","l":"Y huyan de su presencia"},{"c":"","l":"Aquellos que lo odian."},{"c":"","l":""},{"c":"","l":"Surja Dios Hijo."},{"c":"","l":"Se dispersen sus enemigos"},{"c":"","l":"Y huyan de su presencia"},{"c":"","l":"Aquellos que lo odian."},{"c":"","l":""},{"c":"","l":"Surja Dios Espíritu."},{"c":"","l":"Se dispersen sus enemigos"},{"c":"","l":"Y huyan de su presencia"},{"c":"","l":"Aquellos que lo odian."},{"c":"","l":""},{"c":"","l":"*Dios vive en mí, y yo en &Eacute;l."},{"c":"","l":"Y yo en &Eacute;l."},{"c":"","l":"Dios vive en mí y yo en &Eacute;l."},{"c":"","l":"Y yo en &Eacute;l.*"},{"c":"","l":""},{"c":"","l":"Surja Dios Trino."},{"c":"","l":"Se dispersen sus enemigos."},{"c":"","l":"Y huyan de su presencia,"},{"c":"","l":"Aquellos que lo odian."},{"c":"","l":""},{"c":"","l":"*Dios vive en mí, y yo en &Eacute;l."},{"c":"","l":"Y yo en &Eacute;l."},{"c":"","l":"Dios vive en mí y yo en &Eacute;l."},{"c":"","l":"Y yo en &Eacute;l.*"},{"c":"","l":""},{"c":"","l":"En tu presencia voy,"},{"c":"","l":"En tu presencia voy,"},{"c":"","l":"En tu presencia voy, Dios trino."},{"c":"","l":""},{"c":"","l":"En tu presencia voy,"},{"c":"","l":"En tu presencia voy,"},{"c":"","l":"En tu presencia voy, Dios trino."},{"c":"","l":""},{"c":"","l":"En tu presencia voy,"},{"c":"","l":"En tu presencia voy,"},{"c":"","l":"En tu presencia voy, Dios trino."},{"c":"","l":""},{"c":"","l":"*Dios vive en mí, y yo en &Eacute;l."},{"c":"","l":"Y yo en &Eacute;l."},{"c":"","l":"Dios vive en mí y yo en &Eacute;l."},{"c":"","l":"Y yo en &Eacute;l.*"}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=C306VHrz7Wc&list=RDC306VHrz7Wc","autor":"Pablo Martinez"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (424, 'No soy digno', '[{"c":"","l":"*No soy digno de que entres tú en mi casa (x4)*"},{"c":"","l":""},{"c":"","l":"Pero dime una palabra tuya y yo me sanaré (bis)"},{"c":"","l":"Sólo dime una palabra tuya y yo me sanaré (bis)"},{"c":"","l":""},{"c":"","l":"Sólo dame un aliento tuyo y yo tendré vida (bis)"},{"c":"","l":"Sólo dame un aliento tuyo y yo daré vida (bis)"},{"c":"","l":""},{"c":"","l":"*No soy digno de que entres tú en mi casa (x4)*"},{"c":"","l":""},{"c":"","l":"Sólo dame una mirada tuya y yo podré ver (bis)"},{"c":"","l":"Sólo dame una mirada tuya y yo podré ver (bis)"},{"c":"","l":""},{"c":"","l":"Sólo dame una sonrisa tuya y yo podré reír (bis)"},{"c":"","l":"Sólo dame una sonrisa tuya y yo haré reír (bis)"},{"c":"","l":""},{"c":"","l":"*No soy digno de que entres tú en mi casa (x4)*"},{"c":"","l":""},{"c":"","l":"Sólo dame una caricia tuya y yo acariciaré (bis)"},{"c":"","l":"Sólo dame una caricia tuya y yo acariciaré (bis)"},{"c":"","l":""},{"c":"","l":"Pero dime una palabra tuya y eso bastará (bis)"},{"c":"","l":"Pero dime una palabra tuya y eso bastará (bis)"},{"c":"","l":""}]', 'ACCION DE GRACIAS / ADORACION', '{"youtube_url":"https://www.youtube.com/watch?v=3yHxzC_1__0&list=RD3yHxzC_1__0&start_radio=1","autor":"Hermana Glenda"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (425, 'Gloria', '[{"c":"","l":"*Gloria, Gloria, A Dios en lo alto del cielo, Gloria*"},{"c":"","l":""},{"c":"","l":"Y en la tierra (Paz a los hombres), y en la tierra (Paz a los hombres)"},{"c":"","l":"Paz a los hombres que ama el Señor"},{"c":"","l":""},{"c":"","l":"Te alabamos (te alabamos), te bendecimos (te bendecimos)"},{"c":"","l":"Te adoramos (te adoramos), te glorificamos (te glorificamos)"},{"c":"","l":""},{"c":"","l":"Te daaamos(te damos gracias), graaaacias (por tu inmeeeeeensa),"},{"c":"","l":"por tu inmensa gloooria"},{"c":"","l":""},{"c":"","l":"(Señor Hijo único), Jesucristo Señor Dios,"},{"c":"","l":"(Cordero de Dios), Hijo del Paaaaaaaadre,"},{"c":"","l":""},{"c":"","l":"(Tú que quitas el pecado) aaaaahh, (el pecado del mundo) aaaaaah"},{"c":"","l":"(Ten piedad de nosotros), ten piedad de nosotros"},{"c":"","l":""},{"c":"","l":"(Tú que quitas el pecado) aaaaahh, (el pecado del mundo) aaaaaah"},{"c":"","l":"(Atiende), atiende, a nuestra súplica,"},{"c":"","l":""},{"c":"","l":"(Tú que estás a la derecha, a la derecha de Dios Padre)"},{"c":"","l":"Ten piedad de nosotros, Ten piedad de nosotros"},{"c":"","l":""},{"c":"","l":"Porque sólo Tú eres santo (porque solo tu eres santo),"},{"c":"","l":"sólo Tú Señor (solo tu Señor),"},{"c":"","l":"Sólo Tú Altísimo (solo tu altísimo),"},{"c":"","l":"Jesucristo (Jesucristo)."},{"c":"","l":""},{"c":"","l":"Con el Espíiiiritu (con el espíritu Santo)"},{"c":"","l":"Saaaanto (en la gloria de ...),"},{"c":"","l":"En la gloria de Dios Paaadre Aaaaamén (x2)*"},{"c":"","l":""},{"c":"","l":"Con el Espíiiiritu (con el espíritu Santo)"},{"c":"","l":"Saaaanto (en la gloria de ...),"},{"c":"","l":"En la gloria de Dios Paaadre Aaaaamén."},{"c":"","l":""},{"c":"","l":"En la gloria de Dios Paaadre Aaaaamén,"},{"c":"","l":"En la gloria de Dios Paaadre Aaaaamén."},{"c":"","l":""}]', 'GLORIA', '{"youtube_url":"https://www.youtube.com/watch?v=AB1mOatVBWU&list=RDAB1mOatVBWU&start_radio=1","autor":"Giombini"}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (426, 'Pastorcito de Belén', '[{"c":"","l":"El Niño Dios ha nacido"},{"c":"","l":"allá lejos en Belén,"},{"c":"","l":"vendrán los Reyes a verlo"},{"c":"","l":"y los pastores también."},{"c":"","l":"El Niño Dios ha nacido"},{"c":"","l":"allá lejos en Belén."},{"c":"","l":""},{"c":"","l":"*Ay Niñito de Belén,*"},{"c":"","l":"*ruega por todos*"},{"c":"","l":"*y por mí también.*"},{"c":"","l":""},{"c":"","l":"Su padre como lo mira,"},{"c":"","l":"su madre, llorando está,"},{"c":"","l":"quizá que llore sabiendo"},{"c":"","l":"tormentos que ha de pasar."},{"c":"","l":"Su padre como lo mira,"},{"c":"","l":"su madre llorando está."},{"c":"","l":""},{"c":"","l":"Los Reyes le traen oro,"},{"c":"","l":"los pastores, su bondad."},{"c":"","l":"Y una estrellita del cielo,"},{"c":"","l":"plata del cielo le da."},{"c":"","l":"Los Reyes le traen oro,"},{"c":"","l":"los pastores, su bondad."}]', 'NAVIDAD', '{"youtube_url":"","autor":""}');
INSERT INTO Canciones (id, titulo, letra, grupo, extras) VALUES (427, 'La Virgen María nos reúne', '[{"c":"G             C            G","l":"*La Virgen María nos reúne*"},{"c":"D             G","l":"*en nombre del Señor,*"},{"c":"G             C        G          D         G","l":"*del Señor Jesús, Dios nuestro Señor.*"},{"c":"G                 C                      G","l":"Venimos a buscar el pan de la Palabra,"},{"c":"D                  G            D           G","l":"Palabra del Señor que reconforta el alma."},{"c":"G                 C                    G","l":"Venimos a comer el Pan sacramentado,"},{"c":"D                   G        D           G","l":"el Cuerpo del Señor, Jesús resucitado."},{"c":"G                 C                    G","l":"Venimos a llevar el pan de la alegría,"},{"c":"D                     G            D       G","l":"mensaje que nos dio el Hijo de María."}]', 'MARIA', '{"youtube_url":"","autor":"Anónimo"}');
